import {
	Component,
	Input,
	OnChanges,
	OnInit,
	SimpleChanges,
	ViewChild,
} from "@angular/core";
import {
	SohoAutoCompleteComponent,
	SohoModalDialogRef,
} from "@infor/sohoxi-angular";
import { ArrayUtil, IAutocompleteEntity } from "lime";
import {
	Constants,
	EntityAccessDialogType,
	EntityOperation,
	IEntityAccess,
	IEntityAccessDialogOptions,
	IEntityAccessInfoResponse,
	IOperationResponse,
	IPageAccessResponse,
	IWidgetHandle,
	NameNumberValue,
	PageAccessLevel,
	PrincipalType,
	Templates,
	WidgetAccessLevel,
} from "../base/core";
import { AutoCompleter, CoreBase, CoreUtil } from "../base/runtime";
import { LanguageService } from "../base/service";
import { PageService } from "../page/service";
import { CommonDataService } from "../service";
import { WidgetService } from "../widget/service";

@Component({
	selector: "lm-entity-access-component",
	templateUrl: "./entity-access.html",
	styleUrls: ["./entity-access.scss"],
})
export class EntityAccessComponent extends CoreBase implements OnChanges {
	@Input() options: IEntityAccessDialogOptions;
	@Input() isAdmin: boolean;
	@ViewChild(SohoAutoCompleteComponent) autocomplete: SohoAutoCompleteComponent;

	entityAccess: IEntityAccess[] = [];
	accessLevels: NameNumberValue[] = [];
	everyoneAccessLevels: NameNumberValue[] = [];
	userType = PrincipalType.User;
	selectedType = "2"; // Role
	enableRole = true;
	enableUser = true;
	enableDistributionGroup = true;
	autoCompleter: AutoCompleter<IAutocompleteEntity[]>;
	autocompleteTemplate: string;
	lang: ILanguageLime;
	showAdminMsg = false;

	private existingItems: IEntityAccess[];
	// Keep track of which items have been deleted to handle the scenario where items get re-added
	private deletedItems: IEntityAccess[] = [];
	private isInitialized = false;

	constructor(
		languageService: LanguageService,
		private readonly commonDataService: CommonDataService,
	) {
		super("EntityAccessComponent");
		this.lang = languageService.getLanguage();
		this.init();
	}

	ngOnChanges(changes: SimpleChanges): void {
		const options = this.options;
		if (!options || this.isInitialized) {
			return;
		}

		this.isInitialized = true;

		let items = options.access;
		if (!items) {
			options.access = items = [];
		}

		this.existingItems = items;
		items = CoreUtil.copy(items);
		ArrayUtil.sortByProperty(items, "principalName");
		this.verifyRoles(items);
		this.entityAccess = items;

		if (options.accessLevels) {
			this.accessLevels = options.accessLevels;
		} else {
			this.accessLevels = [
				{ name: this.lang.editAccess, value: PageAccessLevel.Edit },
				{ name: this.lang.viewAccess, value: PageAccessLevel.View },
			];
		}

		if (options.everyoneAccessLevels) {
			this.everyoneAccessLevels = options.everyoneAccessLevels;
		} else {
			this.everyoneAccessLevels = CoreUtil.copy(this.accessLevels);
		}

		if (options.includedTypes) {
			const principalTypes = options.includedTypes;
			// Set what principal types should be visible note that there is no special handling
			// when only one is visible
			this.enableRole = false;
			this.enableUser = false;
			this.enableDistributionGroup = false;
			for (let i = 0; i < principalTypes.length; i++) {
				const principalType = principalTypes[i];
				switch (principalType) {
					case PrincipalType.User:
						this.enableUser = true;
						break;
					case PrincipalType.Role:
						this.enableRole = true;
						break;
					case PrincipalType.DistributionGroup:
						this.enableDistributionGroup = true;
						break;
				}
			}

			// Check for new default selection
			if (this.enableRole) {
				this.selectedType = PrincipalType.Role.toString();
			} else if (this.enableUser) {
				this.selectedType = PrincipalType.User.toString();
			}
		}
	}

	getAccessLevels(access: IEntityAccess): NameNumberValue[] {
		if (this.isEveryone(access)) {
			return this.everyoneAccessLevels;
		}
		return this.accessLevels;
	}

	isDisabled(access: IEntityAccess): boolean {
		// Disable removal of the Everyone role / group
		const type = access.principalType;
		return (
			Constants.groupEveryone === access.principal &&
			type === PrincipalType.Role
		);
	}

	isEveryone(access: IEntityAccess): boolean {
		return this.isDisabled(access);
	}

	getPrincipalTypeDisplayName(access: IEntityAccess): string {
		const principalType = access.principalType;
		if (PrincipalType.Role === principalType) {
			return this.lang.role;
		}
		if (PrincipalType.User === principalType) {
			return this.lang.user;
		}
		if (PrincipalType.DistributionGroup === principalType) {
			return this.lang.distributionGroup;
		}
		return "";
	}

	onSelected(event: SohoAutoCompleteEvent): void {
		const item = event[2];
		if (!item || !item.value) {
			return;
		}

		this.addEntity(item);
	}

	onEnterKey(): void {
		// Only add typed value if Role and if there are no results (with results, enter adds highlighted result).
		if (
			this.selectedType !== "2" ||
			this.autoCompleter.getLastResult()?.length
		) {
			return;
		}

		const value = this.autocomplete.getValue();
		if (!value?.length) {
			return;
		}

		const item: IAutocompleteEntity = {
			type: PrincipalType.Role,
			value: value,
			label: value,
			info: value,
		};
		this.addEntity(item);
	}

	onChangedAccessLevel(entity: IEntityAccess): void {
		const existing = CoreUtil.getAccess(this.existingItems, entity);
		if (existing) {
			existing.accessLevel = entity.accessLevel;
			if (existing.operation !== EntityOperation.Create) {
				existing.operation = EntityOperation.Update;
			}
		}
	}

	onChangedSwitch(entity: IEntityAccess): void {
		const existing = CoreUtil.getAccess(this.existingItems, entity);
		if (existing) {
			existing.isCatalog = entity.isCatalog;
			if (existing.operation !== EntityOperation.Create) {
				existing.operation = EntityOperation.Update;
			}
		}
	}

	delete(entity: IEntityAccess): void {
		ArrayUtil.remove(this.entityAccess, entity);
		this.deletedItems.push(entity);
		if (entity.operation === EntityOperation.Create) {
			this.removeExisting(entity);
		} else {
			const existing = CoreUtil.getAccess(this.existingItems, entity);
			if (existing) {
				existing.operation = EntityOperation.Delete;
			}
		}
		this.setShowAdminMsgFlag();
	}

	private addEntity(item: IAutocompleteEntity): void {
		if (
			ArrayUtil.containsByProperty(this.entityAccess, "principal", item.value)
		) {
			return;
		}

		const options = this.options;
		const entity = {
			accessLevel: options.defaultAccessLevel,
			operation: EntityOperation.Create,
			principal: item.value,
			principalName: item.label ? item.label : item.value,
			principalType: item.type,
			info: item.info,
		} as IEntityAccess;

		// The operation should be EntityOperation.Update when an item has been deleted and then re-added
		const updatedItem = ArrayUtil.find(this.deletedItems, (e) =>
			CoreUtil.isAccess(entity, e),
		);
		if (updatedItem) {
			entity.operation = EntityOperation.Update;
			ArrayUtil.remove(this.deletedItems, updatedItem);
		}

		if (options.dialogType === EntityAccessDialogType.Widget) {
			entity.isCatalog = true;
		}

		// Remove any deleted / updated while the dialog was open to prevent duplicate items
		this.removeExisting(entity);

		this.existingItems.push(entity);
		this.entityAccess.push(entity);
		this.setShowAdminMsgFlag();
	}

	private removeExisting(entity: IEntityAccess): void {
		ArrayUtil.removeByPredicate(this.existingItems, (e) => {
			return CoreUtil.isAccess(entity, e);
		});
	}

	private verifyRoles(items: IEntityAccess[]): void {
		// Add the default implicit Everyone permission if it is missing.
		const principal = Constants.groupEveryone;
		let everyoneAccess: IEntityAccess = ArrayUtil.itemByProperty(
			items,
			"principal",
			principal,
		);
		if (everyoneAccess) {
			everyoneAccess.principalName = this.lang.everyone;
			ArrayUtil.remove(items, everyoneAccess);
			items.unshift(everyoneAccess);
		} else {
			everyoneAccess = {
				principal: principal,
				principalName: this.lang.everyone,
				accessLevel: this.options.defaultAccessLevel,
				principalType: PrincipalType.Role,
				operation: EntityOperation.Create,
			} as IEntityAccess;
			if (this.options.dialogType === EntityAccessDialogType.Widget) {
				everyoneAccess.isCatalog = true;
			}
			items.unshift(everyoneAccess);
			this.existingItems.unshift(everyoneAccess);
		}
		this.setShowAdminMsgFlag();
	}

	private init(): void {
		const self = this;
		this.autoCompleter = new AutoCompleter<IAutocompleteEntity[]>(
			(query) =>
				self.commonDataService.searchEntity(self.getPrincipalType(), query),
			(response) => ArrayUtil.sortByProperty(response, "label"),
			self.commonDataService,
			false,
		);
		this.autocompleteTemplate = Templates.autocompleteEntity;
	}

	private getPrincipalType(): number {
		return parseInt(this.selectedType, 10);
	}

	/**
	 * Checks if Admin or Content Admin role is present in the access level list.
	 */
	private isAdminOrContentAdminInList(): boolean {
		for (const item of this.existingItems) {
			if (
				item.principal === Constants.roleAdmin ||
				item.principalName === Constants.roleContentAdmin
			) {
				return item.operation !== EntityOperation.Delete;
			}
		}
		return false;
	}

	/**
	 * Sets the showAdminMsg flag.
	 */
	private setShowAdminMsgFlag() {
		this.showAdminMsg = this.isAdminOrContentAdminInList();
	}
}

@Component({
	templateUrl: "./permissions.html",
	styleUrls: ["./permissions.scss"],
})
export class ShowWidgetOrPagePermissionsComponent implements OnInit {
	@Input() dialog: SohoModalDialogRef<ShowWidgetOrPagePermissionsComponent>;
	@Input() id: string;
	@Input() widgetHandle: IWidgetHandle;

	everyone: IEntityAccess;
	users: IEntityAccess[] = [];
	groups: IEntityAccess[] = [];
	roles: IEntityAccess[] = [];
	lang: ILanguageLime;
	hiddenIcon = "scripts/lime/resources/icons/ic-hidden.png";
	userId: string;

	private isWidget: boolean;

	constructor(
		languageService: LanguageService,
		private widgetService: WidgetService,
		private pageService: PageService,
	) {
		this.lang = languageService.getLanguage();
	}

	ngOnInit(): void {
		this.isWidget = this.widgetHandle != null;
		this.getAccess();
	}

	close(): void {
		this.dialog.close();
	}

	convertAccessLevel(accessLevel: number): string {
		if (this.isWidget) {
			switch (accessLevel) {
				case WidgetAccessLevel.Configure:
					return this.lang.configure;
				case WidgetAccessLevel.View:
					return this.lang.viewAccess;
				case WidgetAccessLevel.Disabled:
					return this.lang.disabled;
				case WidgetAccessLevel.Publish:
					return this.lang.canPublish;
				default:
					return this.lang.configure;
			}
		} else {
			switch (accessLevel) {
				case PageAccessLevel.Edit:
					return this.lang.editAccess;
				case PageAccessLevel.View:
					return this.lang.viewAccess;
				case PageAccessLevel.Disabled:
					return this.lang.disabled;
				default:
					return this.lang.viewAccess;
			}
		}
	}

	private getAccess() {
		if (this.isWidget) {
			return this.widgetService.getWidgetAccess(this.widgetHandle).subscribe(
				(r: IEntityAccessInfoResponse) => {
					if (r && r.content) {
						this.sortAccess(r.content.accessList);
					}
				},
				(r: IOperationResponse) => {
					this.handleAccessError(r);
				},
			);
		} else {
			return this.pageService.getPageAccess(this.id).subscribe(
				(r: IPageAccessResponse) => {
					if (r && r.content) {
						this.sortAccess(r.content.access);
					}
				},
				(r: IOperationResponse) => {
					this.handleAccessError(r);
				},
			);
		}
	}

	private handleAccessError(response: IOperationResponse) {
		if (response.hasError()) {
			this.pageService.handleError(response);
			this.dialog.close();
		}
	}

	private sortAccess(access: IEntityAccess[]) {
		this.setEveryoneAccess(access);
		access.forEach((accessItem) => {
			switch (accessItem.principalType) {
				case PrincipalType.User:
					this.users.push(accessItem);
					break;
				case PrincipalType.Role:
					this.roles.push(accessItem);
					break;
				case PrincipalType.DistributionGroup:
					this.groups.push(accessItem);
					break;
				default:
					this.users.push(accessItem);
					break;
			}
		});
	}

	private setEveryoneAccess(items: IEntityAccess[]): void {
		// Add the default implicit Everyone permission if it is missing.
		const principal = Constants.groupEveryone;
		let everyoneAccess: IEntityAccess = ArrayUtil.itemByProperty(
			items,
			"principal",
			principal,
		);
		if (everyoneAccess) {
			everyoneAccess.principalName = this.lang.everyone;
			ArrayUtil.remove(items, everyoneAccess);
		} else {
			everyoneAccess = {
				principal: principal,
				principalName: this.lang.everyone,
				accessLevel: this.isWidget
					? (WidgetAccessLevel.Configure as number)
					: (PageAccessLevel.View as number),
				// principalType: PrincipalType.Role
				// operation: EntityOperation.Create
			} as IEntityAccess;
			if (this.isWidget) {
				everyoneAccess.isCatalog = true;
			}
		}
		this.everyone = everyoneAccess;
	}
}
