import { BrowserStorageService } from "../../services/browser-storage.service";
import { ContentImportComponent } from "../common";

export interface ITranslationEntity {
	language?: string;
	title?: string;
	description?: string;
}

export interface ITranslationData {
	language: string;
	localization: IStringMap;
	primaryName: string;
}

interface IMyDialogResult extends IDialogResult {
	value?: {
		translation?: ITranslationEntity;
	};
}

export class LanguageConverter {
	constructor(public lang: ILanguageLime) {}

	toList(languageMap: IStringMap): ILanguageInfo[] {
		const items = [];

		for (const tag of Object.keys(languageMap)) {
			items.push({
				tag: tag,
				name: this.getDisplayName(tag),
				native: languageMap[tag],
			});
		}

		ArrayUtil.sortByProperty(items, "name");
		return items;
	}

	getDisplayName(languageCode: string): string {
		if (!languageCode) {
			return languageCode;
		}
		const key = "lang" + languageCode.replace("-", "");
		const translatedLanguageName = this.lang[key] as string;
		return translatedLanguageName ? translatedLanguageName : languageCode;
	}
}

export class TranslationComponentBase extends CoreBase {
	lang: ILanguageLime;

	protected converter: LanguageConverter;

	constructor(logPrefix: string, languageService: LanguageService) {
		super(logPrefix);
		this.lang = languageService.getLanguage();
		this.converter = new LanguageConverter(this.lang);
	}

	getLanguageDisplayName(languageCode: string): string {
		return this.converter.getDisplayName(languageCode);
	}
}

@Component({
	selector: "lm-translations-component",
	templateUrl: "./translation.html",
	styleUrls: ["./translation.scss"],
})
export class TranslationsComponent
	extends TranslationComponentBase
	implements OnChanges
{
	@ViewChild("translationView", { read: ViewContainerRef, static: false })
	view: ViewContainerRef;
	@Input() parameter: ILocalizationParameter;
	@Input() provider: () => ILocalizationParameter;
	@Input() category: EntityCategory;
	@Output() localizationChange = new EventEmitter<ITranslationData[]>();
	@Input() memoLayout: number;
	hasTranslations: boolean;
	languages: IStringMap;
	defaultLanguage: string;
	langsLength: number;
	addedLangsLength: number;
	enablePortation = false;
	items: ITranslationData[];
	private isDialogOpen: boolean;
	private isLoading: boolean;

	constructor(
		private readonly dialogService: SohoModalDialogService,
		private readonly contextService: ContextService,
		languageService: LanguageService,
		private readonly commonDataService: CommonDataService,
		private readonly dataService: DataService,
		private readonly toastService: SohoToastService,
	) {
		super("TranslationsComponent", languageService);

		this.lang = languageService.getLanguage();
		this.defaultLanguage = this.contextService
			.getContext()
			.settings.getDefaultLanguage();
	}

	ngOnChanges(changes: SimpleChanges): void {
		const parameter = this.getParameter();
		if (parameter) {
			this.enablePortation = parameter.enablePortation;
			this.updateLocalization();
		}
	}

	add(translation?: ITranslationEntity) {
		if (!translation) {
			translation = {};
		}
		this.showDialog(translation);
	}

	edit(language: string) {
		const translation: ITranslationEntity = {};
		CoreUtil.extend(translation, this.getParameter().localizationMap[language]);
		if (Object.keys(translation).length > 0) {
			translation.language = language;
			this.showDialog(translation);
		}
	}

	delete(language: string) {
		const parameter = this.getParameter();
		delete parameter.localizationMap[language];
		this.hasTranslations = !$.isEmptyObject(parameter.localizationMap);
		this.addedLangsLength = Object.keys(parameter.localizationMap).length;

		this.updateLocalization();
	}

	getPrimaryValue(): string {
		const items = this.getParameter().translationOptions.items;
		return items.length > 0 ? items[0].defaultValue : null;
	}

	exportTranslations(): void {
		let name = this.getPrimaryValue();
		while (name && name.charAt(0) === ".") {
			name = name.substring(1);
		}
		if (!name) {
			name = "Localization";
		}
		name = encodeURIComponent(name);
		const localization = encodeURIComponent(
			JSON.stringify(this.getParameter().localizationMap),
		);
		const query =
			"?localization=" +
			localization +
			"&category=" +
			this.category +
			"&rid=" +
			new Date().getTime(); // Add this to prevent browser caching
		const url =
			this.dataService.getUrl("common/localization/export/" + name + ".zip") +
			query;
		window.open(url, "_blank");
	}

	importTranslations(): void {
		const self = this;
		const title = self.lang.importTranslations;
		const importOptions: IImportOptions = {
			url: "/user",
			title: title,
			operation: self.category.toString(),
			acceptFileExtension: ".zip",
		};

		const dialog = this.dialogService
			.modal(ContentImportComponent, this.view)
			.title(title)
			.id("lm-tr-import-dialog")
			.afterClose((result: IDialogResult) => {
				if (result && result.value) {
					if (
						result.button === DialogButtonType.Yes ||
						result.button === DialogButtonType.Ok
					) {
						self.getParameter().localizationMap = result.value.message.content;
						self.updateLocalization();
						self.showImportSuccessToast();
					} else {
						this.dataService.showError(
							self.lang.importTranslations,
							self.lang.errorGeneric,
						);
					}
				}
			});

		dialog
			.apply((component) => {
				component.dialog = dialog;
				component.options = importOptions;
			})
			.open();
	}

	private getParameter(): ILocalizationParameter {
		if (this.provider) {
			return this.provider();
		}
		return this.parameter;
	}

	private updateLocalization(): void {
		const localization = this.getParameter();
		const items: ITranslationData[] = [];
		const translationItems = localization.translationOptions.items;
		const primaryName = translationItems[0].name;

		const map = localization.localizationMap;
		this.hasTranslations = !$.isEmptyObject(map);
		if (this.hasTranslations) {
			Object.keys(map).forEach((key) => {
				items.push({
					language: key,
					localization: map[key],
					primaryName: primaryName,
				});
			});
		}

		ArrayUtil.sortByProperty(items, "language");
		this.items = items;

		this.localizationChange.emit(items);
	}

	private showImportSuccessToast() {
		this.toastService.show({
			title: this.lang.importTranslationsSuccessTitle,
			message: this.lang.importTranslationsSuccessMessage,
			position: "bottom right",
		});
	}

	private getLanguages(translation: ITranslationEntity) {
		const self = this;

		if (self.isLoading) {
			return;
		}

		self.isLoading = true;
		this.commonDataService.listLanguages().subscribe(
			(response: ILanguagueResponse) => {
				self.isLoading = false;
				self.languages = response.content;
				self.langsLength = Object.keys(self.languages).length;
				self.showDialog(translation);
			},
			(r: IOperationResponse) => {
				self.isLoading = false;
				this.commonDataService.handleError(r);
			},
		);
	}

	private initializeLanguages(languages: IStringMap): void {
		for (const language in languages) {
			if (languages.hasOwnProperty(language)) {
				this.updateLanguageTitle(language, languages);
			}
		}
	}

	private updateLanguageTitle(
		languageCode: string,
		languages: IStringMap,
	): void {
		const suffix = languageCode.replace("-", "");
		const langKey = "lang" + suffix;
		let translatedTitle = this.lang[langKey] as string;
		if (!translatedTitle) {
			const name = languages[languageCode];
			translatedTitle = name;
		}
		languages[languageCode] = translatedTitle;
	}

	private showDialog(translation: ITranslationEntity) {
		if (CommonUtil.isUndefined(this.languages)) {
			this.getLanguages(translation);
			return;
		}

		if (this.isDialogOpen) {
			return;
		}
		this.isDialogOpen = true;

		const parameter = this.getParameter();
		const langCopy = CoreUtil.copy(this.languages);
		this.initializeLanguages(langCopy);
		if (CommonUtil.isUndefined(translation.language)) {
			for (const lang in parameter.localizationMap) {
				delete langCopy[lang];
			}
		}

		const title = translation.language
			? this.lang.editTranslation
			: this.lang.addTranslation;
		const dialog = this.dialogService
			.modal(AddTranslationComponent, this.view)
			.id("lm-at-mdl")
			.title(title)
			.afterClose((r: IMyDialogResult) => {
				this.isDialogOpen = false;
				if (r && r.value) {
					if (r.value.translation) {
						const item = r.value.translation;
						this.addOrUpdateTranslation(item, translation);
						this.hasTranslations = true;
					}
				}
			});

		dialog
			.apply((component) => {
				component.dialog = dialog;
				component.memoLayout = this.memoLayout;
				component.translationOptions = parameter.translationOptions;
				component.translation = CoreUtil.copy(translation);
				component.languages = langCopy;
				component.defaultLanguage = this.defaultLanguage;
			})
			.open();
	}

	private addOrUpdateTranslation(
		newItem: ITranslationEntity,
		oldItem?: ITranslationEntity,
	) {
		if (oldItem && newItem.language !== oldItem.language) {
			this.delete(oldItem.language);
		}

		const parameter = this.getParameter();
		parameter.localizationMap[newItem.language] = this.toMapItem(newItem);
		this.addedLangsLength = Object.keys(parameter.localizationMap).length;

		this.updateLocalization();
	}

	private toMapItem(source: ITranslationEntity): any {
		const item = {};
		for (const key of Object.keys(source)) {
			if (key !== "language") {
				item[key] = source[key];
			}
		}
		return item;
	}
}

@Component({
	selector: "lm-add-translation-component",
	templateUrl: "./translation-add.html",
	styleUrls: ["./translation-add.scss"],
})
export class AddTranslationComponent
	extends TranslationComponentBase
	implements OnInit
{
	memoLayout: number;
	dialog: SohoModalDialogRef<AddTranslationComponent>;
	translationOptions: ITranslationOptions;
	languages: IStringMap;
	translation: ITranslationEntity;
	languageList: IKeyValue[] = [];
	selectedLanguage: string;
	selectedLanguageDisplayName: string;
	buttonText: string;
	isAdd: boolean;
	isDefaultLanguage: boolean;
	defaultLanguage: string;
	items: ITranslationItem[];
	isSingleItem: boolean;
	data: IStringMap;
	hasCustomValidation = false;

	constructor(
		languageService: LanguageService,
		private readonly browserStorageService: BrowserStorageService,
	) {
		super("AddTranslationComponent", languageService);
	}

	private get languageKey(): string {
		return this.className + "Language";
	}

	ngOnInit() {
		const translation = this.translation;
		const translationOptions = { ...this.translationOptions };
		this.items = translationOptions.items || [translationOptions.item];
		this.isSingleItem = this.items.length === 1;

		this.data = this.toData(translation as IStringMap);

		const isAdd = CommonUtil.isUndefined(translation.language);
		this.isAdd = isAdd;
		this.buttonText = isAdd ? this.lang.add : this.lang.update;

		this.languageList = this.toSortedList(this.languages);
		this.selectedLanguage = isAdd ? this.loadSelected() : translation.language;
		this.selectedLanguageDisplayName = this.getLanguageDisplayName(
			this.selectedLanguage,
		);
		this.hasCustomValidation = this.isCustomValidation();
		this.setIsDefaultLanguage();
	}

	add(): void {
		const translation = this.translation;
		const selectedLanguage = this.selectedLanguage;
		if (!selectedLanguage) {
			return;
		}

		const data = this.data;
		for (const item of this.items) {
			const name = item.name;
			const value = data[name];
			const trimmedValue = value ? value.trim() : value;
			translation[name] = trimmedValue;
		}

		if (this.isAdd) {
			translation.language = selectedLanguage;
		}

		this.saveSelected();
		this.closeDialog({ value: { translation } });
	}

	close(): void {
		this.closeDialog();
	}

	getValidationValue(isRequired: boolean): string {
		return isRequired !== false ? "required" : null;
	}

	setIsDefaultLanguage(): void {
		this.isDefaultLanguage = this.selectedLanguage === this.defaultLanguage;
	}

	isRequired(item: ITranslationItem): boolean {
		if (this.isSingleItem) {
			return true;
		}

		return item.isRequired !== false;
	}

	isValid(): boolean {
		if (!this.hasCustomValidation) {
			return true;
		}

		// Custom validation is currently only used when all items are optional
		// In this case at least one item must have a value

		if (this.isSingleItem) {
			return this.hasValue(this.items[0]);
		}

		for (const item of this.items) {
			if (this.hasValue(item)) {
				return true;
			}
		}

		return false;
	}

	private hasValue(item: ITranslationItem): boolean {
		const value = this.data[item.name];
		return value && value.trim().length > 0;
	}

	private loadSelected(): string {
		const language = this.browserStorageService.getLocalStorageItem<string>(
			this.languageKey,
		);
		if (language && this.languageList.find((l) => l.key === language)) {
			return language;
		}
		return this.languageList[0].key;
	}

	private saveSelected(): void {
		this.browserStorageService.setLocalStorageItem(
			this.languageKey,
			this.selectedLanguage,
		);
	}

	private toData(source: IStringMap): IStringMap {
		const data = {};
		for (const item of this.items) {
			const name = item.name;
			data[name] = source[name];
		}
		return data;
	}

	private toSortedList(map: IStringMap): IKeyValue[] {
		const items: IKeyValue[] = [];
		for (const key of Object.keys(map)) {
			items.push({ key: key, value: map[key] });
		}
		items.sort((itemA, itemB) => {
			const a = itemA.value;
			const b = itemB.value;
			return a < b ? -1 : a > b ? 1 : 0;
		});
		return items;
	}

	private closeDialog(result?: IMyDialogResult) {
		return this.dialog.close(result);
	}

	/**
	 * Check if custom validation should be used.
	 *
	 * If only one item exists, regular validation should be used.
	 * If multiple items exist and all are optional, custom validation should be used.
	 */
	private isCustomValidation(): boolean {
		if (ArrayUtil.find(this.items, (item) => item.isMarkdown)) {
			// Always custom for markdown for now
			return true;
		}

		if (this.isSingleItem) {
			return false;
		}

		const optionalItems = this.items.filter((item) => {
			return item.isRequired === false;
		});
		return optionalItems.length === this.items.length;
	}
}

/**
 *
 * @since 1.0.22
 */
@Injectable({
	providedIn: "root",
})
export class TranslationServiceInternal implements ITranslationService {
	private enabled: boolean;

	constructor(
		service: TranslationService,
		private readonly dialogService: SohoModalDialogService,
		private readonly languageService: LanguageService,
		private readonly contextService: ContextService,
	) {
		service.initialize(this);
	}

	isEnabled(): boolean {
		if (this.enabled === undefined) {
			this.enabled = this.getContext().settings.isContentTranslationEnabled();
		}
		return this.enabled;
	}

	translate(options: ITranslationOptions): Observable<ITranslationResult> {
		const subject = new AsyncSubject<ITranslationResult>();
		const view = options.view;
		const item = options.item;
		const items = options.items;

		if (!view) {
			throw new Error("view not set");
		}
		if ((!items && !item) || (item && items)) {
			throw new Error("item or items must be set");
		}

		const title = this.languageService.getLanguage().translations;
		const isSingle = !!options.item;
		const parameter = this.getParameter(options);

		const dialog = this.dialogService
			.modal(TranslationDialog, view)
			.id("lm-translate-dialog")
			.title(title)
			.afterClose((result: IDialogResult) => {
				if (result && result.value) {
					const value = result.value;
					const data = isSingle ? this.toSingle(item, value) : value;
					subject.next({ data: data });
					subject.complete();
				} else {
					subject.error({});
				}
			});

		dialog
			.apply((component) => {
				component.dialog = dialog;
				component.localization = parameter;
				component.options = options;
			})
			.open();

		return subject.asObservable();
	}

	getLanguage(): string {
		return this.getContext().getLanguage();
	}

	private getContext(): IContext {
		return this.contextService.getContext();
	}

	private getParameter(options: ITranslationOptions): ILocalizationParameter {
		let map: IStringMapMap;

		if (!options.data) {
			options.data = {};
		}

		if (options.items) {
			map = CommonUtil.copyJson(options.data);
		} else {
			const item = options.item;
			if (!item.name) {
				item.name = "name";
			}
			options.items = [item];
			options.item = null;
			map = this.fromSingle(CommonUtil.copyJson(options.data), item.name);
		}

		return {
			translationOptions: options,
			localizationMap: map,
			enablePortation: false,
		};
	}

	private toSingle(item: ITranslationItem, languageMap: IStringMapMap) {
		const data = {};
		const name = item.name;
		for (const language of Object.keys(languageMap)) {
			data[language] = languageMap[language][name];
		}
		return data;
	}

	private fromSingle(data: any, name: string): IStringMapMap {
		const languageMap = {};
		for (const language of Object.keys(data)) {
			const map = {};
			map[name] = data[language];
			languageMap[language] = map;
		}
		return languageMap;
	}
}

@Component({
	template: `<div>
		<lm-translations-component
			[parameter]="localization"
			[category]="category"></lm-translations-component>

		<div class="modal-buttonset">
			<button
				type="button"
				class="btn-modal"
				id="lm-tr-dlg-cncl"
				(click)="close()">
				{{ lang.cancel }}
			</button>
			<button
				type="button"
				class="btn-modal-primary"
				id="lm-tr-dlg-ok"
				(click)="save()">
				{{ lang.ok }}
			</button>
		</div>
	</div> `,
})
export class TranslationDialog extends CoreBase {
	dialog: SohoModalDialogRef<TranslationDialog>;
	options: ITranslationOptions;
	lang: ILanguageLime;

	localization: ILocalizationParameter;
	category = EntityCategory.custom;

	constructor(languageService: LanguageService) {
		super("TranslationDialog");
		this.lang = languageService.getLanguage();
	}

	save(): void {
		this.dialog.close({
			value: this.localization.localizationMap,
		});
	}

	close(): void {
		this.dialog.close();
	}
}
