import {
	AfterViewInit,
	ChangeDetectionStrategy,
	Component,
	EventEmitter,
	Input,
	OnChanges,
	Output,
	SimpleChanges,
} from "@angular/core";
import { CommonUtil, IWidgetContext, IWidgetInstance } from "lime";
import {
	DynamicLinkSize,
	dynamicLinkSizeMap,
	IDynamicContainer,
	IDynamicItemExtended,
} from "lime/core";
import {
	DynamicColorType,
	DynamicLinksExpandType,
	UIUtil,
} from "../../base/core";

export interface IDynamicLinkViewOptions {
	text: string;
	icon?: string;
	iconColor?: string;
	fontSize?: string;
	isHeading?: boolean;
	url?: string;
	hasChildren?: boolean;
	isExpanded?: boolean;
	parentIndex?: number;
}

export function parseLink(
	linkItem: IDynamicItemExtended,
): IDynamicLinkViewOptions {
	return {
		fontSize: parseLinkSize(linkItem.sz),
		icon: linkItem.i,
		iconColor: parseLinkColor(linkItem.cl, linkItem.clt),
		isHeading: linkItem.sz === DynamicLinkSize.Heading,
		text: linkItem.t,
		url: linkItem.u,
	};
}

function parseLinkSize(size: DynamicLinkSize = DynamicLinkSize.Normal): string {
	return dynamicLinkSizeMap.get(size);
}

function parseLinkColor(
	colorNumber = 0,
	colorType = DynamicColorType.Custom,
): string {
	return colorType === DynamicColorType.InheritPage
		? UIUtil.numberToHexCode(colorNumber)
		: UIUtil.numberToHexCodeExtended(colorNumber);
}

@Component({
	changeDetection: ChangeDetectionStrategy.OnPush,
	selector: "lm-dyn-link-content",
	template: `
		<span
			*ngIf="icon"
			class="dyn-cont-icon"
			[style.background-color]="iconColor">
			<svg class="icon" aria-hidden="true" focusable="false">
				<use [attr.xlink:href]="icon" />
			</svg>
		</span>
		<span
			[style.font-size]="fontSize"
			class="lm-truncate-text"
			[class.icon-margin]="indent"
			[class.chevron-margin]="isExpandable"
			>{{ text }}</span
		>
	`,
	styles: [
		`
			:host {
				display: flex;
				align-items: center;
				width: 100%;
				position: relative;
			}

			.dyn-cont-icon {
				position: absolute;
				top: -7.5px;
				height: 30px;
				width: 30px;
				border-radius: 50%;
			}

			.dyn-cont-icon > .icon {
				top: 7px;
				left: 6px;
				height: 16px;
				color: white;
			}

			.icon-margin {
				margin-left: 40px;
			}

			.chevron-margin {
				margin-right: 30px;
			}

			:host-context(html[dir="rtl"]) .dyn-cont-icon > .icon {
				margin-right: 12px
			}

			:host-context(html[dir="rtl"]) .icon-margin {
				margin-right: 40px;
				margin-left: 0;
			}

			:host-context(html[dir="rtl"]) .chevron-margin {
				margin-left: 30px;
			}
		`,
	],
})
export class DynamicLinkContentComponent {
	@Input() text: string;
	@Input() icon?: string;
	@Input() iconColor?: string;
	@Input() fontSize?: string;
	@Input() indent?: boolean;
	@Input() isExpandable?: boolean;
}

@Component({
	changeDetection: ChangeDetectionStrategy.OnPush,
	selector: "lm-dyn-link-list",
	styles: [
		`
			:host {
				display: block;
			}

			ul {
				display: flex;
				flex-direction: column;
				justify-content: space-between;
			}

			.heading {
				margin-top: 20px;
				position: relative;
			}

			li {
				display: flex;
				align-items: center;
				margin-bottom: 10px;
			}

			li.dyn-link {
				padding-top: 20px;
			}

			li.heading + li.dyn-link,
			li.dyn-link + li.dyn-link {
				padding-top: 0;
			}

			li > a {
				cursor: pointer;
				text-decoration: none;
			}

			li > button {
				position: absolute;
				right: -5px;
				top: -10px;
			}

			li > button.btn-toggle ::ng-deep svg {
				color: #5c5c5c !important;
			}

			:host-context(.lm-banner) li > button.btn-toggle ::ng-deep svg {
				color: #ffffff !important;
			}

			:host-context(html[dir="rtl"]) li > button {
				right: auto;
				left: -5px;
			}
		`,
	],
	template: `
		<ul>
			<ng-container *ngFor="let link of links">
				<li
					*ngIf="isVisible(link)"
					[ngClass]="[link.isHeading ? 'heading' : 'dyn-link']">
					<!-- Has URL -->
					<a
						[name]="link.text | lmAutoId : 'lm-dyn-link'"
						class="lm-width-full"
						*ngIf="link.url"
						(click)="fireLinkClicked(link.url)">
						<lm-dyn-link-content
							[text]="link.text"
							[icon]="link.icon"
							[iconColor]="link.iconColor"
							[fontSize]="link.fontSize"
							[indent]="indent"
							[isExpandable]="link.hasChildren && expandStrategy">
						</lm-dyn-link-content>
					</a>
					<!-- Does not have URL -->
					<div class="lm-width-full" *ngIf="!link.url">
						<lm-dyn-link-content
							[text]="link.text"
							[icon]="link.icon"
							[iconColor]="link.iconColor"
							[fontSize]="link.fontSize"
							[indent]="indent"
							[isExpandable]="link.hasChildren && expandStrategy">
						</lm-dyn-link-content>
					</div>
					<button
						soho-button="icon"
						[name]="link.text | lmAutoId : 'lm-dyn-link-expander'"
						*ngIf="link.hasChildren && expandStrategy"
						(click)="link.isExpanded = !link.isExpanded"
						[isToggle]="true"
						[isTogglePressed]="expandStrategy === 1"
						toggleOnIcon="caret-up"
						toggleOffIcon="caret-down"></button>
				</li>
			</ng-container>
		</ul>
	`,
})
export class DynamicLinkListComponent implements OnChanges {
	@Input() links: IDynamicLinkViewOptions[];
	@Input() expandStrategy: DynamicLinksExpandType = DynamicLinksExpandType.None;
	@Output() linkClicked = new EventEmitter<string>();

	indent: boolean;

	ngOnChanges(changes: SimpleChanges): void {
		if (changes.links) {
			this.indent = changes.links.currentValue.some((link) => !!link.icon);
			this.links = this.addExpandInfo(this.links);
		}
	}

	fireLinkClicked(url: string) {
		this.linkClicked.emit(url);
	}

	isVisible(link: IDynamicLinkViewOptions): boolean {
		if (link.isHeading) {
			return link.hasChildren || !!link.url;
		} else {
			return (
				CommonUtil.isUndefined(link.parentIndex) ||
				this.links[link.parentIndex].isExpanded
			);
		}
	}

	private addExpandInfo(
		links: IDynamicLinkViewOptions[],
	): IDynamicLinkViewOptions[] {
		let parentIndex: number;

		return links.map((link, index) => {
			if (link.isHeading) {
				parentIndex = index;
				const isLast = index === links.length - 1;
				const hasChildren = !isLast && !links[index + 1].isHeading;
				link.hasChildren = hasChildren;

				if (hasChildren) {
					link.isExpanded = !this.expandStrategy || this.expandStrategy === 1;
				}
			} else {
				link.parentIndex = parentIndex;
			}
			return link;
		});
	}
}

@Component({
	selector: "lm-dyn-links",
	template: `
		<lm-dyn-link-list
			[links]="links"
			[expandStrategy]="expandType"
			(linkClicked)="launch($event)">
		</lm-dyn-link-list>
	`,
	styles: [
		`
			:host {
				display: block;
				padding: 0 20px 20px 20px;
			}
		`,
	],
})
export class DynamicLinksComponent implements AfterViewInit {
	@Input() widgetContext: IWidgetContext;
	@Input() widgetInstance: IWidgetInstance;

	links: IDynamicLinkViewOptions[] = [];
	expandType: DynamicLinksExpandType;

	ngAfterViewInit(): void {
		const context = this.widgetContext;
		const settings = context.getSettings();
		const container = settings.get<IDynamicContainer>("lm_container");
		if (container && container.its) {
			this.links = container.its.map(parseLink);
			this.expandType = container.ex;
		}
	}

	launch(url: string): void {
		this.widgetContext.launch({ url: url });
	}
}
