/**
 * Dependencies:
 * device
 * runtime
 * core
 * ../../lime
 */

import {
	ArrayUtil,
	CommonUtil,
	IApplication,
	ILaunchOptions,
	IViewUrlOptions,
	Log,
	StringUtil,
} from "lime";
import { AsyncSubject, Observable } from "rxjs";
import {
	Constants,
	IApplicationEx,
	IApplicationView,
	ICompanyonService,
	IConfiguration,
	IContext,
} from "./core";
import { IExternalLinkMessage, MobileMessage } from "./device";
import { CoreBase, CoreUtil, HttpUtil } from "./runtime";

export class ContextValueResolver extends CoreBase {
	constructor(
		private readonly config: IConfiguration,
		private readonly context: IContext,
		private readonly companyonService: ICompanyonService,
		private readonly source: string,
	) {
		super("ContextValueResolver");
	}

	resolveAndReplaceInternal(template: string, logicalId: string): string {
		// Resolve special case with :{Port} that should collapse to empty if 0 or blank
		template = this.replaceSpecialCases(template, logicalId);

		const resolveFunction = (key: string) => {
			const value = this.resolveInternal(key, logicalId);
			return value;
		};

		return StringUtil.replaceParameters(template, resolveFunction);
	}

	resolveAndReplaceInternalAsync(
		template: string,
		logicalId: string,
		async: any,
		isFirst: boolean,
		isUrl: boolean,
	): void {
		// Check if the template contains an override logical ID prefix
		if (template.indexOf("{lid://") === 0) {
			const end = template.indexOf("}");
			if (end > 0) {
				logicalId = template.substring(1, end);
				template = template.substring(end + 1);
			}
		}

		if (!logicalId) {
			this.asyncComplete(async, this.resolveAndReplace(template));
			return;
		}

		// Get the application to make sure that it exists in the cache before resolving
		this.config.getApplication(logicalId).subscribe(
			(application: IApplication) => {
				template = this.resolveAndReplaceInternal(template, logicalId);

				if (isFirst && template && template.indexOf("{") >= 0) {
					// If the template still contains replacement variables we try once more. Fully recursive replacement is not supported for now.
					this.resolveAndReplaceInternalAsync(
						template,
						logicalId,
						async,
						false,
						isUrl,
					);
				} else {
					if (isUrl) {
						template = this.getAbsoluteUrl(template, application.useHttps);
					}
					this.asyncComplete(async, template);
				}
			},
			() => {
				const message = "Application not found: " + logicalId;
				this.asyncError(async, message);
			},
		);
	}

	resolveAndReplace(template: string): string {
		return this.resolveAndReplaceInternal(template, this.getLogicalId());
	}

	resolveViewUrl(
		options: IViewUrlOptions,
		application: IApplication,
		async: any,
	): void {
		// The views property is not officially part of the API for now and not inlcuded in IApplicationView.
		// Views might also be loaded asynchronously if the amount data is to much to always return wheter its used or not.
		const views: IApplicationView[] = (application as IApplicationEx).views;
		if (views) {
			const template = this.getViewTemplate(views, options.viewId);
			if (template) {
				// Default is true so the check needs to be specifically if set to false only
				if (options.resolve === false) {
					this.asyncComplete(async, template);
					return;
				}
				this.resolveAndReplaceInternalAsync(
					template,
					application.logicalId,
					async,
					true,
					true,
				);
				return;
			}
		}
		this.asyncError(async, "View not found");
	}

	getViewUrlAsync(options: IViewUrlOptions): Observable<string> {
		const subject = new AsyncSubject<string>();
		const logicalId = options.logicalId || this.getLogicalId();
		this.config.getApplication(logicalId).subscribe(
			(application: IApplication) => {
				this.resolveViewUrl(options, application, subject);
			},
			(e: any) => {
				subject.error(e);
			},
		);
		return subject.asObservable();
	}

	resolveValue(key: string, logicalId: string): string {
		if (!key) {
			return key;
		}

		const i = key.indexOf(".");
		let prefix = null;
		if (i > 1) {
			prefix = key.substring(0, i);
			prefix = prefix.toLowerCase();
		}

		const cst = Constants;
		const config = this.config;

		// If it is prefixed then it must come from the correct source or null will be returned
		if (prefix && Constants.configurationPrefixes.indexOf(prefix) >= 0) {
			// Substring but exclude the dot.
			const name = key.substring(i + 1, key.length);
			// Value is scoped to a specific container
			let resolvedValue = null;

			// Special case for application.Scheme
			if (
				name.toLowerCase() === Constants.scheme &&
				prefix === cst.configurationApplicationPrefix
			) {
				// Special case Scheme maps to UseHttps
				const schema = this.resolveScheme(logicalId, config, prefix);
				if (schema) {
					return schema;
				}
			}

			const application = this.config.getApplicationCached(logicalId);

			if (prefix === cst.configurationWidgetPrefix) {
				resolvedValue = this.resolveFromSource(
					this.getWidgetData(),
					logicalId,
					cst.configurationSettings,
					name,
				);
			} else if (prefix === cst.configurationLocalizationPrefix) {
				resolvedValue = this.resolveFromSource(
					this.getWidgetLanguage(),
					logicalId,
					null,
					name,
				);
			} else if (prefix === cst.configurationViewPrefix) {
				if (application) {
					resolvedValue = this.getViewTemplate(
						(application as any).views as IApplicationView[],
						name,
					);
					if (resolvedValue && resolvedValue.indexOf("http") !== 0) {
						resolvedValue =
							this.getScheme(application.useHttps) + "://" + resolvedValue;
					}
				}
			} else if (prefix === cst.configurationApplicationPrefix) {
				if (application) {
					const customProp = application.customProperties;
					if (customProp && customProp.hasOwnProperty(name)) {
						resolvedValue = customProp[name];
					}
				}
			} else if (prefix === cst.configurationFrameworkPrefix) {
				resolvedValue = this.resolveFramework(name);
			} else {
				resolvedValue = this.resolveFromSource(config, logicalId, prefix, name);
			}
			return resolvedValue;
		}

		// First check settings for widget
		let value = this.resolveFromSource(
			this.getWidgetData(),
			logicalId,
			cst.configurationSettings,
			key,
		);
		if (value != null) {
			return value.toString();
		}

		// Check for Ming.le query parameter values
		value = this.resolveMingle(key);
		if (value != null) {
			return value;
		}

		// Check ad-hoc configuration
		value = this.resolveFromSource(
			config,
			logicalId,
			cst.configurationProperties,
			key,
		);
		if (value != null) {
			return value;
		}

		const keyLowerCase = key.toLocaleLowerCase();
		// Check if this is to resolve tenantid
		if (keyLowerCase === Constants.tenantId) {
			return this.context.getTenantId();
		}

		// Check if this is to resolve userid
		if (keyLowerCase === Constants.userid) {
			return this.context.getUserId();
		}

		// Check if this is to resolve language
		if (keyLowerCase === Constants.language) {
			return this.context.getLanguage();
		}

		// Check Ming.le configuration
		value = this.resolveFromSource(
			config,
			logicalId,
			cst.configurationApplication,
			key,
		);
		if (value != null) {
			return value;
		}

		// For key Scheme use UseHttps
		if (keyLowerCase === Constants.scheme) {
			return this.resolveScheme(
				logicalId,
				config,
				cst.configurationApplication,
			);
		}

		return null;
	}

	launch(launchOptions: ILaunchOptions) {
		if (!launchOptions) {
			throw new Error("launchOptions is not set");
		}

		const url = launchOptions.url;
		if (!url) {
			throw new Error("url is not set");
		}

		if (url.startsWith("unsafe:")) {
			this.logError(`Aborting launch of unsafe url: ${url}`);
			return;
		}

		if (CommonUtil.isUndefined(launchOptions.resolve)) {
			launchOptions.resolve = true;
		}

		if (launchOptions.resolve && url.indexOf("{") >= 0) {
			this.logDebug("About to resolve launch of: " + url);
			this.resolveAndReplaceAsync(url, null).subscribe(
				(result) => {
					this.launchInternal(result);
				},
				(err) => {
					if (this.context.isDev()) {
						alert(
							"Not supported in test mode unless configration is provided and dev-configration attribute set on test widget. Please see Homepages developers guide",
						);
					}
					this.logError("Failed to resolve " + url + ". " + (err || ""));
				},
			);
		} else {
			this.launchInternal(url);
		}
	}

	resolveAndReplaceAsync(
		template: string,
		logicalId: string,
	): Observable<string> {
		const subject = new AsyncSubject<string>();
		this.resolveAndReplaceInternalAsync(
			template,
			logicalId || this.getLogicalId(),
			subject,
			true,
			false,
		);
		return subject.asObservable();
	}

	launchInternal(url: string) {
		if (this.isWebUrl(url)) {
			if (this.isMingleLink(url)) {
				const siteGuid = this.getLegacyBookmarkGuid(url);
				if (siteGuid != null) {
					const bookmarkUrl = this.getBookmarkUrl(siteGuid);
					this.launchBookmark(bookmarkUrl);
					return;
				} else {
					const contextLink = this.getFavoriteContext(url, true);
					if (contextLink != null) {
						this.launchBookmark(contextLink);
						return;
					}
				}
			}
			// In mobile the external URL needs to be dispatched to Infor GO

			if (this.context.isMobile && !this.context.isDev()) {
				this.openURLMobile(url);
			} else if (this.hasSupportedApplicationScheme(url)) {
				this.logDebug(
					"Launching application scheme url in the current window " + url,
				);
				location.href = url;
			} else {
				this.logDebug("Launching URL in tab " + url);
				const handle = window.open(url, "_blank");
				if (handle) {
					try {
						handle.opener = null;
					} catch (ex) {
						this.logDebug("Failed reset opener on handle " + url, ex);
					}
				}
			}
		} else {
			const isFavorite = this.isFavoriteContext(url);
			const messageName = isFavorite
				? "sendPrepareFavoritesMessage"
				: "sendPrepareDrillbackMessage";
			this.logDebug("Launching URL in Ming.le " + url + " with " + messageName);
			const client = infor.companyon.client;
			if (isFavorite) {
				client.sendPrepareFavoritesMessage(url);
			} else {
				client.sendPrepareDrillbackMessage(url);
			}
		}
	}

	isMingleLink(url: string): boolean {
		const containerUrl = this.context.getContainerUrl();
		return url.indexOf(containerUrl) === 0;
	}

	/**
	 * Returns favoriteContext URL paramater or null if not found.
	 * @param url
	 */
	getFavoriteContext(url: string, includeAllParams?: boolean): string {
		try {
			url = decodeURIComponent(url);
		} catch (ex) {
			this.logError("getFavoriteContext: Failed to decode", ex);
			return null;
		}

		if (!this.isFavoriteContext(url)) {
			return null;
		}

		const queryIndex = url.indexOf("?");
		// This should not happen if the favorite check returns true
		if (queryIndex === -1) {
			return null;
		}

		url = url.substring(queryIndex);
		let favContext = null;

		if (includeAllParams) {
			favContext = url;
		} else {
			const paramMap = HttpUtil.parseQuery(url);
			if (paramMap) {
				favContext = paramMap["favoriteContext"];
			}
		}

		return decodeURIComponent(favContext);
	}

	getLegacyBookmarkGuid(url: string): string {
		const favContext = this.getFavoriteContext(url);
		if (favContext !== null) {
			const siteID = favContext.replace("?favoriteContext=", "");
			if (siteID.match(/^\w{8}-\w{4}-\w{4}-\w{4}-\w{12}/g)) {
				return siteID;
			}
		}

		return null;
	}

	getAbsoluteUrl(url: string, useHttps: any): string {
		if (url.indexOf("http://") !== 0 && url.indexOf("https://") !== 0) {
			url = this.getScheme(useHttps) + "://" + url;
		}
		return url;
	}

	isFavoriteContext(url: string): boolean {
		const queryMap = HttpUtil.parseQuery(url);
		if (!queryMap) {
			return false;
		}
		const favoriteParam = queryMap["favoriteContext"];
		return !StringUtil.isNullOrWhitespace(favoriteParam);
	}

	protected getWidgetData(): any {
		return {};
	}

	protected getWidgetLanguage(): any {
		return {};
	}

	protected getLogicalId(): string {
		return null;
	}

	protected resolveFramework(name: string) {
		name = name.toLowerCase();

		// TODO Support page ID?
		// if ("pageid" === name) {
		// 	return widget.parentContext.id;
		// }

		if ("random" === name) {
			return CommonUtil.random();
		}
		return null;
	}

	private openURLMobile(url: string): void {
		if (this.isDebug()) {
			this.logDebug("About to send open message to mobile, opening URL " + url);
		}
		const data: IExternalLinkMessage = { link: url, source: this.source };
		const message = { name: MobileMessage.REQUEST_OPEN_LINK, data: data };
		this.companyonService.send(message);
	}

	private replaceSpecialCases(template: string, logicalId: string): string {
		// Search and replace port & context
		template = this.replaceSpecialVariable(
			template,
			logicalId,
			":{Port}",
			"Port",
			":",
			"",
		);
		template = this.replaceSpecialVariable(
			template,
			logicalId,
			":{port}",
			"Port",
			":",
			"",
		);
		template = this.replaceSpecialVariable(
			template,
			logicalId,
			":{Application.Port}",
			"Application.Port",
			":",
			"",
		);
		template = this.replaceSpecialVariable(
			template,
			logicalId,
			":{application.port}",
			"Application.Port",
			":",
			"",
		);

		// Context variations
		template = this.replaceSpecialVariable(
			template,
			logicalId,
			"/{Context}",
			"Context",
			"/",
			"",
		);
		template = this.replaceSpecialVariable(
			template,
			logicalId,
			"/{context}",
			"Context",
			"/",
			"",
		);
		template = this.replaceSpecialVariable(
			template,
			logicalId,
			"/{Application.Context}",
			"Application.Context",
			"/",
			"",
		);
		template = this.replaceSpecialVariable(
			template,
			logicalId,
			"/{application.context}",
			"Application.Context",
			"/",
			"",
		);
		return template;
	}

	private replaceSpecialVariable(
		template: string,
		logicalId: string,
		searchText: string,
		variableName: string,
		resolvedPrefix: string,
		defaultText: string,
	): string {
		if (template && template.indexOf(searchText) > -1) {
			let resolved = this.resolveInternal(variableName, logicalId);
			// ReSharper disable once CoercedEqualsUsing
			if (!resolved || resolved === "0") {
				// Replace with default eg empty
				template = template.replace(searchText, defaultText);
			} else {
				if (resolvedPrefix) {
					resolved = resolvedPrefix + resolved;
				}
				template = template.replace(searchText, resolved);
			}
		}
		return template;
	}

	private isWebUrl(url: string): boolean {
		if (url.indexOf("http") === 0 || url.indexOf("/") === 0) {
			return true;
		}
		if (this.hasSupportedApplicationScheme(url)) {
			return true;
		}
		return false;
	}

	private hasSupportedApplicationScheme(url: string): boolean {
		return (
			url.indexOf("mailto:") === 0 ||
			url.indexOf("tel:") === 0 ||
			url.indexOf("callto:") === 0
		);
	}

	private isMingleLegacyLink(containerUrl: string, url: string): boolean {
		let mingleUrl = containerUrl;
		if (!StringUtil.endsWith(containerUrl, "/")) {
			mingleUrl = mingleUrl + "/";
		}
		if (url.indexOf(mingleUrl) === 0) {
			return true;
		}
		return false;
	}

	private getBookmarkUrl(siteId: string): string {
		return "?favoriteContext=" + siteId + "&type=SiteGuid";
	}

	/**
	 * Lauches a bookmark via companyon.
	 * @param url // Example: ?favoriteContext=62ca2b30-51e1-49cd-9919-68594b71773a~IFSPAGE&type=SiteGuid
	 */
	private launchBookmark(url: string) {
		Log.debug("Launching bookmark: " + url);
		infor.companyon.client.sendPrepareFavoritesMessage(url);
	}

	private getScheme(useHttps: any): string {
		return useHttps === true || useHttps === "true" || useHttps === "1"
			? "https"
			: "http";
	}

	private resolveInternal(key: string, logicalId: string): string {
		// Check if we have a rule that should be applied after replacing
		let name = key;
		const index = key.indexOf("|");
		let encode = true;
		let defaultValue = "";
		let useUriEncode = true;
		let toLowerCase = false;
		let toUpperCase = false;
		if (index > 0) {
			name = key.substring(0, index);
			let filter = key.substring(index + 1, key.length);
			filter = filter.trim();

			if (filter && filter.length > 1) {
				filter = filter.toLowerCase();
				const ruleIndex = filter.indexOf(":");
				let filterParam: string = null;
				if (ruleIndex > 0) {
					// Get filter before we change the filter
					filterParam = filter.substring(ruleIndex + 1, filter.length);
					filterParam = filterParam.trim().toLowerCase();

					filter = filter.substring(0, ruleIndex);
				}

				if (filter === "encode") {
					if (filterParam === "none") {
						encode = false;
					} else if (filterParam === "uri") {
						useUriEncode = true;
					} else if (filterParam === "component") {
						useUriEncode = false;
					}
				} else if (filter === "default") {
					defaultValue = filterParam;
				} else if (filter === "lower") {
					toLowerCase = true;
				} else if (filter === "upper") {
					toUpperCase = true;
				}
			}
		}

		name = name.trim();
		let value = this.resolveValue(name, logicalId);
		if (value) {
			// Apply lower or upper filter
			if (toUpperCase) {
				value = value.toUpperCase();
			} else if (toLowerCase) {
				value = value.toLowerCase();
			}
			// Apply encoding or default values according to filter
			if (encode) {
				if (useUriEncode) {
					value = encodeURI(value);
				} else {
					value = encodeURIComponent(value);
				}
			}

			return value;
		}

		// "" is returned as default value and the entire Key is replaced with noting and {} are removed
		// If the value cannot be resolved and the KEY is identified as something that could be JSON then we'll keep it
		if (defaultValue === "" && this.isJSONKey("{" + key + "}")) {
			const recreatedKey = "{" + key + "}";
			this.logDebug(
				"resolveInternal: " +
					recreatedKey +
					" appears to be a JSON parameter, keeping the JSON value when it could not be resolved.",
			);
			return recreatedKey;
		}

		return defaultValue;
	}

	private isJSONKey(key: string): boolean {
		if (!key) {
			return false;
		}
		return CoreUtil.isJsonString(key);
	}

	private resolveScheme(
		logicalId: string,
		container: any,
		prefix: string,
	): string {
		let useHttps = this.resolveFromSource(
			container,
			logicalId,
			prefix,
			Constants.useHttps,
		);
		if (useHttps) {
			useHttps = useHttps.toLowerCase();
			return this.getScheme(useHttps);
		}
		return null;
	}

	private resolveMingle(key: string): string {
		const c = Constants;
		if (key.indexOf(c.minglePrefix) === 0) {
			key = key.toLowerCase();
			const isMatch = (constant: string) => {
				return constant.toLowerCase() === key;
			};

			const context = this.context;
			if (isMatch(c.mingleLanguage)) {
				return context.getInforCurrentLanguage();
			}
			if (isMatch(c.mingleLocale)) {
				return context.getInforCurrentLocale();
			}
			if (isMatch(c.mingleTimeZone)) {
				return context.getInforTimeZone();
			}
			if (isMatch(c.mingleTimeZoneRaw)) {
				return context.getInforTimeZoneRaw();
			}
			if (isMatch(c.mingleStdTimeZone)) {
				return context.getInforStdTimeZone();
			}
			if (isMatch(c.mingleThemeName)) {
				return context.getInforThemeName();
			}
		}
		return null;
	}

	private resolveFromSource(
		container: any,
		logicalId: string,
		propertyName: string,
		key: string,
	): string {
		if (!container) {
			return null;
		}

		let mapObject;
		const cst = Constants;
		if (!propertyName) {
			mapObject = container;
		} else if (propertyName === cst.configurationApplication) {
			const application = (container as IConfiguration).getApplicationCached(
				logicalId,
			);
			if (application) {
				mapObject = CoreUtil.copy(application);
				// If the application has custom properties add those as well
				this.addCustomProperties(mapObject, application);
			} else {
				Log.debug("Application with logicalId" + logicalId + " was not found.");
			}
		} else if (propertyName === cst.configurationPropertyPrefix) {
			mapObject = container[cst.configurationProperties];
		} else {
			mapObject = container[propertyName];
		}

		if (!mapObject) {
			if (this.isDebug()) {
				this.logDebug(
					"[resolveFromSource] " +
						propertyName +
						" " +
						key +
						", no such configuration.",
				);
			}
			return null;
		}

		// Try with exact case
		let stringValue: string;
		let value = mapObject[key];
		if (CommonUtil.hasValue(value)) {
			stringValue = value.toString();
			if (this.isDebug()) {
				this.logDebug(
					"[resolveFromSource] Resolved " + key + " to: " + stringValue,
				);
			}
			return stringValue;
		}

		// Try case insensitive
		const keyUpper = key.toUpperCase();
		for (const name in mapObject) {
			if (keyUpper === name.toUpperCase()) {
				value = mapObject[name];
				if (CommonUtil.hasValue(value)) {
					stringValue = value.toString();
					if (this.isDebug()) {
						this.logDebug(
							"[resolveFromSource] Resolved " +
								keyUpper +
								" to: " +
								stringValue,
						);
					}
					return stringValue;
				} else {
					return null;
				}
			}
		}

		if (this.isDebug()) {
			this.logDebug(
				"[resolve] " + propertyName + " has no value for " + key + ".",
			);
		}
		return null;
	}

	private getViewTemplate(views: IApplicationView[], viewId: string): string {
		const view = ArrayUtil.itemByProperty(
			views,
			"viewId",
			viewId,
		) as IApplicationView;
		return view ? view.urlTemplate : null;
	}

	private addCustomProperties(mapObject: any, application: IApplication) {
		if (!application) {
			return;
		}
		const prop = application.customProperties;
		if (prop) {
			for (const key in prop) {
				if (!prop.hasOwnProperty(key)) {
					continue;
				}
				if (key in mapObject) {
					Log.debug(
						"addCustomProperties: " +
							key +
							" will not be available available for resolve since it overlaps existing application property",
					);
				} else {
					const value = prop[key];
					Log.debug(
						"addCustomProperties: Adding key: " +
							key +
							", value: " +
							value +
							" to resolve object",
					);
					mapObject[key] = value;
				}
			}
		}
	}
}
