import {
	Directive,
	ElementRef,
	EventEmitter,
	Input,
	OnInit,
	Output,
} from "@angular/core";
import { fromEvent, merge, Observable, Observer } from "rxjs";
import {
	debounceTime,
	distinctUntilChanged,
	filter,
	map,
} from "rxjs/operators";

/**
 * Observe a given element, and notify when the number of DOM children changes.
 */
const fromChildListChanges = (
	element: HTMLElement,
	pageSize: number,
): Observable<number> =>
	Observable.create((observer: Observer<number>) => {
		const mutation = new MutationObserver((mutations) => {
			if (mutations.length >= pageSize) {
				observer.next(mutations.length);
			}
		});

		mutation.observe(element, { childList: true });
		return () => mutation.disconnect();
	});

@Directive({
	selector: "[lm-scroll]",
})
export class ScrollDirective implements OnInit {
	/**
	 * Threshold (in pixels) from top/bottom of container for when top/bottom events should be triggered.
	 */
	@Input() threshold = 0;

	/**
	 * Debounce time for controlling how often scroll events should be triggered.
	 */
	@Input() debounce = 0;

	/**
	 * Page size of items loaded into the list which controls when child list change should be triggered.
	 */
	@Input() pageSize = 1;

	/**
	 * Fired when container is scrolled to the bottom.
	 */
	@Output() bottom = new EventEmitter();

	constructor(private element: ElementRef<HTMLElement>) {}

	ngOnInit() {
		const childListChanges$ = fromChildListChanges(
			this.element.nativeElement,
			this.pageSize,
		);
		const scroll$ = fromEvent(this.element.nativeElement, "scroll");
		merge(childListChanges$, scroll$)
			.pipe(
				debounceTime(this.debounce),
				map(() => this.isScrolledBottom()),
				distinctUntilChanged(),
				filter(Boolean),
			)
			.subscribe(this.bottom);
	}

	private isScrolledBottom(): boolean {
		const element = this.element.nativeElement;
		return (
			element.scrollTop + element.offsetHeight + this.threshold >=
			element.scrollHeight
		);
	}
}
