/**
 * Instance event implementation.
 *
 * Use this class to defined your own instance event.
 * If you just want to consume instance events refer to IInstanceEvent.
 */
export class InstanceEvent<T> implements IInstanceEvent<T> {
	private handlers: ((data?: T) => void)[] = [];

	/**
	 * Registers an event handler function.
	 * @param handler The event handler function to register.
	 */
	on(handler: (data?: T) => void): () => void {
		this.handlers.push(handler);
		return () => {
			this.off(handler);
		};
	}

	/**
	 * Unregisters an existing event handler function.
	 * @param handler The event handler function to unregister.
	 */
	off(handler: (data?: T) => void) {
		this.handlers = this.handlers.filter((h) => h !== handler);
	}

	/**
	 * Raises an event.
	 * @param data The event data.
	 */
	raise(data?: T) {
		if (this.handlers) {
			try {
				this.handlers.slice(0).forEach((h) => h(data));
			} catch (e) {
				Log.error("Exception in core.raise", e);
			}
		} else {
			if (Log.isDebug()) {
				const message = data ? JSON.stringify(data) : "null";
				Log.debug("There are no handles for the event " + message);
			}
		}
	}

	/**
	 * Clears all event handlers for this event.
	 */
	clear(): void {
		this.handlers = [];
	}
}

export class CoreBase implements IErrorState {
	logPrefix: string;

	constructor(
		protected className: string,
		protected readonly messageService?: SohoMessageService,
		protected readonly languageService?: ILanguageService,
	) {
		if (!this.logPrefix) {
			this.logPrefix = className ? "[" + className + "] " : "";
		}

		this.logDebug("constructor");
	}

	showMessage(
		title: string,
		message: string,
		isTrustedContent?: boolean,
	): Observable<any> {
		return this.showInternal(
			this.messageService.message(),
			title,
			message,
			isTrustedContent,
		);
	}

	showError(title: string, message: string): Observable<any> {
		return this.showInternal(this.messageService.error(), title, message);
	}

	showConfirm(title: string, message: string): Observable<any> {
		const subject = new AsyncSubject<any>();

		const titles = this.getButtonTitles();
		const buttons = [
			{
				text: titles.no,
				click: (e, modal) => {
					modal.close();
					// Complete the subject, triggering an error will require suppress handling of invoker
					subject.complete();
				},
				id: "lm-showconfirm-dialog-no",
			},
			{
				text: titles.yes,
				click: (e, modal) => {
					modal.close();
					this.asyncComplete(subject, {});
				},
				isDefault: true,
				id: "lm-showconfirm-dialog-yes",
			},
		];

		this.messageService
			.message()
			.title(HtmlUtil.escapeStringForHtml(title))
			.attributes({ name: "id", value: "lm-showconfirm-dialog" })
			.message(HtmlUtil.escapeStringForHtml(message))
			.buttons(buttons)
			.open();

		return subject.asObservable();
	}

	/**
	 * See [[IErrorState]].hasError()
	 */
	hasError(): boolean {
		const state = this as IErrorState;
		return state.errorMessage || state.errorCode || state.error;
	}

	isDebug(): boolean {
		return Log.isDebug();
	}

	logError(message: string, ex?: any): void {
		Log.error(this.logPrefix + message, ex);
	}

	logWarning(message: string): void {
		Log.warning(this.logPrefix + message);
	}

	logInfo(message: string): void {
		Log.info(this.logPrefix + message);
	}

	logDebug(message: (() => string) | string, ex?: any): void {
		const text = message instanceof Function ? message() : message;
		Log.debug(this.logPrefix + text, ex);
	}

	logResponse(response: IOperationResponse) {
		this.logError(response.toErrorLog());
	}

	onSelectedToolbar(event: SohoToolbarFlexSelectedEvent) {
		const item = event.item as any;
		const eventType = item.type;
		let dataset;
		if (eventType === "actionbutton" || eventType === "menubutton") {
			dataset = item.selectedAnchor[0].dataset;
		} else {
			dataset = item.element.dataset;
		}

		const action = dataset.action;
		if (action) {
			this.onToolbarAction(action, dataset.param);
		}
	}

	protected onToolbarAction(action: string, param?: string) {
		const eventHandler = this[action] as unknown;
		if (eventHandler && eventHandler instanceof Function) {
			try {
				(this[action] as (param?: string) => void)(param);
			} catch (ex) {
				this.logError("Failed to invoke action event handler: " + action, ex);
			}
		} else {
			this.logDebug("No action event handler found: " + action);
		}
	}

	/**
	 * Completes an AsyncSubject or resolves a Promise.
	 */
	protected asyncComplete<T>(async: any, value: T): void {
		if (!async) {
			return;
		}

		// Temporary helper method while we support both Promises and Observables
		if (async.complete) {
			async.next(value);
			async.complete();
			return;
		}
		async.resolve(value);
	}

	/**
	 * Errors an AsyncSubject or rejects a Promise.
	 */
	protected asyncError<T>(async: any, value?: T): void {
		if (!async) {
			return;
		}

		if (async.error) {
			async.error(value);
			return;
		}
		async.reject(value);
	}

	protected destroyRef(ref: ComponentRef<any>): void {
		if (ref) {
			ref.destroy();
		}
	}

	protected clearView(view: ViewContainerRef): void {
		if (view) {
			view.clear();
		}
	}

	private getButtonTitles(): any {
		let titles: any;
		if (this.languageService) {
			titles = this.languageService.getLanguage();
		}
		return (
			titles || {
				ok: "OK",
				yes: "Yes",
				no: "No",
			}
		);
	}

	private showInternal(
		messageRef: SohoMessageRef,
		title: string,
		message: string,
		isTrustedContent?: boolean,
	): Observable<any> {
		const subject = new AsyncSubject<any>();
		const button = {
			text: this.getButtonTitles().ok,
			isDefault: true,
			click: (e, modal) => {
				modal.close();
				this.asyncComplete(subject, {});
			},
			id: "lm-show-info-message-ok",
		};

		if (!isTrustedContent) {
			message = HtmlUtil.escapeStringForHtml(message);
			title = HtmlUtil.escapeStringForHtml(title);
		}

		messageRef
			.title(title)
			.message(message)
			.attributes({ name: "id", value: "lm-show-info-message" })
			.buttons([button])
			.open();
		return subject.asObservable();
	}
}

export class ModalDialogBase extends CoreBase {
	modalDialog: SohoModalDialogRef<any>;
	isBusy = false;
	canClose = true;
	hasSubmitError = false;

	constructor(
		public className: string,
		messageService?: SohoMessageService,
		languageService?: ILanguageService,
	) {
		super(className, messageService, languageService);
	}

	close(): void {
		if (this.canClose) {
			this.modalDialog.close();
		}
	}

	cancel(): void {
		if (this.isBusy) {
			return;
		}
		this.canClose = true;
		this.close();
	}

	protected initModalDialog(): void {
		this.modalDialog.beforeClose(() => this.canClose);
	}

	protected closeWithResult(button: number, value: any): void {
		const result: IDialogResult = {
			button: button,
			value: value,
		};
		this.setCanClose(true);
		this.setBusy(false);
		this.modalDialog.close(result);
	}

	protected setCanClose(canClose: boolean): void {
		if (this.canClose !== canClose) {
			this.canClose = canClose;
		}
	}

	protected setBusy(isBusy: boolean): void {
		if (this.isBusy !== isBusy) {
			this.isBusy = isBusy;
		}
	}

	/**
	 * Method that can be used in a submit action to prevent the modal from closing if the observable operation fails.
	 *
	 * @param observable Observable operation to be chained.
	 * @param reThrowError Rethrow the error if the operation is unsuccessful, otherwise the error will be ignored.
	 * @param keepOpen Keep the modal open even if the operation is successful, useful if the modal should be
	 * closed with a custom result.
	 */
	protected submitSafe<T>(
		observable: Observable<T>,
		reThrowError?: boolean,
		keepOpen?: boolean,
	): Observable<never | T> {
		this.setBusy(true);
		this.setCanClose(false);
		this.hasSubmitError = false;
		return observable.pipe(
			catchError((error) => {
				this.setCanClose(true);
				this.hasSubmitError = true;
				return reThrowError ? throwError(error) : of();
			}),
			tap<T>(() => {
				this.setCanClose(true);
				if (!keepOpen) {
					this.close();
				}
			}),
			finalize(() => this.setBusy(false)),
		);
	}
}

/**
 * Dialogbase for add/edit dynamic entities with translations
 */
export abstract class DynamicSettingsDialogBase extends ModalDialogBase {
	container: IDynamicContainer;
	/**
	 * New container localizations
	 */
	containerLznEdited: IDynamicEntityLocalizationMap;
	/**
	 * Determines if translations can be added
	 */
	isTranslateable: boolean;
	/**
	 * Properties for translate input fields.
	 */
	optionsItems: ITranslationItem[];
	/**
	 * Determines if dialog should open with permission tab selected
	 */
	isPermissionTabOnInit: boolean;

	isEditable = true;

	constructor(
		public className: string,
		sohoMessageService: SohoMessageService,
	) {
		super(className, sohoMessageService);
	}

	abstract hasInvalidTranslation(lang: IDynamicEntityLocalization): boolean;

	abstract deleteTranslation(lang: IDynamicEntityLocalization): void;

	abstract onLocalizationChange(
		editedLocalizations: IDynamicEntityLocalizationMap,
	): void;

	showConfirmDiscardTranslations(): Observable<any> {
		this.setCanClose(false);
		return this.showConfirm(
			"Delete translations",
			"You are about to save a component with one or more blank fields. The existing translations will be removed. Do you want to continue?",
		);
	}

	hasInvalidTranslations(lznMap: IDynamicEntityLocalizationMap): boolean {
		if (lznMap) {
			for (const lang of Object.keys(lznMap)) {
				if (this.hasInvalidTranslation(lznMap[lang])) {
					return true;
				}
			}
		}
		return false;
	}

	getInvalidTranslations(
		lznMap: IDynamicEntityLocalizationMap,
	): IDynamicEntityLocalizationMap {
		const invalidMap = {};
		if (lznMap) {
			for (const lang of Object.keys(lznMap)) {
				if (this.hasInvalidTranslation(lznMap[lang])) {
					invalidMap[lang] = lznMap[lang];
				}
			}
		}
		return invalidMap;
	}

	deleteTranslations(lznMap: IDynamicEntityLocalizationMap): void {
		if (lznMap) {
			for (const lang of Object.keys(lznMap)) {
				this.deleteTranslation(lznMap[lang]);
				this.deleteLocalization(lznMap, lang);
			}
		}
	}

	deleteLocalization(
		lznMap: IDynamicEntityLocalizationMap,
		lang: string,
	): void {
		const hasTitle = lznMap[lang].t && lznMap[lang].t.length > 0;
		const hasItems =
			lznMap[lang].its && Object.keys(lznMap[lang].its).length > 0;
		if (!hasItems && !hasTitle) {
			const isNew = !this.container.lzn || !this.container.lzn[lang];
			if (isNew) {
				delete lznMap[lang];
			} else {
				lznMap[lang].op = EntityOperation.Delete;
			}
		}
	}

	getTranslationItemIndex(name: string): number {
		if (this.optionsItems) {
			return ArrayUtil.indexByPredicate(
				this.optionsItems,
				(item) => item.name === name,
			);
		}
		return -1;
	}

	removeTranslationItem(name: string): void {
		if (this.optionsItems) {
			ArrayUtil.removeByPredicate(
				this.optionsItems,
				(item) => item.name === name,
			);
		}
	}
}

/**
 * Use this class together with the lm-dynamic-page-translations template to leverage localizations.
 */
export abstract class DynamicItemSettingsDialog extends DynamicSettingsDialogBase {
	item: IDynamicItem;
	itemLzn: IDynamicEntityLocalizationMap;
	itemLznEdited: IDynamicEntityLocalizationMap;

	constructor(
		public className: string,
		sohoMessageService: SohoMessageService,
	) {
		super(className, sohoMessageService);
	}

	abstract getEmptyTranslateablePropertyNames(): string[];

	initLocalizations(): void {
		if (this.item) {
			this.itemLzn = this.getItemLocalizations(this.item);
		}
	}

	/**
	 * Returns the localizations for the given item.
	 * @param item
	 */
	getItemLocalizations(item: IDynamicItem): IDynamicEntityLocalizationMap {
		const localizations = {};
		if (this.containerLznEdited) {
			// Go through each component translation
			for (const lang of Object.keys(this.containerLznEdited)) {
				// Check if the translation has any items
				if (this.containerLznEdited[lang].its) {
					// Check if the items contain translations for this link
					if (this.containerLznEdited[lang].its[item.eid]) {
						// Add operation and all translations to this link
						localizations[lang] = this.containerLznEdited[lang].its[item.eid];
					}
				}
			}
		}
		return localizations;
	}

	onLocalizationChange(editedLocalizations: IDynamicEntityLocalizationMap) {
		this.containerLznEdited = {
			...this.containerLznEdited,
			...editedLocalizations,
		};
		this.itemLzn = this.getItemLocalizations(this.item);

		// Remove deleted localizations.
		for (const langKey of Object.keys(this.containerLznEdited)) {
			const hasLangLzn = this.itemLznEdited && !!this.itemLznEdited[langKey];
			if (!editedLocalizations[langKey] && hasLangLzn) {
				this.itemLznEdited[langKey].op = EntityOperation.Delete;
			}
		}

		this.itemLznEdited = { ...this.itemLznEdited, ...editedLocalizations };
	}

	/**
	 * Get the localizations object prepared for the server request.
	 * @param lzn
	 * @param item
	 */
	getContainerLocalizations(
		lzn: IDynamicEntityLocalizationMap,
		entityId: string,
	): IDynamicEntityLocalizationMap {
		const localizations = {};

		// Create language objects for each edited translation
		for (const lang of Object.keys(lzn)) {
			let title = "";

			if (this.container.lzn && this.container.lzn[lang]) {
				title = this.container.lzn[lang].t || "";
			}

			if (lzn[lang].op === EntityOperation.Delete) {
				// Copy old items
				localizations[lang] = {
					its: this.container.lzn[lang] ? this.container.lzn[lang].its : null,
					op: EntityOperation.Update,
					t: title,
				};
				// Remove current item
				if (localizations[lang].its) {
					if (localizations[lang].its[entityId]) {
						delete localizations[lang].its[entityId];
					}
					// If no items exist and no title, set to delete language
					if (Object.keys(localizations[lang].its).length === 0 && !title) {
						localizations[lang].op = EntityOperation.Delete;
					}
				}
			} else {
				const items = this.optionsItems
					.filter((item) => item.name && item.name.length)
					.reduce((acc, item) => {
						acc[item.name] = lzn[lang][item.name];
						return acc;
					}, {});
				localizations[lang] = {
					its: {
						[entityId]: items,
					},
					op: EntityOperation.Update,
					t: title,
				};
			}

			// Set container title to empty string if it's not already set.
			if (
				!this.container.lzn ||
				(this.container.lzn &&
					(!this.container.lzn[lang] || !this.container.lzn[lang].t))
			) {
				localizations[lang].t = "";
			}
		}

		// Add unedited items of each edited language. This is so the server does not remove them.
		if (this.container && this.container.lzn) {
			for (const langKey of Object.keys(localizations)) {
				const currentItems = this.container.lzn[langKey]
					? this.container.lzn[langKey]
					: { its: null };
				if (currentItems.its) {
					for (const itemId of Object.keys(currentItems.its)) {
						if (itemId != entityId) {
							localizations[langKey].its[itemId] = currentItems.its[itemId];
						}
					}
				}
			}
		}

		return localizations;
	}

	deleteTranslation(lang: IDynamicEntityLocalization) {
		const fields = this.getEmptyTranslateablePropertyNames();
		const eid = this.item.eid;
		for (const field of fields) {
			if (lang.its && lang.its[eid] && lang.its[eid][field]) {
				delete lang.its[eid][field];
			}
		}
		if (!(lang.its && lang.its[eid] && Object.keys(lang.its[eid]).length > 0)) {
			delete lang.its[eid];
		}
	}
}

/**
 * Utility functions.
 */
export class CoreUtil {
	static copy<T>(source: T): T {
		if (source && source.constructor === Array) {
			const items = [];
			for (const item of source as any as any[]) {
				items.push(CoreUtil.copy(item));
			}
			return items as any as T;
		}
		return $.extend(true, {}, source);
	}

	static isEmpty(obj: any): boolean {
		return Object.keys(obj).length === 0 && obj.constructor === Object;
	}

	static isGuid(value: string): boolean {
		if (value && value.length === 36) {
			const parts = value.split("-");
			if (parts.length === 5) {
				const lengths = [8, 4, 4, 4, 12];
				for (let i = 0; i < 5; i++) {
					if (parts[i].length !== lengths[i]) {
						return false;
					}
				}
				return true;
			}
		}
		return false;
	}

	static extend(destination: any, source: any): any {
		return $.extend(true, destination, source);
	}

	static destroy(ref: ComponentRef<any>): void {
		try {
			if (ref) {
				ref.destroy();
			}
		} catch (ex) {
			Log.error("Failed to destroy component", ex);
		}
	}

	/**
	 * Converts an array of users or group to an entity array that can be used with the autocomplete control.
	 */
	static getEntityArray(
		principalType: PrincipalType,
		array: any[],
	): IAutocompleteEntity[] {
		const list: IAutocompleteEntity[] = [];
		for (let i = 0; i < array.length; i++) {
			const item = array[i];
			const isUser = principalType === PrincipalType.User;
			const isRole =
				principalType === PrincipalType.Role ||
				principalType === PrincipalType.DistributionGroup;
			const entity: IAutocompleteEntity = {
				type: principalType,
				label: isUser ? item.displayName : isRole ? item.id : item.name,
				value: isUser ? item.userName : item.id,
				info: isUser ? item.email : isRole ? item.name : item.description,
			};
			list.push(entity);
		}
		return list;
	}

	static isAccess(e1: IEntityAccess, e2: IEntityAccess): boolean {
		return (
			e1.principalType === e2.principalType && e1.principal === e2.principal
		);
	}

	static getAccess(
		entities: IEntityAccess[],
		entity: IEntityAccess,
	): IEntityAccess {
		return ArrayUtil.itemByPredicate(entities, (e) => {
			return CoreUtil.isAccess(entity, e);
		});
	}

	static getToastOptions(title: string, message: string): SohoToastOptions {
		return {
			title: HtmlUtil.escapeStringForHtml(title),
			message: HtmlUtil.escapeStringForHtml(message),
			position: SohoToastService.BOTTOM_RIGHT,
			timeout: 3000,
		};
	}

	static isJsonString(str: string): boolean {
		try {
			JSON.parse(str);
		} catch (e) {
			return false;
		}
		return true;
	}

	static tryParse<T>(value: string): T {
		try {
			return value ? (JSON.parse(value) as T) : null;
		} catch (ex) {
			Log.debug("tryParse: Failed to parse JSON", ex);
		}
		return null;
	}

	static reloadDocument(): void {
		try {
			const location = window.location;
			const path = location.pathname;
			const finalPath = path && path.indexOf("lime") >= 0 ? "/lime/" : "/";
			const hash = location.hash || "";
			const query = location.search || "";
			const hasQuery = !!query;

			const url =
				location.origin +
				finalPath +
				query +
				(hasQuery ? "&" : "?") +
				"reload=" +
				new Date().getTime() +
				hash;
			window.location.href = url;
		} catch (ex) {
			Log.error("reloadDocument: Failed to reload", ex);
		}
	}

	static trim<T>(value: T): T {
		if (typeof value === "string") {
			return (value as string).trim() as unknown as T;
		}
		return value;
	}

	static truncate(value: string, maxLength: number): string {
		if (!value || value.length <= maxLength) {
			return value;
		}
		return value.substring(0, maxLength);
	}
}

export class AccessUtil {
	static publishedPages(
		languageService: ILanguageService,
		page: IPage,
	): IEntityAccessDialogOptions {
		const lang = languageService.getLanguage();
		const level = PageAccessLevel;
		return {
			title: page.data.title,
			dialogType: EntityAccessDialogType.PublishedPage,
			entityId: page.data.id,
			access: page.access ? CoreUtil.copy(page.access) : [],
			accessLevels: [
				{ name: lang.disabled, value: level.Disabled },
				{ name: lang.viewAccess, value: level.View },
				{ name: lang.editAccess, value: level.Edit },
			],
			defaultAccessLevel: level.View,
		} as IEntityAccessDialogOptions;
	}
	static standardPages(
		languageService: ILanguageService,
		page: IPage,
	): IEntityAccessDialogOptions {
		const lang = languageService.getLanguage();
		const level = PageAccessLevel;
		return {
			title: page.data.title,
			dialogType: EntityAccessDialogType.StandardPage,
			entityId: page.data.id,
			access: page.access,
			accessLevels: [
				{ name: lang.disabled, value: level.Disabled },
				{ name: lang.viewAccess, value: level.View },
			],
			defaultAccessLevel: level.View,
		} as IEntityAccessDialogOptions;
	}

	static widgets(
		languageService: ILanguageService,
		widgetId: string,
		widgetTitle: string,
		isStandardWidgetAdmin: boolean,
	): IEntityAccessDialogOptions {
		const lang = languageService.getLanguage();
		const level = WidgetAccessLevel;

		const accessLevels = [
			{ name: lang.disabled, value: level.Disabled },
			{ name: lang.viewAccess, value: level.View },
			{ name: lang.configure, value: level.Configure },
		];

		const everyoneAccessLevels = CoreUtil.copy(accessLevels);

		// Can publish should not be available for standard widgets or tenant widgets in admin tool
		if (!isStandardWidgetAdmin) {
			accessLevels.push({ name: lang.canPublish, value: level.Publish });
		}

		return {
			dialogType: EntityAccessDialogType.Widget,
			entityId: widgetId,
			title: `Widget Permissions - ${widgetTitle}`,
			accessLevels: accessLevels,
			everyoneAccessLevels: everyoneAccessLevels,
			defaultAccessLevel: level.Configure,
			showSwitch: true,
			switchLabel: "Catalog",
		} as IEntityAccessDialogOptions;
	}
}

/**
 * HTTP utility functions.
 */
export class HttpUtil {
	static readonly isLocalhost = window.location.hostname === "localhost";
	private static queryMap: IStringMap;

	private static jsonStart = /^\[|^\{(?!\{)/;
	private static jsonEnds = {
		"[": /]$/,
		"{": /}$/,
	};

	static isSuccess(status: number): boolean {
		return status >= 200 && status <= 299;
	}

	static isError(status: number): boolean {
		return status >= 400;
	}

	static canRetry(status: number): boolean {
		return status === 502 || status === 503 || status === 504;
	}

	static isJsonLike(value: string): boolean {
		const jsonStart = value.match(HttpUtil.jsonStart);
		return jsonStart && HttpUtil.jsonEnds[jsonStart[0]].test(value);
	}

	static isHttpUrl(url: string): boolean {
		// Note that "http" is also checked since it is used in dev mode
		return (
			url && (url.indexOf("https://") === 0 || url.indexOf("http://") === 0)
		);
	}

	static getQuery(): IStringMap {
		let map = HttpUtil.queryMap;
		if (!map) {
			HttpUtil.queryMap = map = HttpUtil.parseQuery(window.location.search);
		}
		return map;
	}

	static getParameter(name: string): string {
		return HttpUtil.getQuery()[name];
	}

	/**
	 * Parses a query string to a parameter map.
	 *
	 * Note that this function does not support multiple parameters with the same name.
	 *
	 * @param query A query string.
	 * @returns A parameter map.
	 */
	static parseQuery(query: string): IStringMap {
		const index = query.indexOf("?");
		if (index >= 0) {
			query = query.substring(index + 1);
		}
		let match,
			pl = /\+/g, // Regex for replacing addition symbol with a space
			search = /([^&=]+)=?([^&]*)/g,
			decode = (s: string) => decodeURIComponent(s.replace(pl, " "));

		const parameters = {};
		while ((match = search.exec(query))) {
			parameters[decode(match[1])] = decode(match[2]);
		}
		return parameters;
	}

	static combine(url1: string, url2: string): string {
		if (!url1) {
			return url2;
		}
		if (!url2) {
			return url1;
		}
		const end = url1.length - 1;
		if (url1.charAt(end) === "/") {
			url1 = url1.substring(0, end);
		}
		if (url2.charAt(0) === "/") {
			url2 = url2.substring(1);
		}
		return url1 + "/" + url2;
	}

	static appendParam(url: string, name: string, value: string): string {
		const pair = name + "=" + encodeURIComponent(value);
		if (url.indexOf("?") >= 0) {
			url += "&" + pair;
		} else {
			url += "?" + pair;
		}
		return url;
	}

	static toQuery(params: any): string {
		let query = "";
		for (const key of Object.keys(params)) {
			if (query.length > 0) {
				query += "&";
			}
			let value = params[key];
			value = value != null ? value.toString() : "";
			if (value.length > 0) {
				query += key + "=" + value;
			} else {
				query += key;
			}
		}
		return query;
	}

	/**
	 * Returns the host and port including the protocol.
	 * http://testserver.infor.com:8080
	 */
	static getCurrentBaseURL(): string {
		const url = window.location.href;
		const parts = url.split("/");
		return parts[0] + "//" + parts[2];
	}

	/**
	 * Checks if the application is running in a frame.
	 *
	 * This function is mainly for preventing framing of ourselves, framing by others is handled by headers.
	 * Added check for Cypress after request from ION team. Cypress is a testing framework.
	 */
	static isFramed(): boolean {
		try {
			return window["Cypress"] ? false : window.self !== window.top;
		} catch (e) {
			// Return false for now on errors, change to true if / when we are confident with this
			return false;
		}
	}
}

export class ClientConfiguration {
	static appModuleRef: NgModuleRef<any>;
	private static url = "";
	private static subject: AsyncSubject<any>;
	private static preload = false;

	static overrideUrl(url: string) {
		ClientConfiguration.url = url;
	}

	static isPreLoaded(): boolean {
		return ClientConfiguration.preload;
	}

	static popPreLoad(): Observable<any> {
		const subject = ClientConfiguration.subject;
		const observable = subject ? subject.asObservable() : null;
		ClientConfiguration.subject = null;
		ClientConfiguration.preload = false;
		return observable;
	}

	static tryPreLoad(): void {
		const key = "lmLoader";
		const loader = window[key] as any;
		if (!loader) {
			return;
		}
		window[key] = null;

		const subject = new AsyncSubject<any>();
		const config = ClientConfiguration;
		config.subject = subject;

		loader.load((status: number, text: string) => {
			let data = null;
			if (status === 200) {
				try {
					data = JSON.parse(text);
				} catch (ex) {
					Log.error("tryPreLoad: Failed to parse container json", ex);
				}
			}

			if (data) {
				config.preload = true;
				subject.next(data);
				subject.complete();
			} else {
				subject.error({ status: status });
			}
		});
	}

	static initialize() {
		const config = ClientConfiguration;
		if (HttpUtil.isLocalhost) {
			Log.setDebug();
			config.overrideUrl(config.getLocalUrl());
		}
	}

	static getUrl(): string {
		return ClientConfiguration.url;
	}

	static getLocalUrl(): string {
		return "";
	}
}

export class AutoCompleter<T> {
	readonly source: (
		query: string,
		done: SohoAutoCompleteResponseFunction,
	) => void;
	private lastQuery: string;
	private lastResult: IAutocompleteEntity[];

	constructor(
		searchProvider: (query: string) => Observable<T>,
		resultConverter: (response: T) => IAutocompleteEntity[],
		errorHandler: IErrorHandler,
		reuseCache = true,
	) {
		const self = this;
		this.source = (query: string, done: SohoAutoCompleteResponseFunction) => {
			const finalQuery = CoreUtil.trim(query);
			if (!finalQuery) {
				done(finalQuery, []);
				return;
			}

			if (finalQuery === self.lastQuery && reuseCache) {
				done(finalQuery, self.lastResult || []);
				return;
			}

			searchProvider(finalQuery).subscribe(
				(response: T) => {
					const result = resultConverter(response);
					self.lastQuery = finalQuery;
					self.lastResult = result;
					done(finalQuery, result);
				},
				(response: IOperationResponse) => {
					if (errorHandler) {
						errorHandler.handleError(response);
					}
				},
			);
		};
	}

	getLastResult(): IAutocompleteEntity[] {
		return this.lastResult;
	}
}
