import {
	Component,
	ComponentRef,
	Input,
	NgZone,
	OnDestroy,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoBusyIndicatorDirective,
	SohoContextualActionPanelService,
	SohoMessageService,
	SohoModalDialogService,
} from "@infor/sohoxi-angular";
import {
	CommonUtil,
	DialogButtonType,
	HtmlUtil,
	IDialogResult,
	Log,
	StringUtil,
} from "lime";
import {
	AdminPages,
	CompanyonRequest,
	Constants,
	ContainerService,
	ContextService,
	CoreBase,
	DevService,
	EditModeService,
	HttpUtil,
	IAddWidgetInfo,
	IAdminToggle,
	IEditMode,
	IMingleContext,
	IPageContainer,
	IPageInstance,
	IStringMap,
	IStringToAnyMap,
	IWidgetDefinition,
	IWidgetHandle,
	LanguageService,
	LazyTypeService,
	PageUtil,
	Product,
	ProgressService,
	WidgetService,
} from "lime/core";
import { map, withLatestFrom } from "rxjs/operators";
import {
	IMissingPage,
	InforStartMode,
	ResponseErrorCodes,
} from "../../base/core";
import { MaintenanceService } from "../../base/maintenance.service";
import { CoreUtil } from "../../base/runtime";
import { MingleMessageBroker } from "../../mingle";
import { PageService } from "../../page/service";
import {
	ISystemMessage,
	SystemMessagesService,
	SystemMessageType,
} from "../../services/system-messages.service";

@Component({
	selector: "lm-svg",
	templateUrl: "../../../svg.html",
})
export class SvgComponent {}

@Component({
	selector: "lm-page-container",
	templateUrl: "./page-container.html",
	styleUrls: ["./page-container.scss"],
})
export class PageContainerComponent
	extends CoreBase
	implements OnDestroy, OnInit
{
	@ViewChild("containerView", { read: ViewContainerRef, static: true })
	containerView: ViewContainerRef;

	@ViewChild("pageEditView", { read: ViewContainerRef, static: false })
	pageEditView: ViewContainerRef;

	@ViewChild("myPagesView", { read: ViewContainerRef, static: false })
	myPagesView: ViewContainerRef;

	@ViewChild(SohoBusyIndicatorDirective, { static: false })
	busyIndicator: SohoBusyIndicatorDirective;

	@Input() enableMissingEvent: boolean;

	isMobile: boolean;
	showNavigator: boolean;
	hidePages = false;
	isEditMode = false;
	editMode = {} as IEditMode;
	navigator: any;
	pageContainer: IPageContainer;
	lmBusy: boolean;
	isAdminOpen = false;
	adminPage: AdminPages;
	showSystemMessage = true;
	hasSystemMessage$ = this.systemMessageService.systemMessages$.pipe(
		map((messages) => messages.length > 0),
	);

	private isMingleInitialized = false;
	private hasMingleFocus = true;
	private showPageCount = 0;
	private editRef: ComponentRef<any>;

	constructor(
		public containerService: ContainerService,
		private lazyTypeService: LazyTypeService,
		private contextService: ContextService,
		private widgetService: WidgetService,
		private dialogService: SohoModalDialogService,
		private capService: SohoContextualActionPanelService,
		private progressService: ProgressService,
		private pageService: PageService,
		private devService: DevService,
		private zone: NgZone,
		private maintenanceService: MaintenanceService,
		editModeService: EditModeService,
		mingleMessageBroker: MingleMessageBroker,
		messageService: SohoMessageService,
		languageService: LanguageService,
		private readonly systemMessageService: SystemMessagesService,
	) {
		super("PageContainerComponent", messageService, languageService);

		mingleMessageBroker.initialize();

		this.showNavigator = contextService.isStandardNavigator;
		if (contextService.isSafeModeAll) {
			this.addSystemSafeModeMessage();
		}

		containerService.container$.subscribe((container: IPageContainer) => {
			const isRefresh = !!this.pageContainer;
			if (container) {
				this.onContainer(container);
				if (isRefresh) {
					this.showSystemMessage = true;
				}
			}
		});

		// Enable functionality that should only be available in standard mode
		if (contextService.isStandard) {
			containerService.admin$
				.pipe(withLatestFrom(this.contextService.context$))
				.subscribe(([adminToggle, context]) => {
					if (context.isAdministrationEnabled()) {
						this.toggleAdminTool(adminToggle);
					} else {
						this.logWarning("User is not authorized to access Administration");
					}
				});

			editModeService.changed().on((current: IEditMode) => {
				const mode = current.mode;
				const isActive = current.isActive;
				const isLayout = mode === "layout";
				this.editMode = current;
				this.isEditMode =
					isActive &&
					(mode === "page" || mode === "widget" || mode === "preview");
				if (isLayout) {
					this.toggleEditLayout(isActive);
				}
			});
		}

		progressService.busyChanged().on((isBusy: boolean) => {
			this.lmBusy = isBusy;
		});
	}

	ngOnDestroy(): void {
		this.destroyEdit();
	}

	ngOnInit(): void {
		// TODO Temporary, remove rootView property when everything has been migrated to components
		this.languageService.rootView = this.containerView;
		this.isMobile = this.contextService.isMobile;
	}

	ngAfterViewInit() {
		if (this.devService.isDev) {
			return;
		}

		this.initBusy();
		CommonUtil.detectBrowser();
	}

	isHidden(): boolean {
		return !!(this.isEditMode || this.hidePages);
	}

	private addSystemSafeModeMessage(): void {
		const message: ISystemMessage = {
			errorCode: ResponseErrorCodes.safeMode,
			message: this.languageService.language.safemodeMessage,
			messageType: SystemMessageType.information,
		};
		this.systemMessageService.addMessage(message);
	}

	private destroyEdit(): void {
		const ref = this.editRef;
		if (ref) {
			ref.destroy();
			this.editRef = null;
		}
	}

	private toggleEditLayout(isActive: boolean): void {
		if (!isActive) {
			this.destroyEdit();
			this.pageEditView.clear();
			this.hidePages = false;
			return;
		}

		this.lmBusy = true;
		this.lazyTypeService
			.loadLazyModule()
			.then(({ PageEditComponent, ngModuleRef }) => {
				const ref = this.pageEditView.createComponent(PageEditComponent, {
					ngModuleRef,
				});
				ref.instance.currentPage = this.containerService.selectedPage;
				this.editRef = ref;
				this.hidePages = true;
			})
			.finally(() => {
				this.lmBusy = false;
			});
	}

	private toggleAdminTool(adminToggle: IAdminToggle) {
		this.adminPage = adminToggle.page || AdminPages.Home;
		this.isAdminOpen = !adminToggle.isClose;

		const hidePages = !(adminToggle.isHide || adminToggle.isClose);

		if (!hidePages) {
			// Need to trigger a resize for Soho to reevaluate the widget layout
			$(window).trigger("resize");
		}

		const ref = this.editRef;
		if (ref) {
			ref.instance.isHidden = hidePages;
		} else {
			this.hidePages = hidePages;
		}
	}

	private initBusy(): void {
		this.busyIndicator.text = Soho.Locale.translate("Loading");
	}

	private onMissingPage(
		missingPage: IMissingPage,
		enablePreview: boolean,
	): void {
		if (this.enableMissingEvent) {
			this.containerService.raiseMissingPage(missingPage);
			return;
		}

		if (enablePreview) {
			const language = this.languageService.getLanguage();
			this.showMessage(Product.productName, language.pageNotExist);
		}
	}

	private openPage(pageId: string, preview: boolean): boolean {
		const container = this.pageContainer;
		if (container.contains(pageId)) {
			this.containerService.select(pageId);
			return true;
		}

		if (preview) {
			this.pageService.previewPage({ pageId: pageId, notifyMingle: true });
			return true;
		}

		return false;
	}

	private onShowPage(pageId: string, source: number, refId?: number): void {
		// Number of calls to this method to have special handling of the first incoming message
		this.showPageCount += 1;
		this.logInfo("onShowPage: " + this.showPageCount);
		const currentSource = this.contextService.getContext().getSocialUser();
		let enablePreview = !this.enableMissingEvent && !this.devService.isDev;
		// Preview is always turned off for mobile
		if (enablePreview) {
			// Extra check if it is enabled that preview should not be enabled if the source is the same as the user,
			// And also the first time only
			const startMode = HttpUtil.getParameter(Constants.mingleStartMode);
			const isYourLink = source === currentSource;
			const isFirstStart = this.showPageCount === 1;
			const isHomepagesLaunch =
				startMode === InforStartMode.urlFavoriteExternal;
			// We can consider the launch of Homepages from the bookmarks menu in Mingle as well
			if (isYourLink && isFirstStart && isHomepagesLaunch) {
				this.logInfo(
					"Preview will be disabled for pageId: " +
						pageId +
						" as this is a start-up scenario.",
				);
				enablePreview = false;
			}
		}
		pageId = PageUtil.normalizeId(pageId);

		if (pageId && this.openPage(pageId, enablePreview)) {
			return;
		}
		this.onMissingPage({ pageId: pageId, refId: refId }, enablePreview);
	}

	private onAddWidget(widgetJson: string): void {
		try {
			const widget = JSON.parse(widgetJson);
			const widgetId = widget.widgetId as string;
			if (!widgetId) {
				return;
			}

			const info = {
				widgetInfo: { widgetId: widgetId },
				byRef: false,
			} as IAddWidgetInfo;
			const settings = widget.settings as IStringToAnyMap;
			const title = widget.title as string;
			if (settings || title) {
				info.customWidget = { settings: settings, title: title };
				const logicalId = settings[Constants.settingsNameLogicalId];
				if (logicalId) {
					info.customWidget.logicalId = logicalId;
					Log.debug("OnAddWidget with logicalId " + logicalId);
				}
			}

			const language = this.languageService.getLanguage();
			const widgetHandle: IWidgetHandle = { id: widgetId };
			widgetHandle.byRef = false;
			// Message does not support published tenant widgets unless the standard widget id is passed as well.

			this.widgetService.getDefinition(widgetHandle).subscribe(
				(definition: IWidgetDefinition) => {
					// Check if allowed?
					if (this.pageContainer.context.settings.isPrivatePagesEnabled()) {
						const privates: IPageInstance[] = [];
						for (let i = 0; i < this.pageContainer.pages.length; i++) {
							if (PageUtil.isPrivate(this.pageContainer.pages[i])) {
								privates.push(this.pageContainer.pages[i]);
							}
						}
						const isAddAllowed = this.pageContainer.isAddPageAllowed();
						if (privates.length === 0 && !isAddAllowed) {
							this.showMessage(
								language.unableToAddWidget,
								language.maxPageCountMessage,
							); // Perhaps not the best message (nothing about private pages)
							return;
						}

						this.progressService.setBusy(true);
						this.lazyTypeService
							.loadLazyModule()
							.then(({ SelectPageComponent }) => {
								const dialog = this.dialogService
									.modal(
										SelectPageComponent,
										this.containerService.dialogParent,
									)
									.id("lm-cont-addtopage-dialog")
									.title(language.selectPage)
									.afterClose((r: IDialogResult) => {
										if (r && r.button === DialogButtonType.Ok) {
											const value = r.value;
											if (value === Constants.selectNewPrivate) {
												this.pageContainer
													.showAddPage(this.containerView, false)
													.subscribe((pageData) => {
														if (pageData) {
															this.containerService.select(pageData.id);
															this.pageContainer.addWidget(info);
														}
													});
											} else if (value) {
												const selectedPageId: string = r.value;
												this.containerService.select(selectedPageId);
												this.pageContainer.addWidget(info);
											} else {
												return;
											}
										}
									});

								dialog
									.apply((component: any) => {
										component.dialog = dialog;
										component.pages = privates;
										component.isNewPageAllowed = isAddAllowed;
									})
									.open();
							});
					} else {
						this.showMessage(
							language.unableToAddWidget,
							language.privatePagesNotEnabled,
						);
						return;
					}
				},
				() => {
					// Error fetching definition
					this.showMessage(language.unableToAddWidget, language.brokenWidget);
					return;
				},
			);
		} catch (ex) {
			this.logError(
				"onAddWidget: Failed to add widget from JSON: " + widgetJson,
				ex,
			);
		}
	}

	/**
	 * Handles Ming.le drillback links.
	 * URL example: "?LogicalId=lid://infor.homepages.1&page=asd45as54asd564asd564"
	 */
	private onDrillback(data: any): void {
		try {
			const request = new CompanyonRequest(this.contextService.logicalId, data);
			if (!request.isValid()) {
				return;
			}

			this.zone.run(() => {
				const parameters = request.getParameters();
				this.setContextParameters(parameters);

				const pageId = request.get(Constants.shortcutTypePage);
				if (pageId) {
					const source = 0; // Drillback does not have the user who created them;
					this.onShowPage(pageId, source, request.Id);
					return;
				}

				const adminId = request.get(Constants.shortcutTypeAdmin);
				if (adminId) {
					const adminPage = Number(adminId);
					if (!isNaN(adminPage)) {
						this.containerService.showAdmin(adminPage);
					}
					return;
				}

				// Add widget JSON in drillback
				const widgetJson = request.get("widget");
				if (widgetJson) {
					this.onAddWidget(widgetJson);
					return;
				}

				// Empty drillbacks just to get to the application is OK
			});
		} catch (ex) {
			this.logError("Failed to handle drillback " + JSON.stringify(data), ex);
		}
	}

	private onBookmark(data: any): void {
		try {
			const request = new CompanyonRequest(this.contextService.logicalId, data);
			if (!request.isValid()) {
				if (this.isDebug()) {
					this.logDebug(
						"onBookmark: The data is not valid, ignoring message. Data: " +
							data +
							", toJSON: " +
							JSON.stringify(data),
					);
				}
				return;
			}

			const favoriteContext = data.favoriteContext;

			if (CoreUtil.isJsonString(favoriteContext)) {
				if (this.isDebug()) {
					this.logDebug(
						"onBookmark: data.favoriteContext is JSON string. FavoriteContext: " +
							favoriteContext,
					);
				}
				const context = JSON.parse(favoriteContext) as IMingleContext;
				context.refId = request.Id;
				if (context.parameters) {
					this.setContextParameters(context.parameters);
				}
				if (context.id) {
					this.zone.run(() => {
						if (context.type === Constants.shortcutTypePage) {
							const source =
								context.source ||
								this.contextService.getContext().getSocialUser();
							this.onShowPage(context.id, source, request.Id);
							this.containerService.setFavoriteMessagePending(true);
							return;
						}

						if (context.type === Constants.shortcutTypeAdmin) {
							const adminPage = Number(context.id);
							if (!isNaN(adminPage)) {
								this.containerService.showAdmin(adminPage);
							}
							return;
						}

						if (context.type === Constants.shortcutTypeWidget) {
							this.logInfo(
								"onBookmark: raising widget selected event " + favoriteContext,
							);
							this.containerService.setFavoriteMessagePending(true);
							this.containerService.raiseMobileWidgetSelected(context);
						}
					});
				}
			} else {
				if (this.isDebug()) {
					const isString = StringUtil.isString(data);
					let message = "onBookmark: data is NOT a valid JSON string.";
					if (!isString) {
						message = message + " Data is not a string";
					}
					this.logDebug(message);
				}
				const params = HttpUtil.parseQuery(favoriteContext);
				if (params) {
					this.setContextParameters(params);
				}
			}
		} catch (ex) {
			this.logError("Failed to handle bookmark " + JSON.stringify(data), ex);
		}
	}

	private setContextParameters(parameters: IStringMap): void {
		const escapedParameters = {};
		for (const parameter in parameters) {
			if (
				parameters.hasOwnProperty(parameter) &&
				typeof parameters[parameter] === "string"
			) {
				escapedParameters[parameter] = HtmlUtil.escapeStringForHtml(
					parameters[parameter],
				);
			}
		}
		this.containerService.setContextParameters(escapedParameters);
	}

	private onGotFocus(data: any): void {
		this.zone.run(() => {
			try {
				this.logDebug("onGotFocus: " + JSON.stringify(data));
				if (!this.hasMingleFocus) {
					const containerService = this.containerService;
					if (containerService.selectedPage) {
						containerService.selectedPage.show();
					}
					this.hasMingleFocus = true;
				}
			} catch (ex) {
				this.logError(
					"Failed to handle onGotFocus " + JSON.stringify(data),
					ex,
				);
			}
		});
	}

	private onLostFocus(data: any): void {
		try {
			this.logDebug("onLostFocus: " + JSON.stringify(data));
			// Since we incorrectly get multiple messages per transition we ignore messages depending on internal state
			if (this.hasMingleFocus) {
				const containerService = this.containerService;
				if (containerService.selectedPage) {
					containerService.selectedPage.hide();
				}
				this.hasMingleFocus = false;
			}
		} catch (ex) {
			this.logError("Failed to handle onLostFocus " + JSON.stringify(data), ex);
		}
	}

	private initMingleCallbacks(): void {
		if (this.isMingleInitialized) {
			return;
		}
		this.isMingleInitialized = true;

		const client = infor.companyon.client;

		const self = this;
		client.registerMessageHandler("showFavoriteContext", (data: any) => {
			self.onBookmark(data);
		});

		client.registerMessageHandler("applicationDrillback", (data: any) => {
			self.onDrillback(data);
		});

		client.registerMessageHandler("cachedIFrameLostFocus", (data: any) => {
			self.onLostFocus(data);
		});

		client.registerMessageHandler("cachedIFrameInFocus", (data: any) => {
			self.onGotFocus(data);
		});

		this.maintenanceService.startListening();

		// Use explicit initialization for Homepages
		client.sendMessage("appInitComplete", window.name);
	}

	private onContainer(pageContainer: IPageContainer): void {
		this.logDebug("Received page container");
		this.pageContainer = pageContainer;
		this.initMingleCallbacks();
	}
}
