import { Component, HostBinding, Input, OnInit } from "@angular/core";
import { IContext, MemoItem } from "lime/core";
import { MemoLayout } from "scripts/lime/core/base/core";

@Component({
	selector: "lm-memo",
	templateUrl: "./memo.html",
	styleUrls: ["./memo.scss"],
})
export class MemoComponent implements OnInit {
	@Input() memo: MemoItem;
	@Input() context: IContext;
	@Input() parentAreaName: string;
	@Input() @HostBinding("class.in-widget") inWidget = false;

	autoId = "lm-mm-item";

	@HostBinding("class.layout-text-first") get textFirstLayout() {
		return this.memo.layout === MemoLayout.TextFirst;
	}
	@HostBinding("class.layout-image-first") get imageFirstLayout() {
		return this.memo.layout === MemoLayout.ImageFirst;
	}
	@HostBinding("class.layout-background-image") get backgroundImageLayout() {
		return this.memo.layout === MemoLayout.BackgroundImage;
	}
	@HostBinding("class.layout-image-only") get imageOnlyLayout() {
		return this.memo.layout === MemoLayout.ImageOnly;
	}
	@HostBinding("class.has-button") get hasButton() {
		return !!this.memo.actionUrl;
	}

	@HostBinding("class.has-no-image") get hasNoImage() {
		return !this.memo.imageUrl;
	}

	@HostBinding("class.is-critical") get isCritical() {
		return this.parentAreaName === "critical";
	}

	ngOnInit() {
		this.autoId = "lm-mm-" + this.parentAreaName + "-item";
	}

	onLaunch(url: string) {
		this.context.launch({ url });
	}
}
