import { Injectable } from "@angular/core";
import { StringUtil } from "lime";
import { CoreBase } from "./base/runtime";

// This file in a combination of messagebroker.js and messagehandler.js from Ming.le
// The code was originally JavaScript / AngularJS and has been ported to TypeScript / Angular

const mingleConstants = {
	MsgType: {
		PROXYMESSAGE: "workspaceProxyMessage",
		SUBSCRIBE: "workspaceClientSubscribe",
		DEFAULTMESSAGEHANDLER: "defaultMessageHandler",
		INITCLIENT: "initClient",
		DRILLBACK: "prepareApplicationDrillback",
		APPINITCOMPLETED: "appInitComplete",
		PROCESSDRILLBACK: "applicationDrillback",
		SHORTCUTCONTEXT: "setShortcutContext",
		IBC: "inforBusinessContext",
	},
	InitMethod: {
		IMPLICIT: "Implicit",
		EXPLICIT: "Explicit",
	},
	InternalMessages: [
		"setShortcutContext",
		"initClient",
		"appInitComplete",
		"defaultMessageHandler",
		"workspaceClientSubscribe",
		"generic_",
		"prepareFavoriteContext",
	],
};

class Listener {
	// Listener dictionary keyed by message type, value is array of listeners for a specific message type
	private readonly listeners: any = {};

	getListeners(): any {
		return this.listeners;
	}

	add(listener: any): void {
		if (!listener) {
			return;
		}

		const listeners = this.listeners;
		const messageType = listener.messageType;
		let messageListeners = listeners[messageType];
		if (!messageListeners) {
			listeners[messageType] = messageListeners = [];
		}

		let addListener = true;
		for (let i = 0; i < messageListeners.length; i++) {
			const existingListener = messageListeners[i];
			if (
				existingListener.iframeName &&
				listener.iframeName &&
				listener.iframeName === existingListener.iframeName
			) {
				addListener = false;
				messageListeners[i] = listener;
			}
		}

		if (addListener) {
			messageListeners.push(listener);
		}
	}
}

class Publisher {
	publish(listenerMap, message): void {
		const messageType = message.type;
		if (
			(typeof message.data === "undefined" || message.data.length === 0) &&
			messageType.toLowerCase() === mingleConstants.MsgType.IBC.toLowerCase()
		) {
			message = { data: { screenId: "" } };
		}

		const listeners = this.getListeners(listenerMap, messageType);
		this.processMessage(listeners, message);
	}

	private getListeners(listenerMap, messageType): any[] {
		if (!listenerMap) {
			return [];
		}
		return listenerMap[messageType] || [];
	}

	private processMessage(listeners, message): void {
		for (const listener of listeners) {
			if (!listener) {
				continue;
			}

			let target = null;

			if (typeof listener.callback === "function") {
				listener.callback(message.data);
			} else if (!StringUtil.isNullOrWhitespace(listener.iframeName)) {
				const iframeSelector = $('iframe[name="' + listener.iframeName + '"]');
				if (iframeSelector.length > 0) {
					target = (iframeSelector.get(0) as any).contentWindow;
				}
			}

			if (target) {
				this.sendMessage(target, message);
			}
		}
	}

	private sendMessage(target: any, message: any): void {
		const json = JSON.stringify(message);
		target.postMessage(json, "*");
	}
}

class MessageHandler {
	private readonly listener: Listener;
	private readonly publisher: Publisher;

	constructor() {
		this.listener = new Listener();
		this.publisher = new Publisher();
	}

	process(message: any): void {
		if (StringUtil.isNullOrWhitespace(message.type)) {
			return;
		}
		switch (message.type) {
			case mingleConstants.MsgType.PROXYMESSAGE:
				this.handleProxyMessage(message.data);
				break;
			case mingleConstants.MsgType.INITCLIENT:
				this.registerInitClient(message);
				break;
			case mingleConstants.MsgType.PROCESSDRILLBACK:
				this.handlePublishMessage(message);
				break;
			default:
				this.subscribeCustomMessage(message);
				break;
		}
	}

	private subscribeCustomMessage(message: any): void {
		this.addModifiedMessage(message);
	}

	private registerInitClient(message: any): void {
		this.addModifiedMessage(message);
	}

	private addModifiedMessage(message: any): void {
		const modifiedMessage = {
			messageType: message.type,
			callback: message.callback,
		};
		this.listener.add(modifiedMessage);
	}

	private handleSubscriptionMessage(message: any): void {
		this.listener.add(message);
	}

	private handleProxyMessage(message: any): void {
		if (!message) {
			return;
		}
		if (message.type === mingleConstants.MsgType.SUBSCRIBE) {
			this.handleSubscriptionMessage(message.data);
		} else {
			this.handlePublishMessage(message);
		}
	}

	private handlePublishMessage(message: any): void {
		this.publisher.publish(this.listener.getListeners(), message);
	}
}

@Injectable({
	providedIn: "root",
})
export class MingleMessageBroker extends CoreBase {
	private readonly messageHandler;
	private isInitialized = false;

	constructor() {
		super("MingleMessageBroker");
		this.messageHandler = new MessageHandler();
	}

	initialize(): any {
		if (this.isInitialized) {
			return;
		}
		this.isInitialized = true;

		this.setupMessageListener();
	}

	publish(message: any): void {
		this.messageHandler.process(message);
	}

	register(messageType, callback): void {
		this.messageHandler.process({ type: messageType, callback: callback });
	}

	private setupMessageListener(): void {
		if (window.postMessage && window.addEventListener) {
			const self = this;
			window.addEventListener(
				"message",
				(evt: any) => {
					self.onMessageReceived(evt);
				},
				false,
			);
		}
	}

	private onMessageReceived(evt: any): void {
		let isJson: boolean;
		let message: string = null;
		try {
			const data = evt.data;
			if (!data) {
				return;
			}
			message = $.parseJSON(data);
			isJson = true;
		} catch (ex) {
			isJson = false;
		}
		if (!isJson) {
			this.logDebug(
				"Recieved non Ming.le postMessage event since the data isn't JSON",
			);
			return;
		}

		try {
			if (this.isValidMessage(message)) {
				this.messageHandler.process(message);
			} else {
				this.logDebug("Received unrecognized message " + evt.data);
			}
		} catch (ex2) {
			this.logDebug("Failed to receive message", ex2);
		}
	}

	private isValidMessage(jsonMsg): boolean {
		if (
			typeof jsonMsg.type !== "undefined" &&
			jsonMsg.type !== null &&
			typeof jsonMsg.data !== "undefined" &&
			jsonMsg.data !== null
		) {
			return true;
		}
		return false;
	}
}
