import { Injectable } from "@angular/core";
import { SohoMessageService } from "@infor/sohoxi-angular";
import { BehaviorSubject, Observable } from "rxjs";
import { ResponseErrorCodes } from "../base/core";
import { CoreBase } from "../base/runtime";
import { LanguageService } from "../base/service";

export interface ISystemMessage {
	message: string;
	errorCode: number;
	messageType: SystemMessageType;
}

export enum SystemMessageType {
	performance = 0,
	information = 1,
}

@Injectable({
	providedIn: "root",
})
export class SystemMessagesService extends CoreBase {
	systemMessages$: Observable<ISystemMessage[]>;

	private systemMessagesSubject = new BehaviorSubject<ISystemMessage[]>([]);
	private messages: ISystemMessage[] = [];

	constructor(
		readonly languageService: LanguageService,
		readonly messageService: SohoMessageService,
	) {
		super("SystemMessagesService");
		this.systemMessages$ = this.systemMessagesSubject.asObservable();
	}

	addMessage(message: ISystemMessage) {
		const isUnique = !this.messages.find(
			(existing) => existing.errorCode === message.errorCode,
		);
		if (isUnique) {
			this.messages.push(message);
			this.notifyChange();
		}
	}

	clearMessages() {
		this.messages = [];
		this.notifyChange();
	}

	clearMessage(errorCode: ResponseErrorCodes) {
		this.messages = this.messages.filter(
			(message) => message.errorCode !== errorCode,
		);
		this.notifyChange();
	}

	getHeading(): string {
		const lang = this.languageService.getLanguage();
		const messageGeneral = lang.systemMessageGeneric;
		if (this.hasMessage(SystemMessageType.performance)) {
			return messageGeneral;
		} else {
			if (this.messages.length === 1) {
				return this.messages[0].message;
			}
		}
		return messageGeneral;
	}

	showSystemMessages() {
		const lang = this.languageService.getLanguage();
		let title = lang.degradedPerformance;
		const hasPerformanceMessages = this.hasMessage(
			SystemMessageType.performance,
		);
		if (!hasPerformanceMessages) {
			title = lang.systemMessages;
		}

		let message = hasPerformanceMessages
			? `${lang.systemMessageGeneric} <br><br>`
			: ``;
		for (const systemMessage of this.messages) {
			message += `${systemMessage.message} (${systemMessage.errorCode})<br><br>`;
		}
		if (hasPerformanceMessages) {
			message += lang.contactAdminRetry;
		}
		this.messageService
			.message()
			.title(title)
			.message(message)
			.buttons([
				{
					text: lang.ok,
					id: "lm-system-message-ok",
					isDefault: true,
					click: (e, dialog) => dialog.close(),
				},
			])
			.attributes({ name: "id", value: "lm-system-message" })
			.open();
	}
	private hasMessage(messageType: SystemMessageType): boolean {
		for (const message of this.messages) {
			if (message.messageType === messageType) {
				return true;
			}
		}
		return false;
	}

	private notifyChange() {
		this.systemMessagesSubject.next(this.messages);
	}
}
