import {
	Component,
	HostBinding,
	NgZone,
	OnDestroy,
	OnInit,
} from "@angular/core";
import { SohoMessageService } from "@infor/sohoxi-angular";
import { ArrayUtil } from "lime";
import {
	ContextTypeName,
	CoreBase,
	IContextSiteState,
	IContextWidgetItem,
} from "lime/core";
import { Subscription } from "rxjs";
import { ContextConfig, IWidget } from "../../base/core";
import { LanguageService } from "../../base/service";
import {
	ContextAppType,
	IContextualMessages,
	IContextWidget,
	IMingleMessage,
	IScreen,
	ScreenOperator,
} from "../../context-app/core";
import { WidgetParentContext } from "../../context-app/runtime";
import { ContextAppService } from "../../context-app/service";
import { WidgetService } from "../../widget/service";
import { WidgetContainerComponent } from "../widget-container/widget-container";

export class ContextWidgetState {
	widgetItem: IContextWidgetItem;
}

class Evaluator extends CoreBase {
	constructor(private readonly states: ContextWidgetState[]) {
		super("Evaluator");
	}

	/**
	 * Checks if at least one context app is currently visible.
	 */
	hasVisibleItems(messages?: IContextualMessages): boolean {
		for (const state of this.states) {
			if (this.isVisible(state, messages)) {
				return true;
			}
		}
		return false;
	}

	execute(isParentVisible: boolean, messages?: IContextualMessages): void {
		for (const state of this.states) {
			this.evaluate(isParentVisible, state, messages);
		}
	}

	notifyVisibility(widgetItem: IContextWidgetItem, isVisible: boolean): void {
		try {
			widgetItem.isInstanceHidden = !isVisible;

			const widgetInstance = widgetItem.widgetInstance;
			if (!widgetInstance) {
				// The widget has not been created yet, create if visible, do nothing if hidden
				if (isVisible) {
					this.createWidget(widgetItem);
				}
				return;
			}

			const container = widgetInstance.containerRef
				.instance as WidgetContainerComponent;
			if (isVisible) {
				container.show();
			} else {
				container.hide();
			}
		} catch (ex) {
			this.logError("notifyVisibility: Failed to notify", ex);
		}
	}

	private toggleVisibility(
		isParentVisible: boolean,
		widgetItem: IContextWidgetItem,
		isVisible: boolean,
	): void {
		try {
			// Change the logical visibility
			widgetItem.isHidden = !isVisible;

			if (widgetItem.isInstanceHidden === undefined) {
				// Initialize value first time we know if it is visible or not
				widgetItem.isInstanceHidden = !isVisible;
			}

			// Change and notify the actual visibility if necessary
			const isActuallyVisible = isParentVisible && isVisible;
			const isCurrentlyVisible = !widgetItem.isInstanceHidden;
			if (isActuallyVisible !== isCurrentlyVisible) {
				widgetItem.isInstanceHidden = !isActuallyVisible;
				this.notifyVisibility(widgetItem, isActuallyVisible);
			}
		} catch (ex) {
			this.logError("toggleVisibility: Failed to toggle", ex);
		}
	}

	private createWidget(widgetItem: IContextWidgetItem): void {
		if (widgetItem.contextHostComponent) {
			widgetItem.contextHostComponent.createWidget();
		}
	}

	private evaluate(
		isParentVisible: boolean,
		state: ContextWidgetState,
		messages?: IContextualMessages,
	): void {
		const item = state.widgetItem;
		const widget = item.widget;

		let isVisible = false;
		if (widget.type === ContextAppType.Utility) {
			isVisible = true;
		} else if (this.isVisibleForMessages(widget, messages)) {
			isVisible = true;
		}

		this.toggleVisibility(isParentVisible, item, isVisible);

		if (messages && isParentVisible && isVisible) {
			this.deliver(state, messages);
		}
	}

	private isVisible(
		state: ContextWidgetState,
		message?: IContextualMessages,
	): boolean {
		const widget = state.widgetItem.widget;

		if (widget.type === ContextAppType.Utility) {
			return true;
		}

		return this.isVisibleForMessages(widget, message);
	}

	private isVisibleForMessages(
		widget: IContextWidget,
		messages?: IContextualMessages,
	): boolean {
		const innerMessages = this.getInnerMessages(messages);
		if (!innerMessages) {
			return false;
		}

		for (const message of innerMessages) {
			if (
				this.hasMessage(widget, message.type) &&
				this.isMessageApplicable(widget, message)
			) {
				return true;
			}
		}

		return false;
	}

	private getInnerMessages(
		messages?: IContextualMessages,
	): IMingleMessage<any>[] {
		if (messages) {
			const messageWrapper = messages.data;
			if (messageWrapper) {
				return messageWrapper.data;
			}
		}
		return null;
	}

	private deliver(
		state: ContextWidgetState,
		messages: IContextualMessages,
	): void {
		const innerMessages = this.getInnerMessages(messages);
		if (!innerMessages) {
			return;
		}
		const listeners = this.getListeners(messages);

		for (const message of innerMessages) {
			this.deliverMessage(state, message, listeners);
		}
	}

	private deliverMessage(
		state: ContextWidgetState,
		message: IMingleMessage<any>,
		listeners: string[],
	): void {
		const widgetItem = state.widgetItem;
		if (this.isExternalWidget(widgetItem)) {
			if (this.containsListener(listeners, widgetItem)) {
				this.deliverToFrame(widgetItem.widgetInstance, message);
			}
		} else {
			const widgetInstance = widgetItem.widgetInstance;
			if (widgetInstance) {
				// Inline widget delivery
				this.deliverInline(widgetInstance, message);
				// Potential hybrid delivery
				this.deliverHybrid(widgetInstance, message, listeners);
			}
		}
	}

	private deliverInline(widgetInstance: IWidget, message: IMingleMessage<any>) {
		const context = widgetInstance.parentContext as WidgetParentContext;
		if (context) {
			context.deliverMessage(message.type, message);
		}
	}

	private deliverHybrid(
		widgetInstance: IWidget,
		message: IMingleMessage<any>,
		listeners: string[],
	) {
		try {
			const id = widgetInstance.id;
			// To detect hybrid check if iframeName is set from widget side
			if (
				widgetInstance.instance &&
				widgetInstance.instance.getIFrameName != null
			) {
				const frameName = widgetInstance.instance.getIFrameName();
				if (frameName) {
					const isIncluded = ArrayUtil.contains(listeners, frameName);
					let log =
						"deliverHybrid: Widget id " +
						id +
						" has hybrid iframe " +
						frameName;
					log =
						log + isIncluded
							? " that is included in listeners for delivery"
							: " that is skipped since it is not subcribing";
					this.logInfo(log);
					if (isIncluded) {
						// Find element from Name
						const frameElement = this.findIFrameElement(
							widgetInstance,
							frameName,
						);
						if (frameElement) {
							this.deliverToFrameElement(frameElement, message, id);
						}
					}
				}
			}
		} catch (err) {
			this.logWarning(
				"deliverHybrid: Failed to check if widget is hybrid and should receive messages." +
					err,
			);
		}
	}

	private findIFrameElement(
		widgetInstance: IWidget,
		frameName: string,
	): HTMLFrameElement {
		const id = widgetInstance.id;
		const widgetRoot = widgetInstance.element;
		const selector = "iframe[name='" + frameName + "']";
		if (widgetRoot) {
			const result = widgetRoot.find(selector);
			if (result && result[0]) {
				return result[0] as unknown as HTMLFrameElement;
			}
		} else {
			this.logWarning(
				"findIFrameElement: Fallback to search for iframe " +
					frameName +
					" in the entire document. ",
			);
			const links = $(document).find(selector);
			if (links && links[0]) {
				return links[0] as unknown as HTMLFrameElement;
			}
		}
		this.logInfo(
			"findIFrameElement: Unable to getElementById " +
				frameName +
				" for widget " +
				id,
		);
		return null;
	}

	private getListeners(messages: IContextualMessages): string[] {
		if (messages && messages.data && messages.data.iframeListeners) {
			const result = messages.data.iframeListeners;
			if (Array.isArray(result)) {
				return result;
			}
		}
		return null;
	}

	private containsListener(
		listeners: string[],
		widgetItem: IContextWidgetItem,
	): boolean {
		const widgetId = widgetItem.widgetInstance
			? widgetItem.widgetInstance.id
			: "unknown";
		const frame = this.getFrame(widgetItem);
		if (!frame) {
			this.logDebug(
				() =>
					"containsListener: Skip message delivery for external widget," +
					widgetId +
					" since iframe is not set.",
			);
			return false;
		}
		if (!listeners) {
			this.logDebug(
				"containsListener: Skip message delivery since there are no listeners",
			);
			return false;
		}
		const frameElement = frame[0] as unknown as HTMLFrameElement;
		if (!frameElement) {
			this.logDebug(
				"containsListener: Skip message delivery for external widget, " +
					widgetId +
					", iframe not found.",
			);
			return false;
		}

		const frameName = frameElement.getAttribute("name");
		const hasName = frameName && ArrayUtil.contains(listeners, frameName);
		if (hasName) {
			return true;
		}

		const frameId = frameElement.getAttribute("id");
		const result = frameId && ArrayUtil.contains(listeners, frameId);
		if (!result) {
			this.logDebug(
				"containsListener: Skip message delivery for external widget, " +
					widgetId +
					", iframe not in listeners.",
			);
			return false;
		}
		return true;
	}

	private isExternalWidget(widgetItem: IContextWidgetItem): boolean {
		const frame = this.getFrame(widgetItem);
		return frame !== null;
	}

	private getFrame(widgetItem: IContextWidgetItem): JQuery<HTMLElement> {
		if (widgetItem.widgetInstance) {
			const frame = widgetItem.widgetInstance.iframe;
			if (frame) {
				return frame;
			}
		}
		return null;
	}

	private deliverToFrame(
		widgetInstance: IWidget,
		message: IMingleMessage<any>,
	): void {
		const iframe = widgetInstance.iframe;
		if (iframe) {
			const frameElement = iframe[0] as unknown as HTMLFrameElement;
			this.deliverToFrameElement(frameElement, message, widgetInstance.id);
		} else {
			this.logWarning("Unable to find iframe for widget " + widgetInstance.id);
		}
	}

	private deliverToFrameElement(
		frameElement: any,
		message: IMingleMessage<any>,
		widgetId: string,
	): void {
		if (!(frameElement instanceof HTMLIFrameElement)) {
			this.logWarning("Unable to find iframe for widget " + widgetId);
			return;
		}

		const contentWindow = frameElement.contentWindow;
		if (contentWindow) {
			contentWindow.postMessage(JSON.stringify(message), "*");
		} else {
			this.logWarning("Unable to get contentWindow for widget " + widgetId);
		}
	}

	private isMessageApplicable(
		widget: IContextWidget,
		message: IMingleMessage<any>,
	): boolean {
		const type = message.type;
		return "inforBusinessContext" === type
			? this.isAnyScreen(widget, message)
			: true;
	}

	private isAnyScreen(
		widget: IContextWidget,
		message: IMingleMessage<any>,
	): boolean {
		const screens = widget.screens;
		if (!screens || screens.length === 0) {
			return true;
		}

		const data = message.data;
		if (!data || !data.screenId) {
			return true;
		}

		for (const screen of screens) {
			if (this.isScreen(screen, data.screenId)) {
				return true;
			}
		}

		return false;
	}

	private isScreen(screen: IScreen, screenId: string): boolean {
		const value = screen.value;
		if (!screenId || !value) {
			return false;
		}

		const operator = screen.operator;
		if (operator === ScreenOperator.Contains) {
			return screenId.indexOf(value) >= 0;
		} else if (operator === ScreenOperator.StartsWith) {
			return screenId.startsWith(value);
		} else if (operator === ScreenOperator.EndsWith) {
			return screenId.endsWith(value);
		} else {
			return screenId === value;
		}
	}

	private hasMessage(widget: IContextWidget, type: string): boolean {
		const messages = widget.messages;
		if (!messages || messages.length === 0) {
			return true;
		}
		return ArrayUtil.contains(widget.messages, type);
	}
}

/**
 * Application site component for context apps.
 *
 * Each application with context apps will have one site instance in the context zone.
 */
@Component({
	selector: "lm-context-site",
	templateUrl: "./context-site.html",
	styles: [
		`
			:host {
				display: block;
			}
		`,
	],
})
export class ContextSiteComponent
	extends CoreBase
	implements OnInit, OnDestroy
{
	@HostBinding("class.lm-display-none") isHidden = false;

	state: IContextSiteState;
	widgets: ContextWidgetState[];
	evaluator: Evaluator;

	private hasVisibleItems = false;
	private messageSubscription: Subscription;
	private clearMessagesSubscription: Subscription;
	private pendingMessages: IContextualMessages;

	constructor(
		private readonly zone: NgZone,
		messageService: SohoMessageService,
		languageService: LanguageService,
		private readonly contextAppService: ContextAppService,
		private readonly widgetService: WidgetService,
	) {
		super("ContextSiteComponent", messageService, languageService);

		this.clearMessagesSubscription = contextAppService.clearMessages$.subscribe(
			() => {
				this.onClearMessages();
			},
		);

		this.messageSubscription = contextAppService.message$.subscribe(
			(message) => {
				this.zone.run(() => {
					this.onMessages(message);
				});
			},
		);
	}

	ngOnInit(): void {
		this.logDebug("ngOnInit");
	}

	ngOnDestroy(): void {
		this.messageSubscription.unsubscribe();
	}

	showState(state: IContextSiteState): void {
		this.logDebug("showState");

		if (this.state) {
			// Already shown once
			return;
		}

		this.state = state;

		// Make sure that all widget definitions are loaded. This might result in a server request.
		this.contextAppService.loadWidgets(state.widgets).subscribe(
			() => {
				this.showCurrentState();
			},
			() => {
				// TODO Error handling
				this.logWarning("showState: Failed to load widgets.");
			},
		);
	}

	private showCurrentState(): void {
		this.logDebug("showCurrentState");

		const widgetStates = [];
		for (const widget of this.state.widgets) {
			const widgetState = new ContextWidgetState();
			widgetState.widgetItem = {
				widget: widget,
			};
			this.applyDefinitionConfig(widget);
			widgetStates.push(widgetState);
			this.registerMessages(widget);
		}

		this.widgets = widgetStates;

		this.state.visibility$.subscribe((isVisible: boolean) => {
			this.toggleSiteVisibility(isVisible);
		});

		this.evaluator = new Evaluator(widgetStates);
		this.evaluate();
	}

	private applyDefinitionConfig(widget: IContextWidget): void {
		const id = widget.handle.id;
		if (!id) {
			return;
		}
		const definition = this.widgetService.getCachedDefinition(id);
		if (definition && definition.contextConfig) {
			const messageExt = widget.messages;
			const typeExt = widget.type;

			const appConfig = definition.contextConfig;
			// By default the definition controls type and messages
			widget.messages = this.getMessages(appConfig);
			widget.type = this.getContextAppType(appConfig.type);

			let isOverrideMessage = false;
			let isOverrideType = false;
			// If the passed values are no empty they will override
			if (messageExt && messageExt.length > 0) {
				widget.messages = messageExt;
				isOverrideMessage = true;
			}
			if (typeExt) {
				widget.type = typeExt;
				isOverrideType = true;
			}
			this.logDebug(() =>
				"Using context widget data " + (isOverrideType || isOverrideMessage)
					? "with overrides from unput data"
					: "with definition data" + "for widget " + id,
			);
		} else {
			this.logDebug(() => "No definition found for widget " + id);
		}
	}

	private getContextAppType(typeName: ContextTypeName) {
		if (typeName === "context") {
			return ContextAppType.Context;
		}

		return ContextAppType.Utility;
	}

	private getMessages(appConfig: ContextConfig): string[] {
		if (appConfig && appConfig.messages) {
			const result = [];
			appConfig.messages.forEach((message) => {
				result.push(message.name);
			});
			return result;
		} else {
			return null;
		}
	}

	private onClearMessages(): void {
		this.pendingMessages = null;
	}

	private onMessages(message: IContextualMessages): void {
		this.evaluate(message);
	}

	private registerMessages(widget: IContextWidget): void {
		const messages = widget.messages;
		if (messages) {
			for (const message of messages) {
				this.contextAppService.registerAppMessage(message);
			}
		} else if (widget.type === ContextAppType.Context) {
			this.contextAppService.registerAppMessage("inforBusinessContext");
		}
	}

	private isSiteVisible(): boolean {
		const state = this.state;
		return state && state.isVisible;
	}

	private isSiteCurrent(): boolean {
		const state = this.state;
		return state && state.isCurrent;
	}

	private evaluate(message?: IContextualMessages): void {
		if (!this.isSiteCurrent()) {
			return;
		}

		if (message) {
			this.logDebug(() => "evaluate: Received contextualMessage");
		}

		if (!this.evaluator) {
			this.logError("evaluate: Evaluator instance not created");
			return;
		}

		this.hasVisibleItems = this.evaluator.hasVisibleItems(message);
		if (this.hasVisibleItems) {
			this.contextAppService.enableContextZone();
			this.toggleVisibility(this.isSiteVisible());
		} else {
			this.contextAppService.disableContextZone();
			this.toggleVisibility(false);
		}

		if (this.isSiteVisible()) {
			this.evaluator.execute(true, message);
		} else {
			// TODO Support pending message per type?
			this.pendingMessages = message;
		}
	}

	private toggleVisibility(isVisible: boolean): void {
		this.isHidden = !isVisible;
	}

	private toggleSiteVisibility(isVisible: boolean): void {
		this.isHidden = !isVisible;

		// TODO Question to Portal: Should we call enableContextZone() / disableContextZone()?
		// TODO Use this.evaluator.execute to prevent duplicate widget notifications (pending clarifications...)

		if (isVisible) {
			if (this.pendingMessages) {
				this.evaluator.execute(true, this.pendingMessages);
				this.pendingMessages = null;
			} else {
				this.notifyActive(true);
			}
		} else {
			this.notifyActive(false);
		}
	}

	private notifyActive(isVisible: boolean): void {
		for (const state of this.widgets) {
			if (!state.widgetItem.isHidden) {
				this.evaluator.notifyVisibility(state.widgetItem, isVisible);
			}
		}
	}

	// private hideAll(): void {
	// 	for (const state of this.widgets) {
	// 		this.evaluator.notifyVisibility(state.widgetItem, false);
	// 	}
	// }
}
