import { Component, Input, OnInit } from "@angular/core";
import { IWidgetContext } from "lime";
import { IDynamicContainer } from "../../base/core";

@Component({
	template: `
		<lm-markdown-renderer
			[content]="content"
			(linkClick)="launch($event)"></lm-markdown-renderer>

		<style>
			lm-markdown-renderer {
				padding: 10px;
			}
		</style>
	`,
})
export class DynamicTextComponent implements OnInit {
	@Input() widgetContext: IWidgetContext;

	content: string;

	ngOnInit() {
		const container = this.widgetContext
			.getSettings()
			.get<IDynamicContainer>("lm_container");
		this.content = container.txt.tx;
	}

	launch(url: string) {
		this.widgetContext.launch({
			url: url,
			resolve: true,
		});
	}
}
