import {
	ChangeDetectorRef,
	Component,
	ElementRef,
	Input,
	OnDestroy,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import { ArrayUtil, CommonUtil } from "lime";
import {
	ContextService,
	CoreBase,
	IPageInstance,
	IWidget,
	LazyTypeService,
	PageUtil,
	UIUtil,
	WidgetService,
} from "lime/core";
import { BannerContainerComponent } from "../widget-banner/widget-banner";
import { WidgetContainerComponent } from "../widget-container/widget-container";

@Component({
	selector: "lm-page",
	template: ` <div class="homepage-container">
		<lm-banner-container
			class="homepage"
			lm-swipe
			(leftSwipe)="selectNextBannerPage()"
			(rightSwipe)="selectPreviousBannerPage()"
			[hasHiddenWidget]="hasHiddenBannerWidget"
			[ngStyle]="getBannerStyle()"
			*ngIf="hasVisibleBanner()">
		</lm-banner-container>
		<div #pageView class="homepage" data-columns="4">
			<div [id]="page.elementId" class="content">
				<ng-container #contentView></ng-container>
			</div>
		</div>
	</div>`,
})
export class PageComponent extends CoreBase implements OnInit, OnDestroy {
	@ViewChild("pageView", { static: true })
	pageView: ElementRef;

	@ViewChild("contentView", { read: ViewContainerRef, static: true })
	contentView: ViewContainerRef;

	@ViewChild(BannerContainerComponent, { static: false })
	bannerComponent: BannerContainerComponent;

	@Input() page: IPageInstance;

	isBannerOn: boolean;
	hideBanner = true;
	showRestrictedWidgets: boolean;
	hasHiddenBannerWidget: boolean;
	isAnimationsEnabled: boolean;
	pageElement: JQuery;

	private unsubscribers: Array<Function> = [];

	constructor(
		public elementRef: ElementRef,
		private changeDetector: ChangeDetectorRef,
		contextService: ContextService,
		private readonly widgetService: WidgetService,
		private readonly lazyTypeService: LazyTypeService,
	) {
		super("PageComponent");

		const settings = contextService.getContext().settings;
		this.isBannerOn = settings.isFeatureHeroWidget();
		this.showRestrictedWidgets =
			settings.isDisplayRestrictedWidgetsOnPageEnabled();
		this.isAnimationsEnabled = settings.isAnimationEnabled();
	}

	ngOnInit(): void {
		this.pageElement = $(this.pageView.nativeElement);
		PageUtil.addHomepageControl(this.pageElement, this.isAnimationsEnabled);

		this.unsubscribers.push(
			this.page.widgetAdded().on((w) => {
				this.addWidget(w);
			}),
		);

		const page = this.page;
		if (page.isDynamic() && page.data.isLazy) {
			page.lazyContentLoaded.subscribe(() => {
				this.update();
			});
		} else {
			this.update();
		}
	}

	ngOnDestroy(): void {
		this.logDebug("ngOnDestroy");
		for (const f of this.unsubscribers) {
			f();
		}
		if (this.pageElement) {
			PageUtil.destroyHomepageControl(this.pageElement);
			this.pageElement = null;
		}
	}

	selectNextBannerPage() {
		this.bannerComponent.nextPage();
	}

	selectPreviousBannerPage() {
		this.bannerComponent.previousPage();
	}

	addWidget(widget: IWidget): void {
		if (!widget.elementId) {
			widget.elementId = CommonUtil.random();
		}

		if (!this.showRestrictedWidgets && widget.isBrokenByAccessDenied()) {
			this.logInfo(
				`Widget with ID: ${widget.data.id} has been hidden due to unauthorized access`,
			);
			if (widget.isBanner()) {
				this.hasHiddenBannerWidget = true;
			}
			return;
		}

		if (widget.destroyed) {
			const unregisterDestroyed = widget.destroyed().on(() => {
				unregisterDestroyed();
				this.remove(widget);
			});
		}

		const widgetPage = this.page;
		if (widget.added) {
			const unregisterAdded = widget.added().on((w) => {
				unregisterAdded();
				this.onWidgetAdded(w, widgetPage);
			});
		}

		if (widget.isBanner()) {
			this.hideBanner = false;
			if (this.isBannerOn) {
				setTimeout(() => {
					this.createWidgetComponent(widget, this.bannerComponent.contentView);
				}, 1);
			}
		} else {
			this.createWidgetComponent(widget);
		}
	}

	update(): void {
		const page = this.page;
		this.updateBannerVisibility();
		this.addWidgets(page.widgets);
		this.changeDetector.detectChanges();
	}

	updateBannerVisibility(): void {
		this.hideBanner = !this.hasBanner();
	}

	getBannerStyle(): string {
		return UIUtil.colorToBackgroundStyle(this.page.data.color, true);
	}

	hasVisibleBanner(): boolean {
		return this.isBannerOn && !this.hideBanner;
	}

	private createWidgetComponent(
		widget: IWidget,
		bannerView?: ViewContainerRef,
	): void {
		const ref = (bannerView || this.contentView).createComponent(
			WidgetContainerComponent,
		);
		const instance = ref.instance as WidgetContainerComponent;
		instance.page = this.page;
		instance.widget = widget;
		widget.containerRef = ref;
	}

	private hasBanner(): boolean {
		if (this.showRestrictedWidgets) {
			return (
				ArrayUtil.itemByPredicate(this.page.widgets, (w) => w.isBanner()) !=
				null
			);
		} else {
			return (
				ArrayUtil.itemByPredicate(
					this.page.widgets,
					(w) => w.isBanner() && !w.isBrokenByAccessDenied(),
				) != null
			);
		}
	}

	private remove(widget: IWidget) {
		// TODO Remove in Angular context???
		const element = widget.element;
		if (element) {
			try {
				element.remove();
			} catch (ex) {
				this.logError("Failed to remove widget " + widget.id, ex);
			}
		}
	}

	private onWidgetAdded(w: IWidget, page: IPageInstance) {
		page.widgetsAddedCount++;
		if (
			page.id === this.page.id &&
			this.page.widgetsAddedCount === this.page.noOfWidgets()
		) {
			// Delay needed to place larger widgets correctly
			const self = this;
			setTimeout(() => {
				const content = $(self.pageView.nativeElement);
				PageUtil.refreshHomepageLayout(content, self.isAnimationsEnabled);
				content.find(".chart-container").trigger("resize");
			}, 1);
		}

		if (w.isBanner()) {
			this.hideBanner = false;
		}
	}

	private addWidgets(widgets: IWidget[]): void {
		this.page.widgetsAddedCount = 0;
		for (const widget of widgets) {
			this.addWidget(widget);
		}
	}
}
