import { Component, NgZone, ViewChild, ViewContainerRef } from "@angular/core";
import {
	SohoContextualActionPanelService,
	SohoMessageService,
	SohoModalDialogService,
	SohoToastService,
} from "@infor/sohoxi-angular";
import {
	ArrayUtil,
	DialogButtonType,
	HtmlUtil,
	IDialogResult,
	Log,
} from "lime";
import {
	AboutService,
	AccessType,
	Constants,
	ContainerService,
	ContextService,
	CoreBase,
	CoreUtil,
	DataService,
	DevService,
	DialogResponseCode,
	EditModes,
	EditModeService,
	EditSubmodes,
	ExportOptionsComponent,
	IAddWidgetInfo,
	ICatalogAddItem,
	IContext,
	IEditMode,
	IOperationResponse,
	IPageContainer,
	IPageData,
	IPageDataResponse,
	IPageInstance,
	IPageResponse,
	IServerSettings,
	IWidgetInfo,
	LanguageService,
	LazyTypeService,
	PageService,
	PageUtil,
	ProgressService,
	UIUtil,
	WidgetService,
} from "lime/core";
import { of } from "rxjs";
import { filter, map, take } from "rxjs/operators";
import {
	ICatalogOptions,
	IImportErrorHandler,
	MemoItem,
	OperationResponse,
	ResponseErrorCodes,
} from "../../base/core";
import { DisplayNameService } from "../../services/display-name.service";
import { SystemMessagesService } from "../../services/system-messages.service";
import { CriticalMemosComponent } from "../memos/critical/critical";
import { MemoService } from "../memos/memos-widget/memo.service";

export interface IPageItem {
	id: string;
	elementId: string;
	title: string;
	escapedTitle: string;
}

/**
 * Page navigator component.
 */
@Component({
	selector: "lm-page-navigator",
	templateUrl: "./page-navigator.html",
	styleUrls: ["./page-navigator.scss"],
})
export class PageNavigatorComponent extends CoreBase {
	@ViewChild("view", { read: ViewContainerRef, static: true })
	view: ViewContainerRef;

	items: IPageItem[] = [];
	visibleItems: IPageItem[] = [];
	overflowItems: IPageItem[] = [];

	selectedPage: IPageInstance;
	selectedPageTitle: string;
	selectedDefaultPageTitle: string;
	selectedPageId: string;

	linkTitle: string;
	isLink: boolean;
	canEditLayout: boolean;
	canRepublish: boolean;
	canShowWidgetCatalog: boolean;
	canEditPage: boolean;
	canRemove: boolean;
	showFirstSeparatorMenu: boolean;
	canPublish: boolean;
	canExport: boolean;
	canImport: boolean;
	canCopy: boolean;
	canOpenInCatalog: boolean;
	hideOverflow: boolean;
	isSelectedPublished: boolean;
	hasPages: boolean;
	hasOnePage: boolean;
	hasMultiplePages: boolean;

	lang: ILanguageLime;
	pageContainer: IPageContainer;
	context: IContext;
	settings: IServerSettings;
	isPageDeletable: boolean;
	isPagePrivate: boolean;
	isPagePublished: boolean;
	isRepublishEnabled: boolean;
	isSettingsEnabled: boolean;
	isAdvancedEnabled: boolean;
	isPublicPageCopyEnabled;
	selectedPageIndex = 0;
	pageStyle: {};
	hasSystemMessages$ = this.systemMessagesService.systemMessages$.pipe(
		map((messages) => messages.length > 0),
	);
	canOpenAdministration$ = this.contextService.context$.pipe(
		map((context) => context.isAdministrationEnabled()),
	);
	hasCriticalMemos$ = this.memoService.criticalMemos$.pipe(
		map((memos) => !!memos.length),
	);

	private filenameExport = "Homepage";
	private extensionExport = ".json";
	private isMemosOpened = false;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		readonly containerService: ContainerService,
		readonly pageService: PageService,
		private readonly aboutService: AboutService,
		private readonly dataService: DataService,
		private readonly widgetService: WidgetService,
		private readonly contextService: ContextService,
		private readonly progressService: ProgressService,
		private readonly editModeService: EditModeService,
		private readonly modalService: SohoModalDialogService,
		private readonly lazyTypeService: LazyTypeService,
		private readonly toastService: SohoToastService,
		private readonly systemMessagesService: SystemMessagesService,
		private readonly memoService: MemoService,
		private readonly ngZone: NgZone,
		private readonly contextualActionPanelService: SohoContextualActionPanelService,
		private readonly displayNameService: DisplayNameService,
		devService: DevService,
	) {
		super("PageNavigatorComponent", messageService, languageService);

		this.lang = languageService.getLanguage();
		const isDev = devService.isDev; // TODO This probably has to be async...
		this.context = contextService.getContext();
		this.settings = this.context.settings;

		this.isSettingsEnabled = !isDev;
		this.isAdvancedEnabled = !isDev;
		this.lang = languageService.getLanguage();

		// Subscribe to events for the page container service and the edit mode service.
		if (contextService.isStandard) {
			containerService.container$.subscribe((container: IPageContainer) => {
				this.initialize(container);
			});

			containerService.selected$.subscribe((page: IPageInstance) => {
				this.onSelected(page);
			});
			containerService.changed$.subscribe(() => this.onChangedContainer());

			editModeService.stopped().on((editMode: IEditMode) => {
				if (
					(editMode.mode === EditModes.page ||
						editMode.mode === EditModes.widget) &&
					editMode.isSave === false
				) {
					this.refresh();
				}
			});
		}
	}

	ngAfterViewInit() {
		this.contextService.context$
			.pipe(take(1))
			.subscribe(() => this.showCriticalMemos());
	}

	openInCatalog() {
		const pageData = this.selectedPage.data;
		if (!pageData.ownerName || !pageData.changedByName) {
			this.displayNameService
				.getDisplayNames([pageData.ownerId, pageData.changedBy])
				.subscribe((users) => {
					pageData.ownerName = users[pageData.ownerId];
					pageData.changedByName = users[pageData.changedBy];
					this.pageService.showPageCatalog(this.selectedPage);
				});
			return;
		}
		this.pageService.showPageCatalog(this.selectedPage);
	}

	/**
	 * Shows the About Page dialog.
	 */
	showAbout(): void {
		this.aboutService.showAboutDialog(this.view);
	}

	pasteWidget(): void {
		const lang = this.lang;
		if (
			this.selectedPage.noOfWidgets() >=
			this.contextService.getContext().settings.getMaxWidgetsOnPageCount()
		) {
			this.showMessage(lang.unableToAddWidget, lang.maxWidgetsOnPageMessage);
			return;
		}

		this.setBusy(true);

		// Add to the current page context
		const context = this.selectedPage.getWidgetParentContext();
		const clipboardWidget = this.widgetService.getClipboardWidget();
		clipboardWidget.addInfo.isBanner = false;
		this.widgetService
			.addWidgetCopyToPage(context, clipboardWidget.addInfo)
			.subscribe(() => {
				this.setBusy(false);
			});
	}

	removePage() {
		const page = this.selectedPage;

		// Delete if private, remove if public
		if (PageUtil.isPrivate(page)) {
			this.pageContainer.delete(page.id, page.title, false).subscribe(
				(r: IOperationResponse) => {
					// For now the selected event from pageContainer handles selection
				},
				(r: IOperationResponse) => {
					this.dataService.handleError(r);
				},
			);
		} else {
			this.pageContainer.remove(page).subscribe(
				(r: IOperationResponse) => {
					// For now the selected event from pageContainer handles selection
				},
				(r: IOperationResponse) => {
					this.dataService.handleError(r);
				},
			);
		}
	}

	deletePage() {
		const page = this.selectedPage;
		if (page.isEditable) {
			const pageData = page.data;
			const self = this;
			this.pageContainer
				.delete(
					pageData.id,
					page.title,
					pageData.viewAccess !== AccessType.Owner,
				)
				.subscribe(
					(r: IOperationResponse) => {
						// For now the selected event from pageContainer handles delete
					},
					(r: IOperationResponse) => {
						self.dataService.handleError(r);
					},
				);
		}
	}

	showWidgetCatalog() {
		const options = {
			addCallback: (p: ICatalogAddItem) => {
				const addWidgetInfo = {
					isBanner: false,
					widgetInfo: p.item as IWidgetInfo,
					byRef: p.byRef,
					isDuplicate: p.isDuplicate,
				} as IAddWidgetInfo;
				this.pageContainer.addWidget(addWidgetInfo, p.busyCallback);
			},
		} as ICatalogOptions;

		this.setBusy(true);
		this.lazyTypeService
			.injectLazyService("CatalogStartService")
			.then((service) => {
				service.openWidgetCatalog(options, this.view);
			})
			.catch((e) => {
				this.logError("Failed to open catalog", e);
			});
	}

	showMyPages() {
		this.containerService.openMyPages(this.view, this.ngZone);
	}

	showPageSettings() {
		this.pageContainer.showPageInformation(
			this.containerService.selectedPage.id,
		);
	}

	showRepublishPage() {
		const page = this.containerService.selectedPage;
		this.setBusy(true);
		this.pageService.getPublishedExtended(page.data.id).subscribe(
			(r: IPageResponse) => {
				this.setBusy(false);
				if (r.hasError()) {
					this.logResponse(r);
				} else {
					page.localization = r.content.localization;
					page.access = r.content.access;
					this.showPublishPage();
				}
			},
			(r: IOperationResponse) => {
				this.onError(r);
			},
		);
	}

	importPage(): void {
		const self = this;
		const callback: IImportErrorHandler = (r: OperationResponse): void => {
			const errorCode = r.errorHttpCode ? parseInt(r.errorHttpCode) : -1;
			if (errorCode === ResponseErrorCodes.badRequest) {
				self.showMessage(
					self.lang.get("unableImportPage"),
					self.lang.get("unableImportPageMessage"),
				);
			} else {
				self.pageService.handleError(r);
			}
		};

		this.pageContainer.openImportPageDialog(callback).subscribe(
			(r: IDialogResult) => {
				// Upload failure is actually handled by the dialog
				if (
					r &&
					r.value &&
					r.button === DialogButtonType.Yes &&
					r.value.responseCode === DialogResponseCode.Success
				) {
					const response: IPageDataResponse = r.value.message;
					if (r.value.isPublish) {
						const lang = this.lang;
						this.toastService.show(
							CoreUtil.getToastOptions(
								lang.pagePublished,
								lang.format(lang.pagePublishedMessage, response.content.title),
							),
						);
					}
					self.refresh(response.content.id);
				}
			},
			(r: IOperationResponse) => {
				this.pageService.handleError(r);
			},
		);
	}

	showEditPageLayout() {
		this.editModeService.start({
			mode: EditModes.layout,
			title: this.lang.editingPageLayout,
		});
	}

	onClickSelect(item: IPageItem) {
		this.containerService.select(item.id);
	}

	copyPage() {
		this.pageContainer.copyPage(this.selectedPage, false, false);
	}

	refresh(pageId?: string): void {
		this.systemMessagesService.clearMessages();
		this.pageContainer.refresh({ pageId: pageId });
	}

	openLink() {
		const url = this.selectedPage.link.url;
		if (url) {
			this.context.launch({ url: url, resolve: true });
		}
	}

	showAdmin(): void {
		this.containerService.showAdmin();
	}

	// TODO This function should be converted to a property, but this requires an event for widgets on the clipboard
	canPaste(): boolean {
		return (
			this.hasPages &&
			this.isPagePrivate &&
			this.widgetService.hasPastableClipboardWidget()
		);
	}

	// TODO This function should be converted to a property, but this requires an event for the visibility of "My pages"
	hideNavigator(): boolean {
		return !this.hasMultiplePages || this.containerService.isMyPagesOpen();
	}

	canAdmin(): boolean {
		return this.containerService.isAdminOpen();
	}

	trackByPageId(index: number, item: IPageItem): string {
		return item.id;
	}

	showSystemMessages() {
		this.systemMessagesService.showSystemMessages();
	}

	showCriticalMemos(showAll?: boolean) {
		if (this.isMemosOpened) {
			return;
		}
		this.memoService.criticalMemos$
			.pipe(
				filter((memos) => !!memos.length),
				map((memos) => {
					const unseenMemos = this.memoService.getUnseenMemos(memos);
					return {
						memos: [
							...unseenMemos,
							...memos.filter((memo) => !unseenMemos.includes(memo)),
						],
						unseenCount: unseenMemos.length,
					};
				}),
				take(1),
			)
			.subscribe((info) => {
				if (info.unseenCount || showAll) {
					this.isMemosOpened = true;
					const dialog = this.contextualActionPanelService
						.contextualactionpanel(CriticalMemosComponent, this.view)
						.modalSettings({
							trigger: "immediate",
							id: "lm-criticalmemos-cap",
						})
						.initializeContent(false)
						.afterClose(() => (this.isMemosOpened = false));

					dialog
						.apply((comp: CriticalMemosComponent) => {
							comp.dialog = dialog;
							comp.memos = info.memos.map((memo) => new MemoItem(memo));
							comp.unseenCount = info.unseenCount;
						})
						.open();
				}
			});
	}

	exportPage() {
		if (!this.settings.isPageExportEnabled()) {
			this.logDebug(
				"[ExportPage] Click on disabled context menu, should have been prevented by infor control",
			);
			return;
		}

		const widgets = this.selectedPage.widgets;

		// If the page has published widgets, let the user choose how to proceed.
		const definitions = widgets.map((widget) => widget.definition);
		const hasPublished = ArrayUtil.containsByProperty(
			definitions,
			"isPublished",
			true,
		);
		const hasPublishConfiguration = !!widgets.find(
			(widget) => !!widget.data.custom,
		);

		if (hasPublished || hasPublishConfiguration) {
			const dialog = this.modalService
				.modal(ExportOptionsComponent, this.view)
				.id("lm-page-export-dialog")
				.title(this.lang.exportOptions)
				.afterClose((r: IDialogResult) => {
					if (r && r.button === DialogButtonType.Ok) {
						this.exportPageByType(r.value as string);
					}
				});

			dialog
				.apply((component) => {
					component.dialog = dialog;
					component.hasPublished = hasPublished;
					component.hasPublishConfiguration = hasPublishConfiguration;
				})
				.open();
		} else {
			this.exportPageByType(Constants.pageExportKeep);
		}
	}

	showPublishPage() {
		const lang = this.lang;
		let title: string;
		let commandText: string;
		if (this.isPagePrivate) {
			title = lang.publishPage;
			commandText = lang.publish;
		} else {
			title = lang.republishPage;
			commandText = lang.republish;
		}

		this.selectedPage.notifyPublishingMode();

		let cancelClass = "e2e-pubPageCancel";
		let publishClass = "e2e-pubPagePublish";
		let editLayoutClass = "e2e-pubPageEditLayout";
		let editPubConf = "e2e-pubPageEditPubConfig";
		if (!this.isPagePrivate) {
			cancelClass = "e2e-rePubPageCancel";
			publishClass = "e2e-rePubPagePublish";
			editLayoutClass = "e2e-rePubPageEditLayout";
			editPubConf = "e2e-rePubPageEditPubConfig";
		}

		const self = this;
		const page = this.selectedPage;
		const colorNumber = page.data.color || Constants.defaultColorNumber;
		const headerColor = UIUtil.numberToHexCode(colorNumber);

		this.editModeService.start({
			mode: EditModes.page,
			title: title,
			entityTitle: page.title,
			headerColor: headerColor,
			submode: this.isPagePrivate
				? EditSubmodes.publish
				: EditSubmodes.republish,
			actions: [
				{
					text: this.lang.cancel,
					icon: "close-cancel",
					cssClass: cancelClass,
					execute: () => {
						self.pageContainer.onCancelPublish();
					},
					id: "pp-cancel",
				},
				{
					text: commandText,
					cssClass: publishClass,
					icon: "send",
					execute: () => {
						self.pageContainer.publish(
							self.containerService.selectedPage,
							self.containerService.selectedPage.isPublished(),
						);
					},
					id: "pp-publish",
				},
			],
			secondaryActions: [
				{
					text: this.lang.editLayout,
					cssClass: editLayoutClass,
					icon: "settings",
					execute: () => {
						self.showEditPageLayout();
					},
					id: "pp-e-layout",
				},
				{
					text: this.lang.editPublishConfiguration,
					cssClass: editPubConf,
					icon: "edit",
					execute: () => {
						self.pageContainer.editPageConfiguration(!self.isPagePrivate);
					},
					id: "pp-e-publish",
				},
			],
		});

		if (this.isPagePrivate) {
			this.pageContainer.editPageConfiguration(false);
		}
	}

	private initialize(pageContainer: IPageContainer) {
		this.pageContainer = pageContainer;
		const context = pageContainer.context;
		this.context = context;
		const settings = context.settings;

		// Check for settings to make sure no error occurs if server is unavailable (Lime-659)
		if (settings) {
			this.settings = settings;
			this.isPublicPageCopyEnabled = settings.isPublicPageCopyEnabled();
		}

		this.updateState();
	}

	private setBusy(isBusy: boolean): void {
		this.progressService.setBusy(isBusy);
	}

	private getPages(): IPageInstance[] {
		const container = this.pageContainer;
		return container && container.pages ? container.pages : [];
	}

	private _getItems(): IPageItem[] {
		const container = this.pageContainer;
		return container && container.pages ? this.toItems(container.pages) : [];
	}

	private _getVisibleItems(): IPageItem[] {
		const pages = this.getPages();
		if (pages.length <= 7) {
			return this.toItems(pages);
		}

		// Overflow -> show six buttons + overflow button
		return this.toItems(pages.slice(0, 6));
	}

	private _getOverflowItems(): IPageItem[] {
		const pages = this.getPages();
		if (pages.length > 7) {
			return this.toItems(pages.slice(6));
		}
		return [];
	}

	private toItems(pages: IPageInstance[]): IPageItem[] {
		const items = [];
		for (const page of pages) {
			items.push({
				id: page.id,
				elementId: page.elementId,
				title: page.title,
				escapedTitle: HtmlUtil.escapeStringForHtml(page.title),
			});
		}
		return items;
	}

	private onChangedContainer() {
		this.logDebug("Container changed");
		this.updateColor();
		this.updateTitle();
		this.updateState();
	}

	/**
	 * Starts a page export by which type of export is specified.
	 * @param exportType
	 */
	private exportPageByType(exportType: string) {
		const page = this.selectedPage;
		let name = page.data.title;
		let createSavePageData$ = page.createSavePageDataFlatten(exportType);

		if (exportType === Constants.pageExportKeep) {
			if (this.isWebKit()) {
				createSavePageData$ = of(page.createSavePageDataExport(false));
			} else {
				const id = page.id;
				const query = "?rid=" + new Date().getTime(); // Add this to prevent browser caching
				while (name && name.charAt(0) === ".") {
					name = name.substring(1);
				}
				if (!name) {
					name = this.filenameExport;
				}
				name = encodeURIComponent(name);
				const url =
					this.dataService.getUrl(
						"page/export/" + id + "/" + name + this.extensionExport,
					) + query;

				window.open(url, "_blank");
				this.logDebug("[exportPage] " + url);
				return;
			}
		}

		this.setBusy(true);
		createSavePageData$.subscribe(
			(pageData) => {
				this.pageService.exportPage(pageData).subscribe(
					(response: IPageData) => {
						this.createAndDownloadFile(
							JSON.stringify(response),
							name + this.extensionExport,
						);
						this.setBusy(false);
					},
					(response: IOperationResponse) => {
						this.pageService.handleError(response);
						this.progressService.setBusy(false);
					},
				);
			},
			(errorResponse: IOperationResponse) => {
				this.onError(errorResponse);
			},
		);
	}

	/**
	 * Creates a file on the client and starts download.
	 * In safari the file will be opened in a new tab.
	 * @param data
	 * @param fileName
	 * @param fileType  A string indicating the MIME type of the data contained in the Blob.
	 */
	private createAndDownloadFile(
		data: string,
		fileName: string,
		fileType = "application/json",
	): void {
		const blob = new Blob([data], { type: fileType });
		const userAgent = navigator.userAgent;

		if ((window.navigator as any).msSaveOrOpenBlob) {
			(window.navigator as any).msSaveBlob(blob, fileName);
		} else {
			// Create <a> element with page linked as file.
			const elem = window.document.createElement("a") as any;

			if (this.isWebKit()) {
				this.modalService
					.message(
						'<div class="lm-export-page-message-modal lm-scroll-no-y">' +
							"<p>" +
							this.lang.pageDownloadMsg +
							"<br />" +
							'<a href="' +
							window.URL.createObjectURL(blob) +
							'" target="_blank" download="' +
							fileName +
							'">' +
							HtmlUtil.escapeStringForHtml(fileName) +
							"</a>" +
							"</p>" +
							"</div>",
					)
					.buttons([
						{
							text: this.lang.close,
							id: "lm-export-page-dialog-close",
							click: (event, modal) => modal.close(),
						},
					])
					.title(this.lang.export)
					.id("lm-export-page-dialog")
					.open();
			} else {
				elem.href = window.URL.createObjectURL(blob);
				elem.target = "_blank";
				elem.download = fileName;
				document.body.appendChild(elem);
				elem.click();
				document.body.removeChild(elem);
			}
		}

		Log.debug("Prepared page download for User Agent: " + userAgent);
	}

	private isWebKit(): boolean {
		return (
			navigator.userAgent.indexOf("AppleWebKit") > -1 &&
			navigator.userAgent.indexOf("Chrome") === -1
		);
	}

	private onSelected(page: IPageInstance) {
		if (page) {
			this.selectedPage = page;
			this.selectedPageId = page.id;
			this.selectedPageTitle = page.title;
			this.selectedDefaultPageTitle = this.getDefaultTitle(page);
			this.isPagePrivate = PageUtil.isPrivate(page);
			this.isPagePublished = page.isPublished();
			this.isPageDeletable = page.isEditable && !this.isPagePrivate;
			this.isRepublishEnabled = page.isRepublishEnabled();

			const link = page.link;
			if (link && link.enabled) {
				this.isLink = true;
				this.linkTitle = link.title;
			} else {
				this.isLink = false;
				this.linkTitle = null;
			}
		} else {
			this.selectedPage = null;
			this.selectedPageId = null;
			this.selectedPageTitle = null;
			this.selectedDefaultPageTitle = null;
			this.isPagePrivate = false;
			this.isPagePublished = false;
			this.isPageDeletable = false;
			this.isRepublishEnabled = false;
			this.isLink = false;
			this.linkTitle = null;
		}

		this.updateColor();

		if (this.pageContainer) {
			if (page) {
				this.selectedPageIndex = this.pageContainer.pages.indexOf(page);
			} else {
				this.selectedPageIndex = null;
			}
		}

		this.updateState();
	}

	private getDefaultTitle(page: IPageInstance): string {
		if (page) {
			if (page.data) {
				if (page.data.title) {
					return page.data.title;
				}
			}
		}
		return null;
	}

	private updateColor() {
		const page = this.selectedPage;
		const color = page ? page.data.color : Constants.defaultColorNumber;
		this.pageStyle = UIUtil.colorToBackgroundStyle(color);
	}

	private updateTitle() {
		let title: string = null;
		let defaultTitle = null;
		const page = this.selectedPage;
		if (page) {
			if (!page.title) {
				page.title = page.data.title;
			}
			title = page.title;
			if (page.data.title) {
				defaultTitle = page.data.title;
			}
		}
		this.selectedPageTitle = title;
	}

	/**
	 * Clears the busy state and lets the Data Service handle the error.
	 */
	private onError(response: IOperationResponse, message?: string): void {
		this.setBusy(false);
		this.dataService.handleError(response, message);
	}

	/**
	 * Updates the visual state of the component.
	 * This function should be called each time the pages or selected page changes etc.
	 */
	private updateState(): void {
		this.items = this._getItems();
		this.visibleItems = this._getVisibleItems();
		this.overflowItems = this._getOverflowItems();

		this.canEditLayout = this._canEditLayout();
		this.canRepublish = this._canRepublish();
		this.canEditPage = this._canEditPage();
		this.canRemove = this._canRemove();
		this.showFirstSeparatorMenu = this._showFirstSeparatorMenu();
		this.canPublish = this._canPublish();
		this.canExport = this._canExport();
		this.canImport = this._canImport();
		this.canCopy = this._canCopy();
		this.canOpenInCatalog = this._canOpenInCatalog();
		this.isSelectedPublished = this._isSelectedPublished();
		this.hasPages = this._hasPages();
		this.hasOnePage = this._hasOnePage();
		this.hasMultiplePages = this._hasMultiplePages();
		this.hideOverflow = this._hideOverflow();
		this.canShowWidgetCatalog = this._canShowWidgetCatalog();
	}

	private _canEditLayout(): boolean {
		const selected = this.getSelected();
		return selected && selected.isEditable && !selected.isPublished();
	}

	private _canRepublish(): boolean {
		return this._hasPages() && this.isRepublishEnabled;
	}

	private _canShowWidgetCatalog(): boolean {
		return (
			this.hasPages &&
			!this.isPagePublished &&
			this.settings.isPrivatePagesEnabled()
		);
	}

	private _canEditPage(): boolean {
		const selected = this.getSelected();
		return selected && selected.isEditable && !selected.isPublished();
	}

	private _canRemove(): boolean {
		const selected = this.getSelected();
		return selected && !selected.isMandatory;
	}

	private _showFirstSeparatorMenu(): boolean {
		const selected = this.getSelected();
		return (
			selected &&
			selected.isEditable &&
			(!selected.isMandatory || this.isRepublishEnabled)
		);
	}

	private _canPublish(): boolean {
		const selected = this.getSelected();
		return (
			selected &&
			selected.isViewable &&
			selected.isPublishEnabled() &&
			this.isPagePrivate
		);
	}

	private _canExport(): boolean {
		const selected = this.getSelected();
		const settings = this.settings;
		return (
			selected &&
			selected.isViewable &&
			settings &&
			settings.isPageExportEnabled() &&
			!selected.isDynamic()
		);
	}

	private _canImport(): boolean {
		const settings = this.settings;
		return settings && settings.isPageImportEnabled();
	}

	private _canCopy(): boolean {
		const selected = this.getSelected();
		const settings = this.settings;
		return (
			selected &&
			selected.isViewable &&
			settings &&
			settings.isPrivatePagesEnabled() &&
			!selected.isDynamic() &&
			(this.isPagePrivate || this.isPublicPageCopyEnabled)
		);
	}

	private _canOpenInCatalog(): boolean {
		const selected = this.getSelected();
		return (
			selected &&
			selected.isViewable &&
			!this.isPagePrivate &&
			this.settings.isPageCatalogEnabled()
		);
	}

	private _hideOverflow() {
		return this.items.length <= 7;
	}

	private _isSelectedPublished(): boolean {
		const page = this.containerService.selectedPage;
		if (page != null && page.isPublished()) {
			return true;
		}
		return false;
	}

	// TODO Verify if the hasPages check is really required for selected page

	private hasSelected(): boolean {
		return this.selectedPage && this._hasPages();
	}

	private getSelected(): IPageInstance {
		return this._hasPages() ? this.selectedPage : null;
	}

	private _hasPages(): boolean {
		const container = this.pageContainer;
		if (container && container.pages) {
			return container.pages.length > 0;
		}
		return false;
	}

	private _hasOnePage(): boolean {
		if (!this._hasPages()) {
			return false;
		}
		return this.pageContainer.pages.length === 1;
	}

	private _hasMultiplePages(): boolean {
		if (!this._hasPages()) {
			return false;
		}
		return this.pageContainer.pages.length > 1;
	}
}
