import { ChangeDetectionStrategy, Component, ViewChild } from "@angular/core";
import { SohoContextualActionPanelRef } from "@infor/sohoxi-angular";
import { LanguageService, MemoItem } from "lime/core";
import { MemoService } from "../memos-widget/memo.service";
import { MemosComponent } from "../memos-widget/memos";

@Component({
	templateUrl: "./critical.html",
	styles: [
		`
			::ng-deep #lm-criticalmemos-cap {
				width: 1120px;
			}

			lm-memos {
				height: 450px;
			}

			soho-toolbar soho-toolbar-button-set div.separator {
				margin-left: 10px;
				margin-right: 10px;
			}

			:host-context(html[dir="rtl"])
				soho-toolbar-flex
				button[icon$="arrow"]
				::ng-deep
				svg {
				transform: rotateY(180deg);
			}
		`,
	],
	changeDetection: ChangeDetectionStrategy.OnPush,
})
export class CriticalMemosComponent {
	@ViewChild(MemosComponent, { static: true }) memosComponent: MemosComponent;
	dialog: SohoContextualActionPanelRef<CriticalMemosComponent>;
	memos: MemoItem[];
	unseenCount: number;
	lang: ILanguageLime;

	private index = 0;
	private viewedIndeces = new Set([0]);
	private allViewedMemos = this.memoService.getViewedMemosStorage();

	get isWide(): boolean {
		return Soho.breakpoints.isAbove("slim");
	}

	constructor(
		languageService: LanguageService,
		private readonly memoService: MemoService,
	) {
		this.lang = languageService.getLanguage();
	}

	ngOnInit() {
		this.setMemoViewed();
		this.dialog.closed(() =>
			this.memoService.setViewedMemosStorage(this.allViewedMemos),
		);
	}

	get remainingUnseen(): number {
		return Math.max(0, this.unseenCount - this.viewedIndeces.size);
	}

	get previousDisabled(): boolean {
		return this.index === 0;
	}

	get nextDisabled(): boolean {
		return this.index === this.memos.length - 1;
	}

	get nextLabel(): string {
		const remainingUnseen = this.remainingUnseen;
		return `${this.lang.next} ${
			remainingUnseen ? "(" + remainingUnseen + ")" : ""
		}`;
	}

	previous() {
		this.index--;
		this.memosComponent.selectPreviousMemo();
	}

	next() {
		this.index++;
		this.memosComponent.selectNextMemo();
		this.setMemoViewed();
	}

	close() {
		this.dialog.close();
	}

	private setMemoViewed() {
		const memo = this.memos[this.index];
		const viewedMemo = this.allViewedMemos.find(
			(viewed) => viewed.mid === memo.memoId,
		);
		if (viewedMemo) {
			viewedMemo.cd = memo.changeDate;
		} else {
			this.allViewedMemos.push({ mid: memo.memoId, cd: memo.changeDate });
		}
		this.viewedIndeces.add(this.index);
	}
}
