/**
 * Capitalizes a string.
 */
@Pipe({ name: "lmCapitalize" })
export class CapitalizePipe implements PipeTransform {
	transform(value: string): string {
		return value.charAt(0).toUpperCase() + value.substr(1);
	}
}

/**
 * Converts date strings to the current locale.
 */
@Pipe({ name: "lmLocaleDate" })
export class LocaleDatePipe implements PipeTransform {
	transform(value: string): string {
		return value ? CommonUtil.getLocaleDateString(value) : "";
	}
}

/**
 * Truncates a string if exceeding the max length property
 */
@Pipe({ name: "lmEllipsis" })
export class EllipsisPipe implements PipeTransform {
	transform(value: string, maxLength: number): string {
		return value && value.length > maxLength
			? value.substr(0, maxLength - 3) + "..."
			: value;
	}
}

/**
 * Returns the word count of a comma-separated string
 */
@Pipe({ name: "lmStringToCount" })
export class ConcatStringToCountPipe implements PipeTransform {
	transform(input: string): number {
		if (!input) {
			return 0;
		}
		return input.split(",").length;
	}
}

/**
 * Inserts space between camel cased letters in a string and returns it
 */
@Pipe({ name: "lmCamelCaseSpace" })
export class CamelCaseSpacePipe implements PipeTransform {
	transform(input: string): string {
		return UIUtil.splitCamelCase(input);
	}
}

/**
 *	Transform a number value to hex color code.
 */
@Pipe({ name: "lmColorNumberToHex" })
export class ColorNumberToHexPipe implements PipeTransform {
	transform(value: any): string {
		value = parseInt(value);
		return UIUtil.numberToHexCode(value);
	}
}

/**
 *	Transform a number value to hex color code from extended color set.
 */
@Pipe({ name: "lmColorNumberToHexExtended" })
export class ColorNumberToHexExtendedPipe implements PipeTransform {
	transform(value: any): string {
		if (!value) {
			value = 0;
		}
		value = parseInt(value);
		return UIUtil.numberToHexCodeExtended(value);
	}
}

/**
 * Filters settings by Area
 */
@Pipe({ name: "lmSettingsArea" })
export class SettingsAreaPipe implements PipeTransform {
	transform(items: ISettingItem[], input: number): ISettingItem[] {
		if (input || input === 0) {
			return items.filter((item: ISettingItem) => {
				return item.setting.area === input;
			});
		} else {
			return items;
		}
	}
}

/**
 * Filters settings by visibility
 */
@Pipe({ name: "lmSettingsVisibility" })
export class SettingsVisibilityPipe implements PipeTransform {
	transform(items: ISettingItem[]): ISettingItem[] {
		return items
			? items.filter((item: ISettingItem) => {
					return item.setting.isVisible;
			  })
			: [];
	}
}

/**
 * Converts widget source number to name
 */
@Pipe({ name: "lmWidgetSource" })
export class WidgetSourcePipe implements PipeTransform {
	static map = {
		0: "Unknown",
		1: "Registry",
		2: "Installer",
		10: "Partner",
		11: "Customer",
	};

	transform(value: string) {
		return WidgetSourcePipe.map[value];
	}
}

/**
 * Sort string array alphabetically
 */
@Pipe({ name: "lmSortByProperty" })
export class SortByPropertyPipe implements PipeTransform {
	transform(array: Object[], propertyName: string, options?: ISortOptions) {
		return ArrayUtil.sortByProperty(array, propertyName, options);
	}
}

