/**
 * Tags Component
 *
 * Used to show widget/page tags in view. Splits tag string into tags array and generates tag elements.
 * Updates searchInput to search on a tag when clicked
 * tagClass attribute can be used to add classes directly to the tags
 * hideSymbol attribute is used to hide the symbol #
 */
@Component({
	selector: "lm-tags",
	template: `
		<span [attr.id]="tagContainerId">
			<a
				*ngFor="let tag of tagArray"
				[name]="tag | lmAutoId : 'lm-tags-item'"
				[ngClass]="tagClass"
				[attr.disabled]="disabled"
				[attr.aria-disabled]="disabled"
				(click)="onTagClick(tag)"
				[attr.lm-tags-tag]="tag">
				{{ hideSymbol ? tag : "#" + tag }}
			</a>
		</span>
	`,
})
// TODO Use mask, currently conflict with autocomplete: soho - mask[options]="{pattern: '********************************'}"
export class TagsComponent implements OnInit, OnChanges {
	@Input("tagString") tags: string;
	@Input("clickDisabled") disabled: boolean;
	@Input() hideSymbol: boolean;
	@Input() tagClass: string;
	@Input() id: string;

	@Output() onTagClickUpdate = new EventEmitter<string>();
	@Output() onTagsRendered = new EventEmitter<boolean>();

	tagArray: string[];
	tagContainerId;

	constructor() {}

	ngOnInit() {
		this.updateTags();
		this.emitTagsRenderedEvent();
		this.tagContainerId = "lm-tags-" + this.id;
	}

	ngOnChanges(changes: SimpleChanges): void {
		const tags = changes.tags;
		if (
			tags &&
			tags.previousValue &&
			tags.currentValue &&
			tags.previousValue !== tags.currentValue
		) {
			this.updateTags();
		}
	}

	onTagClick(tagName: string): void {
		this.onTagClickUpdate.emit(this.hideSymbol ? tagName : `#${tagName}`);
	}

	private updateTags(): void {
		if (this.tags) {
			this.tagArray = this.tags.split("#");
			this.tagArray.shift();
		} else {
			this.tagArray = [];
		}
	}

	/**
	 * Emits and event when the tags have been rendered in the DOM.
	 */
	private emitTagsRenderedEvent(): void {
		if (this.tagArray.length > 0) {
			const self = this;
			const checkExist = setInterval(() => {
				const currentElement = $("#" + this.tagContainerId);
				if (currentElement.length > 0) {
					const length = currentElement.children(".tag").length;
					if (length) {
						self.onTagsRendered.emit(true);
						clearInterval(checkExist);
					}
				}
			}, 100);
		} else {
			this.onTagsRendered.emit(true);
		}
	}
}

/**
 * Tags customization component.
 *
 * Used in Page and Widget Edit Publish Configuration dialog to add / remove tags for the item.
 */
@Component({
	selector: "lm-tags-customize-component",
	template: ` <div class="lm-margin-xl-b">
		<div class="field lm-margin-zero-b" name="tagsField">
			<label for="lm-customize-tags">{{ lang.tags }}</label>
			<div class="searchfield-wrapper lm-margin-zero-b" id="lm-customize-tags">
				<input
					soho-autocomplete
					[attr.placeholder]="tagHolder"
					[maxlength]="maxLength"
					[disabled]="tags?.length >= maxNr"
					[(ngModel)]="tagModel"
					[source]="source"
					(selected)="onSelected($event)"
					(keydown)="onKey($event)"
					(keyup.enter)="onAdd(tagModel)"
					[template]="template"
					id="lm-customize-tags-input"
					[attributes]="{ name: 'name', value: 'lm-tags-search' }"
					soho-mask
					sohoPattern="********************************" />
			</div>
			<button
				type="button"
				id="lm-customize-tags-add"
				class="btn-icon lm-margin-zero-r"
				[disabled]="!tagModel || tagModel.length < 2 || tags?.length >= maxNr"
				(click)="onAdd(tagModel)"
				soho-tooltip
				[title]="lang.add"
				lm-enter-to-click>
				<span class="audible">{{ lang.add }}</span>
				<svg class="icon" focusable="false">
					<use xlink:href="#icon-add"></use>
				</svg>
			</button>
		</div>
		<span
			*ngIf="errorMsg"
			class="textarea-wordcount error-message lm-margin-zero-t"
			>{{ errorMsg }}</span
		>
		<span
			*ngIf="tags?.length >= maxNr"
			class="textarea-wordcount error-message lm-margin-zero-t"
			>{{ lang.format(lang.maxCountTag, maxNr) }}</span
		>
		<div *ngIf="tags?.length > 0" class="lm-margin-sm-t">
			<a
				*ngFor="let tag of tags"
				class="tag is-dismissible lm-tag-customized lm-margin-sm-r lm-margin-sm-t"
				(click)="onRemove(tag)"
				lm-enter-to-click>
				{{ tag }}
				<span
					class="btn-dismissible"
					[attr.name]="tag | lmAutoId : 'lm-tags-item-dismiss'">
					<svg
						class="icon"
						focusable="false"
						aria-hidden="true"
						role="presentation">
						<use xlink:href="#icon-close"></use>
					</svg>
					<span class="audible">Remove</span>
				</span>
			</a>
		</div>
	</div>`,
})
export class TagsCustomizeComponent implements OnInit {
	@Input() tags: string[] = [];
	@Input() maxLength = 32;
	@Input() maxNr = 5;
	@Input() isAuto = true;

	tagModel = "";
	errorMsg: string;
	tagHolder: string;
	lang: ILanguageLime;
	source: Function;
	template: string;

	constructor(
		private commonDataService: CommonDataService,
		private langService: LanguageService,
	) {
		this.lang = langService.getLanguage();
		this.source = (query, done) => {
			if (this.isAuto) {
				this.commonDataService
					.searchTags(query)
					.subscribe((response: IOperationResponse) => {
						const items = response.content.map((tag) => ({
							label: tag,
							value: tag,
						}));
						done(query, items);
					});
			} else {
				done(query, [{ label: query, value: query }]);
			}
		};
		this.template = Templates.autocompleteDefault;
	}

	ngOnInit(): void {
		this.tagHolder = this.isAuto ? new Date().getFullYear().toString() : "";
	}

	onAdd(tag: string) {
		if (!tag) {
			return;
		}

		const lang = this.lang;
		const tags = this.tags;

		// Cannot be duplicate
		if (!ArrayUtil.contains(tags, tag)) {
			// Cannot be shorter than 2 chars
			if (tag.length >= 2) {
				tags.push(tag);
				this.errorMsg = null;
				this.tagModel = "";
				if (tags.length < this.maxNr) {
					this.getInput().focus();
				}
			} else {
				this.errorMsg = lang.invalidTagMinLength;
			}
		} else {
			this.errorMsg = lang.duplicateTag;
		}
	}

	onKey(event: any): void {
		if (event.which === 27 || event.which === 13) {
			event.preventDefault();
			event.stopPropagation();
		}
	}

	onSelected(event: any): void {
		const tag = event[2].value;
		this.onAdd(tag);
	}

	onRemove(tag) {
		ArrayUtil.remove(this.tags, tag);
		if (this.tags.length > 0) {
			$(".lm-tag-customized").first().focus();
		} else {
			this.getInput().focus();
		}
	}

	private getInput(): JQuery {
		return $("#lm-customize-tags-input");
	}
}

@Directive({
	selector: "[lm-enter-to-click]",
})
export class EnterToClickDirective {
	constructor(private element: ElementRef) {}

	@HostListener("keydown", ["$event"]) onKeyDown(event) {
		this.clickOnEnter(event);
	}

	@HostListener("keypress", ["$event"]) onKeyPress(event) {
		this.clickOnEnter(event);
	}

	private clickOnEnter(event): void {
		if (event.which === 13) {
			this.element.nativeElement.click();
			event.preventDefault();
		}
	}
}

@Directive({
	selector: "[lm-click-stop-propagation]",
})
export class ClickStopPropagationDirective {
	@HostListener("click", ["$event"]) onClick(event: any) {
		event.stopPropagation();
	}
}

@Directive({
	selector: "[lm-expandable]",
})
export class ExpandableDirective {
	@Input()
	set isExpanded(isExpanded) {
		if (isExpanded && !this.isExpandedInternal) {
			this.expand();
		} else if (!isExpanded && this.isExpandedInternal) {
			this.collapse();
		}
		this.isExpandedInternal = isExpanded;
	}

	@Output() afterCollapsed = new EventEmitter();
	@Output() onExpand = new EventEmitter();
	private isExpandedInternal: boolean;
	private transitionTime = 0.4; // seconds
	private timeout = this.transitionTime * 1.1 * 1000;

	constructor(private el: ElementRef, private renderer: Renderer2) {}

	private expand(): void {
		let offsetHeight: number;

		this.onExpand.emit();

		this.setVisibility("hidden");
		this.setHeight("auto");

		requestAnimationFrame(() => {
			offsetHeight = this.getElementHeight();

			this.setHeight(0);
			this.setStyle("transition", `height ${this.transitionTime}s ease-out`);
			this.setVisibility("visible");

			requestAnimationFrame(() => {
				this.setHeight(offsetHeight + "px");

				setTimeout(() => {
					this.setHeight("auto");
				}, this.timeout);
			});
		});
	}

	private collapse(): void {
		requestAnimationFrame(() => {
			this.setStyle("transition", "none");
			this.setHeight(this.getElementHeight() + "px");
			this.setStyle("transition", `height ${this.transitionTime}s ease-out`);

			requestAnimationFrame(() => {
				this.setHeight(0);
				setTimeout(() => {
					this.afterCollapsed.emit();
				}, this.timeout);
			});
		});
	}

	private setStyle(property: string, value: string | number): void {
		this.renderer.setStyle(this.el.nativeElement, property, value);
	}

	private setHeight(height: number | string): void {
		this.setStyle("height", height);
	}

	private setVisibility(visibility: string): void {
		this.setStyle("visibility", visibility);
	}

	private getElementHeight(): number {
		return this.el.nativeElement.offsetHeight;
	}
}

@Component({
	template: `<div
		soho-busyindicator
		[blockUI]="true"
		[activated]="isBusy"
		[displayDelay]="0">
		<div class="field">
			<label for="contentImportFileupload">{{ lang.chooseFile }}</label>
			<input
				soho-fileupload
				name="contentImportFileupload"
				(change)="onSelectionChange($event)"
				accept="{{ acceptFileExtension }}" />
		</div>

		<fieldset *ngIf="selectorItems" class="radio-group">
			<div *ngIf="selectorLabel" class="field lm-margin-md-t">
				<label>{{ selectorLabel }}</label>
			</div>
			<ng-container *ngFor="let item of selectorItems">
				<input
					type="radio"
					class="radio"
					name="options"
					[id]="item.id"
					[(ngModel)]="selectedValue"
					[value]="item.value"
					[checked]="item.isSelected" />
				<label [attr.for]="item.id" class="radio-label">{{ item.label }}</label>
				<br />
			</ng-container>
		</fieldset>

		<div class="modal-buttonset">
			<button
				type="button"
				class="btn-modal"
				id="lm-import-cancel"
				(click)="dialog.close()"
				[disabled]="isBusy">
				{{ lang.cancel }}
			</button>
			<button
				type="button"
				class="btn-modal-primary"
				id="lm-import-btn"
				(click)="importFiles()"
				[disabled]="!isValidFile || isBusy">
				{{ lang.importAction }}
			</button>
		</div>
	</div> `,
})
export class ContentImportComponent extends CoreBase implements OnInit {
	dialog: SohoModalDialogRef<ContentImportComponent>;
	options: IImportOptions;
	lang: ILanguageLime;
	acceptFileExtension: string;
	selectedFiles: any;

	selectorLabel: string;
	selectorItems: ISelectorItem[];
	selectedValue: string;
	isBusy = false;
	isValidFile = false;

	private selectorField: string;
	private canClose = true;

	constructor(
		languageService: LanguageService,
		private readonly dataService: DataService,
	) {
		super("ContentImportComponent");
		this.lang = languageService.getLanguage();
	}

	ngOnInit(): void {
		const options = this.options;

		// Currently not supported in soho component
		this.acceptFileExtension = options.acceptFileExtension || ".zip";

		const items = options.selectorItems;
		if (items && items.length >= 2) {
			const item = items[0];
			this.selectorLabel = options.selectorLabel;
			this.selectorItems = items;
			this.selectedValue = item.value;
			this.selectorField = item.key;
		}

		this.dialog.beforeClose(() => {
			return this.canClose;
		});
	}

	onSelectionChange(event: SohoFileUploadEvent): void {
		const files = event.target.files || [];
		this.isValidFile = files.length > 0 && this.isValidExtension(files[0].name);
		this.selectedFiles = files;
	}

	importFiles(): void {
		if (!this.isValidFile) {
			this.logDebug("No valid file was selected");
			return;
		}

		// Prevent the dialog from closing until the import has succeeded or failed.
		this.canClose = false;

		// TODO Consider adding a progress indicator while uploading.

		const formFields: any = {};
		const value = this.selectedValue;
		if (value) {
			formFields[this.selectorField] = value;
		}
		const content = this.options.content;
		if (content) {
			formFields.content = content;
		}

		const dialog = this.dialog;
		this.isBusy = true;
		const self = this;
		this.dataService
			.upload(
				this.options.url,
				this.options.operation,
				this.selectedFiles,
				formFields,
			)
			.subscribe(
				(response: IOperationResponse) => {
					self.canClose = true;
					self.isBusy = false;
					dialog.close({
						button: DialogButtonType.Yes,
						value: {
							message: response,
							responseCode: DialogResponseCode.Success,
							isPublish: value === "1",
						},
					});
				},
				(response: IOperationResponse) => {
					self.canClose = true;
					self.isBusy = false;
					if (self.options.errorHandler) {
						try {
							self.options.errorHandler(response);
						} catch (err) {
							self.logError(
								"Exception in errorHandler, using default error handling" + err,
							);
							self.dataService.handleError(response);
						}
					} else {
						self.dataService.handleError(response);
					}
				},
			);
	}

	private isValidExtension(filename: string): boolean {
		return filename && filename.endsWith(this.acceptFileExtension);
	}
}

