@Directive({
	selector: "[xi-draggable]",
})
export class XiDraggableDirective
	extends CoreBase
	implements OnDestroy, OnInit
{
	private static bannerClass = "lm-banner";
	@Input() editData: IWidgetEditData;
	@Input() widget: IEditableWidget;
	@Input() isPlaceholder = false;
	@Input() hoverColor: string;
	@Input() lang: ILanguageLime;

	@Output() editDataChange = new EventEmitter<IWidgetEditData>();
	@Output() onDropped = new EventEmitter<any>();
	@Output() onResized = new EventEmitter<any>();

	private element: JQuery;
	private draggable: JQuery;
	private resizable: JQuery;
	private droppable: JQuery;

	constructor(private elementRef: ElementRef) {
		super("XiDraggableDirective");
		this.element = $(elementRef.nativeElement);
	}

	ngOnDestroy(): void {
		this.logDebug("ngOnDestroy");
		this.destroyJQuery(this.draggable, "draggable");
		this.destroyJQuery(this.resizable, "resizable");
		this.destroyJQuery(this.droppable, "droppable");
	}

	ngOnInit() {
		const elem = this.element;
		const isBanner = elem.hasClass(XiDraggableDirective.bannerClass);
		let allowContainerChange = false;

		if (!this.isPlaceholder) {
			const widget = this.widget;
			const placeHolders = [
				".page-edit .placeholder:not(.banner-placeholder)",
				".page-edit .banner-placeholder",
				".page-edit .no-banner",
			];
			allowContainerChange = widget.containerChangeInfo.isAllowed;

			const draggableOptions = {
				revertDuration: 150,
				helper: "clone",
				opacity: 0.8,
				scrollSensitivity: 200,
				scrollSpeed: 3,
				start: (event) => {
					const target = $(event.target);
					if (allowContainerChange) {
						$(placeHolders.join()).addClass("ui-draggable-passive");
						const bannerCount = $(".page-edit .lm-banner").length;
						if (!isBanner && bannerCount === 4) {
							$(".page-edit .widget:not(.lm-banner)").addClass(
								"ui-draggable-passive",
							);
						} else {
							$(".page-edit .widget").addClass("ui-draggable-passive");
						}
					} else {
						if (isBanner) {
							$(placeHolders[1] + ", .page-edit .lm-banner").addClass(
								"ui-draggable-passive",
							);
						} else {
							$(
								placeHolders[0] + ", .page-edit .widget:not(.lm-banner)",
							).addClass("ui-draggable-passive");
						}
					}
					target.removeClass("ui-draggable-passive");
					target.addClass("ui-draggable-cloned");

					this.editData.elementId = widget.elementId;
					this.editData.allowContainerChange = allowContainerChange;
					this.editDataChange.emit(this.editData);
				},
				drag: (event, ui) => {
					// Fix for slow effect while dragging widget when using default homepage control animation
					ui.helper.css("transition", "none");
				},
				stop: (event) => {
					$(".page-edit .widget").removeClass("ui-draggable-passive");
					$(placeHolders.join()).removeClass("ui-draggable-passive");
					$(event.target).removeClass("ui-draggable-cloned");

					// Refresh SVG elements if IE11
					const userAgent = navigator.userAgent;
					if (
						!!userAgent.match(/Trident.*rv\:11\./) &&
						userAgent.toLowerCase().indexOf("windows nt 10") !== -1
					) {
						const svgElements = $(event.target).parent().find("svg");
						for (let i = 0; i < svgElements.length; i++) {
							const parent = $(svgElements[i]).parent();
							parent.html(parent.html());
						}
					}
				},
			} as any;
			if (isBanner && !allowContainerChange) {
				draggableOptions.axis = "x";
			}
			this.draggable = (elem as any).draggable(draggableOptions);

			const getMaxDimension = (
				settingProperty: string,
				dimensionProperty: string,
			) => {
				const settings = this.editData.homepageSettings;
				return (
					settings[settingProperty] * widget.maxSize[dimensionProperty] +
					(widget.maxSize[dimensionProperty] - 1) * settings.gutterSize
				);
			};

			this.resizable = (elem as any).resizable({
				handles: isBanner ? "e" : "e, s",
				autoHide: true,
				maxWidth: getMaxDimension("widgetWidth", "columnSpan"),
				maxHeight: getMaxDimension("widgetHeight", "rowSpan"),
				start: (event) => {
					$(".page-edit .widget").addClass("ui-resizable-passive");
					$(event.target).removeClass("ui-resizable-passive");

					const editData = this.editData;
					editData.elementId = widget.elementId;
					editData.widgetLayout = CoreUtil.copy(widget.layout);
					this.editDataChange.emit(editData);
				},
				resize: (event, ui) => {
					// Fix for slow effect while resizing widget when using default homepage control animation
					ui.element.css("transition", "none");
				},
				stop: (event, ui) => {
					if (isBanner) {
						ui.element.css("transition", "");
					}
					$(".page-edit .widget").removeClass("ui-resizable-passive");
					const editData = this.editData;
					const diffWidth = ui.size.width - ui.originalSize.width;
					const diffHeight = ui.size.height - ui.originalSize.height;
					const element = $(ui.element);
					const settings = editData.homepageSettings;

					let isChanged = false;
					let columnSpan = editData.widgetLayout.columnSpan;
					let rowSpan = editData.widgetLayout.rowSpan;

					// Check horizontal change
					if (Math.abs(diffWidth) > settings.widgetWidth / 2) {
						// Widget should alter width horizontally
						isChanged = true;
						element.removeClass("double-width triple-width quad-width");
						const widthUnits = ui.size.width / settings.widgetWidth;
						if (widthUnits > 3.5 && !isBanner) {
							element.addClass("quad-width");
							columnSpan = 4;
						} else if (
							widthUnits > 2.5 &&
							!element.hasClass("banner-max-width-two")
						) {
							element.addClass("triple-width");
							columnSpan = 3;
						} else if (widthUnits > 1.5) {
							element.addClass("double-width");
							columnSpan = 2;
						} else {
							columnSpan = 1;
						}
					}

					// Check vertical change
					if (Math.abs(diffHeight) > settings.widgetHeight / 2) {
						// Widget should alter width horizontally
						element.removeClass("double-height");
						isChanged = true;
						const heightUnits = ui.size.height / settings.widgetHeight;
						if (heightUnits > 1.5) {
							element.addClass("double-height");
							rowSpan = 2;
						} else {
							rowSpan = 1;
						}
					}

					// Removes styling added by resizing
					element.css({ height: "", width: "" });

					if (isChanged) {
						editData.widgetLayout.columnSpan = columnSpan;
						editData.widgetLayout.rowSpan = rowSpan;
						this.editDataChange.emit(editData);
						this.onResized.emit(isBanner);
					}
				},
			});
		}

		const appendIndicatorElement = (draggable: JQuery) => {
			const indicatorElem = $("<div>").addClass("drop-indicator").append(`
				<div class="edge"></div>
				<div class="line"></div>
				<div class="edge"></div>
			`);

			const isBannerPlaceholder = elem.hasClass("banner-placeholder");
			const isContainerSwap =
				isBanner !== draggable.hasClass(XiDraggableDirective.bannerClass);
			const draggableTopOffset = draggable[0].offsetTop;
			const droppableTopOffset = elem[0].offsetTop;
			const isRowIncrease =
				!isContainerSwap && draggableTopOffset < droppableTopOffset;
			const isRowDecrease =
				!isContainerSwap && draggableTopOffset > droppableTopOffset;
			const color = isBanner || isBannerPlaceholder ? "#ffffff" : "#2578A9";
			let alignment: string;
			let offset = "-14px";

			if (this.isPlaceholder || isContainerSwap || isRowDecrease) {
				alignment = "left";
				if (isBannerPlaceholder) {
					offset = "-3px";
				}
			} else if (isRowIncrease) {
				alignment = "right";
			} else {
				alignment =
					draggable[0].offsetLeft > elem[0].offsetLeft ? "left" : "right";
			}

			indicatorElem.children().css("background-color", color);
			elem.append(indicatorElem.css(alignment, offset));
		};

		const deleteIndicatorElement = () => {
			elem.children(".drop-indicator").remove();
		};

		this.droppable = (elem as any).droppable({
			greedy: true,
			tolerance: "pointer",
			addClasses: false,
			over: (event, ui) => {
				const isValidDrop = elem.hasClass("ui-draggable-passive");

				if (isValidDrop) {
					if (this.hoverColor) {
						elem.css("background-color", this.hoverColor);
						elem.find("button#lmAddHeroCat > span").text(this.lang.dropBanner);
						elem.find("button#lmAddHeroCat > svg").hide();
						elem.find("button#lmPasteBannerCat").hide();
					} else {
						appendIndicatorElement(ui.draggable);
					}
				} else {
					ui.helper.css("border-color", "#e84f4f");
				}
			},
			out: (event, ui) => {
				if (this.hoverColor) {
					elem.css("background-color", "inherit");
					elem.find("button#lmAddHeroCat > span").text(this.lang.addHeroWidget);
					elem.find("button#lmAddHeroCat > svg").show();
					elem.find("button#lmPasteBannerCat").show();
				}
				if (isBanner || elem.hasClass("no-banner")) {
					ui.helper.css("border-color", "#078cd9");
				} else {
					ui.helper.css("border-color", "#ffffff");
				}
				deleteIndicatorElement();
			},
			deactivate: () => {
				deleteIndicatorElement();
			},
			drop: (event, ui) => {
				if (this.isPlaceholder) {
					this.onDropped.emit();
				} else {
					ui.helper.removeClass("widget");
					this.onDropped.emit({ widget: this.widget });
				}
			},
		});
	}

	private destroyJQuery(element: JQuery, name: string): void {
		if (element) {
			try {
				element[name]("destroy");
			} catch (e) {
				this.logError("Failed to destroy " + name);
			}
		}
	}
}

@Directive({
	selector: "input[lm-number-mask]",
})
export class NumberMaskDirective implements OnInit, OnDestroy {
	@Input() max?: number | string;
	@Input() min?: number | string;
	@Input() onlyIntegers?: boolean;

	private destroyed$ = new Subject<void>();

	constructor(
		private model: NgModel,
		private element: ElementRef<HTMLInputElement>,
	) {}

	ngOnInit() {
		// Change detection and validation is split in two pieces for now to solve issue with having to
		// delete a value twice and some other issues. The directive is currently only intended to
		// be used with [ngModelOptions]="{updateOn:'blur'}". Further development and testing required for more generic support.

		const modelChange$ = this.model.valueChanges;
		modelChange$
			.pipe(
				takeUntil(this.destroyed$),
				map((value) => this.toNumber(value)),
				map((value) => this.constrainValue(value)),
			)
			.subscribe((value) => {
				this.updateModel(value);
			});

		const keyups$ = fromEvent(this.element.nativeElement, "keyup").pipe(
			pluck("target", "value"),
		);
		const inputChange$ = fromEvent(this.element.nativeElement, "change").pipe(
			pluck("target", "value"),
		);
		const changes$ = merge(keyups$, inputChange$);
		changes$
			.pipe(
				takeUntil(this.destroyed$),
				distinctUntilChanged(),
				filter((value) => this.isSet(value)),
				map((value) => this.toNumber(value)),
				map((value) => this.constrainValue(value)),
			)
			.subscribe((value) => {
				this.updateModel(value);
			});
	}

	ngOnDestroy() {
		this.destroyed$.next();
		this.destroyed$.complete();
	}

	private updateModel(value: number): void {
		this.model.viewToModelUpdate(value);
		this.model.valueAccessor.writeValue(value);
	}

	private constrainValue(value: number): number {
		value = this.constrainMax(value);
		value = this.constrainMin(value);
		value = this.constrainInteger(value);
		return value;
	}

	private constrainMax(value: number): number {
		if (this.isMaxSet() && value > Number(this.max)) {
			return Number(this.max);
		}
		return value;
	}

	private constrainMin(value: number): number {
		if (this.isMinSet() && value < Number(this.min)) {
			return Number(this.min);
		}
		return value;
	}

	private constrainInteger(value: number): number {
		if (this.onlyIntegers && value !== Math.floor(value)) {
			return Math.floor(value);
		}
		return value;
	}

	private isMaxSet() {
		return this.isSet(this.max);
	}

	private isMinSet() {
		return this.isSet(this.min);
	}

	private toNumber(value: number | string | null | undefined | {}) {
		const num = Number(value);
		return Number.isNaN(num) ? this.constrainMin(0) : num;
	}

	private isSet(value: number | string | null | undefined | {}) {
		return value !== null && value !== undefined && value !== "";
	}
}

@Pipe({ name: "lmTrim" })
export class TrimPipe implements PipeTransform {
	transform(value: string): string {
		return value.trim();
	}
}

@Pipe({ name: "lmDisplayName" })
export class DisplayNamePipe implements PipeTransform {
	private lang: ILanguageLime;
	constructor(languageService: LanguageService) {
		this.lang = languageService.getLanguage();
	}
	transform(value: string): string {
		return StringUtil.isNullOrWhitespace(value) || CoreUtil.isGuid(value)
			? this.lang.unknown
			: value;
	}
}

@Pipe({ name: "lmEscapeHtml" })
export class EscapeHtmlPipe implements PipeTransform {
	transform(value: string): string {
		return HtmlUtil.escapeStringForHtml(value);
	}
}

/**
 * Pipe to transform text (title/id) into automation Id. Replaces " " and "." with "-"
 */
@Pipe({ name: "lmAutoId" })
export class AutomationIdPipe implements PipeTransform {
	transform(value: string, prefix: string, defaultText?: string): string {
		const identifier = StringUtil.formatTextForId(value, defaultText);
		return prefix + "-" + identifier;
	}
}

/**
 * Use this directive to "submit" an input value when the "enter" key is pressed.
 * This is equivalent to the "keydown.enter" event listener, but it also works on iOS.
 *
 * @example ```html
 * <input soho-searchfield (lm-submit)="search()">
 * ```
 */
@Directive({
	selector: "input[lm-submit]",
})
export class SubmitDirective {
	@Output("lm-submit") submit = new EventEmitter<void>();

	@HostListener("keydown.enter")
	keydownEnter() {
		if (this.isIOS()) {
			this.submit.emit();
		}
	}

	@HostListener("keyup.enter")
	keyupEnter() {
		if (!this.isIOS()) {
			this.submit.emit();
		}
	}

	private isIOS() {
		return navigator.platform && /iPad|iOS|iPod/.test(navigator.platform);
	}
}
