import { Component, ElementRef, OnDestroy, OnInit } from "@angular/core";
import { ArrayUtil, CommonUtil } from "lime";
import {
	CoreBase,
	EditModeService,
	ICommandBarAction,
	IEditMode,
} from "lime/core";

@Component({
	selector: "lm-edit-command-bar",
	templateUrl: "./edit-command-bar.html",
	styleUrls: ["./edit-command-bar.scss"],
})
export class EditModeCommandBarComponent
	extends CoreBase
	implements OnInit, OnDestroy
{
	entityTitle: string;
	headerColor: string;
	modeName: string;
	actions: ICommandBarAction[] = [];
	secondary: ICommandBarAction[] = [];
	title: string;

	private unsubscribeChangedContext: () => void;

	constructor(
		private readonly service: EditModeService,
		private readonly element: ElementRef<HTMLElement>,
	) {
		super("EditModeCommandBarComponent");
	}

	ngOnInit(): void {
		const service = this.service;
		this.update(service.current);
		this.unsubscribeChangedContext = service.contextChanged().on((info) => {
			this.entityTitle = info.entityTitle;
			this.headerColor = info.headerColor;
		});
	}

	ngOnDestroy(): void {
		this.logDebug("ngOnDestroy");
		this.unsubscribeChangedContext();
	}

	ngAfterViewInit() {
		const tabbableBtn = this.element.nativeElement.querySelector("button");
		if (tabbableBtn) {
			tabbableBtn.setAttribute("tabindex", "0");
		}
	}

	onPrimary(index: string) {
		this.invokeAction(this.actions, index);
	}

	onSecondary(index: string) {
		this.invokeAction(this.secondary, index);
	}

	private invokeAction(actions: ICommandBarAction[], index: string) {
		const action = actions[index] as ICommandBarAction;
		if (action) {
			action.execute();
		}
	}

	private update(m: IEditMode): void {
		if (m && m.isActive) {
			this.logDebug(m.mode);
			this.modeName = m.mode;
			this.headerColor = m.headerColor;
			this.title = m.title;
			this.entityTitle = m.entityTitle;
			const predicate = (a: ICommandBarAction) =>
				CommonUtil.isUndefined(a.isEnabled) || a.isEnabled;
			this.actions = m.actions
				? ArrayUtil.filterByPredicate(m.actions, predicate)
				: [];
			this.secondary = m.secondaryActions
				? ArrayUtil.filterByPredicate(m.secondaryActions || [], predicate)
				: [];
		}
	}
}
