/**
 * Options for saving a page.
 */
export interface IPageSaveOptions {
	/**
	 * Indicates saving should be delayed.
	 * The default value is false;
	 */
	delayed?: boolean;

	page: IPageInstance;
}

@Injectable({
	providedIn: "root",
})
export class PageContainerFactory {
	constructor(private pageFactory: PageFactory) {}

	createPageContainer(
		messageService: SohoMessageService,
		languageService: LanguageService,
		lazyTypeService: LazyTypeService,
		containerService: ContainerService,
		contextService: ContextService,
		devService: DevService,
		sohoModalDialogService: SohoModalDialogService,
		context: IContext,
		data: IPageContainerData,
		pageService: PageService,
		widgetService: WidgetService,
		progressService: ProgressService,
		toastService: SohoToastService,
		systemMessagesService: SystemMessagesService,
		editModeService?: EditModeService,
	): PageContainer {
		return new PageContainer(
			messageService,
			languageService,
			lazyTypeService,
			containerService,
			contextService,
			devService,
			sohoModalDialogService,
			context,
			data,
			pageService,
			widgetService,
			progressService,
			toastService,
			systemMessagesService,
			this.pageFactory,
			editModeService,
		);
	}
}

export class PageContainer extends CoreBase implements IPageContainer {
	pages: IPageInstance[] = [];
	isLegacyContext: boolean;
	errorMessage: string;

	/**
	 * ID of the most recently published page, prior to a refresh.
	 * Used to know which page to load after a page has been published and the page container is refreshed.
	 */
	recentlyPublishedPageId: string = null;

	private readonly savedPages: IStringMap = {};
	private isSettingsOpen: boolean;
	private lang: ILanguageLime;
	private unsubscribers: Array<Function> = [];
	private selectedSubscription: Subscription;
	private isPendingRefresh: boolean;
	private pendingRefreshInfo: IRefreshInfo;

	private readonly saveDelay = 3000;
	private readonly pendingPages: IPageInstance[] = [];

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		private readonly lazyTypeService: LazyTypeService,
		private containerService: ContainerService,
		private contextService: ContextService,
		private devService: DevService,
		private sohoModalDialogService: SohoModalDialogService,
		public context: IContext,
		public data: IPageContainerData,
		private pageService: PageService,
		private widgetService: WidgetService,
		private progressService: ProgressService,
		private toastService: SohoToastService,
		private systemMessagesService: SystemMessagesService,
		private pageFactory: PageFactory,
		private editModeService?: EditModeService,
	) {
		super("PageContainer", messageService, languageService);
		this.lang = languageService.getLanguage();

		if (data) {
			this.isLegacyContext = data.isLegacyContext;
			const pages = data.pages;
			if (pages) {
				if (this.isLegacyContext) {
					const page = pages[0];
					this.addContextWidget(page);
					this.addLast(page);
				} else {
					for (let i = 0; i < pages.length; i++) {
						this.addLast(pages[i]);
					}
				}
			}
		}

		this.selectedSubscription = containerService.selected$.subscribe(
			(page: IPageInstance) => {
				if (page && page.isDynamic()) {
					this.onDynamic(page);
				}
			},
		);
	}

	hasPages(): boolean {
		const pages = this.pages;
		return pages && pages.length > 0;
	}

	destroy(): void {
		this.logDebug("destroy");
		try {
			this.selectedSubscription.unsubscribe();
			const pages = this.pages;
			if (pages) {
				for (const page of pages) {
					page.destroy();
				}
			}
			for (const f of this.unsubscribers) {
				f();
			}
		} catch (ex) {
			this.logError("Failed to destroy", ex);
		}
	}

	selectStartPage(selectedPageId?: string): void {
		let pageId: string;
		if (selectedPageId && this.contains(selectedPageId)) {
			pageId = selectedPageId;
		} else {
			pageId = this.getStartPage();
		}
		if (pageId) {
			this.containerService.select(pageId);
		}
	}

	getStartPage(): string {
		let startPage;
		const primaryPage = this.getPrimaryPage();
		if (primaryPage) {
			startPage = primaryPage.id;
		} else {
			const settings = this.context.settings;
			startPage = settings.getStartPage();
			const selectedPage = this.getPage(startPage); // Check if it exists here or within select?
			if (!startPage || !selectedPage || !settings.isSelectHomepageEnabled()) {
				startPage = this.pages[0] != null ? this.pages[0].id : null;
			}
		}
		return startPage;
	}

	onCancelPublish() {
		this.showMessageAsync(
			this.lang.confirmCancel,
			this.lang.confirmCancelMessage,
			true,
		).subscribe((r: IDialogResult) => {
			if (r.button === DialogButtonType.Yes) {
				this.editModeService.stop({ isSave: false });
			}
		});
	}

	cacheApplicationsAndDefinitions(serverPage: IPage): void {
		// Needed when adding a shared or copy.
		const definitions = serverPage.widgetDefinitions;
		if (definitions) {
			for (let i = 0; i < definitions.length; i++) {
				this.widgetService.addDefinitionItem(definitions[i]);
			}
		}

		const applications = serverPage.applications;
		if (applications) {
			// Replacement configuration for a logicalId needs to be added to the container
			const config = this.context.getConfiguration();
			if (config) {
				config.addApplicationMap(applications);
			}
		}
	}

	add(
		serverPage: IPage,
		showToastConfirmation: boolean,
		notifyMingle = true,
	): void {
		this.cacheApplicationsAndDefinitions(serverPage);
		const page = this.addLast(serverPage);
		this.containerService.select(page.id, notifyMingle);
		this.raiseChanged();

		const lang = this.lang;

		if (showToastConfirmation) {
			this.toastService.show(
				CoreUtil.getToastOptions(
					lang.pageAdded,
					lang.format(lang.titleAddedMessage, page.title),
				),
			);
		}
	}

	addWidget(addWidgetInfo: IAddWidgetInfo, busyCallback?: () => void): void {
		const lang = this.lang;
		const page = this.getSelected();
		if (
			page.noOfWidgets() >= this.context.settings.getMaxWidgetsOnPageCount()
		) {
			this.showMessage(lang.unableToAddWidget, lang.maxWidgetsOnPageMessage);
			if (busyCallback) {
				busyCallback();
			}
			return;
		}

		this.widgetService
			.preLoadWidget(page.getWidgetParentContext(), addWidgetInfo, busyCallback)
			.subscribe(
				(widget: IWidget) => {
					const title = addWidgetInfo.widgetInfo.title;
					WidgetUtil.applyTitleOverride(addWidgetInfo, widget);

					page.add(widget);

					const name = HtmlUtil.escapeStringForHtml(title || widget.title);
					const options: SohoToastOptions = {
						title: lang.widgetAdded,
						message: lang.format(lang.titleAddedMessage, name),
						position: "bottom right",
						timeout: 3000,
					};
					this.toastService.show(options);
				},
				() => {
					this.showError(lang.unableToAddWidget, lang.brokenWidget);
				},
			);
	}

	getUserPageCount() {
		return this.pages.filter((page) => !page.isMandatory).length;
	}

	reorder(order: string[]): Observable<IOperationResponse> {
		const subject = new AsyncSubject<IOperationResponse>();

		this.pageService.reorderConnections(order).subscribe(
			(r: IOperationResponse) => {
				if (r.hasError()) {
					this.logResponse(r);
					subject.error(r);
				} else {
					r.content = this.pages;
					subject.next(r);
					subject.complete();
					this.raiseChanged();
				}
			},
			(r: IOperationResponse) => {
				this.logResponse(r);
				subject.error(r);
			},
		);

		return subject.asObservable();
	}

	contains(id: string): boolean {
		return ArrayUtil.containsByProperty(this.pages, "id", id);
	}

	publish(page: IPageInstance, isUpdate?: boolean) {
		this.progressService.setBusy(true);
		const pageData = page.createSavePageData();
		const pageRequest = {
			data: pageData,
			access: page.access,
			localization: page.localization,
		} as IPage;

		const self = this;
		this.pageService.updatePublished(pageRequest).subscribe(
			(r: IPageDataResponse) => {
				self.editModeService.stop({ isSave: true });
				self.recentlyPublishedPageId = r.content.id;
				self.progressService.setBusy(false);
				self.refresh();
				self.pageService.showPublishedToast(
					this.pageService.getPageTitleLocalizedOrDefault(pageRequest),
				);
			},
			(r: IOperationResponse) => {
				self.pageService.handleError(r);
				self.editModeService.stop({ isSave: false });
			},
		);
	}

	editPageConfiguration(isUpdate?: boolean) {
		const self = this;
		const page = this.getSelected();

		this.pageService
			.editPageConfiguration(page, isUpdate, this.getDialogParent())
			.subscribe((result) => {
				if (result) {
					const updatedPage = result.value as IPage;
					if (updatedPage) {
						// The data properties are manually copied instead of replacing the entire data object
						// since that caused issues that must be fixed before this can be done.
						const pageData = page.data;
						const updatedData = updatedPage.data;
						pageData.title = updatedData.title;
						pageData.description = updatedData.description;
						pageData.tags = updatedData.tags;
						if (!pageData.content) {
							pageData.content = {};
						}
						if (!pageData.config) {
							pageData.config = {};
						}
						page.access = updatedPage.access;
						page.localization = updatedPage.localization;

						const entityTitle =
							this.pageService.getPageTitleLocalizedOrDefault(updatedPage);
						const colorNumber =
							updatedData.color || Constants.defaultColorNumber;
						const headerColor = UIUtil.numberToHexCode(colorNumber);
						const updatedConfig = updatedData.config;
						const editModeContext: IEditModeContext = {
							entityTitle: entityTitle,
							headerColor: headerColor,
							memoConfig: {
								enableMemo: updatedConfig && updatedConfig.enableMemo === 1,
								disableAnimation:
									updatedConfig && updatedConfig.disableAnimation === 1,
								memoDuration: updatedConfig && updatedConfig.memoDuration,
								data: {
									color: colorNumber,
								},
							},
						};
						self.editModeService.updateEditModeContext(editModeContext);
					}
				}
			});
	}

	remove(page: IPageInstance): Observable<IOperationResponse> {
		const subject = new AsyncSubject<IOperationResponse>();

		const lang = this.lang;
		const message = PageUtil.isPrivate(page)
			? lang.format(lang.confirmRemovePage, page.title)
			: lang.format(lang.confirmRemovePublicPage, page.title);

		this.showMessageAsync(lang.removePage, message, true).subscribe(
			(result: IDialogResult) => {
				if (result.button === DialogButtonType.Yes) {
					this.context.setBusy(true);
					if (this.pageService.isDev()) {
						this.removeDev(subject, page);
						return subject.asObservable();
					}

					this.pageService.removeConnection(page.id).subscribe(
						(r: IOperationResponse) => {
							if (r.hasError()) {
								subject.error(r);
							}
							this.removeFromPages(page);
							subject.next(r);
							subject.complete();
							this.context.setBusy(false);
						},
						(r: IOperationResponse) => {
							subject.error(r);
							this.logResponse(r);
							this.context.setBusy(false);
						},
					);
				}
			},
		);

		return subject.asObservable();
	}

	delete(
		pageId: string,
		name: string,
		isShared: boolean,
	): Observable<IOperationResponse> {
		const lang = this.lang;
		const page = this.getPage(pageId);
		const isPageLoaded = CommonUtil.hasValue(page);
		const subject = new AsyncSubject<IOperationResponse>();

		const title = isShared ? this.lang.deletePage : this.lang.removePage;
		const message = isShared
			? lang.format(lang.confirmDeletePublicPage, name)
			: lang.format(lang.confirmRemovePage, name);

		this.showMessageAsync(title, message, true).subscribe(
			(result: IDialogResult) => {
				if (result.button === DialogButtonType.Yes) {
					this.context.setBusy(true);
					if (this.pageService.isDev()) {
						this.removeDev(subject, page);
						this.context.setBusy(false);
						return subject.asObservable();
					}

					this.pageService.delete(page === null ? pageId : page.id).subscribe(
						(r: IOperationResponse) => {
							if (r.hasError()) {
								subject.error(r);
							}
							if (isPageLoaded) {
								this.removeFromPages(page);
							}
							subject.next(r);
							subject.complete();
							this.context.setBusy(false);
						},
						(r: IOperationResponse) => {
							subject.error(r);
							this.logResponse(r);
							this.context.setBusy(false);
						},
					);
				}
				return subject.asObservable();
			},
		);

		return subject.asObservable();
	}

	removeAllPagesFromClient(): void {
		for (let i = this.pages.length - 1; i >= 0; --i) {
			this.removeFromPages(this.pages[i], true);
		}
	}

	showAddPage(
		parent: ViewContainerRef,
		startEditMode = true,
	): Observable<IPageData> {
		const subject = new AsyncSubject<IPageData>();
		const isDev = this.pageService.isDev();

		if (this.isPageAddPossible()) {
			this.progressService.setBusy(true);
			this.lazyTypeService.loadLazyModule().then(({ NewPageComponent }) => {
				const dialog = this.sohoModalDialogService
					.modal(NewPageComponent, parent)
					.title(this.lang.newPage)
					.id("lm-pnew-modal")
					.cssClass("e2e-newPageDialog")
					.afterClose((result: IDialogResult) => {
						this.logDebug("Add new page dialog closed");
						if (
							result &&
							result.value &&
							result.button === DialogButtonType.Ok
						) {
							if (isDev) {
								const pageData = result.value;
								const dev = this.devService.getConfiguration();
								const page = { data: pageData, isEditable: true } as IPage;
								dev.initPage(pageData);
								PageUtil.verifyContent(pageData);
								this.onPageCreated(new OperationResponse(page), startEditMode);
								dev.container.pages.push(page);
								dev.save(null as IPageData); // Page is just added not content
								subject.next(pageData);
								subject.complete();
							} else {
								const response: IPageDataResponse = result.value;
								if (!response.hasError()) {
									const pageResponse = result.value;
									this.onPageCreated(pageResponse, startEditMode);
									const responsedata = pageResponse.content
										? pageResponse.content.data
										: null;
									subject.next(responsedata);
									subject.complete();
								}
							}
						}
					});

				dialog
					.apply((component: any) => {
						component.modalDialog = dialog;
						component.nextSortOrder = this.getNextSortOrder();
						component.maxUserPage = this.context.settings.getMaxUserPageCount();
						component.isDev = isDev;
					})
					.open();
			});
		} else {
			subject.error({});
		}

		return subject.asObservable();
	}

	loadPage(id: string): Observable<IPage> {
		const subject = new AsyncSubject<IPage>();
		const existingPage = ArrayUtil.itemByProperty(
			this.pages,
			"id",
			id,
		) as IPageInstance;
		// If page is not mine and ownerName is not set, fetch page
		let useExisting = true;
		if (!this.pageService.isDev()) {
			if (!CommonUtil.hasValue(existingPage)) {
				useExisting = false;
			} else {
				// Page exists but check if you are the owner and if the ownerName exist
				const hasOwnerName = !CommonUtil.isUndefined(
					existingPage.data.ownerName,
				);
				useExisting =
					this.context.isCurrentUser(existingPage.data.ownerId) || hasOwnerName;
			}
		}
		if (useExisting) {
			subject.next(existingPage);
			subject.complete();
		} else {
			this.pageService.getPublished(id).subscribe(
				(resp: IPageResponse) => {
					if (resp && resp.content) {
						if (CommonUtil.hasValue(existingPage)) {
							// Replace pageData if existing page was fetched again to set userNames
							existingPage.data = resp.content.data;
						}
						subject.next(resp.content);
						subject.complete();
					} else {
						this.logError(
							`loadPage did not return the page. ${JSON.stringify(resp)}`,
						);
						subject.error(resp);
					}
				},
				(resp: IOperationResponse) => {
					this.logError(`Failed to load page: ${JSON.stringify(resp)}`);
					subject.error(resp);
				},
			);
		}
		return subject.asObservable();
	}

	showPageInformation(id: string) {
		const context = this.context;
		if (!id || context.isBusy()) {
			return;
		}

		context.setBusy(true);
		this.loadPage(id).subscribe(
			(page: IPage) => {
				context.setBusy(false);
				this.showPageSettings(page);
			},
			(error) => {
				this.logError(`Unable to get Page ${error}`);
				this.showMessage(
					this.lang.pageSettings,
					this.lang.unableOpenPageSettings,
				);
				context.setBusy(false);
			},
		);
	}

	showPageSettings(page: IPage) {
		if (this.isSettingsOpen) {
			return;
		}

		this.isSettingsOpen = true;
		this.lazyTypeService.loadLazyModule().then(({ PageSettingsComponent }) => {
			const dialog = this.sohoModalDialogService
				.modal(PageSettingsComponent, this.getDialogParent())
				.id("lm-p-set-mdl")
				.title(this.lang.pageSettings)
				.trigger("immediate")
				.afterClose((r: IDialogResult) => {
					this.isSettingsOpen = false;
					if (r && r.button === DialogButtonType.Ok) {
						page.title = page.data.title;
						page.changeDate = page.data.changeDate;
						page.description = page.data.description;
						this.raiseChangedId(page.data.id);

						if (r.value.colorChanged) {
							this.notifyBannerWidgets(page.data.id);
						}
					}
				});
			dialog
				.apply((component: any) => {
					component.modalDialog = dialog;
					component.parameter = page;
					component.saveDataOnClose = true;
				})
				.open();
		});
	}

	handleSystemMessages(messages: MessageInfo[], addContentMessage: boolean) {
		const hasSystemMessages = messages && PageUtil.isSecurityMessages(messages);

		if (hasSystemMessages) {
			for (const message of messages) {
				const errorCode = message.code;
				let errorMessage = "";
				if (message.code === ResponseErrorCodes.errorLoadUserAttributes) {
					errorMessage = this.lang.messageUserAttributeError;
				} else if (message.code === ResponseErrorCodes.errorLoadUserGroups) {
					errorMessage = this.lang.messageUserDistributionGroupError;
				} else if (message.code === ResponseErrorCodes.errorLoadUserRoles) {
					errorMessage = this.lang.messageUserSecurityRolesError;
				}

				if (addContentMessage) {
					errorMessage = `${errorMessage} ${this.lang.messageUnverifiedContent}`;
				} else {
					errorMessage = `${errorMessage} ${this.lang.headerPermissionCheck}.`;
				}

				this.systemMessagesService.addMessage({
					message: errorMessage,
					errorCode: errorCode,
					messageType: SystemMessageType.performance,
				});
			}
		}
	}

	addFromCatalog(catalogAddItem: ICatalogAddItem) {
		const isCopy = !catalogAddItem.byRef;
		const page: IPage = catalogAddItem.item;
		if (isCopy) {
			this.copyPage(page, true, false, catalogAddItem.busyCallback);
		} else {
			this.addExistingPage(
				page,
				true,
				false,
				null,
				catalogAddItem.busyCallback,
			);
		}
	}

	refreshOnNextSave(): void {
		this.isPendingRefresh = true;
	}

	refresh(info?: IRefreshInfo) {
		info = info || {};
		if (this.pendingPages.length === 0) {
			this.containerService.refresh(info);
			return;
		}

		this.pendingRefreshInfo = this.pendingRefreshInfo = info;
		this.isPendingRefresh = true;
	}

	saveAndRefreshCurrent(): void {
		window.setTimeout(() => {
			if (this.getSelected()) {
				this.saveCurrent().subscribe(() => {
					this.refresh();
				});
			}
		}, 1);
	}

	saveCurrent(): Observable<IOperationResponse> {
		const subject = new AsyncSubject<IOperationResponse>();
		const page = this.getSelected();
		if (page) {
			this.savePage({ page: page }, subject);
		} else {
			subject.error({});
		}
		return subject.asObservable();
	}

	getPage(id: string): IPageInstance {
		return ArrayUtil.itemByProperty(this.pages, "id", id) as IPageInstance;
	}

	raiseChangedId(id: string) {
		this.logDebug("Page with id " + id + " changed");
		this.raiseChanged();
	}

	/**
	 * Add Existing Page
	 *
	 * Add an existing published or private page.
	 */
	addExistingPage(
		page: IPage,
		showToastConfirmation: boolean,
		isCopy?: boolean,
		copyTitle?: string,
		busyCallback?: Function,
	) {
		if (!busyCallback) {
			this.progressService.setBusy(true);
		}

		const pageToAdd: IPageInstance = ArrayUtil.itemByProperty(
			this.pages,
			"id",
			page.data.id,
		);
		const isStandard = page.data.isStandard;
		copyTitle = CoreUtil.truncate(copyTitle, Constants.pageTitleLength);

		if (!pageToAdd || pageToAdd.isPublished()) {
			// Public page.
			// Verify that the page does not exist in My Pages already, in that case show an error message
			const lang = this.lang;
			if (
				!isCopy &&
				ArrayUtil.containsByProperty(this.pages, "id", page.data.id)
			) {
				busyCallback ? busyCallback() : this.progressService.setBusy(false);
				this.showMessage(
					lang.pageExists,
					lang.format(lang.pageExistsMessage, page.title || page.data.title),
				);
				return;
			}

			// Add page if max pages not reached.
			if (this.isPageAddPossible()) {
				const sortOrder = this.getNextSortOrder();
				// Sortorder is set on server
				this.pageService
					.addConnection(page.data.id, isCopy, sortOrder, isStandard, copyTitle)
					.subscribe(
						(r: IPageResponse) => {
							this.add(r.content, showToastConfirmation);
							this.handleSystemMessages(r.messageList, false);
							busyCallback
								? busyCallback()
								: this.progressService.setBusy(false);
						},
						(r: IOperationResponse) => {
							if (PageUtil.isSecurityMessages(r.messageList)) {
								this.handleSystemMessages(r.messageList, false);
							} else {
								this.pageService.handleError(r);
							}
							busyCallback
								? busyCallback()
								: this.progressService.setBusy(false);
						},
					);
			} else {
				busyCallback ? busyCallback() : this.progressService.setBusy(false);
			}
		} else {
			// Private page.
			this.duplicatePrivatePage(pageToAdd.createSavePageData(), copyTitle);
			if (busyCallback) {
				busyCallback();
			}
		}
	}

	/**
	 * Duplicates a private page.
	 */
	duplicatePrivatePage(pageData: IPageData, copyTitle: string) {
		// Verify that a new page can be added
		if (!this.isPageAddPossible()) {
			return;
		}

		// Strip ID and set new title.
		pageData.id = null;
		pageData.title = copyTitle;

		// Set next sort order
		pageData.sortOrder = this.getNextSortOrder();

		PageUtil.updateWidgetIdsPageData(pageData);

		// Create new page.
		this.context.setBusy(true);
		this.pageService.createPrivate(pageData).subscribe(
			(response: IPageResponse) => {
				this.onPageCreated(response, false);
				this.context.setBusy(false);
			},
			(response: IOperationResponse) => {
				this.pageService.handleCreatePageError(
					response,
					this.context.settings.getMaxUserPageCount(),
				);
				this.context.setBusy(false);
			},
		);
	}

	isAddPageAllowed(): boolean {
		return this.isPageAddPossible(false);
	}

	copyPage(
		page: IPage,
		showToastConfirmation: boolean,
		fromPreview: boolean,
		busyCallback?: Function,
	) {
		if (!this.isPageAddPossible()) {
			busyCallback ? busyCallback() : this.progressService.setBusy(false);
			return;
		}

		this.lazyTypeService.loadLazyModule().then(({ CopyPageComponent }) => {
			const dialog = this.sohoModalDialogService
				.modal(CopyPageComponent, this.getDialogParent())
				.id("lm-page-copy-dialog")
				.title(this.lang.duplicatePage)
				.cssClass("e2e-copyPageModal")
				.afterClose((result: IDialogResult) => {
					this.logDebug("Copy page dialog closed");
					if (result && result.value && result.button === DialogButtonType.Ok) {
						const newPage = result.value as IPageData;
						if (fromPreview) {
							// Remove then add to get correct behavior towards the server
							this.removeFromPages(this.getPage(page.data.id));
						}
						this.addExistingPage(
							page,
							showToastConfirmation,
							true,
							newPage.title,
							busyCallback,
						);
						if (fromPreview) {
							this.editModeService.stop({ isSave: true });
						}
					} else {
						if (busyCallback) {
							busyCallback();
						}
					}
				});

			const title = this.getCopyTitle(page);
			dialog
				.apply((component: any) => {
					component.dialog = dialog;
					component.newPage = {
						title: this.lang.format(this.lang.pageCopyTitle, title),
					};
				})
				.open();
		});
	}

	openImportPageDialog(
		errorHandler?: IImportErrorHandler,
	): Observable<IDialogResult> {
		const settings = this.context.settings;
		const userPageCount = this.getUserPageCount();
		const maxCount = settings.getMaxUserPageCount();
		const lang = this.lang;
		if (userPageCount >= maxCount) {
			const title = lang.unableToAddPage;
			const message = lang.format(lang.maxPageCountMessage, maxCount);

			return this.showMessageAsync(title, message);
		}

		const importOptions: IImportOptions = {
			url: "/user",
			title: this.lang.importPage,
			operation: EntityCategory.privatePage.toString(),
			acceptFileExtension: ".json",
		};
		if (errorHandler) {
			importOptions.errorHandler = errorHandler;
		}

		if (settings.isPagePublishEnabled()) {
			importOptions.selectorLabel = lang.importAs;
			importOptions.selectorItems = [
				{
					id: "pageImportDialogPrivate",
					key: "mode",
					value: "0",
					label: lang.privatePage,
					isSelected: true,
				},
				{
					id: "pageImportDialogPublished",
					key: "mode",
					value: "1",
					label: lang.publishedPage,
				},
			];
		}

		const subject = new AsyncSubject<IDialogResult>();
		const dialog = this.sohoModalDialogService
			.modal(ContentImportComponent, this.getDialogParent())
			.id("lm-page-import-dialog")
			.title(this.lang.importPage)
			.afterClose((result: IDialogResult) => {
				subject.next(result);
				subject.complete();
			});

		dialog
			.apply((component) => {
				component.dialog = dialog;
				component.options = importOptions;
			})
			.open();

		return subject.asObservable();
	}

	previewPage(options: IPagePreviewOptions, showPageCatalog: () => void): void {
		const isFromCatalog = options.isFromCatalog;
		const selectedIndex = this.getSelectedIndex();

		this.progressService.setBusy(true);

		let previewTitle =
			options.title || this.lang.format(this.lang.previewingPage, "");

		this.pageService.getPreview(options).subscribe(
			(response: IPageResponse) => {
				if (
					!response ||
					response.hasError() ||
					!response.content ||
					!response.content.data
				) {
					this.progressService.setBusy(false);
					if (isFromCatalog) {
						// Catalog should not be opened for previews / shared links
						showPageCatalog();
					}
					this.pageService.handleError(response);
					return;
				}

				const page = response.content;
				const data = page.data;

				if (options.isDynamic) {
					// The user might have this page so the ID must be changed.
					// This is OK since a page can never be added from a dynamic page preview.
					data.id = "dyn_" + data.id;
					previewTitle = "Previewing page as current user";

					const dynamicOptions = options.dynamicPreviewOptions;
					let isUserPreview = false;
					if (dynamicOptions) {
						const userInfo = dynamicOptions.userInfo;
						if (userInfo) {
							isUserPreview = true;
							previewTitle = "Previewing page as " + userInfo.displayName;
						} else if (dynamicOptions.results) {
							previewTitle = "Previewing page with security policy applied";
						}
					}
					data.isUserPreview = isUserPreview;
				}

				// Register Applications and definitions so the preview will have enough data
				this.cacheApplicationsAndDefinitions(page);

				const pageTitle = page.title || data.title;

				const isEditable = page.isEditable;
				// Edit is never allowed in preview - but remember to change it back is added
				page.isEditable = false;

				const colorNumber = data.color || Constants.defaultColorNumber;
				const headerColor = UIUtil.numberToHexCode(colorNumber);

				const isAddable =
					CommonUtil.isUndefined(options.isAddable) || options.isAddable;
				const self = this;
				const settings = this.context.settings;
				const actions: ICommandBarAction[] = [];
				const secondaryActions: ICommandBarAction[] = [];

				const cancelExecutable = () => {
					self.removeFromPages(self.getPage(data.id), false, selectedIndex);
					self.editModeService.stop({ isSave: false });
					if (isFromCatalog) {
						// Catalog should be reopened if opened from catalog, but not on drillbacks / shared links
						showPageCatalog();
					}
					if (options.onClose) {
						options.onClose();
					}
				};

				let subscription: Subscription;
				if (options.close$) {
					subscription = options.close$.subscribe(() => {
						cancelExecutable();
						if (subscription) {
							subscription.unsubscribe();
						}
					});
				}

				const cancelText = isAddable ? this.lang.cancel : this.lang.close;
				const cancelIcon = isAddable ? "close-cancel" : "close";
				const cancelAction = {
					text: cancelText,
					cssClass: "e2e-previewPageCancel",
					icon: cancelIcon,
					execute: () => {
						cancelExecutable();
					},
				};
				actions.push(cancelAction);

				if (isAddable) {
					const isAddEnabled = settings.isPublicPageAddEnabled();
					const addAction = {
						text: this.lang.addPage,
						cssClass: "e2e-previewPageAdd",
						icon: "add",
						execute: () => {
							if (this.isPageAddPossible()) {
								// Remove then add to get correct behavior towards the server
								self.removeFromPages(self.getPage(data.id));
								// Set the server value for isEditable
								page.isEditable = isEditable;
								self.addExistingPage(page, false);
								self.editModeService.stop({ isSave: true });
							}
						},
						isEnabled: isAddEnabled,
					};
					actions.push(addAction);
				}

				const isDuplicatable =
					CommonUtil.isUndefined(options.isDuplicatable) ||
					options.isDuplicatable;
				if (isDuplicatable) {
					const isDuplicateEnabled =
						!page.data.isDynamic &&
						settings.isPublicPageCopyEnabled() &&
						settings.isPrivatePagesEnabled();
					const duplicateAction = {
						text: this.lang.duplicatePage,
						icon: "duplicate",
						execute: () => {
							self.copyPage(page, false, true);
						},
						isEnabled: isDuplicateEnabled,
					} as ICommandBarAction;
					secondaryActions.push(duplicateAction);
				}

				if (options.actions) {
					secondaryActions.push(...options.actions);
				}

				this.editModeService.start({
					mode: EditModes.preview,
					title: previewTitle,
					entityTitle: pageTitle,
					headerColor: headerColor,
					actions: actions,
					secondaryActions: secondaryActions,
				});
				this.add(page, false, options.notifyMingle);
				this.progressService.setBusy(false);
			},
			(response: IOperationResponse) => {
				this.context.setBusy(false);
				// Delay needed so that the dialog does not show up behind the page catalog
				let useDelay = false;
				if (isFromCatalog) {
					// Catalog should not be opened for previews / shared links
					showPageCatalog();
					useDelay = true;
				}
				let message = null;
				const errorCode = response.errorHttpCode
					? parseInt(response.errorHttpCode)
					: -1;
				if (errorCode === ResponseErrorCodes.notFound) {
					message = this.lang.pageNotExist;
				} else if (errorCode === ResponseErrorCodes.forbidden) {
					message = this.lang.errorUnauthorizedPage;
				} else {
					// Show default message
					this.pageService.handleError(response);
				}
				if (message) {
					const self = this;
					// Show Specific message
					if (useDelay) {
						setTimeout(
							() => self.showMessage(self.lang.unableToOpenPage, message),
							1000,
						);
					} else {
						self.showMessage(self.lang.unableToOpenPage, message);
					}
				}
			},
		);
	}

	private onDynamic(page: IPageInstance): void {
		const data = page.data;
		if (!data.isLazy) {
			return;
		}

		this.logDebug("Lazy loading dynamic page: " + data.title);
		const progress = this.progressService;
		progress.setBusy(true);
		this.pageService.getDynamic(data.id).subscribe(
			(response: IPageResponse) => {
				this.handleSystemMessages(response.messageList, true);

				const content = response.content;
				const definitions = content.widgetDefinitions;
				if (definitions) {
					this.widgetService.addDefinitionItems(definitions);
				}

				page.updateLazyContent(content.data);
				this.containerService.raiseSelected(page); // Trigger the selected event to update color etc (might be a temporary fix)
				progress.setBusy(false);
			},
			(resp: IOperationResponse) => {
				progress.setBusy(false);
				this.logError(`Failed to load dynamic page: ${JSON.stringify(resp)}`);
				if (PageUtil.isSecurityMessages(resp.messageList)) {
					this.handleSystemMessages(resp.messageList, true);
				} else {
					this.showError(this.lang.unableToOpenPage, this.lang.unableToLoad);
				}
			},
		);
	}

	private getDialogParent(): ViewContainerRef {
		// TODO Temporary for dialog issues
		return this.containerService.dialogParent;
	}

	private addContextWidget(page: IPage): void {
		const definitions = this.data.widgetDefinitions;
		if (definitions) {
			const definitionItem = definitions[0];
			if (definitionItem) {
				const definition = definitionItem.definition;
				if (definition) {
					const widget: IWidgetData = {
						instanceId: CommonUtil.random(),
						id: definition.widgetId,
						type: definition.type,
						layout: new WidgetLayout(0, 0),
					};
					page.data.content.widgets = [widget];
				}
			} else {
				Log.warning("addContextWidget: Widget Definition does not exist");
			}
		}
	}

	private getNextSortOrder(): number {
		const pages = this.pages;
		if (!pages || pages.length === 0) {
			return 0;
		}

		let sortOrder = pages.length - 1;
		for (const page of pages) {
			sortOrder = Math.max(sortOrder, page.sortOrder);
		}

		return sortOrder + 1;
	}

	private removeDev(
		subject: AsyncSubject<IOperationResponse>,
		page: IPageInstance,
	) {
		this.removeFromPages(page);
		this.devService.savePage(null as IPageData);
		subject.next(new OperationResponse(page.id));
		subject.complete();
	}

	private removeFromPages(
		page: IPageInstance,
		isRefresh = false,
		selectedIndex = -1,
	): void {
		const id = page.id;

		if (!isRefresh) {
			const selected = this.getSelected();
			if (selectedIndex < 0 && selected && selected.id === id) {
				selectedIndex = ArrayUtil.indexByProperty(this.pages, "id", id);
			}
		}

		// Destroy parts that must still be attached to the DOM first
		page.preDestroy();

		// Remove homepage element from DOM. This must be done before destroying the page and
		// removing the page data, otherwise a memory leak will occur.
		const element = $("#" + page.elementId).parent(".homepage");
		PageUtil.destroyHomepageControl(element);

		// TODO Banner in not guaranteed to be the previous element
		const bannerContainerElement = element.prev();
		if (bannerContainerElement && bannerContainerElement.length > 0) {
			bannerContainerElement.remove();
		}
		element.unwrap().remove();

		// Destroy page and all its widgets
		page.destroy();
		ArrayUtil.removeByProperty(this.pages, "id", id);

		for (let i = 0; i < this.data.pages.length; i++) {
			if (this.data.pages[i].data.id === id) {
				this.data.pages.splice(i, 1);
				break;
			}
		}

		if (selectedIndex >= 0) {
			this.selectOnRemove(selectedIndex);
		}

		this.logDebug("Page " + page.data.title + " was removed");

		if (this.pages.length === 0) {
			this.containerService.notifyMingle();
		}
		this.raiseChanged();
	}

	private getSelectedIndex(): number {
		const page = this.getSelected();
		return page ? ArrayUtil.indexOf(this.pages, page) : -1;
	}

	private getSelected(): IPageInstance {
		return this.containerService.selectedPage;
	}

	private notifyBannerWidgets(pageId: string): void {
		const page = this.getPage(pageId);
		const colorString = UIUtil.numberToHexCode(page.data.color, true);

		page.notifyBannerColorChange(colorString);
	}

	private addLast(serverPage: IPage): IPageInstance {
		const subMode = this.getSubMode();
		const page = this.pageFactory.createPage(
			this.context,
			serverPage,
			this.widgetService,
			this.lang,
			this.progressService,
			this.contextService,
			subMode,
		);
		this.addEventHandlers(page);
		this.pages.push(page);
		return page;
	}

	private getSubMode(): SubMode {
		return this.contextService.isMobile ? SubMode.MobilePage : SubMode.Default;
	}

	private savePage(
		options: IPageSaveOptions,
		subject: AsyncSubject<IOperationResponse>,
	) {
		if (options.delayed && !subject) {
			this.queueSavePage(options.page);
			return;
		}

		const page = options.page;
		const pageData = page.createSavePageData();
		if (!this.canSave(pageData.id, pageData)) {
			this.asyncComplete(subject, {});
			return;
		}

		this.pageService.update(pageData).subscribe(
			(r: IOperationResponse) => {
				this.logDebug(`Page saved: ${pageData.title}`);
				if (subject) {
					this.asyncComplete(subject, r);
				}
				if (this.isPendingRefresh) {
					const info = this.pendingRefreshInfo || {};
					this.isPendingRefresh = false;
					this.pendingRefreshInfo = null;
					this.refresh(info);
				}
			},
			(r: IOperationResponse) => {
				this.pageService.handleError(r);
				this.asyncError(subject, r);
			},
		);
	}

	private queueSavePage(page: IPageInstance): void {
		const isPending = ArrayUtil.containsByProperty(
			this.pendingPages,
			"id",
			page.id,
		);
		if (isPending) {
			// This page is already queued for saving
			return;
		}

		this.logDebug("Delaying save of current page");

		this.pendingPages.push(page);
		setTimeout(() => {
			this.saveNextPending();
		}, this.saveDelay);
	}

	private saveNextPending(): void {
		if (this.pendingPages.length === 0) {
			this.logWarning("No pending page to save");
			return;
		}

		const page = this.pendingPages.shift();
		const options = { page: page };
		if (page.isPublished()) {
			this.saveUserData(options);
		} else {
			this.savePage(options, null);
		}
	}

	private canSave(pageId: string, data: any): boolean {
		const json = JSON.stringify(data);
		const existing = this.savedPages[pageId];
		if (existing && existing === json) {
			this.logInfo(
				"canSave: Skipping page save due to identical page content for " +
					pageId,
			);
			return false;
		}

		this.savedPages[pageId] = json;
		return true;
	}

	private showMessageAsync(
		title: string,
		message: string,
		isConfirm?: boolean,
	): Observable<IDialogResult> {
		const subject = new AsyncSubject<any>();

		const resolve = (result: IDialogResult) => {
			subject.next(result);
			subject.complete();
		};

		const buttons = isConfirm
			? [
					{
						text: this.lang.no,
						id: "lm-pg-rm-no",
						click: (e, modal) => {
							modal.close();
							resolve({ button: DialogButtonType.No });
						},
					},
					{
						text: this.lang.yes,
						id: "lm-pg-rm-yes",
						isDefault: true,
						click: (e, modal) => {
							modal.close(true);
							resolve({ button: DialogButtonType.Yes });
						},
					},
			  ]
			: [
					{
						text: this.lang.ok,
						id: "lm-pg-message-ok",
						isDefault: true,
						click: (e, modal) => {
							modal.close();
							resolve({ button: DialogButtonType.Ok });
						},
					},
			  ];

		this.messageService
			.message()
			.title(HtmlUtil.escapeStringForHtml(title))
			.message(HtmlUtil.escapeStringForHtml(message))
			.buttons(buttons)
			.attributes({ name: "id", value: "lm-pg-message" })
			.open();

		return subject.asObservable();
	}

	private addEventHandlers(page: IPageInstance) {
		page.changed().on((info: IPageChangedInfo) => {
			if (!info || !info.page) {
				return;
			}

			// Check edit modes where save should be skipped
			const service = this.editModeService;
			if (
				service.containsMode(EditModes.page) ||
				service.containsMode(EditModes.widget)
			) {
				// Don't save anything here when in publish page / widdget mode for now.
				// The page will be saved if it is published.
				return;
			}

			const delayed = info.delayed !== false; // Delay by default

			if (page.isPublished()) {
				this.saveUserData({ page: page, delayed: delayed });
				return;
			}

			const options: IPageSaveOptions = { page: info.page };
			if (info.layoutChanged) {
				const subject = new AsyncSubject<IOperationResponse>();
				this.savePage(options, subject);
				subject.asObservable().subscribe(
					() => {
						// Nothing to do when successful. Layout is reverted on error by refreshing page.
					},
					() => {
						this.refresh();
					},
				);
			} else {
				options.delayed = delayed;
				this.savePage(options, null);
			}
		});
	}

	private getPrimaryPage(): IPageInstance {
		return ArrayUtil.itemByPredicate(
			this.pages,
			(p) => p.isPrimary,
		) as IPageInstance;
	}

	private saveUserData(options: IPageSaveOptions) {
		if (options.delayed) {
			this.queueSavePage(options.page);
			return;
		}

		const page = options.page;
		const data = page.getWidgetUserSettings();
		if (!this.canSave(page.id, data)) {
			return;
		}

		// Save the widget user data in the settings object
		if (page.setWidgetUserSettings(data)) {
			this.pageService
				.updateConnectionSettings(page.data.id, page.settings)
				.subscribe(
					(response: IOperationResponse) => {
						// Nothing to do for now
					},
					(r: IOperationResponse) => {
						this.widgetService.handleError(r);
					},
				);
		}
	}

	/**
	 * Selects the page with this index or one below if index is out of range
	 */
	private selectOnRemove(index: number) {
		if (this.pages.length === 0) {
			this.containerService.select(null);
		} else if (0 <= index && index < this.pages.length) {
			this.containerService.select(this.pages[index].id);
		} else {
			this.containerService.select(this.pages[index - 1].id);
		}
	}

	private onPageCreated(response: IPageResponse, startEditMode?: boolean) {
		const page = response.content;
		this.add(page, false);
		if (startEditMode) {
			this.editModeService.start({
				mode: EditModes.layout,
				title: this.lang.editingPageLayout,
			});
		}
		this.logDebug("Created page: " + page.data.title);
	}

	private raiseChanged(): void {
		this.containerService.raiseChanged();
	}

	/**
	 * Get a value that indicates if a new page can be added.
	 *
	 * @param showDialog true to show a message dialog if a page cannot be added
	 * @ return true if a new page can be added or false if the user has reached the max page count
	 */
	private isPageAddPossible(showDialog = true): boolean {
		const lang = this.lang;
		const settings = this.context.settings;
		let userPageCount = this.getUserPageCount();

		// Fix for preview page since a page is temporarily added in that mode, causing misleading page count
		if (this.editModeService.isMode("preview")) {
			userPageCount--;
		}

		const maxCount = settings.getMaxUserPageCount();
		if (userPageCount >= maxCount) {
			if (showDialog) {
				this.showMessage(
					lang.unableToAddPage,
					lang.format(lang.maxPageCountMessage, maxCount),
				);
			}
			return false;
		}
		return true;
	}

	private getCopyTitle(page: IPage): string {
		let title = page.title || page.data.title;

		// Handle max length
		const length = title.length;
		const copySuffixLength =
			this.lang.format(this.lang.pageCopyTitle, title).length - length;
		if (length + copySuffixLength > Constants.pageTitleLength) {
			title = title.substr(
				0,
				length + (Constants.pageTitleLength - length) - (copySuffixLength + 3),
			);
			title += "...";
		}
		return title;
	}
}
