import { Injectable, NgZone, ViewContainerRef } from "@angular/core";
import { SohoContextualActionPanelService } from "@infor/sohoxi-angular";
import { CommonUtil, Log } from "lime";
import { Observable, ReplaySubject } from "rxjs";
import { ContextService, DataService } from "../service";
import {
	AdminPages,
	Constants,
	IAdminToggle,
	IInstanceEvent,
	IMingleContext,
	IMissingPage,
	IPageContainer,
	IPageInstance,
	IShortcutContextData,
	IStringMap,
	ResponseErrorCodes,
	UIUtil,
} from "./core";
import { CoreBase, InstanceEvent } from "./runtime";
import { LazyTypeService, ProgressService } from "./service";

export interface IRefreshInfo {
	isFull?: boolean;
	pageId?: string;
}

@Injectable({
	providedIn: "root",
})
export class ContainerService extends CoreBase {
	container: IPageContainer;
	selectedPage: IPageInstance;
	dialogParent: ViewContainerRef;
	private favoriteMessagePending = false;

	private containerSubject = new ReplaySubject<IPageContainer>(1);
	readonly container$: Observable<IPageContainer> =
		this.containerSubject.asObservable();

	private selectedSubject = new ReplaySubject<IPageInstance>(1);
	readonly selected$: Observable<IPageInstance> =
		this.selectedSubject.asObservable();

	private changedSubject = new ReplaySubject<IPageContainer>(1);
	readonly changed$: Observable<IPageContainer> =
		this.changedSubject.asObservable();

	private refreshSubject = new ReplaySubject<IRefreshInfo>(1);
	readonly refresh$: Observable<IRefreshInfo> =
		this.refreshSubject.asObservable();

	private adminSubject = new ReplaySubject<IAdminToggle>(1);
	readonly admin$: Observable<IAdminToggle> = this.adminSubject.asObservable();

	private missingPageSubject = new ReplaySubject<IMissingPage>(1);
	readonly missingPage$: Observable<IMissingPage> =
		this.missingPageSubject.asObservable();

	private showWelcomeSubject = new ReplaySubject<boolean>(1);
	readonly showWelcome$: Observable<boolean> =
		this.showWelcomeSubject.asObservable();

	private mobileWidgetEvent = new InstanceEvent<IMingleContext>();
	private contextParameters: IStringMap;
	private myPagesOpen = false;
	private isAdminOpened = false;
	private isAdminDisabled = false;
	private readonly isStandard;
	private isRefreshing = false;

	/**
	 * Last mobile Mingle Context used for the lazy loaded module to check for
	 * a message that it might have missed as it cannot register on events until it is loaded.
	 */
	private lastmobileMingleContext: IMingleContext = null;

	constructor(
		private readonly contextService: ContextService,
		private readonly dataService: DataService,
		private readonly progressService: ProgressService,
		private readonly capService: SohoContextualActionPanelService,
		private readonly lazyTypeService: LazyTypeService,
	) {
		super("ContainerService");
		this.isStandard = contextService.isStandard;

		progressService.busyChanged().on((v) => {
			this.updateWelcome();
		});
	}

	getContainer(): IPageContainer {
		return this.container;
	}

	updateContainer(container: IPageContainer): void {
		this.container = container;
		this.containerSubject.next(container);
		this.updateWelcome();
	}

	getSelectedPageId(): string {
		const page = this.selectedPage;
		return page ? page.id : null;
	}

	hasPages(): boolean {
		const container = this.container;
		return container && container.hasPages();
	}

	hasError(): boolean {
		const container = this.container;
		return !!(container && container.errorMessage);
	}

	showAddPage(): void {
		if (this.isStandard) {
			const container = this.container;
			if (container) {
				container.showAddPage(this.dialogParent, true);
			}
		}
	}

	raiseChanged(): void {
		this.changedSubject.next(this.container);
		this.updateWelcome();
	}

	raiseSelected(page: IPageInstance): void {
		this.selectedSubject.next(page);
	}

	raiseMissingPage(missingPage: IMissingPage): void {
		this.missingPageSubject.next(missingPage);
	}

	mobileWidgetSelected(): IInstanceEvent<IMingleContext> {
		return this.mobileWidgetEvent;
	}

	raiseMobileWidgetSelected(mingleContext: IMingleContext): void {
		if (Log.isDebug()) {
			this.logDebug("raiseMobileWidgetSelected");
		}
		this.lastmobileMingleContext = mingleContext;
		this.mobileWidgetEvent.raise(mingleContext);
	}

	/**
	 * Used when there is a favorite context message received, that is being handled.
	 */
	getFavoriteMessagePending(): boolean {
		return this.favoriteMessagePending;
	}

	/**
	 *
	 * @param value Set when there is an incoming message
	 */
	setFavoriteMessagePending(value: boolean) {
		this.favoriteMessagePending = value;
	}

	/**
	 * Last mobile Mingle Context used for the lazy loaded module to check for
	 * a message that it might have missed as it cannot register on events until it is loaded.
	 */
	consumePreviousMobileEvent(): IMingleContext {
		const context = this.lastmobileMingleContext;
		this.lastmobileMingleContext = null;
		return context;
	}

	openMyPages(viewRef: ViewContainerRef, ngZone: NgZone): void {
		if (this.isStandard && !this.myPagesOpen) {
			this.myPagesOpen = true;

			this.progressService.setBusy(true);
			this.lazyTypeService.loadLazyModule().then(({ MyPagesComponent }) => {
				const dialog = this.capService
					.contextualactionpanel(MyPagesComponent, viewRef)
					.modalSettings({
						trigger: "immediate",
						id: "lm-mypages-cap",
					})
					.initializeContent(false)
					.afterClose(() => {
						ngZone.run(() => (this.myPagesOpen = false));
					});

				dialog
					.apply((component: any) => {
						component.dialog = dialog;
					})
					.open();
			});
		}
	}

	isMyPagesOpen(): boolean {
		return this.myPagesOpen;
	}

	showAdmin(page?: AdminPages): void {
		if (this.isStandard && !this.isAdminDisabled) {
			this.isAdminOpened = true;
			this.raiseAdmin({ isHide: false, isClose: false, page: page });
		}
	}

	hideAdmin(page: AdminPages, notifyMingle = true): void {
		if (this.isAdminOpened) {
			this.raiseAdmin({ isHide: true, isClose: false, page: page });
			if (notifyMingle) {
				this.notifyMingle();
			}
		}
	}

	closeAdmin(): void {
		if (this.isAdminOpened) {
			this.isAdminOpened = false;
			this.raiseAdmin({ isHide: false, isClose: true });
			this.notifyMingle();
		}
	}

	disableAdmin(): void {
		this.isAdminDisabled = true;
		this.closeAdmin();
	}

	isAdminOpen(): boolean {
		return this.isAdminOpened;
	}

	sendShortcutContext(data: IShortcutContextData) {
		if (this.isLegacyContext()) {
			return;
		}

		this.logInfo("sendShortcutContext " + JSON.stringify(data));
		const client = infor.companyon.client;
		client.sendMessage("setShortcutContext", data);
	}

	notifyMingle(adminPage?: AdminPages): void {
		const publishFavoriteContext =
			this.contextService.isMobile || this.contextService.isStandard;
		if (!publishFavoriteContext) {
			return;
		}

		// Enable bookmarking of a page and admin in Ming.le by sending the setShortcutContext message
		if (adminPage) {
			const context: IMingleContext = {
				type: Constants.shortcutTypeAdmin,
				id: `${adminPage}`,
			};
			const data: IShortcutContextData = {
				name: `${UIUtil.splitCamelCase(
					AdminPages[adminPage],
				)} - Homepages Administration`,
				absoluteURL: "false",
				shortcutContext: context,
			};
			this.sendShortcutContext(data);
		} else {
			const page = this.selectedPage;
			const name = page ? page.title : "";
			const description = page ? page.description : "";
			const id = page ? page.id : "";

			const source = this.contextService.getContext().getSocialUser();

			const context: IMingleContext = {
				type: Constants.shortcutTypePage,
				id: id,
				source: source,
			};
			const data = {
				name: name,
				description: description,
				absoluteURL: "false",
				shortcutContext: context,
			};
			this.sendShortcutContext(data);

			if (page) {
				// Enable sharing of published pages in Ming.le by sending the inforBusinessContext message.
				// An empty entities array is used for private pages since those cannot currently be shared.
				const logicalId = this.contextService.logicalId;
				let entities;

				if (page.isPublished()) {
					const drillback = "?LogicalId=" + logicalId + "&page=" + id;
					entities = [
						{
							entityType: "Homepage",
							id1: name, // Set id1 to name to display something readable for the link
							name: name,
							description: description,
							drillbackURL: drillback,
						},
					];
				} else {
					entities = [];
				}
				const businessContext = {
					screenId: "homepages_Page",
					logicalId: logicalId,
					entities: entities,
					contextId: CommonUtil.random(),
					originatingTime: new Date().getTime(),
				};
				const client = infor.companyon.client;
				client.sendMessage("inforBusinessContext", businessContext);
			}
		}
	}

	select(pageId: string, notifyMingle = true): boolean {
		const container = this.container;
		if (!container) {
			return;
		}

		if (!pageId) {
			this.selectedPage = null;
			this.raiseSelected(null);
			return false;
		}

		let selectedPage = this.container.getPage(pageId);
		if (!selectedPage) {
			// This happens when the currently selected page has been deleted but the users UI hasn't been updated (see LIME-814).
			// In that case we set the selected pages to the first in the array if any pages exist.
			const pages = this.container.pages;
			if (pages.length > 0) {
				selectedPage = pages[0];
			} else {
				return false;
			}
		}

		const previousPage = this.selectedPage;
		if (previousPage) {
			previousPage.hide();
		}

		this.selectedPage = selectedPage;
		this.raiseSelected(selectedPage);
		selectedPage.show();

		if (notifyMingle) {
			try {
				this.notifyMingle();
			} catch (ex) {
				this.logError("Failed to notify Ming.le", ex);
			}
		}
		return true;
	}

	refresh(info: IRefreshInfo) {
		this.isRefreshing = true;
		const container = this.container;
		const page = this.selectedPage;
		let pageId =
			container && container.recentlyPublishedPageId
				? container.recentlyPublishedPageId
				: null;

		if (pageId) {
			// Page has just been published and only ID exists in container.
			container.recentlyPublishedPageId = null;
		} else if (info.pageId) {
			pageId = info.pageId;
		} else if (page) {
			pageId = page.id;
		}

		let isFull = info && info.isFull;
		if (
			!isFull &&
			(!container || container.errorMessage || !this.selectedPage)
		) {
			// For case where when container failed to load and "Refresh" button appears, or when user has no pages, full refresh of startpage is needed
			isFull = true;
		}

		if (isFull) {
			const responseCode = this.dataService.getLastHttpResponseCode();
			const errorCodes = ResponseErrorCodes;

			// Unauthorized codes means a hard refresh is required.
			// Undefined means that a redirect (302, 303, 307) is ordered which also means that a hard refresh is required.
			this.logDebug(
				"[Refresh] Last HTTP response status code: " + responseCode,
			);
			if (
				responseCode === errorCodes.unauthorized ||
				responseCode === errorCodes.undefined
			) {
				// Hard refresh.
				document.location.reload();
				return;
			}
		}
		if (container) {
			container.removeAllPagesFromClient();
			container.destroy();
		}
		info.isFull = isFull;
		info.pageId = pageId;
		this.refreshSubject.next(info);

		this.isRefreshing = false;
	}

	setContextParameters(parameters: IStringMap): void {
		this.contextParameters = parameters;
	}

	getContextParameters(): IStringMap {
		return this.contextParameters;
	}

	private updateWelcome(): void {
		const showWelcome = !(
			this.hasPages() ||
			this.hasError() ||
			this.progressService.isBusy() ||
			this.isRefreshing
		);
		if (showWelcome) {
			this.logDebug("updateWelcome: " + showWelcome);
		}
		this.showWelcomeSubject.next(showWelcome);
	}

	private raiseAdmin(toggle: IAdminToggle): void {
		this.adminSubject.next(toggle);
	}

	private isLegacyContext(): boolean {
		return this.container && this.container.isLegacyContext;
	}

	private getPageType(page: IPageInstance): string {
		if (page.isStandard()) {
			return "standard";
		}
		if (page.isDynamic()) {
			return "dynamic";
		}
		if (page.isPublished()) {
			return "published";
		}
		return "private";
	}

	private isMandatory(page: IPageInstance): string {
		return page.isMandatory === true ? "true" : "false";
	}
}
