import {
	Component,
	ComponentRef,
	ElementRef,
	NgZone,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import { ViewTracker } from "@yggdrasil/core";
import {
	ContainerService,
	ContextService,
	CoreBase,
	EditModeService,
	EditModes,
	IContext,
	IEditMode,
	IEditableWidget,
	IPageInstance,
	LanguageService,
	PageUtil,
	UIUtil,
} from "lime/core";
import { Subscription } from "rxjs";
import { PageComponent } from "../page/page";

@Component({
	selector: "lm-page-list",
	templateUrl: "./page-list.html",
	styles: [
		`
			.area-inactive {
				opacity: 0.3;
			}
		`,
	],
})
export class PageListComponent extends CoreBase implements OnInit {
	@ViewChild("listView", { static: true })
	listView: ElementRef;

	@ViewChild("contentView", { read: ViewContainerRef, static: true })
	contentView: ViewContainerRef;

	readonly isLegacyContext: boolean;

	lang: ILanguageLime;
	context: IContext;
	memosVisible: boolean;
	memoColor: string;
	memoDuration: number;
	memoAnimation: boolean;
	publishingWidget = false;

	private page: IPageInstance;
	private unsubscribers: Array<Function> = [];
	private selectedSubscription: Subscription;
	private viewTracker?: ViewTracker;

	constructor(
		private zone: NgZone,
		languageService: LanguageService,
		contextService: ContextService,
		public editModeService: EditModeService,
		public containerService: ContainerService,
	) {
		super("PageListComponent");

		this.lang = languageService.getLanguage();
		this.context = contextService.getContext();
		this.isLegacyContext = contextService.isLegacyContext;

		this.selectedSubscription = containerService.selected$.subscribe((p) => {
			// Without this timeout the dev container won't render the page in the DOM
			setTimeout(() => {
				this.update(p);
			}, 0);
		});

		if (contextService.isStandard) {
			this.unsubscribers.push(
				editModeService.started().on((editMode: IEditMode) => {
					if (editMode.mode === EditModes.layout && this.page) {
						this.startEditLayout();
						this.page.toggleEditMode(true);
					} else if (editMode.mode === EditModes.widget) {
						this.publishingWidget = true;
					}
				}),
			);

			this.unsubscribers.push(
				editModeService.stopped().on((editMode: IEditMode) => {
					if (editMode.mode === EditModes.layout && this.page) {
						this.stopEditLayout(editMode);
						this.page.toggleEditMode(false);
					} else if (editMode.mode === EditModes.widget) {
						this.publishingWidget = false;
					}
				}),
			);

			this.unsubscribers.push(
				editModeService.contextChanged().on((info) => {
					if (info.memoConfig) {
						this.updateMemoArea(info.memoConfig);
					}
				}),
			);
		}
	}

	ngOnInit(): void {
		this.containerService.dialogParent = this.contentView;
	}

	private startEditLayout() {
		const control = this.findPageControl(this.page);
		PageUtil.updateLayout(this.page.widgets);
		PageUtil.destroyHomepageControl(control);
	}

	private stopEditLayout(editMode: IEditMode) {
		const page = this.page;
		const control = this.findPageControl(page);
		const isAnimationEnabled = this.context.settings.isAnimationEnabled();
		PageUtil.addHomepageControl(control, isAnimationEnabled);

		if (!editMode.isSave) {
			setTimeout(() => {
				PageUtil.refreshHomepageLayout(control, isAnimationEnabled);
			}, 1);
			return;
		}

		page.widgetsAddedCount = 0;
		this.updateContent(page);
		const currentMode = this.editModeService.getCurrent();
		const isPageEditActive =
			currentMode != null &&
			currentMode.isActive &&
			currentMode.mode === EditModes.page;
		page.updateWidgets(editMode.result as IEditableWidget[], !isPageEditActive);

		if (isPageEditActive) {
			setTimeout(() => {
				page.notifyPublishingMode();
			}, 500);
		}
	}

	private createContent(
		view: ViewContainerRef,
		page: IPageInstance,
	): ComponentRef<PageComponent> {
		const ref = view.createComponent(PageComponent);
		page.componentRef = ref;
		const instance = ref.instance;
		instance.page = page;
		return ref;
	}

	private updateContent(page: IPageInstance): ComponentRef<PageComponent> {
		let componentRef = page.componentRef;
		if (!componentRef) {
			componentRef = this.createContent(this.contentView, page);
		}

		setTimeout(() => {
			const pageComponent = componentRef.instance as PageComponent;
			pageComponent.updateBannerVisibility();
		}, 1);

		return componentRef;
	}

	private findPageControl(page: IPageInstance): JQuery {
		return this.findContent(page).parent(".homepage");
	}

	private findContent(page: IPageInstance): JQuery {
		return $(this.listView.nativeElement).find("#" + page.elementId);
	}

	private update(page: IPageInstance): void {
		if (!page) {
			if (this.page) {
				// Remove homepage container
				const componentRef = this.page.componentRef;
				if (componentRef) {
					componentRef.destroy();
				}
				this.page = null;
			}
			this.memosVisible = false;
			return;
		}

		this.updateMemoArea(page);
		// TODO Show / Hide using Angular instead of jQuery

		// TODO Cache jQuery element?
		const element = $(this.listView.nativeElement);

		this.page = page;
		const visiblePages = element.find(".homepage");
		if (visiblePages.length > 0) {
			visiblePages.hide();
			// Note: Angular component name not css class
			PageUtil.detachHomepageEvents(visiblePages.not("lm-banner-container"));
		}

		const pageElement = page.getElement();
		if (pageElement && pageElement.length > 0) {
			const hiddenPages = pageElement.find(".homepage");
			hiddenPages.show();
			const isAnimationsEnabled = this.context.settings.isAnimationEnabled();
			// Note: Angular component name not css class
			PageUtil.attachHomepageEvents(
				hiddenPages.not("lm-banner-container"),
				true,
				isAnimationsEnabled,
			);

			const ref = page.componentRef;
			if (ref) {
				const pageComponent = ref.instance as PageComponent;
				pageComponent.updateBannerVisibility();
			}
			return;
		}

		this.zone.run(() => {
			this.updateContent(page);
		});
	}

	private updateMemoArea(memoConfig: Partial<IPageInstance>) {
		if (memoConfig.enableMemo) {
			this.memosVisible = true;
			this.memoColor = UIUtil.numberToMemoHexCode(memoConfig.data.color);
			this.memoDuration = memoConfig.memoDuration || 0;
			this.memoAnimation = !memoConfig.disableAnimation;
		} else {
			this.memosVisible = false;
		}
	}
}
