import { Component, Input } from "@angular/core";
import { ContextService } from "lime/core";
import { IMaintenanceItem } from "../../base/core";

@Component({
	selector: "lm-maintenance-entity",
	styleUrls: ["./maintenance-entity.scss"],
	template: `
		<svg class="icon" aria-hidden="true" focusable="false">
			<use xlink:href="#lime-icon-maintenance" />
		</svg>
		<p class="maintenance-title">{{ item.title }}</p>
		<p *ngIf="item.optionalMessage" class="maintenance-optional-message">
			{{ item.optionalMessage }}
		</p>
		<p *ngIf="!item.link" class="maintenance-message">{{ item.message }}</p>
		<p *ngIf="item.link" class="maintenance-message">
			{{ splitMessage.beforeLink }}
			<a class="hyperlink" (click)="launch(item.link)">{{ item.link }}</a>
			{{ splitMessage.afterLink }}
		</p>
	`,
})
export class MaintenanceEntityComponent {
	@Input() item: IMaintenanceItem;

	constructor(private contextService: ContextService) {}

	get splitMessage(): { beforeLink: string; afterLink: string } {
		if (!this.item.message || !this.item.link) {
			return { beforeLink: "", afterLink: "" };
		}
		const linkPlaceholder = "{0}";
		const [beforeLink, afterLink] = this.item.message.split(linkPlaceholder);
		return { beforeLink, afterLink };
	}

	launch(url: string) {
		this.contextService.getContext().launch({ url });
	}
}
