import {
	Directive,
	ElementRef,
	EventEmitter,
	Input,
	Output,
} from "@angular/core";
import { combineLatest, fromEvent } from "rxjs";
import { filter, map, share } from "rxjs/operators";

@Directive({
	selector: "[lm-swipe]",
})
export class SwipeDirective {
	@Output() leftSwipe = new EventEmitter<ISwipeEvent>();
	@Output() rightSwipe = new EventEmitter<ISwipeEvent>();

	/**
	 * Minimum distance (pixels) between touch start and touch end for it to be considered a swipe.
	 */
	@Input() minDistance = 50;

	constructor(private element: ElementRef<HTMLElement>) {}

	ngOnInit() {
		const touchStart$ = fromEvent<TouchEvent>(
			this.element.nativeElement,
			"touchstart",
		);
		const touchEnd$ = fromEvent<TouchEvent>(
			this.element.nativeElement,
			"touchend",
		);
		const swipes$ = combineLatest(touchStart$, touchEnd$).pipe(
			filter(onlySingleTouch),
			filter(onlyOrderedTouch),
			map(touchEventsToSwipe),
			filter(isHorizontal),
			filter(isOverDistance(this.minDistance)),
			share(),
		);

		swipes$.pipe(filter(isLeftSwipe)).subscribe(this.leftSwipe);

		swipes$.pipe(filter(isRightSwipe)).subscribe(this.rightSwipe);
	}
}

export interface ISwipeEvent {
	startX: number;
	startY: number;
	stopX: number;
	stopY: number;
}

type TouchEventPair = [TouchEvent, TouchEvent];

function onlySingleTouch([startEvent, stopEvent]: TouchEventPair): boolean {
	return startEvent.touches.length === 1 && stopEvent.touches.length === 0;
}

function onlyOrderedTouch([startEvent, stopEvent]: TouchEventPair): boolean {
	return startEvent.timeStamp < stopEvent.timeStamp;
}

function touchEventsToSwipe([
	startEvent,
	stopEvent,
]: TouchEventPair): ISwipeEvent {
	return {
		startX: startEvent.changedTouches[0].pageX,
		startY: startEvent.changedTouches[0].pageY,
		stopX: stopEvent.changedTouches[0].pageX,
		stopY: stopEvent.changedTouches[0].pageY,
	};
}

function isHorizontal(swipe: ISwipeEvent): boolean {
	return horizontalDistance(swipe) > verticalDistance(swipe);
}

function horizontalDistance(swipe: ISwipeEvent): number {
	return Math.abs(swipe.stopX - swipe.startX);
}

function verticalDistance(swipe: ISwipeEvent): number {
	return Math.abs(swipe.stopY - swipe.startY);
}

function totalDistance(swipe: ISwipeEvent): number {
	return Math.sqrt(
		Math.pow(horizontalDistance(swipe), 2) +
			Math.pow(verticalDistance(swipe), 2),
	);
}

const isOverDistance = (distance: number) => (swipe: ISwipeEvent) => {
	return totalDistance(swipe) > distance;
};

function isLeftSwipe(swipe: ISwipeEvent) {
	return swipe.startX > swipe.stopX;
}

function isRightSwipe(swipe: ISwipeEvent) {
	return swipe.startX < swipe.stopX;
}
