/**
 * Dependencies:
 * runtime
 * core
 */
import { Injectable } from "@angular/core";
import { EnvironmentInfoMap } from "lime";
import { Observable, Observer, ReplaySubject } from "rxjs";
import { ICompanyonMessage, ICompanyonService } from "./core";
import { CoreBase } from "./runtime";

@Injectable({
	providedIn: "root",
})
export class CompanyonService extends CoreBase implements ICompanyonService {
	private readonly parentUrlSubject = new ReplaySubject<string>(1);
	private readonly environmentSubject = new ReplaySubject<EnvironmentInfoMap>(
		1,
	);
	private parentUrl: string;
	private environment: EnvironmentInfoMap;

	constructor() {
		super("CompanyonService");
	}

	receive$<T>(messageName: string): Observable<T> {
		this.logDebug(`receive$ called for message '${messageName}'`);
		return Observable.create((observer: Observer<T>) => {
			try {
				const listenerId = `${Math.floor(
					Math.random() * Number.MAX_SAFE_INTEGER,
				)}`;
				const unregister = () => this.clientUnregister(messageName, listenerId);
				this.clientRegister(
					messageName,
					(data) => {
						observer.next(data);
						if (this.isDebug()) {
							this.logDebug(
								`Listener with id ${listenerId} received '${messageName}': ${JSON.stringify(
									data,
								)}`,
							);
						}
					},
					listenerId,
				);
				return unregister;
			} catch (err) {
				this.logError(`Failed to register handler for ${messageName}`);
				observer.error(err);
			}
		});
	}

	send$<T>(message: ICompanyonMessage<T>): Observable<void> {
		if (this.logDebug) {
			this.logDebug(`send$ called with message '${JSON.stringify(message)}'`);
		}
		return Observable.create((observer: Observer<void>) => {
			try {
				this.clientSend(message.name, message.data);
				observer.next(void 0);
				observer.complete();
			} catch (err) {
				this.logError(`Failed to send message '${message.name}'`);
				observer.error(err);
			}
		});
	}

	send<T>(message: ICompanyonMessage<T>): void {
		this.clientSend(message.name, message.data);
	}

	getEnvironmentInformation(): Observable<EnvironmentInfoMap> {
		if (!this.environment) {
			infor.companyon.client.getEnvironmentInformation(
				(environment: EnvironmentInfoMap) => {
					this.environment = environment;
					this.environmentSubject.next(environment);
				},
			);
		}
		return this.environmentSubject.asObservable();
	}

	getParentUrl(): Observable<string> {
		if (!this.parentUrl) {
			infor.companyon.client.getInforMingleHomeUrl((url) => {
				this.parentUrl = url;
				this.parentUrlSubject.next(url);
			});
		}
		return this.parentUrlSubject.asObservable();
	}

	private clientSend(name: string, data?: {}): void {
		if (this.isDebug()) {
			this.logDebug(`Sending message '${name}': ${JSON.stringify(data)}`);
		}
		infor.companyon.client.sendMessage(name, data);
	}

	private clientRegister(
		name: string,
		handler: Function,
		namespace?: string,
	): void {
		this.logDebug(`Registering handler for '${name}' (ns:${namespace})`);
		infor.companyon.client.registerMessageHandler(name, handler, namespace);
	}

	private clientUnregister(name: string, namespace?: string) {
		this.logDebug(`Unregistering handler for '${name}' (ns:${namespace})`);
		infor.companyon.client.unRegisterMessageHandler(name, namespace);
	}
}
