import {
	ChangeDetectionStrategy,
	Component,
	Input,
	OnInit,
} from "@angular/core";
import { IWidgetContext, IWidgetInstance } from "lime";
import {
	DynamicColorType,
	IDynamicContainer,
	IDynamicItemExtended,
	UIUtil,
} from "../../base/core";

// Component for the shortcut content layout (icon and text)
@Component({
	changeDetection: ChangeDetectionStrategy.OnPush,
	selector: "lm-dyn-sc-icon",
	template: `
		<span
			*ngIf="item.i"
			class="dyn-sc-icon"
			[style.background-color]="getHexColor()">
			<svg class="icon" aria-hidden="true" focusable="false">
				<use [attr.xlink:href]="item.i" />
			</svg>
		</span>
	`,
	styles: [
		`
			.dyn-sc-icon {
				border-radius: 50%;
				transition: box-shadow 0.2s;
				box-shadow: none;
				display: flex;
				justify-content: center;
				align-items: center;
				height: 55px;
				width: 55px;
			}

			.dyn-sc-icon > .icon {
				height: 19px;
				color: white;
			}

			.icon-text {
				font-size: 14px;
				text-align: center;
			}
		`,
	],
})
export class DynamicShortcutIconComponent {
	@Input() item: IDynamicItemExtended;

	getHexColor() {
		const colorType = this.item.clt ? this.item.clt : DynamicColorType.Custom;
		const colorNumber = this.item.cl ? this.item.cl : 0;
		return colorType === DynamicColorType.InheritPage
			? UIUtil.numberToHexCode(colorNumber)
			: UIUtil.numberToHexCodeExtended(colorNumber);
	}
}

@Component({
	changeDetection: ChangeDetectionStrategy.OnPush,
	selector: "lm-dyn-shortcuts",
	template: `
		<div class="dyn-shortcuts">
			<div class="shortcut-wrapper" *ngFor="let item of items">
				<div (click)="onClick(item.u)" class="shortcut-content">
					<lm-dyn-sc-icon [item]="item"></lm-dyn-sc-icon>
					<p class="lm-truncate-text icon-text">
						<span>{{ item.t }}</span>
					</p>
				</div>
			</div>
		</div>
	`,
	styles: [
		`
			:host-context(.double-width:not(.to-single), .to-double)
				.shortcut-wrapper {
				width: calc(100% * (1 / 5));
			}

			:host-context(.triple-width:not(.to-single):not(.to-double), .to-triple)
				.shortcut-wrapper {
				width: calc(100% * (1 / 7));
			}

			:host-context(.quad-width:not(.to-single):not(.to-double):not(.to-triple))
				.shortcut-wrapper {
				width: calc(100% * (1 / 9));
			}

			.dyn-shortcuts {
				padding: 10px 10px;
				height: 100%;
			}

			.shortcut-wrapper {
				display: inline-block;
				height: 100px;
				padding: 10px 5px;
				width: calc(100% * (1 / 2));
			}

			.shortcut-content {
				cursor: pointer;
				max-width: 100%;
			}

			.shortcut-content p {
				max-width: 100%;
			}

			.shortcut-content:hover ::ng-deep .dyn-sc-icon {
				box-shadow: 0 0 0 9px rgba(255, 255, 255, 0.25) inset !important;
			}

			.icon-text {
				padding-top: 5px;
				font-size: 14px;
				text-align: center;
			}

			lm-dyn-sc-icon {
				margin-left: auto;
				margin-right: auto;
				display: block;
				width: 55px;
			}
		`,
	],
})
export class DynamicShortcutsComponent implements OnInit {
	@Input() widgetContext: IWidgetContext;
	@Input() widgetInstance: IWidgetInstance;

	items: IDynamicItemExtended[] = [];

	ngOnInit() {
		const settings = this.widgetContext.getSettings();
		const container = settings.get<IDynamicContainer>("lm_container");
		if (container.st && container.its) {
			this.items = container.its;
		}
	}

	onClick(url: string) {
		this.widgetContext.launch({ url: url });
	}
}
