import {
	IWidgetDefinition,
	IWidgetProvider,
	IWidgetRegistration,
} from "../../base/core";
import { ClientConfiguration, CoreBase } from "../../base/runtime";
import { WidgetUtil } from "../../widget/runtime";
import { DynamicImageComponent } from "./image";
import { DynamicItemsComponent } from "./items/items";
import { DynamicLinksComponent } from "./links";
import { DynamicShortcutsComponent } from "./shortcuts";
import { DynamicTextComponent } from "./text";

export class DynamicWidgetProvider extends CoreBase implements IWidgetProvider {
	constructor() {
		super("DynamicWidgetProvider");
	}

	getWidgets(): IWidgetRegistration[] {
		this.logDebug("Providing dynamic widgets");

		const widgets = [];
		widgets.push(
			this.createRegistration("infor.lime.dyn.image", DynamicImageComponent),
		);
		widgets.push(
			this.createRegistration("infor.lime.dyn.links", DynamicLinksComponent),
		);
		widgets.push(
			this.createRegistration(
				"infor.lime.dyn.shortcuts",
				DynamicShortcutsComponent,
			),
		);
		widgets.push(
			this.createRegistration("infor.lime.dyn.items", DynamicItemsComponent),
		);
		widgets.push(
			this.createRegistration("infor.lime.dyn.text", DynamicTextComponent),
		);

		return widgets;
	}

	private createRegistration(
		widgetId: string,
		componentType: any,
	): IWidgetRegistration {
		const definition = this.createDefinition(widgetId, componentType);
		definition.getModuleRef = () => {
			// TODO Check why this.moduleRef was undefined
			return ClientConfiguration.appModuleRef;
		};

		return {
			definition: definition,
			module: {
				widgetFactory: () => {
					return { angularConfig: definition.angularConfig };
				},
			},
		};
	}

	private createDefinition(
		widgetId: string,
		componentType: any,
	): IWidgetDefinition {
		const targets = ["banner", "default"];
		const definition = {
			widgetId: widgetId,
			version: "1.0",
			author: "Infor",
			framework: "angular",
			isCatalog: false,
			aotVersion: WidgetUtil.aotVersion,
			sohoVersion: WidgetUtil.sohoVersion,
			targets: targets,
			targetsDef: targets,
		} as IWidgetDefinition;

		(definition as any).angularConfig = {
			componentType: componentType,
			moduleFactory: {}, // Not used but must be set
		};

		return definition;
	}
}
