import {
	Component,
	HostBinding,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoApplicationMenuComponent,
	SohoMessageService,
} from "@infor/sohoxi-angular";
import { IWidgetAction } from "lime";
import {
	AboutService,
	CoreBase,
	IPageInstance,
	IWidgetInfo,
	MobileMode,
	MobileService,
} from "lime/core";
import { combineLatest, Observable, of, Subscription } from "rxjs";
import { catchError, delay, filter, finalize, map, take } from "rxjs/operators";
import { Constants, InforStartMode } from "../../base/core";
import { HttpUtil } from "../../base/runtime";
import { LanguageService } from "../../base/service";

import { WidgetContainerComponent } from "../widget-container/widget-container";

@Component({
	selector: "lm-mobile-container",
	styleUrls: ["./mobile-container.scss"],
	templateUrl: "./mobile-container.html",
})
export class MobileContainerComponent extends CoreBase {
	@HostBinding("class.custom-busy") useCustomBusy = true;

	@ViewChild(SohoApplicationMenuComponent, { static: true })
	appMenu: SohoApplicationMenuComponent;

	widgets$: Observable<IWidgetInfo[]> = this.mobileService.widgetList$;
	pages$: Observable<IPageInstance[]> = this.mobileService.pageList$;
	title$: Observable<string> = this.mobileService.title$;
	isMobileSingle$: Observable<boolean> = this.mobileService.mode$.pipe(
		map((mode) => mode === MobileMode.Widget),
	);

	headerColor$: Observable<string> = this.mobileService.pageColor$;

	hidePageList$: Observable<boolean> = this.mobileService.features$.pipe(
		map((features) => !features.pages),
	);

	hideWidgetList$: Observable<boolean> = this.mobileService.features$.pipe(
		map((features) => !features.widgets),
	);

	hidePageContainer$: Observable<boolean> = combineLatest(
		this.mobileService.mode$,
		this.mobileService.empty$,
	).pipe(map(([mode, empty]) => mode !== MobileMode.Pages || empty.isVisible));

	hideWidgetContainer$: Observable<boolean> = combineLatest(
		this.mobileService.mode$,
		this.mobileService.empty$,
	).pipe(map(([mode, empty]) => mode !== MobileMode.Widget || empty.isVisible));

	showEmptyComponent$: Observable<boolean> = this.mobileService.empty$.pipe(
		map((empty) => empty.isVisible),
	);

	showEmptyPageListPlaceholder$: Observable<boolean> = this.pages$.pipe(
		map((pages) => pages.length === 0),
	);

	showEmptyWidgetListPlaceholder$: Observable<boolean> = this.widgets$.pipe(
		map((widgets) => widgets.length === 0),
	);

	lang: ILanguageLime;
	loadingWidgets: boolean;
	widgetContainer: WidgetContainerComponent;
	isBusy = true;

	private widgetContainerSubscription: Subscription;
	private startupOverlayTimeout: number;
	private startupOverlayTimeMs = 600;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		private mobileService: MobileService,
		private aboutService: AboutService,
		private viewRef: ViewContainerRef,
	) {
		super("MobileContainerComponent", messageService, languageService);
		this.lang = this.languageService.getLanguage();
		this.widgetContainerSubscription = mobileService.widgetContainer$
			.pipe(filter((container) => !!container))
			.subscribe((container) => (this.widgetContainer = container));
	}

	ngAfterViewInit() {
		this.useCustomBusy = true;
		this.appMenu.menuVisibility
			.pipe(take(1))
			.subscribe(() => this.getWidgets());
		this.mobileService.menuVisibility$.subscribe((visible: boolean) => {
			if (!visible) {
				this.appMenu.closeMenu();
			}
		});

		this.mobileService.startupOverlayVisibility$.subscribe(
			(visible: boolean) => {
				this.logInfo(
					"startupOverlayVisibility: Clearing startup overlay, visible: " +
						visible,
				);
				if (!visible) {
					this.logInfo("startupOverlayVisibility: Clearing startup overlay");
					this.isBusy = false;
					this.clearBusyTimeout();
				}
			},
		);

		// Always show busy the first time for 0.5 seconds
		this.logInfo("Turning on overlay");
		this.startupOverlayTimeout = window.setTimeout(() => {
			// This should also be set on first open request
			this.isBusy = false;
			this.logInfo("Turning off overlay");
		}, this.getStartupOverlayTimeMs());
	}

	ngOnDestroy() {
		this.widgetContainerSubscription.unsubscribe();
	}

	openWidget(widgetInfo: IWidgetInfo) {
		this.mobileService.openWidget(widgetInfo).subscribe();
	}

	openPage(page: IPageInstance): void {
		this.mobileService.selectPage(page.id);
		this.appMenu.closeMenu();
	}

	getWidgets() {
		// TODO: It might be better to delegate "busy" handling to MobileService...
		this.loadingWidgets = true;
		this.mobileService
			.listWidgets()
			.pipe(
				delay(1000),
				catchError((error) => {
					this.logError("Failed to list widgets", error);
					return of([]);
				}),
				finalize(() => (this.loadingWidgets = false)),
			)
			.subscribe();
	}

	showAbout() {
		this.aboutService.showAboutDialog(this.viewRef);
	}

	executeAction(action: IWidgetAction) {
		try {
			action.execute();
		} catch (ex) {
			this.logWarning(
				`[${this.widgetContainer.widget.id}] Failed to invoke widget action`,
			);
		}
	}

	showWidgetAbout() {
		this.widgetContainer.showAbout();
	}

	isActionVisible(action: IWidgetAction): boolean {
		return (
			action.isVisible !== false &&
			(!this.requiresConfig || action.isEnabledNotConfigured)
		);
	}

	get showPrimaryAction(): boolean {
		return this.widgetContainer.hasPrimaryAction;
	}

	get primaryAction(): IWidgetAction {
		return this.widgetContainer.primaryAction;
	}

	get primaryActionDisabled(): boolean {
		return this.widgetContainer.primaryAction.isEnabled === false;
	}

	get primaryActionIcon(): string {
		const action = this.primaryAction;
		return action.customIconName || action.standardIconName;
	}

	get widgetActions(): IWidgetAction[] {
		const widget = this.widgetContainer.widget;
		return widget.instance && widget.instance.actions;
	}

	get hasVisibleActions(): boolean {
		return this.widgetContainer.hasVisibleActions;
	}

	get requiresConfig(): boolean {
		return this.widgetContainer.requiresConfig;
	}

	private clearBusyTimeout() {
		let timeout = this.startupOverlayTimeout;
		if (timeout) {
			window.clearTimeout(timeout);
			timeout = null;
		}
	}

	private getStartupOverlayTimeMs(): number {
		const value = HttpUtil.getParameter(Constants.mingleStartMode);
		let result = this.startupOverlayTimeMs;
		if (value === InforStartMode.favoriteContext) {
			result = 1500; // 1,5 sec
			this.logInfo(
				"getStartupOverlayTimeMs: running in favorite context startup mode. Setting overlay to " +
					result,
			);
		}
		return result;
	}
}
