/**
 * Directory file dependency order:
 * context
 * service
 * runtime
 * core
 */

import { IWidgetSettingMetadata } from "lime";
import { IWidgetLayout } from "../base/core";

export interface IWidgetSettingMetadataEx extends IWidgetSettingMetadata {
	definition: IWidgetSettingMetadata;
	id: string;
	label: string;
	value: any;
	/**
	 * Gets or sets a value that indicates if the setting is hidden in the current context.
	 */
	isHidden?: boolean;
	/**
	 * Gets or sets a value that indicates if the setting is read only in the current context.
	 */
	isReadOnly?: boolean;

	/**
	 * Gets or sets a value that indicates if the setting is visble based on isHidden and widget current state
	 * information. Note that this is not necessariy the inverse of isHidden.
	 */
	isVisible?: boolean;

	/**
	 * Gets ir sets a value that indicates if the setting is the first visible settings.
	 */
	isFirst?: boolean;
}

/**
 * Defines the available widget types.
 */
export class WidgetType {
	/**
	 * An inline widget is implemented using aa and AMD module using JavaScript / TypeScript and its content
	 * is added directly in the Homespages DOM.
	 */
	static Inline = "inline";

	/**
	 * An external widgets is an HTML pages loaded in an IFrame using a URL or URL template.
	 */
	static External = "external";
}

export class WidgetLayout implements IWidgetLayout {
	constructor(
		public column?: number,
		public row?: number,
		public columnSpan: number = 1,
		public rowSpan: number = 1,
	) {}

	static isSameCell(a: IWidgetLayout, b: IWidgetLayout): boolean {
		return a.column === b.column && a.row === b.row;
	}

	/**
	 * Gets a value that indicates if widget A is after widget B in the page layout.
	 */
	static isAfter(a: IWidgetLayout, b: IWidgetLayout): boolean {
		return a.row > b.row || (a.row === b.row && a.column > b.column);
	}

	/**
	 * Gets a value that indicates if widget A is before widget B in the page layout.
	 */
	static isBefore(a: IWidgetLayout, b: IWidgetLayout): boolean {
		return a.row < b.row || (a.row === b.row && a.column < b.column);
	}
}
