class IonMetadataService extends CoreBase {
	private configuration: IConfiguration;
	private lang: ILanguageLime;
	private tenantId: string;
	private ionMetadataCache = new IonMetaDataCache();
	// "/products/{logicalIdPrefix}"
	private logicalIdPath = "/products/";
	// "/apisuites/{suiteContext}"
	private suitePath = "/apisuites/";
	// The base path need to add the tenant at a different location then other ION APIs /ionapi/metadata/v1/{tenantid}"
	private basePath = "/ionapi/metadata/v1/";

	constructor(
		configuration: IConfiguration,
		lang: ILanguageLime,
		tenantId: string,
	) {
		super("IonMetadataService");
		this.configuration = configuration;
		this.lang = lang;
		this.tenantId = tenantId;
	}

	getIonApiInfoAsync(
		options: IIonApiInfoOptions,
		widgetId: string,
	): Observable<IIonApiInfo> {
		const subject = new AsyncSubject<IIonApiInfo>();
		const validationError = this.getValidationError(options, widgetId);
		if (validationError != null) {
			const errorInfo: IIonApiInfo = this.createError();
			errorInfo.errorMessage = validationError;
			subject.error(errorInfo);
		} else {
			const products = this.ionMetadataCache.get(options);
			if (products) {
				const result: IIonApiInfo = {
					ionApiProducts: products,
					hasProducts: products.length > 0,
				};
				subject.next(result);
				subject.complete();
			} else {
				this.callMetadata(options, widgetId).subscribe(
					(ionAPIInfo: IIonApiInfo) => {
						subject.next(ionAPIInfo);
						subject.complete();
					},
					(ionError: IIonApiInfo) => {
						subject.error(ionError);
					},
				);
			}
		}

		return subject.asObservable();
	}

	private getValidationError(options: IIonApiInfoOptions, source: string) {
		if (
			StringUtil.isNullOrWhitespace(options.suiteContext) &&
			StringUtil.isNullOrWhitespace(options.productLogicalId)
		) {
			const message = "suiteContext or productLogicalId has to be set";
			this.logError(
				"Invalid input from widget with id: " + source + " " + message,
			);
			return message;
		}
		return null;
	}

	private callMetadata(
		options: IIonApiInfoOptions,
		source: string,
	): Observable<IIonApiInfo> {
		const subject = new AsyncSubject<IIonApiInfo>();
		const isSuite = !StringUtil.isNullOrWhitespace(options.suiteContext);
		let url: string = this.basePath + this.tenantId;
		if (isSuite) {
			url = url + this.suitePath + options.suiteContext;
		} else {
			url = url + this.logicalIdPath + options.productLogicalId;
		}
		this.configuration
			.executeIonApiAsync(
				{ url: url, method: "GET", cache: false, enableNonTenantUrl: true },
				source,
			)
			.subscribe(
				(response) => {
					const result: IIonApiInfo = isSuite
						? this.parseSuiteResponse(
								response as IIonApiResponse<IIonSuiteContext[]>,
						  )
						: this.parseLogicalIdResponse(
								response as IIonApiResponse<IIonLogicalIdResponse>,
						  );
					// Store the result in the cache
					this.ionMetadataCache.put(options, result);
					subject.next(result);
					subject.complete();
				},
				(ex) => {
					const errorInfo: IIonApiInfo = this.createError();
					this.logError(
						"Failed to call ION API metadata " +
							url +
							", " +
							JSON.stringify(ex || ""),
					);
					subject.error(errorInfo);
				},
			);
		return subject.asObservable();
	}

	private parseSuiteResponse(
		response: IIonApiResponse<IIonSuiteContext[]>,
	): IIonApiInfo {
		try {
			const products: IIonApiProduct[] = [];
			if (response && response.data) {
				const items: IIonSuiteContext[] = response.data;
				if (items) {
					items.forEach((contextItem) => {
						const suiteContext = contextItem.suiteContext;
						const typeName = contextItem.type;
						if (contextItem.products) {
							contextItem.products.forEach((item) => {
								this.createAndAddFromProduct(
									item,
									products,
									typeName,
									suiteContext,
								);
							});
						}
					});
				}
				const result: IIonApiInfo = {
					ionApiProducts: products,
					hasProducts: products.length > 0,
				};
				return result;
			}
		} catch (ex) {
			this.logError("parseSuiteResponse: failed + " + JSON.stringify(ex || ""));
			return this.createError();
		}
	}

	private createAndAddFromProduct(
		item: IIonProductsEntity,
		products: IIonApiProduct[],
		typeName: string,
		suiteContext: string,
	) {
		if (item) {
			const product: IIonApiProduct = {
				description: item.suiteDescription,
				logicalIdPrefix: item.logicalIdPrefix,
				name: item.suiteName,
				typeName: typeName,
				suiteContext: suiteContext,
			};
			products.push(product);
		}
	}
	private parseLogicalIdResponse(
		response: IIonApiResponse<IIonLogicalIdResponse>,
	): IIonApiInfo {
		try {
			const products: IIonApiProduct[] = [];
			if (response && response.data) {
				const data = response.data;
				const logicalIdPrefix = data.logicalIdPrefix;
				if (data.apiSuites) {
					data.apiSuites.forEach((item) => {
						this.createAndAddFromSuite(item, products, logicalIdPrefix);
					});
				}
			}
			const result: IIonApiInfo = {
				ionApiProducts: products,
				hasProducts: products.length > 0,
			};
			return result;
		} catch (ex) {
			this.logError("parseSuiteResponse: failed + " + JSON.stringify(ex || ""));
			return this.createError();
		}
	}

	private createAndAddFromSuite(
		item: IIonApiSuitesEntity,
		products: IIonApiProduct[],
		logicalIdPrefix: string,
	) {
		if (item) {
			const product: IIonApiProduct = {
				description: item.description,
				logicalIdPrefix: logicalIdPrefix,
				name: item.name,
				suiteContext: item.suiteContext,
				typeName: item.type,
			};
			products.push(product);
		}
	}

	private createError(): IIonApiInfo {
		const errorInfo: IIonApiInfo = {
			hasProducts: false,
			configurationRequiredMessage: this.lang.ionApiConfig,
			ionApiProducts: [],
		};
		return errorInfo;
	}
}

