import {
	Component,
	ElementRef,
	HostBinding,
	NgZone,
	OnInit,
} from "@angular/core";
import { SohoMessageService } from "@infor/sohoxi-angular";
import {
	ContainerLoaderService,
	ContainerService,
	ContextService,
	CoreBase,
	DataService,
	DevService,
	IContainerOptions,
	IOperationResponse,
	IPageContainer,
	LanguageService,
	Theme,
} from "lime/core";
import { map } from "rxjs/operators";
import { IRefreshInfo } from "../../base/container";
import { HttpUtil } from "../../base/runtime";
import { TranslationServiceInternal } from "../../components/translation/translations";
import { WidgetService } from "../../widget/service";
import { DynamicWidgetProvider } from "../widget-dyn/common";

@Component({
	selector: "lm-app",
	templateUrl: "./app.html",
})
export class LimeAppComponent extends CoreBase implements OnInit {
	isStandard: boolean;
	isMobile: boolean;
	isContextApp: boolean;
	isWidgetCatalog: boolean;
	isDev: boolean;

	displayVersion$ = this.containerService.container$.pipe(
		map((container) => container.data.displayVersion),
	);

	@HostBinding("class") get theme(): string {
		return Theme.className;
	}

	constructor(
		private readonly zone: NgZone,
		private readonly elementRef: ElementRef,
		messageService: SohoMessageService,
		languageService: LanguageService,
		private readonly translationService: TranslationServiceInternal, // Must be injected for initialization of the public service
		private readonly contextService: ContextService,
		private readonly dataService: DataService,
		private readonly containerService: ContainerService,
		private readonly containerLoaderService: ContainerLoaderService,
		private readonly widgetService: WidgetService,
		private readonly devService: DevService,
	) {
		super("LimeAppComponent", messageService, languageService);

		this.isStandard = contextService.isStandard;
		this.isMobile = contextService.isMobile;
		this.isContextApp = contextService.isContextApp;
		this.isWidgetCatalog = contextService.isWidgetCatalog;
	}

	ngOnInit(): void {
		// The LimeAppComponent only handles initialization in standard mode,
		// other components are responsible for the mobile and context app modes.

		this.devService.init(this.elementRef);
		this.isDev = this.devService.isDev;
		this.widgetService.registerProvider(new DynamicWidgetProvider());

		if (this.contextService.isStandard) {
			this.containerService.refresh$.subscribe((refreshInfo: IRefreshInfo) => {
				this.init(refreshInfo);
			});

			this.init();
		}
	}

	private init(refreshInfo?: IRefreshInfo) {
		const options = {
			mode: this.contextService.mode,
			settings: true,
			pages: true,
		} as IContainerOptions;

		const widgetId = this.contextService.legacyWidgetIdParameter;
		if (widgetId) {
			if (!this.validateLegacyContext()) {
				return;
			}
			options.pages = false;
			options.widgetId = widgetId;
		}

		let pageId: string = null;
		if (refreshInfo) {
			pageId = refreshInfo.pageId;
		}

		this.containerLoaderService.loadContainer(options).subscribe(
			(container: IPageContainer) => {
				this.containerService.updateContainer(container);
				container.selectStartPage(pageId);
			},
			(r: IOperationResponse) => {
				// TODO Verify is zone is still required here
				this.zone.run(() => {
					this.dataService.handleError(r);
				});
			},
		);
	}

	private validateLegacyContext(): boolean {
		if (HttpUtil.isFramed()) {
			return true;
		}

		this.logError("This client mode may only be used in an IFrame context");
		return false;
	}
}
