import { Injectable, ViewContainerRef } from "@angular/core";
import {
	SohoMessageService,
	SohoModalDialogService,
	SohoToastService,
} from "@infor/sohoxi-angular";
import { CommonUtil, IDialogResult, Log, SubMode } from "lime";
import { AsyncSubject, Observable, Observer, of } from "rxjs";
import { map } from "rxjs/operators";
import { ContainerService } from "../base/container";
import {
	CatalogType,
	Constants,
	ICatalogOptions,
	ICatalogStartResponse,
	IDataListCache,
	IIntegerResponse,
	IMemoItemData,
	IMemoItemResponse,
	IOperationResponse,
	IPage,
	IPageAccessResponse,
	IPageCatalogRequest,
	IPageCatalogResponse,
	IPageData,
	IPageDataResponse,
	IPageDetailInforResponse,
	IPageInstance,
	IPagePreviewOptions,
	IPageResponse,
	IWidgetDefinition,
	IWidgetHandle,
	OperationResponse,
	PageColor,
	ResponseErrorCodes,
} from "../base/core";
import { DevService } from "../base/dev";
import { ClientConfiguration, CoreBase, CoreUtil } from "../base/runtime";
import {
	LanguageService,
	LazyTypeService,
	ProgressService,
} from "../base/service";
import { PageFactory } from "../page/runtime";
import { CacheService, ContextService, DataService } from "../service";
import { WidgetService } from "../widget/service";

class WidgetNotifications {
	static show = "show";
	static hide = "hide";
	static close = "close";
}

@Injectable({
	providedIn: "root",
})
export class PageService extends CoreBase {
	private readonly pageListCache: IDataListCache;
	private readonly lang: ILanguageLime;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		private readonly containerService: ContainerService,
		private readonly lazyTypeService: LazyTypeService,
		private readonly dataService: DataService,
		private readonly cacheService: CacheService,
		private readonly sohoModalDialogService: SohoModalDialogService,
		private readonly contextService: ContextService,
		private readonly toastService: SohoToastService,
		private readonly progressService: ProgressService,
		private readonly widgetServic: WidgetService,
		private readonly devService: DevService,
		private readonly pageFactory: PageFactory,
	) {
		super("PageService", messageService, languageService);

		this.pageListCache = this.cacheService.createCache(
			Constants.clientCachePages,
		);
		this.lang = languageService.getLanguage();

		containerService.refresh$.subscribe(() => {
			this.invalidatePageCache();
		});
	}

	isDev(): boolean {
		return this.devService.isDev;
	}

	createPrivate(page: IPageData): Observable<IPageResponse> {
		return this.dataService.post("/page/private/create", { content: page });
	}

	update(page: IPageData): Observable<IOperationResponse> {
		if (this.devService.isDev) {
			this.devService.savePage(page);
			return of(new OperationResponse(""));
		}

		return this.dataService.post("/page/update", { content: page });
	}

	updateSettings(page: IPageData): Observable<IPageDataResponse> {
		if (this.devService.isDev) {
			this.devService.savePage(page);
			return of(new OperationResponse(page));
		}

		return this.dataService.post("/page/settings/update", { content: page });
	}

	delete(id: string): Observable<IOperationResponse> {
		this.pageListCache.isValid = false;
		return this.dataService.post("/page/delete", { content: id });
	}

	getPublished(id: string): Observable<IPageResponse> {
		return this.dataService.post("/page/published", { content: id });
	}

	getDynamic(id: string): Observable<IPageResponse> {
		return this.dataService.post("/page/dynamic/get", { content: id });
	}

	getPublishedExtended(pageId: string): Observable<IPageResponse> {
		return this.dataService.post("/page/published/extended", {
			content: pageId,
		});
	}

	listCatalog(request: IPageCatalogRequest): Observable<IPageCatalogResponse> {
		return this.dataService.post("/page/catalog/list", request);
	}

	startPageCatalog(): Observable<ICatalogStartResponse> {
		return this.dataService.post("/page/catalog/start", {});
	}

	getPageCatalogDetail(id: string): Observable<IPageDetailInforResponse> {
		return this.dataService.post("/page/catalog/detail", { content: id });
	}

	updatePublished(page: IPage): Observable<IPageDataResponse> {
		this.pageListCache.isValid = false;
		return this.dataService.post("/page/published/update", { content: page });
	}

	deletePublished(pages: string[]): Observable<IIntegerResponse> {
		return this.dataService.post("/page/published/delete", { content: pages });
	}

	addConnection(
		id: string,
		asTemplate: boolean,
		sortOrder: number,
		isStandard: boolean,
		templateTitle?: string,
	): Observable<IPageResponse> {
		const request = {
			pageId: id,
			asTemplate: asTemplate,
			templateTitle: templateTitle,
			sortOrder: sortOrder,
			isStandard: isStandard,
		};
		return this.dataService.post("/page/connection/add", request);
	}

	reorderConnections(pages: string[]): Observable<IOperationResponse> {
		return this.dataService.post("/page/connection/reorder", {
			content: pages,
		});
	}

	updateConnectionSettings(
		pageId: string,
		settings: any,
	): Observable<IOperationResponse> {
		const request = { content: { pageId: pageId, settings: settings } };
		return this.dataService.post("/page/connection/settings/update", request);
	}

	removeConnection(id: string): Observable<IOperationResponse> {
		return this.dataService.post("/page/connection/remove", { content: id });
	}

	/*
	 * Forwards errors to DataService error handler.
	 */
	handleError(response: IOperationResponse, message?: string) {
		this.dataService.handleError(response, message);
	}

	handleUserPageImportError(response: IOperationResponse, message?: string) {
		this.dataService.handleError(response, message);
	}

	showPageCatalog(detailItem?: Partial<IPageInstance>): void {
		if (!this.contextService.isStandard) {
			return;
		}

		const options: ICatalogOptions = {
			type: CatalogType.Page,
			provider: (r) => {
				return this.listCatalog(r);
			},
			startProvider: () => {
				return this.startPageCatalog();
			},
			addCallback: (p) => {
				return this.containerService.getContainer().addFromCatalog(p);
			},
			previewCallback: (p) => {
				return this.previewFromCatalog(p);
			},
			detailItem,
		};

		this.progressService.setBusy(true);
		this.lazyTypeService
			.injectLazyService("CatalogStartService")
			.then((service) => {
				// TODO The rootView property should be removed, this is the only place where it is still used...
				const view = this.languageService.rootView;
				service.openPageCatalog(options, view);
			});
	}

	previewPage(options: IPagePreviewOptions): void {
		this.containerService.getContainer().previewPage(options, () => {
			this.showPageCatalog();
		});
	}

	getPreview(options: IPagePreviewOptions): Observable<IPageResponse> {
		if (options.page) {
			return Observable.create((observer: Observer<IPageResponse>) => {
				observer.next(new OperationResponse(options.page));
				observer.complete();
			});
		}

		let path;
		const request: any = { content: options.pageId };

		// TODO Decide which combination needs a custom request
		if (options.isDynamic && options.isDraft) {
			path = "/page/dynamic/get";
			request.isPreview = true;
			request.isDraft = true;
			const previewOptions = options.dynamicPreviewOptions;
			if (previewOptions) {
				request.previewOptions = previewOptions;
			}
		} else {
			path = "/page/published/preview";
		}

		return this.dataService.post(path, request);
	}

	/**
	 * Invalidates the Page cache.
	 */
	invalidatePageCache(): void {
		if (this.pageListCache) {
			this.pageListCache.isValid = false;
		}
	}

	getFeaturedBackgroundClass(pageColor: number): string {
		const prefix = "featured-page-";
		switch (pageColor) {
			case PageColor.Amber:
				return prefix + "amber";
			case PageColor.Amethyst:
				return prefix + "amethyst";
			case PageColor.AzureDark:
				return prefix + "azure-dark";
			case PageColor.AzureLight:
				return prefix + "azure-light";
			case PageColor.Emerald:
				return prefix + "emerald";
			case PageColor.Graphite:
				return prefix + "graphite";
			case PageColor.Slate:
				return prefix + "slate";
			case PageColor.Turquoise:
				return prefix + "turquoise";
			case PageColor.Ruby:
				return prefix + "ruby";
			default:
				Log.error(
					"No background class could be found for page color: " + pageColor,
				);
				break;
		}
		return "";
	}

	exportPage(pageData: IPageData): Observable<IPageData> {
		return this.dataService.post("/page/export", { content: pageData });
	}

	getPageAccess(pageId: string): Observable<IPageAccessResponse> {
		return this.dataService.post("/page/access", { content: pageId });
	}

	editPageConfiguration(
		page: IPage,
		isUpdate: boolean,
		parentElement: ViewContainerRef,
		isEditFromCatalog?: boolean,
	): Observable<IDialogResult> {
		const subject = new AsyncSubject<IDialogResult>();
		const self = this;

		this.progressService.setBusy(true);
		this.lazyTypeService.loadLazyModule().then(({ PagePublishComponent }) => {
			const dialog = self.sohoModalDialogService
				.modal(PagePublishComponent, parentElement)
				.id("lm-pp-mdl")
				.suppressEnterKey(true)
				.title(this.lang.editPublishConfiguration)
				.afterClose((r: IDialogResult) => {
					subject.next(r);
					subject.complete();
				});

			dialog
				.apply((component: any) => {
					component.modalDialog = dialog;
					component.page = page;
					component.isPublished = isUpdate;
					component.isEditFromCatalog = isEditFromCatalog;
				})
				.open();
		});

		return subject.asObservable();
	}

	showPublishedToast(pageTitle: string): void {
		const lang = this.lang;
		this.toastService.show(
			CoreUtil.getToastOptions(
				lang.pagePublished,
				lang.format(lang.pagePublishedMessage, pageTitle),
			),
		);
	}

	handleCreatePageError(response: IOperationResponse, maxUserPage: number) {
		const title = this.lang.unableToAddPage;
		let message = this.lang.unableToAddPageMesssage;
		// Check if this is a IOperationResponse or a http error
		if (response.errorList) {
			if (
				response.errorList[0].code ===
				ResponseErrorCodes.exceedsMaxUserPagesCount
			) {
				message = this.lang.format(this.lang.maxPageCountMessage, maxUserPage);
			}
		}
		this.showError(title, message);
		this.logResponse(response);
	}

	createSingleWidgetPage(
		widgetHandle: IWidgetHandle,
	): Observable<IPageInstance> {
		const subject = new AsyncSubject<IPageInstance>();

		// Load definition
		this.widgetServic.getDefinition(widgetHandle).subscribe(
			(defintion) => {
				subject.next(this.createPageInstance(widgetHandle, defintion));
				subject.complete();
			},
			(e) => {
				subject.error(e);
			},
		);

		return subject.asObservable();
	}

	listMemos(): Observable<IMemoItemData[]> {
		let url = "/page/memo/list";
		if (this.isDev()) {
			const config = ClientConfiguration;
			url = config.getLocalUrl() + "/limerest" + url;
			this.logInfo("Using dev mode calling url " + url);
		}
		// TODO Decide if the service should cache the result or not, and if so for how long
		return this.dataService
			.post(url, {})
			.pipe(map((response: IMemoItemResponse) => response.content));
	}

	getPageTitleLocalizedOrDefault(page: IPage) {
		const context = this.contextService.getContext();
		const currentLocalization =
			page.localization && page.localization[context.getLanguage()];
		const localizedTitle =
			context.settings.isContentTranslationEnabled() &&
			currentLocalization &&
			currentLocalization.title;
		return localizedTitle || page.title || page.data.title;
	}

	private previewFromCatalog(page: IPage): boolean {
		const container = this.containerService.getContainer();
		const id = page.data.id;

		// Only allow preview if page isn't already added.
		if (container.contains(id)) {
			this.showMessage(
				this.lang.pageExists,
				this.lang.format(
					this.lang.pageExistsMessage,
					page.title || page.data.title,
				),
			);
			return false; // preview wasn't opened
		}

		this.previewPage({
			pageId: id,
			isFromCatalog: true,
			notifyMingle: true,
		});
		return true;
	}

	private createPageInstance(
		widgetHandle: IWidgetHandle,
		definition: IWidgetDefinition,
	): IPageInstance {
		const widgetId = definition.widgetId;
		const serverPage: IPage = {
			data: {
				content: {
					widgets: [
						{
							id: widgetId,
							instanceId: CommonUtil.random(),
							layout: { column: 0, columnSpan: 1, row: 0, rowSpan: 1 },
						},
					],
				},
				widgetRefs: [widgetHandle],
			},
		};

		// TODO Handle applications for mobile widgets
		// applications?: IStringToIApplicationArrayMap;

		const page = this.pageFactory.createPage(
			this.contextService.getContext(),
			serverPage,
			this.widgetServic,
			this.lang,
			this.progressService,
			this.contextService,
			SubMode.MobileSingle,
		);

		// TODO This is set in setDefinition but needs to be available earlier (or we need to use other property in mobile)
		page.widgets[0].id = widgetId;

		return page;
	}
}
