import {
	AfterViewInit,
	ChangeDetectorRef,
	Component,
	ComponentRef,
	NgZone,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import { SohoMessageService } from "@infor/sohoxi-angular";
import { CoreBase, WidgetService } from "lime/core";
import { Observable, ReplaySubject, Subscription } from "rxjs";
import { ContainerService } from "../../base/container";
import {
	Constants,
	IWidgetDefinition,
	IWidgetProvider,
	IWidgetRegistration,
	WidgetAccessLevel,
} from "../../base/core";
import { HttpUtil } from "../../base/runtime";
import { LanguageService, ProgressService } from "../../base/service";
import { ContainerLoaderService } from "../../container/loader";
import {
	ContextConstants,
	IContextSiteData,
	IContextSiteState,
	IContextWidget,
	IContextWidgetHandle,
	ILoadContextZoneData,
	IToggleContextZoneData,
	ToggleState,
} from "../../context-app/core";
import { ContextAppService } from "../../context-app/service";
import { ContextService, DataService } from "../../service";
import { WidgetType } from "../../widget/core";
import { ContextSiteComponent } from "../context-site/context-site";

interface IContextSiteStateMap {
	[key: string]: ContextSiteState;
}

export interface IContextSiteItem {
	view: ViewContainerRef;
	isActive: boolean;
}

export class ContextSiteState implements IContextSiteState {
	private readonly visibilitySubject = new ReplaySubject<boolean>(1);
	visibility$: Observable<boolean> = this.visibilitySubject.asObservable();

	componentRef: ComponentRef<ContextSiteComponent>;

	private _isVisible = false;
	private _isCurrent = false;

	constructor(
		readonly site: IContextSiteData,
		readonly widgets: IContextWidget[],
	) {}

	get isVisible(): boolean {
		return this._isVisible;
	}

	set isVisible(value: boolean) {
		this._isVisible = value;
	}

	get isCurrent(): boolean {
		return this._isCurrent;
	}

	set isCurrent(value: boolean) {
		this._isCurrent = value;
	}

	toggleVisibility(isVisible: boolean): void {
		this._isVisible = isVisible;
		this.visibilitySubject.next(isVisible);
		// this.detectChanges();
	}

	detectChanges(): void {
		if (this.componentRef) {
			this.componentRef.changeDetectorRef.detectChanges();
		}
	}
}

/**
 * Top level component for context apps.
 *
 * Zone [1] -> Site [0-n] -> Host [0-n]
 */
@Component({
	selector: "lm-context-zone",
	templateUrl: "./context-zone.html",
	styleUrls: ["./context-zone.scss"],
})
export class ContextZoneComponent
	extends CoreBase
	implements OnInit, AfterViewInit, IWidgetProvider
{
	@ViewChild("view", { read: ViewContainerRef, static: true })
	view: ViewContainerRef;

	private readonly siteMap: IContextSiteStateMap = {};
	private selectedSite: ContextSiteState;
	private collapsedSite: ContextSiteState;

	private loadSubscription: Subscription;
	private showSubscription: Subscription;
	private hideSubscription: Subscription;
	private resetSubscription: Subscription;
	private toggleSubscription: Subscription;

	private readonly widgets: IWidgetRegistration[] = [];
	private toggleState: ToggleState = "expand";
	private widgetCounter = 0;

	constructor(
		private readonly zone: NgZone,
		private readonly changeDetector: ChangeDetectorRef,
		messageService: SohoMessageService,
		languageService: LanguageService,
		progressService: ProgressService,
		private contextService: ContextService,
		private readonly contextAppService: ContextAppService,
		private containerLoaderService: ContainerLoaderService,
		private containerService: ContainerService,
		private dataService: DataService,
		private readonly widgetService: WidgetService,
	) {
		super("ContextZoneComponent", messageService, languageService);
	}

	ngOnInit(): void {
		this.widgetService.registerProvider(this);
	}

	ngAfterViewInit(): void {
		this.loadSubscription = this.contextAppService.load$.subscribe((data) => {
			this.zone.run(() => {
				this.onLoad(data);
			});
		});

		this.showSubscription = this.contextAppService.show$.subscribe((data) => {
			this.zone.run(() => {
				this.onNewCurrent();
				this.hideSelected();
				this.onShow(data);
			});
		});

		this.hideSubscription = this.contextAppService.hide$.subscribe((data) => {
			this.zone.run(() => {
				this.onHide(data);
			});
		});

		this.resetSubscription = this.contextAppService.reset$.subscribe((data) => {
			this.zone.run(() => {
				this.onReset(data);
			});
		});

		this.toggleSubscription = this.contextAppService.toggle$.subscribe(
			(data) => {
				this.zone.run(() => {
					this.onToggle(data);
				});
			},
		);
	}

	getWidgets(): IWidgetRegistration[] {
		return this.widgets;
	}

	private onLoad(data: ILoadContextZoneData): void {
		const state = this.getState(data);
		if (state) {
			this.logInfo(
				"onLoad: Unexpected message, context zone already loaded: " +
					data.siteId,
			);
			return;
		}

		this.logInfo("onLoad: Loading context zone: " + data.siteId);
		this.loadNew(data);
	}

	private onReset(data: ILoadContextZoneData): void {
		this.logInfo("onReset: Resetting context zone: " + data.siteId);

		// TODO Destroy / clean up any existing site first if necessary

		this.loadNew(data);
	}

	private onToggle(data: IToggleContextZoneData): void {
		this.toggleState = data.state;

		if (this.isCollapsed()) {
			this.logDebug("onToggle: collapse");
			this.collapsedSite = this.selectedSite;
			this.hideSelected();
		} else if (this.isExpanded()) {
			this.logDebug("onToggle: expand");
			if (!this.selectedSite) {
				this.selectedSite = this.collapsedSite;
				this.collapsedSite = null;
			}
			this.showSelected();
		}
	}

	private isCollapsed(): boolean {
		// Note that when we first are loaded we don't know if we are collapsed or not.
		return this.toggleState === "collapse";
	}

	private isExpanded(): boolean {
		return this.toggleState === "expand";
	}

	private showSelected(): void {
		if (this.selectedSite) {
			this.onShow(this.selectedSite.site);
		}
	}

	private onHide(data: IContextSiteData): void {
		this.logInfo("onHide: Hiding context zone");
		this.onNewCurrent();
		this.hideSelected();
	}

	private onShow(data: IContextSiteData): void {
		const isShowCollapsed = data.state === "collapse";
		if (isShowCollapsed) {
			this.toggleState = "collapse";
		}

		this.logInfo("onShow: Switch to context zone: " + data.siteId);
		this.logInfo(
			this.isCollapsed() ? "onShow: Area is collapsed" : "onShow: Area visible",
		);
		const state = this.getState(data);
		if (state) {
			state.isCurrent = true;
			this.selectedSite = state;
			const component = state.componentRef.instance;
			if (component.state) {
				this.toggleVisibility(state, true);
			} else {
				state.isVisible = this.isExpanded();
				component.showState(state);
			}
		} else {
			// TODO Error
		}
	}

	private onNewCurrent(): void {
		if (this.selectedSite) {
			this.selectedSite.isCurrent = false;
		}
	}

	private hideSelected(): void {
		if (this.selectedSite) {
			this.toggleVisibility(this.selectedSite, false);
			this.selectedSite = null;
		}
	}

	private loadNew(data: ILoadContextZoneData): void {
		const ref = this.view.createComponent(ContextSiteComponent);

		const widgets = this.filterValid(data.widgets);
		this.convertLegacy(widgets);
		this.generateUniqueIds(data.siteId, widgets);

		const state = new ContextSiteState(data as IContextSiteData, widgets);
		state.componentRef = ref;

		this.siteMap[data.siteId] = state;

		// TODO Verify if this is needed in some scenarios, currently handled by zone.run at a hihger level
		// https://github.com/angular/angular/issues/17087
		// ref.changeDetectorRef.detectChanges();
	}

	private toggleVisibility(state: ContextSiteState, isVisible: boolean): void {
		// Note that the toggleVisibility function also triggers change detection.
		state.toggleVisibility(isVisible);
	}

	private getState(data: IContextSiteData): ContextSiteState {
		return this.siteMap[data.siteId];
	}

	private generateUniqueIds(siteId: string, widgets: IContextWidget[]): void {
		let id: string;
		for (const widget of widgets) {
			try {
				id = siteId + (widget.url ? widget.url : JSON.stringify(widget.handle));
				widget.uniqueId = window.btoa(id);
			} catch (err) {
				this.logError(
					"generateUniqueIds: Failed to genereate uniqueid for id " + id,
				);
			}
		}
	}

	private convertLegacy(widgets: IContextWidget[]): void {
		for (const widget of widgets) {
			const url = widget.url;
			if (url && !widget.handle) {
				const handle = this.getHandleFromUrl(url);
				if (handle) {
					// Legacy Homepages URL with "widgetid" parameter should be converted to a widget handle
					widget.handle = handle;
				} else {
					if (this.isLegacyContextViewer(widget)) {
						this.convertToWidgetHandle(
							widget,
							ContextConstants.ContextViewerWidgetId,
						);
					} else {
						// Convert to an external widget
						widget.handle = this.registerDefinition(widget);
						widget.isExternal = true;
					}
				}
				widget.url = null;
			}
		}
	}

	private convertToWidgetHandle(
		widget: IContextWidget,
		widgetId: string,
	): void {
		this.logDebug(
			() =>
				"convertToWidgetHandle: Convert " +
				widget.name +
				" " +
				widget.url +
				" to widgetid " +
				widgetId,
		);
		widget.handle = { id: widgetId };
		widget.name = null;
		widget.url = null;
		widget.isExternal = false;
	}

	private isLegacyContextViewer(widget: IContextWidget): boolean {
		if (
			widget.name === ContextConstants.ContextViewerName &&
			widget.url &&
			widget.url.indexOf(ContextConstants.ContextViewerUrl) > 1
		) {
			return true;
		}
		return false;
	}

	private getHandleFromUrl(url: string): IContextWidgetHandle {
		const hasWidgetId =
			url.indexOf(Constants.widgetId) > 0 &&
			url.indexOf(window.location.hostname) > 0 &&
			url.indexOf("/" + Constants.webRoot) > 0;

		if (hasWidgetId) {
			const parameters = HttpUtil.parseQuery(url);
			const widgetId = parameters[Constants.widgetId];
			if (widgetId) {
				return { id: widgetId };
			}
		}
		return null;
	}

	private generateWidgetId(): string {
		this.widgetCounter++;
		return "infor.mingle.context.n" + this.widgetCounter;
	}

	private registerDefinition(widget: IContextWidget): IContextWidgetHandle {
		const id = this.generateWidgetId();

		const title = widget.name || "Context App";
		const definition = {
			widgetId: id,
			type: WidgetType.External,
			url: widget.url,
			enableSettings: false,
			enableSettingsDef: false,
			accessLevel: WidgetAccessLevel.View,
			standardAccessLevel: WidgetAccessLevel.View,
			title: title,
			standardTitle: title,
		} as IWidgetDefinition;

		this.widgets.push({ definition: definition });
		this.widgetService.cacheDynamic(definition);

		return { id: id };
	}

	private filterValid(widgets: IContextWidget[]): IContextWidget[] {
		return widgets ? widgets.filter((w) => this.isValid(w)) : [];
	}

	private isValid(widget: IContextWidget): boolean {
		const handle = widget.handle;
		if (widget.url || (handle && handle.id)) {
			return true;
		}

		this.logWarning(
			"isValid: Skipping invalid context app widget " + JSON.stringify(widget),
		);
		return false;
	}
}
