export class PageLayout {
	private maxColumns = 3;
	private matrix: boolean[][];

	constructor(private widgets: IWidget[]) {
		this.matrix = this.createMatrix(widgets);
	}

	getMatrix() {
		return this.matrix;
	}

	firstEmpty(): IWidgetLayout {
		const matrix = this.matrix;
		const rows = matrix.length;
		const columns = matrix[0].length;
		for (let row = 0; row < rows; row++) {
			for (let col = 0; col < columns; col++) {
				if (this.matrix[row][col] === false) {
					// Found an empty cell
					return new WidgetLayout(col, row);
				}
			}
		}

		// Add a new empty row
		matrix.push(ArrayUtil.array(this.maxColumns, false));
		return new WidgetLayout(0, rows);
	}

	private getMaxRow(widgets: IWidget[]): number {
		let max = 0;
		for (let i = 0; i < widgets.length; i++) {
			const layout = widgets[i].data.layout;
			if (layout) {
				const row = layout.row + layout.rowSpan - 1;
				if (row > max) {
					max = row;
				}
			}
		}
		return max;
	}

	private createMatrix(widgets: IWidget[]): boolean[][] {
		const max = this.getMaxRow(widgets);
		const matrix = ArrayUtil.matrix<boolean>(max + 1, this.maxColumns, false);
		for (let i = 0; i < widgets.length; i++) {
			const widget = widgets[i];
			const layout = widget.data.layout;
			if (layout) {
				const column = layout.column;
				const row = layout.row;
				for (let c = 0; c < layout.columnSpan; c++) {
					matrix[row][column + c] = true;
				}
				for (let r = 0; r < layout.rowSpan; r++) {
					matrix[row + r][column] = true;
				}
			}
		}
		return matrix;
	}
}

class BrokenWidgetDefinition implements IWidgetDefinition {
	isBroken = true;
	widgetId?: string;
	standardWidgetId?: string;

	constructor(widgetId: string, standardWidgetId: string) {
		this.widgetId = widgetId;
		this.standardWidgetId = standardWidgetId;
	}
}

@Injectable({
	providedIn: "root",
})
export class PageFactory {
	constructor(
		private widgetFactory: WidgetFactory,
		private appTrackerContext: YgApplicationTrackerContext,
	) {}

	createPage(
		context: IContext,
		page: IPage,
		widgetService: WidgetService,
		lang: ILanguageLime,
		progressService: ProgressService,
		contextService: ContextService,
		_subMode: SubMode,
	): Page {
		return new Page(
			context,
			page,
			widgetService,
			lang,
			progressService,
			contextService,
			_subMode,
			this.widgetFactory,
			this.appTrackerContext,
		);
	}
}

class PageParentContext implements IWidgetParentContext {
	constructor(
		private readonly page: Page,
		private readonly widget: IWidgetData,
	) {}

	get id(): string {
		return this.page.id;
	}

	get mode() {
		return this.page.mode;
	}

	get subMode() {
		return this.page.subMode;
	}

	get isPublished() {
		return this.page.isPublished();
	}

	get isStandard() {
		return this.page.isStandard();
	}

	get isDynamic() {
		return this.page.isDynamic();
	}

	get userSettings(): IStringToAnyMap {
		if (this.widget) {
			return this.page.getUserSettingsForWidget(this.widget.instanceId);
		}
		return null;
	}

	set userSettings(settings: IStringToAnyMap) {
		this.page.setWidgetUserSettings(settings);
	}

	get viewTracker(): ViewTracker {
		return this.page.viewTracker;
	}

	isUserPreview(): boolean {
		return this.page.isUserPreview();
	}

	addWidget(widget: IWidget): void {
		this.page.add(widget);
	}
}

export class Page extends CoreBase implements IPageInstance {
	widgetsAddedCount = 0;
	id: string;
	componentRef: any;
	elementId: string;
	widgets: IWidget[] = [];
	data: IPageData;
	dynamicPage: IDynamicPage;

	// Popularity is only set on published (and standard pages)
	popularity: number;
	title: string;
	description: string;
	isEditable: boolean;
	isViewable: boolean;
	isMandatory: boolean;
	isPrimary: boolean;
	isMobile: boolean;
	access: IEntityAccess[];
	applications: IStringToIApplicationArrayMap;
	link: IPageLink;
	sortOrder: number;
	isLocalized: boolean;
	accessState: number;
	viewTracker: ViewTracker;

	private _settings: any;
	private lazyContentSubject = new Subject<void>();

	lazyContentLoaded = this.lazyContentSubject.asObservable();

	private removedEvent = new InstanceEvent<IPageInstance>();
	private changedEvent = new InstanceEvent<IPageChangedInfo>();
	private widgetAddedEvent = new InstanceEvent<IWidget>();

	mode: Mode;

	constructor(
		private context: IContext,
		private page: IPage,
		private widgetService: WidgetService,
		private lang: ILanguageLime,
		private progressService: ProgressService,
		private contextService: ContextService,
		private _subMode: SubMode,
		private widgetFactory: WidgetFactory,
		private appTrackerContext: YgApplicationTrackerContext,
	) {
		super("Page");

		this.isMandatory = page.isMandatory === true;
		this.isEditable = page.isEditable === true;
		this.isViewable = page.isViewable !== false;
		this.isPrimary = page.isPrimary === true;
		this.access = page.access;
		this._settings = page.settings;
		this.popularity = page.popularity;
		this.accessState = page.accessState;
		this.isLocalized = page.isLocalized;

		const data = page.data;
		this.data = data;
		this.dynamicPage = page.dynamicPage;

		const pageId = data.id || CommonUtil.random();
		this.id = pageId;
		this.elementId = pageId.replace(/\./g, "_");
		this.sortOrder = page.sortOrder || data.sortOrder || 0;
		this.isMobile =
			!data.config || !Toggle.isDisabled(data.config.enableMobile);

		// Get the localized title from the page or the default title if no localized title exists.
		this.title = page.title || data.title;
		this.description = page.description || data.description;

		this.mode = this.getMode(contextService);
		this.createPageTracker();
		this.initContent();
		this.initWidgets();
	}

	get settings(): any {
		return this._settings;
	}

	set settings(settings: any) {
		this._settings = settings;
	}

	set subMode(newSubMode: SubMode) {
		this._subMode = newSubMode;
	}

	get subMode(): SubMode {
		return this._subMode;
	}

	updateLazyContent(data: IPageData): void {
		data.isLazy = false;
		if (data.title) {
			this.title = data.title;
		}
		this.data = data;
		this.initWidgets();
		this.lazyContentSubject.next();
		this.lazyContentSubject.complete();
	}

	getElement(): JQuery {
		const ref = this.componentRef;
		return ref ? $(ref.instance.elementRef.nativeElement) : null;
	}

	get enableMemo(): boolean {
		const config = this.data.config;
		return config && config.enableMemo === 1;
	}

	get memoDuration(): number {
		const config = this.data.config;
		return config && config.memoDuration;
	}

	get disableAnimation(): boolean {
		const config = this.data.config;
		return config && config.disableAnimation === 1;
	}

	noOfWidgets() {
		return this.widgets.length;
	}

	findWidgets(
		forId: string,
		options: IFindWidgetOptions,
	): IWidgetInstanceInfo[] {
		const items: IWidgetInstanceInfo[] = [];
		const instanceId = options.instanceId;
		const id = options.id;
		const standardId = options.standardWidgetId;
		const isById = instanceId || id || standardId;

		const widgets = this.widgets;
		for (const widget of widgets) {
			const definition = widget.definition;
			if (definition) {
				const currentInstanceId = widget.data.instanceId;
				if (!options.includeSelf && forId === currentInstanceId) {
					// We should skip the current widget
					continue;
				}

				const currentId = definition.widgetId;
				const currentStandardId = definition.standardWidgetId || currentId;

				if (isById) {
					const isMatch =
						(instanceId && instanceId === currentInstanceId) ||
						(id && id === currentId) ||
						(standardId && standardId === currentStandardId);
					if (!isMatch) {
						continue;
					}
				}

				items.push({
					instanceId: currentInstanceId,
					id: currentId,
					standardWidgetId: currentStandardId,
					title: widget.title || widget.definition.title,
				});
			}
		}

		return items;
	}

	getWidgetByInstanceId(instanceId: string): IWidget {
		const widgets = this.widgets;
		if (widgets) {
			for (const widget of widgets) {
				if (widget.data.instanceId === instanceId) {
					return widget;
				}
			}
		}
		return null;
	}

	getWidgetParentContext(widget: IWidgetData): IWidgetParentContext {
		return new PageParentContext(this, widget);
	}

	getBrokenWidgetParentContext(): IWidgetParentContext {
		return new PageParentContext(this, null);
	}

	isPublished(): boolean {
		return this.data.viewAccess !== AccessType.Owner;
	}

	isStandard(): boolean {
		return this.data.isStandard;
	}

	isDynamic(): boolean {
		return this.data.isDynamic;
	}

	isUserPreview(): boolean {
		return this.data.isUserPreview;
	}

	isPublishEnabled(): boolean {
		// Private pages can be published if the users is allowed to do so.
		return !this.isPublished() && this.context.settings.isPagePublishEnabled();
	}

	isRepublishEnabled(): boolean {
		return (
			this.isEditable &&
			!PageUtil.isPrivate(this) &&
			!this.isDynamic() &&
			this.context.settings.isPagePublishEnabled()
		);
	}

	/**
	 * Gets the layout for the first empty cell where a widget can be added.
	 */
	getLayout(): IWidgetLayout {
		if (this.widgets.length === 0) {
			return new WidgetLayout(0, 0);
		}
		const pageLayout = new PageLayout(this.widgets);
		return pageLayout.firstEmpty();
	}

	notifyPublishingMode(): void {
		const widgets = this.widgets;
		for (const widget of widgets) {
			try {
				if (widget.definition && !widget.definition.isPublished) {
					widget.enableSettingsTemporary(true);
					const publishing = widget.instance.publishing;
					if (publishing) {
						publishing();
						widget.raisePrimaryActionChanged();
					}
				}
			} catch (ex) {
				this.logError("Failed to call publishing event function", ex);
			}
		}
	}

	updateWidgets(editedWidgets: IEditableWidget[], isSave: boolean): void {
		const widgets = this.widgets;
		const updatedWidgets = [] as IWidget[];

		for (const editedWidget of editedWidgets) {
			if (!editedWidget.id) {
				continue;
			}

			let data: IWidgetData;
			let byRef: boolean;
			let isNew = true;
			const existing: IWidget = editedWidget.elementId
				? ArrayUtil.itemByProperty(widgets, "elementId", editedWidget.elementId)
				: null;
			if (existing) {
				isNew = false;
				data = existing.data;
				byRef = existing.byRef;
			} else {
				if (CommonUtil.isUndefined(editedWidget.widget.data)) {
					continue;
				}
				data = editedWidget.widget.data;
				byRef = editedWidget.widget.byRef;
			}

			data.layout = editedWidget.layout;

			if (!CommonUtil.isUndefined(editedWidget.containerChangeInfo.isBanner)) {
				data.isBanner = editedWidget.containerChangeInfo.isBanner;
			}

			let parentContext = this.getWidgetParentContext(data);

			// Check if widget has been deleted
			const id = editedWidget.id;
			const def = this.widgetService.getCachedDefinition(id);

			if (!def) {
				const brokenReason = this.widgetService.getBrokenReason(id);
				data.isBroken = true;
				data.brokenReason = brokenReason;
				data.brokenMessage = WidgetUtil.getBrokenMessage(
					this.lang,
					brokenReason,
				);
				parentContext = {
					addWidget: (w) => {
						this.add(w);
					},
					isUserPreview: () => this.isUserPreview(),
					mode: parentContext.mode,
					subMode: parentContext.subMode,
					viewTracker: parentContext.viewTracker,
				};
				this.logWarning(
					"No definition was found in page for widget ID: " + editedWidget.id,
				);
			}

			const widget = this.widgetFactory.createWidget(
				parentContext,
				data,
				isNew,
				byRef,
			);
			updatedWidgets.push(widget);
		}

		this.clearWidgets();

		// Add the updated widgets
		for (const updated of updatedWidgets) {
			this.addInternal(updated, -1);
			this.widgetAddedEvent.raise(updated);
		}

		if (isSave) {
			if (updatedWidgets.length) {
				zip(...updatedWidgets.map((widget) => widget.initialized$))
					.pipe(take(1))
					.subscribe(() => {
						// Notify change When all widgets have been loaded & initialized
						this.raiseChanged(true);
					});
			} else {
				this.raiseChanged(true);
			}
		}
	}

	afterPublishedStandard(widget: IWidget, sourceDefinition: IWidgetDefinition) {
		// Custom widget was created.
		// Create widget definition from standard widget, replace the standard widget on the page, save the page.
		const definition = CoreUtil.copy(widget.definition);
		definition.standardWidgetId = widget.id;
		definition.widgetId = sourceDefinition.widgetId;
		definition.settings = sourceDefinition.settings;
		definition.enableSettings = sourceDefinition.enableSettings;
		definition.enableTitleEdit = sourceDefinition.enableTitleEdit;
		definition.owner = this.context.getUserId();

		widget.definition = definition;
		widget.id = sourceDefinition.widgetId;

		delete widget.data.title;
		widget.data.id = sourceDefinition.widgetId;

		for (const ref of this.data.widgetRefs) {
			if (ref.id === definition.standardWidgetId) {
				ref.id = definition.widgetId;
				break;
			}
		}
		this.raiseChanged();
	}

	add(widget: IWidget): void {
		this.addInternal(widget, -1);
		this.widgetAddedEvent.raise(widget);
		this.raiseChanged(false, false); // Don't delay save
	}

	remove(widget: IWidget): void {
		this.removeInternal(widget);
		widget.destroy();
		this.raiseChanged();
		this.notify(WidgetActivationType.close, false);
	}

	changed(): IInstanceEvent<IPageChangedInfo> {
		return this.changedEvent;
	}

	removed(): IInstanceEvent<IPageInstance> {
		return this.removedEvent;
	}

	widgetAdded(): IInstanceEvent<IWidget> {
		return this.widgetAddedEvent;
	}

	show(): void {
		this.trackPageStart();
		this.logDebug("Show " + this.id);
		this.notify(WidgetActivationType.visibility, true);
	}

	hide(): void {
		this.trackPageEnd();
		this.logDebug("Hide " + this.id);
		this.notify(WidgetActivationType.visibility, false);
	}

	preDestroy(): void {
		const widgets = this.widgets;
		for (const widget of widgets) {
			widget.preDestroy();
		}
	}

	destroy(): void {
		this.logDebug("Destroy " + this.id);
		this.clearWidgets();
		this.changedEvent.clear();
		this.removedEvent.clear();
		this.widgetAddedEvent.clear();

		const ref = this.componentRef;
		if (ref) {
			ref.destroy();
		}
	}

	notifyBannerColorChange(color: string): void {
		const widgets = this.widgets;
		for (const widget of widgets) {
			if (widget.isBanner()) {
				widget.notifyInvoke("bannerBackgroundChanged", color);
			}
		}
	}

	toggleEditMode(isEdit: boolean): void {
		const widgets = this.widgets;
		for (const widget of widgets) {
			if (isEdit) {
				// Deactivate
				this.notify(WidgetActivationType.edit, false);
				// Edit mode start
				widget.notifyInvoke("editing");
			} else {
				// Edit mode stop
				widget.notifyInvoke("edited");
				// Activate
				this.notify(WidgetActivationType.edit, true);
			}
		}
	}

	getUserSettingsForWidget(instanceId: string) {
		const settings = this.settings;
		if (settings) {
			const widgets = settings.widgets;
			if (widgets) {
				return widgets[instanceId];
			}
		}
		return null;
	}

	getWidgetUserSettings(): any {
		// Iterate widgets and collect user data which might not be anything if all settings are disabled
		// User data should not be collected for private widgets on private pages
		const isPublishedPage = this.isPublished();
		const page = this;
		let data: any = null;
		const widgets = page.widgets;
		if (widgets) {
			for (const widget of widgets) {
				const instanceId = widget.data.instanceId;
				if (instanceId) {
					if (isPublishedPage || widget.isPublished()) {
						const instanceData = widget.getUserData();
						if (instanceData) {
							if (!data) {
								data = {};
							}
							data[instanceId] = instanceData;
						}
					}
				}
			}
		}
		return data;
	}

	setWidgetUserSettings(data: any): boolean {
		let settings = this.settings;
		if (!settings && !data) {
			return false;
		}

		if (!settings) {
			this.settings = settings = {};
		}

		const name = "widgets";
		if (data) {
			settings[name] = data;
		} else {
			delete settings[name];
		}

		return true;
	}

	createSavePageDataExport(isFlattenExport: boolean): IPageData {
		const data = this.createSavePageData(isFlattenExport);
		PageUtil.updateWidgetIdsPageData(data);
		return data;
	}

	createSavePageData(isFlattenExport?: boolean): IPageData {
		const self = this;
		let pageData = self.data;
		pageData.widgetRefs = null;

		// Copy page data before saving since it it modified by this function
		pageData = CoreUtil.copy(pageData);

		// Dictionary as the same key should only be added once
		const widgetRefs: IStringToAnyMap = [];
		const widgetDatas = pageData.content.widgets;
		if (widgetDatas) {
			const removedWidgetDatas = [];

			for (const widgetData of widgetDatas) {
				const id = widgetData.id;
				if (id) {
					const widget = self.getWidgetByInstanceId(widgetData.instanceId);
					if (widget) {
						const isByRef = widget.byRef;
						let widgetHandle: IWidgetHandle = { id: id, byRef: isByRef };

						if (isByRef) {
							let standardId: string;
							if (widget.publishedHandle) {
								standardId = widget.publishedHandle.pid;
							} else if (!widget.definition) {
								// When the banner widget setting is false, banner widgets will not have the definition set.
								const def = this.widgetService.getCachedDefinition(id);
								standardId = def ? def.standardWidgetId : null;
							} else {
								standardId = widget.definition
									? widget.definition.standardWidgetId
									: null;
							}
							if (isFlattenExport) {
								// Partially save this widget as a standard and keep all settings
								widgetHandle.byRef = false;
								widgetHandle.id = standardId;
							} else {
								widgetHandle.pid = standardId;
							}

							if (isFlattenExport && widget.isBroken()) {
								// Don't inlude broken widgets
								widgetHandle = null;
								removedWidgetDatas.push(widgetData);
							}
						}
						if (widgetHandle != null) {
							widgetRefs[widgetHandle.id] = widgetHandle;
						}

						if (isByRef && !isFlattenExport) {
							// Clear properties that should not be saved
							// Keep them if this is for a deep export
							delete widgetData.settings;
							delete widgetData.title;
						}
					}
				}
			}

			// Delete any widgets that should be removed
			if (removedWidgetDatas.length > 0) {
				for (const removedData of removedWidgetDatas) {
					// Locate and remove from widgetDatas
					ArrayUtil.removeByProperty(
						widgetDatas,
						"instanceId",
						removedData.instanceId,
					);
				}
			}
		}

		pageData.widgetRefs = [];
		Object.keys(widgetRefs).forEach((key) => {
			const handle: IWidgetHandle = widgetRefs[key];
			pageData.widgetRefs.push(handle);
		});

		if (!isFlattenExport) {
			// Flatten export don't care about user settings - the user settings will be the exported data
			const hadSettings = this.hasSettings();

			const widgetUserSettings = this.getWidgetUserSettings();
			this.setWidgetUserSettings(widgetUserSettings);

			const hasSettings = this.hasSettings();

			let userSettings = null;
			if (hasSettings) {
				userSettings = self.settings;
			} else if (hadSettings) {
				// Set to empty object to clear on server
				userSettings = {};
			}

			pageData.userSettings = userSettings;
		}

		return pageData;
	}

	createSavePageDataFlatten(exportType: string): Observable<IPageData> {
		const subject = new AsyncSubject<IPageData>();
		const widgetDefinitions = this.widgets.map((widget) => widget.definition);
		const pageData = this.createSavePageDataExport(true);
		const widgets = pageData.content.widgets;
		const widgetCount = widgets.length;
		let processedWidgets = 0;

		// Checks if all widgets have been processed and promise should be resolved.
		function isDone() {
			processedWidgets++;
			if (processedWidgets === widgetCount) {
				subject.next(pageData);
				subject.complete();
			}
		}

		// Process each widget. Published widgets needs their info, private widgets already have all they need.
		for (const widget of widgets) {
			const definition = ArrayUtil.itemByProperty(
				widgetDefinitions,
				"widgetId",
				widget.id,
			) as IWidgetDefinition;
			this.processWidget(
				exportType,
				widget,
				widgets,
				definition,
				subject,
				isDone,
			);
		}

		return subject.asObservable();
	}

	private createPageTracker() {
		this.appTrackerContext.getTracker().then((appTracker) => {
			this.logDebug(`Creating page tracker: ${this.title}`);
			this.viewTracker = appTracker.createView({
				name: "Page",
				url: location.href,
				type: "page",
				tags: onlyTruthyTags([
					this.isDynamic() && "dynamic",
					this.isStandard() && "standard",
					this.isPublished() && "published",
					PageUtil.isPrivate(this) && "private",
				]),
				attributes: onlyTruthyAttributes({
					id: this.id,
				}),
			});
		});

		function onlyTruthyTags(tags: Tags): Tags {
			return tags.filter((tag) => tag);
		}

		function onlyTruthyAttributes(obj: Attributes): Attributes {
			const result: Attributes = {};
			for (const key in obj) {
				if (obj[key]) {
					result[key] = obj[key];
				}
			}
			return result;
		}
	}

	private trackPageStart() {
		this.appTrackerContext.getTracker().then(() => {
			this.logDebug(`Tracking start of page: ${this.title}`);
			this.viewTracker?.trackStart();
		});
	}

	private trackPageEnd() {
		this.appTrackerContext.getTracker().then(() => {
			this.logDebug(`Tracking end of page: ${this.title}`);
			this.viewTracker?.trackEnd();
		});
	}

	private processWidget(
		exportType: string,
		widget: IWidgetData,
		widgets: IWidgetData[],
		definition: IWidgetDefinition,
		subject: AsyncSubject<IPageData>,
		isDone: () => void,
	): void {
		if (!definition) {
			// When the banner widget setting is false, banner widgets will not have the definition set.
			definition = this.widgetService.getCachedDefinition(widget.id);
		}

		// Get published info if the widget is published.
		if (definition && definition.isPublished) {
			if (widget.isBroken) {
				// Skip broken widgets when exporting to standard
				isDone();
				return;
			}
			const handle: IWidgetHandle = {
				id: widget.id,
				pid: definition.standardWidgetId,
				byRef: definition.isByRef,
			};
			this.addCustomDefinition(
				exportType,
				widget,
				definition,
				handle,
				subject,
				isDone,
			);
			return;
		}

		if (exportType === Constants.pageExportConvertStandard) {
			this.fixStandardTitle(widget, definition, widget.custom);
		}

		isDone();
	}

	private fixStandardTitle(
		widget: IWidgetData,
		definition: IWidgetDefinition,
		custom: IPublishedWidgetItem,
	): void {
		if (custom) {
			const customDefinition = custom.definition;
			if (customDefinition && customDefinition.isCatalogTitle) {
				const context = this.contextService.getContext();
				let title: string;
				if (definition.isPublished) {
					title = definition.title;
				} else {
					title = WidgetUtil.getLocalized(
						context,
						custom.localization,
						"title",
					);
					if (!title) {
						title = customDefinition.title;
					}
				}
				if (title) {
					widget.title = title;
					widget.isTitleLocked = false;
				}
			}
		}
		if (widget.isTitleLocked) {
			delete widget.title;
		}
		delete widget.custom;
	}

	private addCustomDefinition(
		exportType: string,
		widget: IWidgetData,
		definition: IWidgetDefinition,
		handle: IWidgetHandle,
		subject: AsyncSubject<IPageData>,
		isDone: () => void,
	): void {
		const applyCustom = exportType !== Constants.pageExportConvertStandard;
		this.widgetService.getPublished(handle).subscribe(
			(response) => {
				// Create the custom object
				const responseDefinition = response.definition;
				widget.title = responseDefinition.custom.title;

				const custom = {} as IPublishedWidgetItem;
				const saveDefinition = {} as IWidgetDefinition;
				custom.definition = saveDefinition;
				custom.localization = response.localization;

				saveDefinition.isCatalogTitle =
					responseDefinition.custom.isCatalogTitle;
				saveDefinition.settings = responseDefinition.custom.metadata;
				saveDefinition.enableSettings = responseDefinition.enableSettings;
				saveDefinition.enableTitleEdit = responseDefinition.enableTitleEdit;
				saveDefinition.title = responseDefinition.custom.title;
				saveDefinition.description = responseDefinition.description;
				saveDefinition.tags = "";

				if (applyCustom) {
					widget.custom = custom;
				}

				if (exportType === Constants.pageExportConvertStandard) {
					this.fixStandardTitle(widget, definition, custom);
				}

				// Set id to standard id.
				widget.id = handle.pid;

				isDone();
			},
			(errorResponse) => {
				subject.error(errorResponse);
			},
		);
	}

	private getMode(contextService: ContextService): Mode {
		if (contextService.isContextApp) {
			return Mode.ContextApp;
		}

		if (contextService.isMobile) {
			return Mode.Mobile;
		}

		if (contextService.isLegacyContext) {
			return Mode.ContextApp;
		}

		return Mode.Default;
	}

	private initContent(): void {
		const data = this.data;
		let content = data.content;
		if (!content) {
			data.content = content = {
				widgets: [],
			};
		} else if (
			!content.widgets &&
			!content.color &&
			!$.isEmptyObject(content)
		) {
			// Need to convert old pages where widgets are placed directly on content
			const misplacedWidgets = data.content as any;
			data.content = content = {
				widgets: misplacedWidgets,
			};
		}

		this.link = content.link;
	}

	private initWidgets(): void {
		const data = this.data;
		const widgets = data.content.widgets;
		if (!widgets) {
			data.content.widgets = [];
			return;
		}

		const widgetReferences = data.widgetRefs;
		for (const widget of widgets) {
			const id = widget.id;
			try {
				// Just skip widgets without IDs for now
				if (id) {
					const ref: IWidgetHandle = ArrayUtil.itemByProperty(
						widgetReferences,
						"id",
						id,
					);
					const definitionExist = this.widgetService.getCachedDefinition(
						widget.id,
					);
					const isByRef = ref ? ref.byRef : false;
					if (definitionExist) {
						const parentContext = this.getWidgetParentContext(widget);
						// Remove this information since the definition is available now
						if (widget.isBroken) {
							delete widget.isBroken;
							delete widget.brokenMessage;
							delete widget.brokenReason;
						}
						this.addDynamicInstanceId(widget);
						this.addToWidgets(
							this.widgetFactory.createWidget(
								parentContext,
								widget,
								false,
								isByRef,
							),
						);
					} else {
						widget.isBroken = true;
						widget.brokenReason = this.widgetService.getBrokenReason(id);
						widget.brokenMessage = WidgetUtil.getBrokenMessage(
							this.lang,
							widget.brokenReason,
						);
						const brokenParentContext = this.getBrokenWidgetParentContext();
						const brokenWidget = this.widgetFactory.createWidget(
							brokenParentContext,
							widget,
							false,
							isByRef,
						);
						const wid = ref ? ref.id : id;
						const pid = ref ? ref.pid : "";
						brokenWidget.definition = new BrokenWidgetDefinition(wid, pid);
						this.addToWidgets(brokenWidget);
						this.logWarning(
							`No definition was found in page for widget ID: ${id}`,
						);
					}
				}
			} catch (ex) {
				this.logError(`Failed to add widget ${id || "?"}`, ex);
			}
		}
	}

	private addDynamicInstanceId(widget: IWidgetData) {
		if (this.isDynamic && !widget.instanceId) {
			widget.instanceId = CommonUtil.random();
		}
	}

	private clearWidgets() {
		const widgets = this.widgets;
		for (const widget of widgets) {
			widget.destroy();
		}

		// Clear the content but preserve any external references to the arrays
		widgets.length = 0;
		this.data.content.widgets.length = 0;
	}

	private addToWidgets(widget: IWidget, index?: number) {
		widget.isDev = this.widgetService.isDev();

		if (index >= 0) {
			this.widgets.splice(index, 0, widget);
		} else {
			this.widgets.push(widget);
		}

		widget.changed().on((e: IChangedInfo<IWidget>) => {
			if (e && e.source) {
				this.raiseChanged(false, e.delayed);
			}
		});
	}

	private addInternal(widget: IWidget, index: number): void {
		const data = widget.data;
		if (!data.layout) {
			const layout = this.getLayout();
			const defaultSize = WidgetUtil.getStandardSize(widget.definition);
			layout.columnSpan = defaultSize.columnSpan;
			layout.rowSpan = defaultSize.rowSpan;
			data.layout = layout;
		}

		this.addToWidgets(widget, index);

		if (index >= 0) {
			this.data.content.widgets.splice(index, 0, data);
		} else {
			this.data.content.widgets.push(data);
		}
	}

	private removeInternal(widget: IWidget): void {
		ArrayUtil.remove(this.widgets, widget);
		ArrayUtil.remove(this.data.content.widgets, widget.data);
	}

	private raiseChanged(layoutChanged?: boolean, delayed?: boolean): void {
		this.changedEvent.raise({
			page: this,
			layoutChanged: layoutChanged,
			delayed: delayed,
		} as IPageChangedInfo);
	}

	private notify(widgetActivationType: string, isActivate: boolean) {
		const widgets = this.widgets;
		for (const widget of widgets) {
			widget.notifyActivation(widgetActivationType, isActivate);
		}
	}

	private hasSettings(): boolean {
		const settings = this.settings;
		return settings && Object.keys(settings).length > 0;
	}
}

export class PageUtil {
	static normalizeId(id: string): string {
		return id ? id.toLowerCase() : id;
	}

	static verifyContent(data: IPageData): void {
		const content = data.content as any;
		if (content) {
			// Convert legacy pages to the new format if necessary
			if (!content.widgets && content.length >= 0) {
				data.content = {
					widgets: content,
				};
			}
		} else {
			// Set default emtpy content
			data.content = {
				widgets: [],
			};
		}
	}

	/**
	 * Copies values from the source to the target page.
	 */
	static copyValues(source: IPageData, target: IPageData) {
		target.id = source.id;
		target.title = source.title;
		target.description = source.description;
		target.editAccess = source.editAccess;
		target.ownerId = source.ownerId;
		target.ownerName = source.ownerName;
		target.changeDate = source.changeDate;
		target.changedBy = source.changedBy;
		target.changedByName = source.changedByName;
		target.viewAccess = source.viewAccess;
		target.tags = source.tags;
		if (!target.content) {
			target.content = {};
		}

		target.color = source.color;
	}

	static copy(page: IPageData): IPageData {
		const p: IPageData = { content: {} };
		PageUtil.copyValues(page, p);
		return p;
	}

	/**
	 * Gets a value that indicates if a page is private.
	 */
	static isPrivate(page: IPage): boolean {
		if (page && page.data.isStandard) {
			return false;
		}
		if (page && page.data.viewAccess === AccessType.Owner) {
			return true;
		}
		return false;
	}

	static addHomepageControl(element: JQuery, animationEnabled: boolean): void {
		if (element.data("homepage")) {
			PageUtil.attachHomepageEvents(element, true, animationEnabled);
			return;
		}

		element.homepage({ animate: animationEnabled });
	}

	static destroyHomepageControl(element: JQuery): void {
		const data: any = element.data("homepage");
		if (data) {
			data.destroy();
		}
	}

	static attachHomepageEvents(
		element: JQuery,
		refresh: boolean,
		animationEnabled: boolean,
	): void {
		const data: any = element.data("homepage");
		if (!data) {
			PageUtil.addHomepageControl(element, animationEnabled);
			return;
		}

		data.handleEvents();
		if (refresh) {
			PageUtil.refreshHomepageLayout(element, animationEnabled);
		}
	}

	static detachHomepageEvents(element: JQuery): void {
		const data: any = element.data("homepage");
		if (data) {
			data.detachEvents();
		}
	}

	static refreshHomepageLayout(
		element: JQuery,
		animationEnabled: boolean,
	): void {
		const data: any = element.data("homepage");
		if (!data) {
			PageUtil.addHomepageControl(element, animationEnabled);
			return;
		}

		data.resize(data, true);

		// To make sure charts and toolbars are resized correctly when switching between pages, handleResize for banners
		const banner = element.parent().find(".lm-banner");
		if (banner && banner.length > 0) {
			(banner.filter(":visible") as any).handleResize();
		}
	}

	/**
	 * Returns the current Xi Homepages settings from one of the active homepages
	 */
	static getSettings(): IHomepageSettings {
		const homepages = $(".homepage");
		for (let i = 0; i < homepages.length; i++) {
			const data: any = $(homepages[i]).data("homepage");
			if (data) {
				return data.settings as IHomepageSettings;
			}
		}
		return null;
	}

	static getLayout(
		element: JQuery,
		settings: IHomepageSettings,
	): IWidgetLayout {
		// Note that this function currently ignores extra gutters for widgets greater than 1x1.
		// Currently this is OK since the values are rounded to integers.

		const getVal = (name: string): number => {
			return parseInt(element.css(name));
		};
		const widgetHeight = settings.widgetHeight;
		const widgetWidth = settings.widgetWidth;
		const gutter = settings.gutterSize;
		const location: IWidgetLayout = {
			column: Math.round(getVal("left") / (widgetWidth + gutter)),
			row: Math.round(getVal("top") / (widgetHeight + gutter)),
			columnSpan: Math.round(getVal("width") / widgetWidth),
			rowSpan: Math.round(getVal("height") / widgetHeight),
		};
		return location;
	}

	static updateLayout(widgets: IWidget[]): void {
		const settings = PageUtil.getSettings();
		if (!settings) {
			return;
		}

		for (const widget of widgets) {
			if (!widget.isBanner() && widget.element) {
				const layout = this.getLayout(widget.element, settings);
				if (layout) {
					widget.data.layout = layout;
				}
			}
		}
	}

	static isSecurityMessages(messages: MessageInfo[]): boolean {
		try {
			if (messages) {
				for (let index = 0; index < messages.length; index++) {
					const message = messages[index];
					if (message) {
						if (
							message.code === ResponseErrorCodes.errorLoadUserAttributes ||
							message.code === ResponseErrorCodes.errorLoadUserGroups ||
							message.code === ResponseErrorCodes.errorLoadUserRoles
						) {
							return true;
						}
					}
				}
			}
			return false;
		} catch (ex) {
			return false;
		}
	}

	/**
	 * Creates new instance IDs for all widgets and updates the keys for any widget user settings.
	 * This method is intended for export and duplication scenarios.
	 * Settings are retrieved from the page data level.
	 */
	static updateWidgetIdsPageData(pageData: IPageData): void {
		PageUtil.updateWidgetIds(pageData.content.widgets, pageData.userSettings);
	}

	/**
	 * Creates new instance IDs for all widgets and updates the keys for any widget user settings.
	 * This method is intended for when the container is loaded.
	 * Settings are retrieved from the page level.
	 */
	static updateWidgetIdsPage(page: IPage): void {
		PageUtil.updateWidgetIds(page.data.content.widgets, page.settings);
	}

	static updateWidgetIds(widgets?: IWidgetData[], settings?: any): void {
		if (!widgets || widgets.length === 0) {
			return;
		}

		const widgetSettings = settings ? settings["widgets"] : null;

		for (const widget of widgets) {
			const oldId = widget.instanceId;
			const newId = CommonUtil.random();

			if (widgetSettings) {
				const value = widgetSettings[oldId];
				if (value) {
					delete widgetSettings[oldId];
					widgetSettings[newId] = value;
				}
			}

			widget.instanceId = newId;
		}
	}
}

export class PageDataValidator extends ValidatorBase<IPageData> {
	constructor(optionalDescription?: boolean) {
		super([
			{
				max: Constants.pageTitleLength,
				name: "title",
			},
			{
				max: Constants.pageDescriptionLength,
				name: "description",
				optional: optionalDescription,
			},
		]);
	}
}
