import * as marked from "marked";
import { Observable } from "rxjs";

export class MarkdownParser {
	constructor(private supportOptions: IMarkdownSyntaxSupportOptions) {}
	parse(markdownContent: string): Observable<string> {
		return new Observable<string>((observer) => {
			const parseOptions: marked.MarkedOptions = {
				gfm: true,
				headerIds: false,
				renderer: new SohoMarkdownRenderer(this.supportOptions),
			};
			marked(markdownContent, parseOptions, (error, result) => {
				if (error) {
					observer.error(error);
				} else {
					observer.next(result);
					observer.complete();
				}
			});
		});
	}
}

class SohoMarkdownRenderer extends marked.Renderer {
	constructor(private support: IMarkdownSyntaxSupportOptions) {
		super();
	}
	code(code: string, language: string, isEscaped: boolean): string {
		if (!this.support.codeBlocks) {
			return "";
		}
		return super.code(code, language, isEscaped);
	}
	blockquote(quote: string): string {
		if (!this.support.quotes) {
			return "";
		}
		return super.blockquote(quote);
	}
	html(html: string): string {
		if (!this.support.html) {
			return "";
		}
		return super.html(html);
	}
	heading(
		text: string,
		level: number,
		raw: string,
		slugger: marked.Slugger,
	): string {
		if (!this.support.headings) {
			return "";
		}
		return super.heading(text, level, raw, slugger);
	}
	hr(): string {
		if (!this.support.horizontalLines) {
			return "";
		}
		return super.hr();
	}
	list(body: string, ordered: boolean, start: number): string {
		if (!this.support.lists) {
			return "";
		}
		return super.list(body, ordered, start);
	}
	listitem(text: string): string {
		if (!this.support.lists) {
			return "";
		}
		return super.listitem(text);
	}
	table(header: string, body: string): string {
		if (!this.support.tables) {
			return "";
		}
		return super.table(header, body);
	}
	tablerow(content: string): string {
		if (!this.support.tables) {
			return "";
		}
		return super.tablerow(content);
	}
	tablecell(
		content: string,
		flags: { header: boolean; align: "center" | "left" | "right" },
	): string {
		if (!this.support.tables) {
			return "";
		}
		return super.tablecell(content, flags);
	}
	strong(text: string): string {
		if (!this.support.bold) {
			return "";
		}
		return super.strong(text);
	}
	em(text: string): string {
		if (!this.support.emphasis) {
			return "";
		}
		return super.em(text);
	}
	codespan(code: string): string {
		if (!this.support.inlineCode) {
			return "";
		}
		return super.codespan(code);
	}
	del(text: string): string {
		if (!this.support.strikethrough) {
			return "";
		}
		return super.del(text);
	}
	image(href: string, title: string, text: string): string {
		if (!this.support.images) {
			return "";
		}
		return super.image(href, title, text);
	}
	link(href: string, title: string, text: string) {
		if (!this.support.links) {
			return "";
		}
		const standardLink = super.link(href, title, text);
		return standardLink.replace("<a ", `<a class="hyperlink" target="_blank" `);
	}
	paragraph(text: string) {
		if (!this.support.paragraphs) {
			return `<p class="lm-display-inline markdown-text">${text}</p>\n`;
		}
		return super.paragraph(text);
	}
}

export class HtmlParser {
	parse(htmlContent: string): Observable<string> {
		return new Observable<string>((observer) => {
			const template = document.createElement("template");
			template.innerHTML = htmlContent;
			const result = this.parseFragment(template.content);
			observer.next(result);
			observer.complete();
		});
	}

	private parseFragment(fragment: Node): string {
		let result = "";

		for (let i = 0; i < fragment.childNodes.length; i++) {
			const child = fragment.childNodes[i];

			if (isElement(child)) {
				switch (child.nodeName) {
					case "H1":
						result += `# ${this.parseFragment(child)}\n`;
						break;
					case "H2":
						result += `## ${this.parseFragment(child)}\n`;
						break;
					case "H3":
						result += `### ${this.parseFragment(child)}\n`;
						break;
					case "H4":
						result += `#### ${this.parseFragment(child)}\n`;
						break;
					case "A":
						result += `[${this.parseFragment(child)}](${child.getAttribute(
							"href",
						)})`;
						break;
					case "P":
						result += `${this.parseFragment(child)}\n`;
						break;
					case "DIV":
						result += `${this.parseFragment(child)}\n`;
						break;
					case "IMG":
						result += `![${child.getAttribute("alt")}](${child.getAttribute(
							"src",
						)})`;
						break;
					case "EM":
						result += `*${this.parseFragment(child)}*`;
						break;
					case "I":
						result += `*${this.parseFragment(child)}*`;
						break;
					case "STRONG":
						result += `**${this.parseFragment(child)}**`;
						break;
					case "B":
						result += `**${this.parseFragment(child)}**`;
						break;
					case "DEL":
						result += `~${this.parseFragment(child)}~`;
						break;
					case "STRIKE":
						result += `~${this.parseFragment(child)}~`;
						break;
					case "BR":
						result += "\n\n";
						break;
					case "SPAN":
						result += this.parseFragment(child);
						break;
					case "LI":
						if (child.parentElement.tagName === "OL") {
							result += `1. ${this.parseFragment(child)}\n`;
						} else if (child.parentElement.tagName === "UL") {
							result += `- ${this.parseFragment(child)}\n`;
						}
						break;
					case "UL":
						result += `\n${this.parseFragment(child)}`;
						break;
					case "OL":
						result += `\n${this.parseFragment(child)}`;
						break;
				}
			} else {
				result += child.textContent;
			}
		}
		return result;
	}
}

function isElement(node: Node): node is Element {
	return node.nodeType === Node.ELEMENT_NODE;
}

export interface IMarkdownSyntaxSupportOptions {
	readonly quotes?: boolean;
	readonly inlineCode?: boolean;
	readonly codeBlocks?: boolean;
	readonly strikethrough?: boolean;
	readonly emphasis?: boolean;
	readonly headings?: boolean;
	readonly horizontalLines?: boolean;
	readonly html?: boolean;
	readonly images?: boolean;
	readonly links?: boolean;
	readonly lists?: boolean;
	readonly bold?: boolean;
	readonly tables?: boolean;
	readonly paragraphs?: boolean;
}

export class MarkdownSyntaxSupport {
	static readonly All: IMarkdownSyntaxSupportOptions = {
		quotes: true,
		inlineCode: true,
		codeBlocks: true,
		strikethrough: true,
		emphasis: true,
		headings: true,
		bold: true,
		horizontalLines: true,
		html: true,
		images: true,
		links: true,
		lists: true,
		tables: true,
		paragraphs: true,
	};
}
