import {
	Component,
	Input,
	OnDestroy,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import { SohoMessageService } from "@infor/sohoxi-angular";
import { Subscription } from "rxjs";
import { ContainerService } from "../../base/container";
import { AdminPages, IAdminContainerComponent } from "../../base/core";
import { CoreBase } from "../../base/runtime";
import {
	LanguageService,
	LazyTypeService,
	ProgressService,
} from "../../base/service";
import { ContextService } from "../../service";

@Component({
	selector: "lm-admin-host",
	templateUrl: "./admin-host.html",
})
export class AdminHostComponent extends CoreBase implements OnInit, OnDestroy {
	@ViewChild("adminView", { read: ViewContainerRef, static: true })
	adminView: ViewContainerRef;
	@Input() page: AdminPages;

	isHidden: boolean;

	private toggleSubscription: Subscription;
	private adminInstance: IAdminContainerComponent;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		private readonly contextService: ContextService,
		private readonly containerService: ContainerService,
		private readonly lazyTypeService: LazyTypeService,
		private readonly progressService: ProgressService,
	) {
		super("AdminHostComponent", messageService, languageService);

		if (contextService.isStandard) {
			this.toggleSubscription = containerService.admin$.subscribe(
				(toggleAdmin) => {
					this.isHidden = toggleAdmin.isHide;
					const isShow = !(toggleAdmin.isHide || toggleAdmin.isClose);
					const page = toggleAdmin.page || this.page;
					if (isShow && page) {
						if (this.adminInstance) {
							this.adminInstance.changeTab(page);
							// Edge fix for https://jira.infor.com/browse/LIME-3808
							$(window).trigger("resize");
						} else {
							// Delay page display until module lazy load is complete
							this.page = page;
						}
					}
				},
			);
		}
	}

	ngOnInit(): void {
		if (this.contextService.isStandard) {
			this.load();
		}
	}

	ngOnDestroy(): void {
		this.toggleSubscription.unsubscribe();
	}

	private load(): void {
		this.progressService.setBusy(true);
		this.lazyTypeService
			.loadAdminModule()
			.then(({ AdminContainerComponent, ngModuleRef }) => {
				const component = this.adminView.createComponent(
					AdminContainerComponent,
					{ ngModuleRef },
				);
				const instance = component.instance;
				this.adminInstance = instance;
				instance.changeTab(this.page);
			})
			.catch(() => {
				// Disable the admin tool to avoid the "blank white screen"
				// More changes are required if we want the update dialog to be displayed more than once
				this.containerService.disableAdmin();
			})
			.finally(() => this.progressService.setBusy(false));
	}
}
