import {
	ChangeDetectorRef,
	Directive,
	ElementRef,
	HostBinding,
	OnDestroy,
	OnInit,
} from "@angular/core";
import { interval, Subject } from "rxjs";
import { distinctUntilChanged, map, takeUntil } from "rxjs/operators";

class WidgetSize {
	static readonly SINGLE = 358;
	static readonly DOUBLE = 734;
	static readonly TRIPLE = 1110;
	static readonly QUAD = 1498;
}

@Directive({
	selector: "[lm-dimensions]",
})
export class DimensionsDirective implements OnInit, OnDestroy {
	/**
	 * Controls the interval in milliseconds for detecting changes in element width. Tune for performance.
	 */
	private static readonly CHANGE_DETECTION_INTERVAL_MS = 500;

	@HostBinding("class.lm-one-column") singleColumn: boolean;
	@HostBinding("class.lm-two-column") doubleColumn: boolean;
	@HostBinding("class.lm-three-column") tripleColumn: boolean;
	@HostBinding("class.lm-four-column") quadColumn: boolean;

	private destroyed$ = new Subject<void>();

	constructor(
		private elementRef: ElementRef<HTMLElement>,
		private changeDetectorRef: ChangeDetectorRef,
	) {}

	ngOnInit() {
		/**
		 * NOTE: An interval is needed here because Angular change detection does not
		 * trigger on element resize. Instead, the element size is checked periodically.
		 */
		interval(DimensionsDirective.CHANGE_DETECTION_INTERVAL_MS)
			.pipe(
				takeUntil(this.destroyed$),
				map(() => this.getElementWidth()),
				distinctUntilChanged(),
			)
			.subscribe((elementWidth) => {
				this.widthChanged(elementWidth);
			});
	}
	ngOnDestroy() {
		this.destroyed$.next();
		this.destroyed$.complete();
	}

	triggerDetection(): void {
		this.widthChanged(this.getElementWidth());
	}

	private getElementWidth() {
		return this.elementRef.nativeElement.getBoundingClientRect().width;
	}

	private widthChanged(elementWidth: number) {
		this.singleColumn = elementWidth < WidgetSize.DOUBLE;
		this.doubleColumn =
			elementWidth >= WidgetSize.DOUBLE && elementWidth < WidgetSize.TRIPLE;
		this.tripleColumn =
			elementWidth >= WidgetSize.TRIPLE && elementWidth < WidgetSize.QUAD;
		this.quadColumn = elementWidth >= WidgetSize.QUAD;
		this.changeDetectorRef.markForCheck();
	}
}
