import { Component, EventEmitter, Input, Output } from "@angular/core";
import {
	ArrayUtil,
	ILanguage,
	IWidgetContext,
	IWidgetInstance,
	Log,
} from "lime";
import { IEmptyConfig } from "../../base/core";
import { LanguageService } from "../../base/service";

@Component({
	selector: "lm-widget-empty-config",
	template: `
		<div
			soho-emptymessage
			color="azure"
			[icon]="icon"
			[title]="title"
			[info]="description"
			[button]="button"
			[attributes]="{ name: 'name', value: 'lm-emptyconfig' }"></div>
	`,
})
export class WidgetEmptyConfigComponent {
	@Input() emptyConfig: IEmptyConfig;
	@Input() instance: IWidgetInstance;
	@Input() widgetContext: IWidgetContext;
	@Input() isInactive: boolean;
	@Output() onConfigureClicked = new EventEmitter();

	widgetTitle: string;
	title: string;
	description: string;
	icon: string;
	button: SohoEmptyMessageButtonOptions;
	defaultIcon = "icon-empty-error-loading";
	iconsOptions = [
		"generic",
		"error-loading",
		"new-project",
		"no-alerts",
		"no-analytics",
		"no-budget",
		"no-data",
		"no-events",
		"no-notes",
		"no-orders",
		"no-tasks",
	];

	constructor(private readonly languageService: LanguageService) {}

	ngOnInit() {
		const settingsLang = this.languageService.getLanguage();
		const widgetLang = this.widgetContext.getLanguage();
		const emptyConfig = this.emptyConfig;

		if (emptyConfig) {
			this.title = widgetLang.get(emptyConfig.titleId);
			this.description = widgetLang.get(emptyConfig.descriptionId);
		}

		this.icon = this.setIcon(emptyConfig?.icon);
		this.button = this.setButton(
			emptyConfig?.buttonId,
			settingsLang,
			widgetLang,
		);
		this.widgetTitle = this.widgetContext.getTitle();
	}

	setIcon(icon: string): string {
		const isValidIcon = ArrayUtil.contains(this.iconsOptions, icon);
		if (isValidIcon) {
			return "icon-empty-" + icon;
		}
		return this.defaultIcon;
	}

	setButton(
		buttonId: string,
		settingsLang: ILanguageLime,
		widgetLang: ILanguage,
	): SohoEmptyMessageButtonOptions {
		const buttonText = buttonId
			? widgetLang.get(buttonId)
			: settingsLang.widgetSettings;
		return {
			text: buttonText,
			isPrimary: true,
			click: () => this.onButtonClick(this),
		};
	}

	onButtonClick(self: WidgetEmptyConfigComponent): void {
		const instance = self.instance;
		if (instance?.emptyConfigClicked) {
			try {
				instance.emptyConfigClicked();
			} catch (e) {
				const message = "Failed to invoke the emptyConfigClicked event handler";
				Log.error(message, e);
			}
		} else {
			self.onConfigureClicked.emit();
		}
	}
}
