import {
	Component,
	ElementRef,
	EventEmitter,
	Input,
	NgZone,
	OnDestroy,
	OnInit,
	Output,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import { NumUtil } from "lime";
import { WidgetUtil } from "../../widget/runtime";

@Component({
	selector: "lm-banner-container",
	templateUrl: "./widget-banner.html",
	styleUrls: ["./widget-banner.scss"],
})
export class BannerContainerComponent implements OnInit, OnDestroy {
	private static widthClasses = "to-single to-double to-triple to-quad";
	@Input() isEdit: boolean;
	@Input() currentColumns: number;
	@Input() hasHiddenWidget: boolean;
	@Input() hasBanner: boolean;
	@Output() currentColumnsChange = new EventEmitter<number>();

	@ViewChild("contentView", { read: ViewContainerRef, static: true })
	contentView: ViewContainerRef;

	bannerPages: { pos: number; banners: JQuery[] }[];
	bannerContainer: JQuery;
	selectedBannerPage = 0;
	private banners: JQuery;
	private hasBannerClass = "has-banner";

	constructor(
		private readonly element: ElementRef,
		private readonly zone: NgZone,
	) {
		this.bannerContainer = $(element.nativeElement);
	}

	ngOnInit(): void {
		this.bannerContainer.next().on("resize.homepage", (e, homepageColumns) => {
			const columnsChanged =
				typeof homepageColumns === "number" &&
				homepageColumns !== this.currentColumns;
			const newBannerCount =
				!this.banners ||
				this.banners.length !== this.bannerContainer.find(".lm-banner").length;
			const triggeredByBannerResize = homepageColumns === "bannerResized";

			if (columnsChanged || newBannerCount || triggeredByBannerResize) {
				if (columnsChanged) {
					this.currentColumns = homepageColumns;
					if (this.isEdit) {
						this.currentColumnsChange.emit(homepageColumns);
					}
				}

				this.zone.run(() => {
					this.updateBannerContainer(this.currentColumns);
				});
			}
		});
	}

	ngOnDestroy(): void {
		if (this.bannerContainer) {
			this.bannerContainer.next().off("resize.homepage");
		}
	}

	nextPage() {
		this.selectPage(
			NumUtil.mod(this.selectedBannerPage + 1, this.bannerPages.length),
		);
	}

	previousPage() {
		this.selectPage(
			NumUtil.mod(this.selectedBannerPage - 1, this.bannerPages.length),
		);
	}

	selectPage(pageIndex: number, force?: boolean): void {
		if (pageIndex === this.selectedBannerPage && !force) {
			return;
		}

		this.selectedBannerPage = pageIndex;

		// Hide all banners and only show the ones on the selected page. Update left position based on the visible banners on the same page.
		this.banners.hide();
		let index = 0;
		let extraLeft = 0;
		for (const banner of this.bannerPages[pageIndex].banners) {
			extraLeft = this.setLeftPosition(banner, index, extraLeft);
			banner.show();
			index++;
		}

		this.triggerChartsResize();
	}

	private updateBannerContainer(columns: number): void {
		const banners = this.bannerContainer.find(
			".lm-banner:not('.ui-draggable-dragging')",
		);

		if (this.isEdit) {
			this.setHasBannerClass();
			this.toggleContainerVisibility(banners, columns);
		}

		const totalBanners = banners.length;
		if (!totalBanners || !columns) {
			this.banners = null;
			return;
		}

		this.banners = banners;

		// Calculate margin of the .content div (matching main homepage)
		const marginleft = -(180 * columns + (columns - 1) * 10);
		this.bannerContainer.find(".content").css("margin-left", marginleft + "px");

		// Always reset pages and remove temporary banner classes
		this.bannerPages = [{ pos: 0, banners: [] }];
		banners.removeClass(BannerContainerComponent.widthClasses);

		let tempClass: string;
		if (!this.isEdit && this.hasHiddenWidget) {
			if (totalBanners === 1) {
				tempClass = "to-quad";
				$(banners[0]).addClass(tempClass);
			} else if (totalBanners === 3) {
				tempClass = "to-double";
				$(banners[0]).addClass(tempClass);
			} else {
				tempClass = "to-double";
				$(banners[0]).addClass(tempClass);
				$(banners[1]).addClass(tempClass);
			}
		}
		if (columns === 4) {
			// No pagination, temporary layout classes have been applied if any banner widget has been hidden
			// otherwise all banners match their desired columnSpan
			banners.show();
			let extraLeft = 0;
			banners.each((index, banner) => {
				extraLeft = this.setLeftPosition(banner, index, extraLeft);
			});
			this.selectedBannerPage = 0;
			this.bannerContainer.removeClass("has-pagination");
			this.triggerChartsResize();
		} else {
			// Calculate the temporary layout classes and pagination of banners
			let occupies: number;
			let addedToPage = 0;
			let pageIndex = 0;

			banners.each((index, banner) => {
				occupies =
					WidgetUtil.bannerWidthMatrix[totalBanners - 1][columns - 1][index];
				const element = $(banner);
				if (occupies === 0) {
					// Special case when having three banners in three column mode, make sure first or second banner maintains its double size
					occupies =
						element.hasClass("double-width") ||
						element.hasClass("to-double") ||
						(index === 0 &&
							($(banners[2]).hasClass("double-width") ||
								$(banners[2]).hasClass("to-double")))
							? 2
							: 1;
				}
				tempClass =
					BannerContainerComponent.widthClasses.split(" ")[occupies - 1];
				element.removeClass(BannerContainerComponent.widthClasses);
				element.addClass(tempClass);

				if (addedToPage + occupies <= columns) {
					this.bannerPages[pageIndex].banners.push(element);
				} else {
					pageIndex++;
					addedToPage = 0;
					this.bannerPages.push({ pos: pageIndex, banners: [element as any] });
				}

				addedToPage += occupies;
			});

			const pages = this.bannerPages.length;

			if (pages > 1 && !(this.isEdit && columns < 4)) {
				this.bannerContainer.addClass("has-pagination");
			}

			// Always select the current page or the last possible page if current page has been removed
			if (this.selectedBannerPage > pages - 1) {
				this.selectPage(pages - 1);
			} else {
				this.selectPage(this.selectedBannerPage, true);
			}
		}
	}

	private toggleContainerVisibility(banners: JQuery, columns: number): void {
		const container = this.bannerContainer;
		const isEditable = container.siblings("#lmBannerNotEditable").length === 0;
		if (banners.length && isEditable) {
			if (columns === 4) {
				container.show();
				container.prev().hide();
			} else {
				container.hide();
				container.prev().show();
			}
		} else {
			// If not editable another view is visible
			container.hide();
			container.prev().hide();
		}
	}

	private setLeftPosition(
		banner: any,
		index: number,
		extraLeft: number,
	): number {
		// Set the left position based on the width of neighboring banners on the same page
		const prev = this.isEdit
			? $(banner).prev()
			: $(banner).parent().prev().find(".lm-banner");

		if (prev.length && prev.css("display") !== "none") {
			if (prev.hasClass("double-width") || prev.hasClass("to-double")) {
				extraLeft = 380;
			} else if (prev.hasClass("triple-width") || prev.hasClass("to-triple")) {
				extraLeft = 760;
			}
		}

		$(banner).css("left", index * 380 + extraLeft + "px");
		return extraLeft;
	}

	private triggerChartsResize(): void {
		// Make sure charts are resized correctly
		this.bannerContainer.find(".chart-container").trigger("resize");
	}

	private setHasBannerClass(): void {
		if (this.hasBanner) {
			this.bannerContainer.addClass(this.hasBannerClass);
		} else {
			this.bannerContainer.removeClass(this.hasBannerClass);
		}
	}
}
