import { Mode, SubMode } from "lime";
import { Observable, ReplaySubject } from "rxjs";
import { IStringToAnyMap, IWidget, IWidgetParentContext } from "../base/core";

interface ISubjectMap {
	[key: string]: ReplaySubject<unknown>;
}

export class WidgetParentContext implements IWidgetParentContext {
	isPublished = true;
	isStandard: boolean;
	isDynamic: boolean;
	userSettings: IStringToAnyMap;
	mode = Mode.ContextApp;

	private _subMode = SubMode.Default;
	private readonly messageSubjects: ISubjectMap = {};

	get subMode(): SubMode {
		return this._subMode;
	}

	set subMode(value: SubMode) {
		this._subMode = value;
	}

	constructor(readonly id: string) {}

	addWidget(widget: IWidget): void {
		// NOP
	}

	isUserPreview(): boolean {
		return false;
	}

	receive(name: string): Observable<unknown> {
		return this.getMessageSubject(name).asObservable();
	}

	deliverMessage(name: string, data: unknown): void {
		this.getMessageSubject(name).next(data);
	}

	private getMessageSubject(name: string): ReplaySubject<unknown> {
		let subject = this.messageSubjects[name];
		if (!subject) {
			subject = new ReplaySubject(1);
			this.messageSubjects[name] = subject;
		}
		return subject;
	}
}
