import { ArrayUtil, CommonUtil, Log, NumUtil, WidgetConstants } from "lime";
import { AsyncSubject, forkJoin, Observable } from "rxjs";
import { ContainerService } from "../base/container";
import {
	ClientMode,
	Constants,
	IContext,
	IContextOptions,
	IOperationResponse,
	IPage,
	IPageContainer,
	IPageContainerData,
	IPageData,
	IWidgetData,
	IWidgetDefinition,
	IWidgetDefinitionItem,
	OperationResponse,
	ResponseErrorCodes,
	SettingsNames,
} from "../base/core";
import {
	DevConfigurationData,
	DevConfigurationInfo,
	DevService,
} from "../base/dev";
import {
	ClientConfiguration,
	CoreBase,
	CoreUtil,
	HttpUtil,
} from "../base/runtime";
import {
	EditModeService,
	LanguageService,
	LazyTypeService,
	ProgressService,
} from "../base/service";
import { PageUtil } from "../page/runtime";
import { PageService } from "../page/service";
import { ContextService, DataService } from "../service";
import { SystemMessagesService } from "../services/system-messages.service";
import { WidgetLayout } from "../widget/core";
import { WidgetUtil } from "../widget/runtime";
import { WidgetService } from "../widget/service";
import {
	IContainerOptions,
	IPageContainerRequest,
	IPageContainerResponse,
} from "./core";
import { PageContainer, PageContainerFactory } from "./service";

@Injectable({
	providedIn: "root",
})
export class ContainerLoaderService extends CoreBase {
	private readonly context: IContext;
	private readonly language: ILanguageLime;
	private containerData: IPageContainerData;
	private pageContainer: PageContainer;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		private readonly lazyTypeService: LazyTypeService,
		private sohoContextualActionPanelService: SohoContextualActionPanelService,
		private progressService: ProgressService,
		private dataservice: DataService,
		private contextService: ContextService,
		private pageService: PageService,
		private containerService: ContainerService,
		private editModeService: EditModeService,
		private widgetService: WidgetService,
		private sohoModalDialogService: SohoModalDialogService,
		private toastService: SohoToastService,
		private http: HttpClient,
		private readonly devService: DevService,
		private readonly systemMessagesService: SystemMessagesService,
		private pageContainerFactory: PageContainerFactory,
	) {
		super("ContainerService", messageService, languageService);

		this.context = contextService.getContext();
		this.language = languageService.getLanguage();
	}

	getContainer(): IPageContainer {
		return this.pageContainer;
	}

	loadContainer(
		containerOptions: IContainerOptions,
	): Observable<IPageContainer> {
		const subject = new AsyncSubject<IPageContainer>();
		const context = this.context;

		const isPreLoaded = ClientConfiguration.isPreLoaded();
		if (!isPreLoaded) {
			context.setBusy(true);
		}

		this.initLanguage();

		// Widget development mode
		if (this.devService.isDev) {
			this.initDev(subject);
			context.setBusy(false);
			return subject.asObservable();
		}

		// Normal mode
		const config = ClientConfiguration;
		config.initialize();

		// Preloaded container data (not possible in all scenarios)
		const observable = config.popPreLoad();
		if (observable) {
			this.logDebug("Waiting for preloaded container");
			observable.subscribe(
				(response: IPageContainerResponse) => {
					this.onLoad(subject, response);
				},
				(response: IOperationResponse) => {
					if (this.canRetry(response)) {
						this.loadRequest(containerOptions, subject);
					} else {
						this.onLoadError(subject, response);
					}
				},
			);
			return subject.asObservable();
		}

		// Load container data
		this.loadRequest(containerOptions, subject);
		return subject.asObservable();
	}

	private canRetry(error: any): boolean {
		return error && HttpUtil.canRetry(error.status);
	}

	private loadRequest(
		containerOptions: IContainerOptions,
		subject: AsyncSubject<IPageContainer>,
	): void {
		const request: IPageContainerRequest = { options: containerOptions };
		containerOptions.mode = containerOptions.mode || ClientMode.Standard;

		this.dataservice.post("/page/container", request).subscribe(
			(response: IPageContainerResponse) => {
				this.onLoad(subject, response);
			},
			(response: IOperationResponse) => {
				this.onLoadError(subject, response);
			},
		);
	}

	private onLoad(
		subject: AsyncSubject<IPageContainer>,
		response: IPageContainerResponse,
	): void {
		try {
			this.onResponse(response);
			subject.next(this.pageContainer);
			subject.complete();
		} finally {
			this.context.setBusy(false);
		}
	}

	private onLoadError(
		subject: AsyncSubject<IPageContainer>,
		response: IOperationResponse,
	): void {
		this.context.setBusy(false);
		this.logError("onLoadError: Failed to load page container: " + response);
		this.createErrorContainer("Failed to load page container");
		let errorTitle = this.language.errorUnavailable;
		const errorList = response.errorList;
		if (
			errorList &&
			errorList.length &&
			errorList[0].code === ResponseErrorCodes.forbidden
		) {
			errorTitle = this.language.errorUnauthorizedPage + " (403)";
		}
		let message = this.language.contactAdminRetry;
		if (response.errorHttpCode === ResponseErrorCodes.undefined.toString()) {
			message = this.language.errorSignOut;
		}
		this.showMessage(errorTitle, message);
		subject.next(this.pageContainer);
		subject.complete();
	}

	private initLanguage(): void {
		// Get url parameters from mingle limeLanguage is a global javascript variable
		const language = this.context.getLanguage();
		Log.debug("Parameter " + Constants.mingleLanguage + " set to :" + language);

		// Initialize language
		this.dataservice.setLanguage(language);
	}

	private getLocalization(definition: IWidgetDefinition, language: string) {
		const localization = definition.localization;
		return localization
			? localization[language] || localization["en-US"]
			: null;
	}

	private updateShared(devData: DevConfigurationData, language: string): void {
		const definition = devData.sharedDefinition;
		const variant = devData.widgetDefinition;
		if (!definition || !variant) {
			return;
		}

		definition.widgetId = variant.widgetId;
		definition.sharedWidgetId = variant.sharedWidgetId;

		// Apply settings value overrides from the variant to the definition
		definition.defaultValues = variant.defaultValues;
		WidgetUtil.updateDefaults(definition);

		// Apply localization value overrides from the variant to the definition
		const localization = this.getLocalization(definition, language);
		const localizationVariant = this.getLocalization(variant, language);
		if (localization && localizationVariant) {
			const titleKey = WidgetConstants.widgetTitle;
			const descriptionKey = WidgetConstants.widgetDescription;
			const title = localizationVariant[titleKey];
			const description = localizationVariant[descriptionKey];
			if (title) {
				localization[titleKey] = title;
			}
			if (description) {
				localization[descriptionKey] = description;
			}
			CoreUtil.extend(localization, localizationVariant);
		}

		// Reset the definition to the combination of the shared definition and the variant
		devData.widgetDefinition = definition;
	}

	private loadDevContainer(
		devInfo: DevConfigurationInfo,
	): IPageContainerResponse {
		// TODO Move all of or most of this to the DevService...

		const dev = this.devService.getConfiguration();
		const configuration = devInfo.configuration;
		const items = devInfo.items;
		const languageKey = this.devService.getLanguageKey();

		// NOTE We currently just use the ID of the first widget to load/save the dev container.
		const containerId = items[0].widgetId;
		const container = dev.load(containerId);
		container.widgetDefinitions = [];

		// Add configuration
		if (configuration) {
			container.configuration = configuration;

			const tenant = (configuration.tenant || "").trim();
			if (tenant) {
				container.tenantId = tenant;
			}
		}

		let page = null as IPageData;
		let serverPage = null as IPage;

		serverPage = container.pages[0];
		serverPage.isEditable = true;
		page = serverPage.data;
		page.widgetRefs = [];
		dev.initPage(page);
		PageUtil.verifyContent(page);

		const isEqual = (
			widgets: IWidgetData[],
			items: DevConfigurationData[],
		): boolean => {
			if (widgets.length !== items.length) {
				return false;
			}
			for (let j = 0; j < widgets.length; j++) {
				if (widgets[j].id !== items[j].widgetDefinition.widgetId) {
					return false;
				}
			}
			return true;
		};

		let widgets = page.content.widgets;
		if (!widgets || !isEqual(widgets, items)) {
			page.content.widgets = widgets = [] as IWidgetData[];
		}

		let isBannerEnabled = false;
		for (let i = 0; i < items.length; i++) {
			const devData = items[i];

			this.updateShared(devData, languageKey);

			const definition = devData.widgetDefinition;
			let id = definition.widgetId;

			const enableSettings = definition.enableSettings !== false;
			const enableTitleEdit = definition.enableTitleEdit !== false;
			definition.enableSettings = enableSettings;
			definition.enableSettingsDef = enableSettings;
			definition.enableTitleEdit = enableTitleEdit;
			definition.enableTitleEditDef = enableTitleEdit;

			// Get the English description for now, consider using client language in dev mode
			const language = this.getLocalization(definition, languageKey);
			let title = null;
			if (language) {
				title = language[WidgetConstants.widgetTitle];
			} else {
				title = definition.title;
			}
			definition.localization = language;

			if (widgets.length < items.length) {
				widgets.push({});
			}

			let widgetData = widgets[i];
			if (widgetData.id !== id) {
				// Reset if the widget IDs no longer match
				widgets[i] = widgetData = {};
			}

			const customDefinition = devData.customDefinition;
			const useCustom = !!customDefinition;

			if (!widgetData.title) {
				widgetData.title = title;
			}

			widgetData.instanceId = CommonUtil.random();
			if (widgetData.isTitleLocked !== false) {
				widgetData.isTitleLocked = true;
			}

			widgetData.isBanner =
				ArrayUtil.contains(definition.targets, "banner") ||
				definition.target === "banner";
			isBannerEnabled = widgetData.isBanner || isBannerEnabled;

			if (useCustom) {
				definition.isPublished = true;
				definition.standardWidgetId = id;
				id = CommonUtil.random();
				definition.widgetId = id;
				definition.custom = customDefinition.custom;
				if (customDefinition.enableSettings === false) {
					definition.enableSettings = false;
				}
				if (customDefinition.enableTitleEdit === false) {
					definition.enableTitleEdit = false;
				}
			} else {
				// If a settings and data file is configured those should be used instead of the saved values - but only if the widget isn't customized
				if (devData.settings) {
					const devSettings = devData.settings.settings;
					if (devSettings) {
						this.logInfo(
							"Using settings from " +
								devData.settingsPath +
								". The stored settings in isolated storage will not be used.",
						);
						widgetData.settings = devSettings;
					}
				}
			}

			// Set the widget ID which might have changed
			widgetData.id = id;

			if (!widgetData.layout) {
				const column = i % 4;
				const row = Math.floor(i / 4);

				const size = definition.defaultSize;
				let columnSpan = 1;
				let rowSpan = 1;

				if (size) {
					if (size.length >= 1) {
						columnSpan = parseInt(size.charAt(0));
						columnSpan = columnSpan >= 1 && columnSpan <= 4 ? columnSpan : 1;
					}
					if (size.length === 3) {
						rowSpan = parseInt(size.charAt(2));
						rowSpan = rowSpan >= 1 && rowSpan <= 2 ? rowSpan : 1;
					}
				}

				widgetData.layout = new WidgetLayout(
					column,
					row,
					widgetData.isBanner ? 4 : columnSpan,
					rowSpan,
				);
			}

			const finalDefinition: IWidgetDefinition = CoreUtil.copy(definition);

			const item = {
				definition: finalDefinition,
				standardTitle: title,
				catalogTitle: title,
				localization: language,
			} as IWidgetDefinitionItem;

			finalDefinition.widgetId = id;
			finalDefinition.settings = definition.settings;
			finalDefinition.devPath = devData.devPath;
			finalDefinition.devPathShared = devData.sharedPath;

			finalDefinition.lang = language;
			container.widgetDefinitions.push(item);

			page.widgetRefs.push({
				id: id,
				// ReSharper disable once DoubleNegationOfBoolean
				byRef: !!finalDefinition.isPublished,
			});
		}

		(container as any).applicationSettings = [
			{ name: SettingsNames.enablePrivatePages, value: "true" },
			{ name: SettingsNames.maxUserPageCount, value: "5" },
			{ name: SettingsNames.maxWidgetsOnPageCount, value: "50" },
		];

		const response = new OperationResponse() as IPageContainerResponse;
		response.content = container;
		return response;
	}

	private initDev(
		subject: AsyncSubject<IPageContainer>,
		loadStartPage?: boolean,
	) {
		Log.setDebug();

		Constants.restRoot = "";

		const devInfo = this.devService.getInfo();
		const promises: any[] = [];

		if (devInfo.configurationPath) {
			promises.push(
				this.downloadFile(
					devInfo.configurationPath,
					devInfo.propConfiguration,
					devInfo,
				),
			);
		}

		for (const item of devInfo.items) {
			const widgetId = item.widgetId;
			if (widgetId) {
				item.devPath = widgetId;
				const definitionPath = widgetId + "/widget.manifest";
				promises.push(
					this.downloadFile(definitionPath, item.propWidgetDefinition, item),
				);
			}
			const sharedPath = item.sharedPath;
			if (sharedPath) {
				const definitionPath = sharedPath + "/widget.manifest";
				promises.push(
					this.downloadFile(definitionPath, item.propSharedDefinition, item),
				);
			}
			if (item.settingsPath) {
				promises.push(
					this.downloadFile(item.settingsPath, item.propSettings, item),
				);
			}
			if (item.customDefinitionPath) {
				promises.push(
					this.downloadFile(
						item.customDefinitionPath,
						item.propCustomDefinition,
						item,
					),
				);
			}
		}

		forkJoin(promises).subscribe(
			(result: any[]) => {
				this.onResponse(this.loadDevContainer(devInfo));
				subject.next(this.pageContainer);
				subject.complete();
			},
			(error: any[]) => {
				this.createErrorContainer(
					"Failed to load page container of one of the configured attributes.",
				);
				subject.next(this.pageContainer);
				subject.complete();
			},
		);
	}

	private downloadFile(
		path: string,
		propertyName: string,
		devObj: any,
	): Observable<any> {
		const uri = path + "?rid=" + CommonUtil.random();
		const subject = new AsyncSubject<any>();

		this.http.get(uri).subscribe(
			(response: HttpResponse<any>) => {
				devObj[propertyName] = response;
				subject.next({});
				subject.complete();
			},
			() => {
				this.logError(`Failed to download ${uri}`);
				subject.next({});
				subject.complete();
			},
		);

		return subject.asObservable();
	}

	private createErrorContainer(message: string) {
		this.pageContainer = this.pageContainerFactory.createPageContainer(
			this.messageService,
			this.languageService,
			this.lazyTypeService,
			this.containerService,
			this.contextService,
			this.devService,
			this.sohoModalDialogService,
			this.context,
			null as IPageContainerData,
			this.pageService,
			this.widgetService,
			this.progressService,
			this.toastService,
			this.systemMessagesService,
		);
		this.pageContainer.errorMessage = message;
	}

	private onResponse(response: IPageContainerResponse): void {
		const isRefresh = !!this.containerData;
		const containerData = response.content;
		this.containerData = containerData;

		if (containerData) {
			this.initLog(isRefresh);
			this.logInfo(
				"Loaded page container. Server version " + containerData.version,
			);

			this.initWidgets();
			this.initPages();
			this.initContext();
			this.initContainer();
			this.logCloudSuites();
		} else {
			this.onEmptyContainer();
		}

		this.checkSecurityMessage(response);
	}

	private initLog(isRefresh: boolean): void {
		if (this.devService.isDev) {
			return;
		}

		const level = NumUtil.getInt(
			ArrayUtil.itemByProperty(
				this.containerData.userSettings,
				"name",
				"LogLevel",
			).value as string,
			Log.levelInfo,
		);

		if (level < Log.level && isRefresh) {
			// Locally set log level is more detailed -> don't change it on refresh
			return;
		}

		Log.level = level;
	}

	private logCloudSuites(): void {
		const cloudSuites = this.containerData.cloudSuites;
		if (cloudSuites) {
			if (cloudSuites.length === 0) {
				this.logInfo(`Cloud Suite: No cloud suites.`);
			} else {
				this.logInfo(`Cloud Suite: ${cloudSuites.join(", ")}`);
			}
		}
	}

	private initContext(): void {
		const options = {
			containerData: this.containerData,
			containerUrl: this.getContainerUrl(),
		} as IContextOptions;

		this.contextService.updateContext(options);
	}

	private initContainer(): void {
		const container = this.pageContainerFactory.createPageContainer(
			this.messageService,
			this.languageService,
			this.lazyTypeService,
			this.containerService,
			this.contextService,
			this.devService,
			this.sohoModalDialogService,
			this.context,
			this.containerData,
			this.pageService,
			this.widgetService,
			this.progressService,
			this.toastService,
			this.systemMessagesService,
			this.editModeService,
		);

		this.pageContainer = container;
	}

	private initPages(): void {
		const pages = this.containerData.pages;
		if (pages) {
			for (const page of pages) {
				const data = page.data;
				if (data) {
					// Set sort order from IPage to IPageData.
					// This is a temporary change, the sortOrder property should be completely moved to IPage since IPageData is shared for published pages.
					data.sortOrder = page.sortOrder;

					PageUtil.verifyContent(data);
					if (PageUtil.isPrivate(page)) {
						// We can only updated IDs on private pages
						PageUtil.updateWidgetIdsPage(page);
					}
				}
			}
		}
	}

	private initWidgets(): void {
		const definitions = this.containerData.widgetDefinitions;
		if (definitions) {
			for (const definition of definitions) {
				this.widgetService.addDefinitionItem(definition);
			}
		}
	}

	private onEmptyContainer(): void {
		const message = "Received empty page container";
		this.createErrorContainer(message);
		this.logError(message);
	}

	private checkSecurityMessage(response: IPageContainerResponse): void {
		if (
			response.messageList &&
			PageUtil.isSecurityMessages(response.messageList)
		) {
			this.logWarning(
				"There was an issue loading user security information. It's possible that the user has more access",
			);
			this.pageContainer.handleSystemMessages(response.messageList, true);
		}
	}

	private getContainerUrl(): string {
		const location = window.location;
		// Check the location for an xfo parameter from Ming.le, if that is set return it
		const parameters = HttpUtil.getQuery();
		const xfoParameter = parameters.xfo;
		if (xfoParameter) {
			this.logInfo("Using ContainerUrl " + xfoParameter);
			return xfoParameter;
		}

		// If no parameter is present use the homepages application
		let homepagesUrl = location.protocol + "//" + location.hostname;

		// Check for default https port
		const port = location.port;
		if (port && port !== "443") {
			homepagesUrl = homepagesUrl + ":" + port;
		}

		this.logInfo("Using ContainerUrl " + homepagesUrl);
		return homepagesUrl;
	}
}
