import { Injectable, NgZone } from "@angular/core";
import { merge, Observable } from "rxjs";
import { map, shareReplay, tap } from "rxjs/operators";
import { CompanyonService } from "./companyon";
import {
	IMaintenanceItem,
	IMaintenanceMessageData,
	IMobileMaintenanceMessageData,
} from "./core";
import { zoned } from "./device";
import { CoreBase } from "./runtime";

@Injectable({
	providedIn: "root",
})
export class MaintenanceService extends CoreBase {
	readonly maintenance$: Observable<IMaintenanceItem[]>;

	constructor(private companyon: CompanyonService, private zone: NgZone) {
		super("MaintenanceService");

		this.maintenance$ = merge(
			this.portalMessages(),
			this.mobileMessages(),
		).pipe(
			tap((items) => this.logDebug(`maintenance ${JSON.stringify(items)}`)),
			zoned(this.zone), // Not sure if necessary. This should normally be handled with the "async" pipe, but that's not always used.
			shareReplay(1),
		);
	}

	startListening() {
		this.maintenance$.subscribe();
	}

	private portalMessages(): Observable<IMaintenanceItem[]> {
		// TODO Verify final message name and message name character casing
		return this.companyon
			.receive$<IMaintenanceMessageData>("GetMaintenanceApps")
			.pipe(
				map((data) => {
					const items: IMaintenanceItem[] = [];
					const info = data.app_maintenance_info;
					if (info) {
						const active = info.active;
						if (active && active.length > 0) {
							for (const application of active) {
								const item: IMaintenanceItem = {
									logicalIdPrefix: application.logical_id_prefix,
									title: application.title,
									message: application.message,
									link: application.link,
									optionalMessage: application.optional_message,
								};
								items.push(this.fixLink(item));
							}
						}
					}
					return items;
				}),
			);
	}

	/**
	 * Modifies a maintenance item such that:
	 *
	 * 1. If it has a link in the message, it will be extracted to the "link" property,
	 * and be replaced with a placeholder.
	 * 2. If it already has a placeholder and a link property, do nothing.
	 * 3. If it has no link or placeholder in the message, do nothing.
	 * @param item
	 */
	private fixLink(item: IMaintenanceItem): IMaintenanceItem {
		const linkPlaceholder = "{0}";
		const urlPattern = /(https?:\/\/\S+)/;
		if (item.message.includes(linkPlaceholder) && item.link) {
			return item;
		}
		const urlMatch = item.message.match(urlPattern);
		if (urlMatch && urlMatch[1]) {
			const messageUrl = urlMatch[1];
			return {
				...item,
				link: messageUrl,
				message: item.message.replace(urlPattern, linkPlaceholder),
			};
		} else {
			return item;
		}
	}

	private mobileMessages(): Observable<IMaintenanceItem[]> {
		return this.companyon
			.receive$<IMobileMaintenanceMessageData>("mobile_get_maintenance_apps")
			.pipe(
				map((apps) => {
					const appsUnderMaintenance = apps.filter((app) => {
						const start = new Date(app.startDate);
						const end = new Date(app.endDate);
						const now = new Date();
						return start < now && now < end; // TODO: What happens when maintenance has ended? Not sure if Infor GO will send a new message, or if we have to deal with it ourselves.
					});
					const items: IMaintenanceItem[] = appsUnderMaintenance.map((app) => ({
						logicalIdPrefix: app.application,
						message: app.message,
						title: app.productName,
					}));
					return items;
				}),
			);
	}
}
