import {
	Component,
	ElementRef,
	NgZone,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import { SohoMessageService } from "@infor/sohoxi-angular";
import { IDialogResult } from "lime";
import {
	ContainerLoaderService,
	ContainerService,
	ContextService,
	CoreBase,
	DataService,
	ICatalogAddItem,
	ICatalogOptions,
	ICatalogStartService,
	IContainerOptions,
	IOperationResponse,
	IPageContainer,
	LanguageService,
	LazyTypeService,
} from "lime/core";

// TODO Note that the background-color override is not theme compatible due to hardcoded color value

@Component({
	selector: "lm-catalog-container",
	styles: [
		`
			::ng-deep div.modal-header {
				padding: 0px !important;
				background-color: #d8d8d8;
			}
			::ng-deep div.modal-body-wrapper {
				padding: 0px !important;
			}
			::ng-deep soho-toolbar.toolbar {
				margin-bottom: 0px !important;
			}
		`,
	],
	templateUrl: "./catalog-container.html",
})
export class CatalogContainerComponent extends CoreBase implements OnInit {
	@ViewChild("view", { read: ViewContainerRef, static: true })
	view: ViewContainerRef;

	private selectedItem: ICatalogAddItem;

	constructor(
		private readonly zone: NgZone,
		private readonly elementRef: ElementRef,
		messageService: SohoMessageService,
		languageService: LanguageService,
		private readonly contextService: ContextService,
		private readonly dataService: DataService,
		private readonly containerService: ContainerService,
		private readonly containerLoaderService: ContainerLoaderService,
		private readonly lazyTypeService: LazyTypeService,
	) {
		super("CatalogContainerComponent", messageService, languageService);
	}

	ngOnInit(): void {
		this.loadPageContainer();
	}

	private raiseClosed(): void {
		const item = this.selectedItem;
		// Sonarlint ignore
		if (item) {
			// Future (Context Apps) Send message that the dialog was closed without selection
		} else {
			// Future (Context Apps) Send message that the dialog was closed and that a widget was selected
		}
	}

	private loadCatalog(): void {
		this.lazyTypeService.injectLazyService("CatalogStartService").then(
			(service) => {
				const options = this.createOptions(service);
				service
					.createWidgetCatalog(options, this.view)
					.subscribe((result: IDialogResult) => {
						this.raiseClosed();
					});
			},
			(e) => {
				this.logError("Failed to open catalog");
			},
		);
	}

	private createOptions(service: ICatalogStartService): ICatalogOptions {
		// TODO Set option for only showing widgets that supports context app mode
		return {
			isSelect: true,
			addCallback: (item: ICatalogAddItem) => {
				this.logDebug("Selected widget " + JSON.stringify(item));
				this.selectedItem = item;
				if (item.busyCallback) {
					item.busyCallback(false);
				}
				service.closeCatalog();
			},
		} as ICatalogOptions;
	}

	private loadPageContainer(): void {
		const options: IContainerOptions = {
			mode: this.contextService.mode,
			settings: true,
			pages: false,
		};

		this.containerLoaderService.loadContainer(options).subscribe(
			(container: IPageContainer) => {
				this.containerService.updateContainer(container);
				this.loadCatalog();
			},
			(r: IOperationResponse) => {
				this.dataService.handleError(r);
			},
		);
	}
}
