import {
	AfterViewInit,
	ChangeDetectionStrategy,
	ChangeDetectorRef,
	Component,
	Input,
} from "@angular/core";
import { IWidgetContext, IWidgetInstance } from "lime";
import {
	DynamicColorType,
	DynamicItemType,
	IDynamicContainer,
	IDynamicHeader,
	IDynamicItem,
	UIUtil,
} from "lime/core";
import { IDynamicLinkViewOptions, parseLink } from "../links";

export interface IHeader {
	title?: string;
	subtitle?: string;
	image?: string;
	background?: string;
	clt?: number;
}

export interface ILinkItem {
	type: "link";
	links: IDynamicLinkViewOptions[];
}

export interface IAttributeItem {
	type: "attribute";
	label: string;
	value: string;
}

export interface ITextItem {
	type: "text";
	text: string;
	heading?: string;
}

export interface ILineBreak {
	type: "linebreak";
}

export type IItem = ILinkItem | IAttributeItem | ITextItem | ILineBreak;

export interface IRow {
	items: IItem[];
	split?: boolean;
	linebreak?: boolean;
	link?: boolean;
}

@Component({
	selector: "lm-dyn-items",
	templateUrl: "./items.html",
	styleUrls: ["./items.scss"],
	changeDetection: ChangeDetectionStrategy.OnPush,
})
export class DynamicItemsComponent implements AfterViewInit {
	@Input() widgetContext: IWidgetContext;
	@Input() widgetInstance: IWidgetInstance;

	container: IDynamicContainer;
	header?: IHeader;
	rows?: IRow[];
	hasItems?: boolean;
	hasHeader: boolean;
	hasHeadings: boolean;
	hasImage: boolean;
	isBanner?: boolean;
	colorTypes = DynamicColorType;

	constructor(private cdr: ChangeDetectorRef) {}

	ngAfterViewInit(): void {
		const context = this.widgetContext;
		const settings = context.getSettings();
		const container = (this.container =
			settings.get<IDynamicContainer>("lm_container"));
		this.isBanner = this.widgetContext.isBanner();
		const items = container && container.its;
		if (items) {
			this.rows = this.makeRows(items);
			this.hasItems = this.rows.length > 0 ? true : false;
		}

		const headerData = container && container.hd;
		if (headerData) {
			this.header = this.makeHeader(headerData);
			this.hasHeader =
				this.hasHeadings || !!this.header.background || !!this.header.image;
		}
		this.cdr.detectChanges();
	}

	isLinkItem(item: IItem): item is ILinkItem {
		return item.type === "link";
	}
	isAttributeItem(item: IItem): item is IAttributeItem {
		return item.type === "attribute";
	}
	isTextItem(item: IItem): item is ITextItem {
		return item.type === "text";
	}

	isLineBreak(item: IItem): item is ILineBreak {
		return item.type === "linebreak";
	}

	launch(url: string) {
		this.widgetContext.launch({ url });
	}

	private makeHeader(headerData: IDynamicHeader): IHeader {
		const title = headerData.h1;
		const subtitle = headerData.h2;
		const clt = headerData.clt;
		let image = null;
		this.hasHeadings = title !== undefined || subtitle !== undefined;
		if (headerData.im) {
			let url = headerData.im.u;
			if (url.indexOf("{") > -1) {
				url = this.widgetContext.resolveAndReplace(url);
			}
			image = `url(${url})`;
		}
		this.hasImage = image ? true : false;

		const covering =
			this.hasHeadings && this.hasImage
				? 45
				: this.hasItems && this.hasImage && !this.hasHeadings
				? 50
				: this.hasItems && this.hasHeadings && !this.hasImage
				? 100
				: this.hasItems && !this.hasHeadings && !this.hasImage
				? 100
				: this.hasItems && !this.hasHeadings
				? 20
				: 100;
		const background = this.getHeaderBackground(headerData, covering);
		return { title, subtitle, image, background, clt };
	}

	private getHeaderBackground(
		headerData: IDynamicHeader,
		colorArea: number,
	): string {
		let color: string;
		const colorType = headerData.clt;
		switch (colorType) {
			case DynamicColorType.None:
				color = "transparent";
				break;
			case DynamicColorType.InheritPage:
				color = this.widgetContext.getBannerBackgroundColor() || "transparent";
				break;
			case DynamicColorType.InheritParent:
			case DynamicColorType.Custom:
				color = UIUtil.numberToHexCodeExtended(headerData.cl || 0);
				break;
			default:
				throw TypeError(`Invalid color type ${colorType}`);
		}
		return `linear-gradient(to bottom, ${color} ${colorArea}%, transparent 0)`;
	}

	private makeRows(dynamicItems: IDynamicItem[]): IRow[] {
		const rows: IRow[] = [];
		dynamicItems.forEach((dynamicItem) => {
			const item = this.parseDynamicItem(dynamicItem);
			const lastRow = rows[rows.length - 1];

			if (lastRow && lastRow.items[0].type === "linebreak") {
				lastRow.linebreak = true;
			}
			if (
				lastRow &&
				lastRow.items.length >= 1 &&
				lastRow.items[0].type === item.type
			) {
				lastRow.items.push(item);
				lastRow.split = true;
			} else {
				rows.push({
					items: [item],
				});
			}
		});
		return rows;
	}

	private parseDynamicItem(item: IDynamicItem): IItem {
		const itemType = item.it;
		switch (itemType) {
			case DynamicItemType.Link:
				const linkItem: ILinkItem = {
					links: [parseLink(item)],
					type: "link",
				};
				linkItem.links[0].fontSize = "14px";
				return linkItem;
			case DynamicItemType.Attribute:
				const attributeItem: IAttributeItem = {
					label: item.l,
					type: "attribute",
					value: item.t,
				};
				return attributeItem;
			case DynamicItemType.Text:
				const textItem: ITextItem = {
					heading: item.l,
					text: item.t,
					type: "text",
				};
				return textItem;
			case DynamicItemType.Linebreak:
				const lineBreak: ILineBreak = {
					type: "linebreak",
				};
				return lineBreak;
			default:
				throw TypeError(`Invalid item type '${itemType}'`);
		}
	}
}
