import { CommonModule } from "@angular/common";
import { HttpClientModule } from "@angular/common/http";
import {
	ModuleWithProviders,
	NgModule,
	Optional,
	SkipSelf,
} from "@angular/core";
import { FormsModule } from "@angular/forms";
import { SohoComponentsModule } from "@infor/sohoxi-angular";
import { DialogService } from "lime";
import {
	ContainerService,
	ContextService,
	DataService,
	EditModeService,
	LanguageService,
	ProgressService,
	WidgetService,
} from "./index";

@NgModule({
	imports: [CommonModule, FormsModule, HttpClientModule, SohoComponentsModule],
	providers: [
		ContainerService,
		ContextService,
		DataService,
		DialogService,
		EditModeService,
		LanguageService,
		ProgressService,
		WidgetService,
	],
	exports: [],
})
export class LimeCoreServicesModule {
	constructor(@Optional() @SkipSelf() parentModule: LimeCoreServicesModule) {
		if (parentModule) {
			throw new Error(
				"LimeCoreServicesModule is already loaded. Import it in the AppModule only",
			);
		}
	}

	static forRoot(): ModuleWithProviders<LimeCoreServicesModule> {
		return {
			ngModule: LimeCoreServicesModule,
		};
	}
}
