import { Injectable } from "@angular/core";
import { Observable, ReplaySubject } from "rxjs";
import { map, take } from "rxjs/operators";
import { ContainerService } from "../../../base/container";
import { Constants, IMemoItemData, MemoPriority } from "../../../base/core";
import { DevService } from "../../../base/dev";
import { PageService } from "../../../page/service";
import { BrowserStorageService } from "../../../services/browser-storage.service";

export type MemoPreviewMode = null | "regular" | "top" | "banner";

export interface IMemoPreviewOptions {
	mode: MemoPreviewMode;
	items?: IMemoItemData[];
}

@Injectable({
	providedIn: "root",
})
export class MemoService {
	memos$: Observable<IMemoItemData[]>;
	criticalMemos$: Observable<IMemoItemData[]>;
	private memosSubject = new ReplaySubject<IMemoItemData[]>(1);

	private items: IMemoItemData[];
	private isInitialized: boolean;
	private _previewMode: MemoPreviewMode = null;

	constructor(
		private readonly pageService: PageService,
		private readonly storageService: BrowserStorageService,
		private readonly devService: DevService,
		containerService: ContainerService,
	) {
		this.memos$ = this.memosSubject.asObservable();
		this.criticalMemos$ = this.memos$.pipe(
			map((memos) => memos.filter((memo) => memo.pr === MemoPriority.Critical)),
		);
		containerService.container$.pipe(take(1)).subscribe((container) => {
			const items = container.data && container.data.memos;
			if (items) {
				this.isInitialized = true;
				this.items = items;
				this.memosSubject.next(items);
			}
		});

		if (!this.devService.isDev) {
			containerService.refresh$.subscribe(() => {
				this.listMemos();
			});
		}
	}

	initialize(): void {
		if (this.isInitialized || this.isPreview()) {
			return;
		}

		this.isInitialized = true;

		if (!this.items) {
			this.listMemos();
		}
	}

	startPreview(options: IMemoPreviewOptions): void {
		this._previewMode = options.mode;
		if (options.items) {
			this.memosSubject.next(options.items);
		}
	}

	stopPreview(): void {
		if (this._previewMode != null) {
			this._previewMode = null;
			this.memosSubject.next(this.items || []);
		}
	}

	isPreview(): boolean {
		return this._previewMode != null;
	}

	getUnseenMemos(memos: IMemoItemData[]): IMemoItemData[] {
		const viewedMemos = this.getViewedMemosStorage();
		return memos.filter((memo) => {
			const viewedMemo = viewedMemos.find((viewed) => viewed.mid === memo.mid);
			return !viewedMemo || new Date(viewedMemo.cd) < new Date(memo.cd);
		});
	}

	getViewedMemosStorage(): IMemoItemData[] {
		return (
			this.storageService.getLocalStorageItem<IMemoItemData[]>(
				Constants.viewedCriticalMemos,
			) || []
		);
	}

	setViewedMemosStorage(memos: IMemoItemData[]) {
		this.storageService.setLocalStorageItem(
			Constants.viewedCriticalMemos,
			memos,
		);
	}

	private listMemos() {
		this.pageService.listMemos().subscribe(
			(memoItems) => {
				this.items = memoItems;
				this.memosSubject.next(memoItems);
			},
			(error) => {
				this.memosSubject.error(error);
			},
		);
	}
}
