import { Pipe, PipeTransform } from "@angular/core";
import { DynamicImageAlignment } from "../../../base/core";

/**
 * Converts DynamicImageAlignment to a value that can be used to set the background-size style property.
 */
@Pipe({
	name: "imageSize",
	pure: true,
})
export class ImageSizePipe implements PipeTransform {
	transform(alignment: DynamicImageAlignment) {
		switch (alignment) {
			case DynamicImageAlignment.Cover:
				return "cover";
			case DynamicImageAlignment.Fill:
				return "100% 100%";
			case DynamicImageAlignment.Fit:
				return "contain";
			default:
				return "auto";
		}
	}
}
