import { Component } from "@angular/core";
import {
	MobileEmptyType,
	MobileService,
} from "scripts/lime/core/services/mobile.service";

@Component({
	selector: "lm-mobile-container-empty",
	templateUrl: "./mobile-container-empty.html",
	styleUrls: ["./mobile-container-empty.scss"],
})
export class MobileContainerEmptyComponent {
	message: string;
	isPermissionError = false;
	isBrokenError = false;

	constructor(mobileService: MobileService) {
		mobileService.empty$.subscribe((empty) => {
			this.message = empty.message;
			this.isPermissionError = empty.type === MobileEmptyType.Permission;
			this.isBrokenError = empty.type === MobileEmptyType.Broken;
		});
	}
}
