import { animate, style, transition, trigger } from "@angular/animations";
import {
	AfterViewInit,
	Component,
	EventEmitter,
	HostBinding,
	HostListener,
	Input,
	OnDestroy,
	OnInit,
	Output,
	ViewChild,
} from "@angular/core";
import { Subscription, timer } from "rxjs";
import { filter } from "rxjs/operators";
import { IContext, MemoItem } from "../../../base/core";
import { CoreBase } from "../../../base/runtime";
import { ContextService } from "../../../service";
import { DimensionsDirective } from "./dimensions.directive";
import { MemoService } from "./memo.service";
@Component({
	selector: "lm-memos",
	templateUrl: "./memos.html",
	styleUrls: ["./memos.scss"],
	animations: [
		trigger("fadeInOut", [
			transition(":enter", [
				style({ opacity: "0" }),
				animate("0.5s linear", style({ opacity: "1" })),
			]),
			transition(":leave", [
				style({ opacity: "1" }),
				animate("0.5s linear", style({ opacity: "0" })),
			]),
		]),
	],
})
export class MemosComponent
	extends CoreBase
	implements OnInit, AfterViewInit, OnDestroy
{
	@ViewChild(DimensionsDirective, { static: false })
	dimensionsDirective: DimensionsDirective;

	@Input() set memoDuration(seconds: number) {
		this.duration = seconds * 1000;
		this.startInterval();
	}
	@Input() memos: MemoItem[] = [];
	@Input() inWidget = false;
	@Input() inBanner = false;
	@Input() backgroundColor: string;
	@Input() animate = true;
	@Input() criticalOnly: boolean;
	@Input() parentAreaName: string;

	@Output() onError = new EventEmitter<void>();
	@Output() onEmpty = new EventEmitter<void>();

	switchId: string;

	@HostBinding("class.light-mode") useLightMode: boolean;

	visibleMemo: MemoItem;
	selectedIndex = 0;
	context: IContext;
	isPreview: boolean;
	isHovering = false;

	private sliderSubscription: Subscription;
	private memoSubscription: Subscription;
	private duration = 10000;
	private isDarkTheme: boolean;

	constructor(
		contextService: ContextService,
		private readonly memoService: MemoService,
	) {
		super("MemosComponent");
		this.context = contextService.getContext();
	}

	@HostListener("mouseenter") onMouseEnter(): void {
		this.isHovering = true;
	}

	@HostListener("mouseleave") onMouseLeave(): void {
		this.isHovering = false;
	}

	ngOnInit() {
		this.isDarkTheme = this.context.getInforThemeName() === "Dark";
		this.memoService.initialize();

		this.switchId = "lm-mm-" + this.parentAreaName + "-switch-";

		if (this.memos.length) {
			this.initMemos();
		} else {
			this.memoSubscription = this.memoService.memos$.subscribe(
				(memos) => {
					this.memos = memos.map((memo) => new MemoItem(memo));
					this.initMemos();
				},
				() => {
					this.logError("Unable to load announcements");
					if (this.inWidget) {
						this.onError.emit();
					}
				},
			);
		}
	}

	ngAfterViewInit(): void {
		if (this.dimensionsDirective) {
			this.dimensionsDirective.triggerDetection();
		}
	}

	ngOnDestroy() {
		if (this.memoSubscription) {
			this.memoSubscription.unsubscribe();
		}
		this.stopInterval();
	}

	startInterval(): void {
		this.stopInterval();

		const memos = this.memos;
		const duration = this.duration;
		if (memos.length <= 1 || duration === 0) {
			return;
		}

		this.sliderSubscription = timer(duration, duration)
			.pipe(filter(() => !this.isHovering))
			.subscribe(() => {
				const index = this.getNextIndex();
				this.setSelected(index);
			});
	}

	stopInterval(): void {
		if (this.sliderSubscription) {
			this.sliderSubscription.unsubscribe();
			this.sliderSubscription = null;
		}
	}

	selectPreviousMemo() {
		const index = this.getPreviousIndex();
		this.setSelected(index);
	}

	selectNextMemo() {
		const index = this.getNextIndex();
		this.setSelected(index);
	}

	setSelected(index: number): void {
		this.selectedIndex = index;
		const visibleMemo = this.memos[index];

		this.updateColorMode(visibleMemo);

		this.visibleMemo = visibleMemo;
	}

	private initMemos() {
		if (this.memos.length) {
			this.setSelected(0);
			this.startInterval();
			this.isPreview = this.memoService.isPreview();
		} else {
			this.useLightMode = this.getUseLightMode();
			this.onEmpty.emit();
		}
	}

	private getNextIndex(): number {
		return this.selectedIndex < this.memos.length - 1
			? this.selectedIndex + 1
			: 0;
	}

	private getPreviousIndex(): number {
		return this.selectedIndex > 0
			? this.selectedIndex - 1
			: this.memos.length - 1;
	}

	private updateColorMode(memo: MemoItem) {
		this.useLightMode = this.getUseLightMode(memo);
	}

	private getUseLightMode(memo?: MemoItem): boolean {
		if (!memo || memo.textColor === "default") {
			return !this.inWidget || this.isDarkTheme || this.inBanner;
		} else {
			return memo.textColor === "light";
		}
	}
}
