@Component({
	templateUrl: "./widget-restore.html",
})
export class WidgetRestoreComponent extends CoreBase {
	dialog: SohoModalDialogRef<WidgetRestoreComponent>;
	lang: ILanguageLime;
	userSettings = Constants.widgetRestoreUserSettings;
	standardWidgetSettings = Constants.widgetRestoreStandardSettings;
	selectedOption = Constants.widgetRestoreUserSettings;

	constructor(languageService: LanguageService) {
		super("WidgetRestoreComponent");
		this.lang = languageService.getLanguage();
	}

	ok(): void {
		this.dialog.close({
			button: DialogButtonType.Ok,
			value: this.selectedOption,
		});
	}

	close(): void {
		this.dialog.close();
	}
}

/**
 * Component for the Widget container.
 */
@Component({
	selector: "lm-widget-container",
	templateUrl: "./widget-container.html",
	styleUrls: ["./widget-container.scss"],
})
export class WidgetContainerComponent
	extends CoreBase
	implements OnInit, OnDestroy
{
	get hasPrimaryAction(): boolean {
		const action = this.primaryAction;
		if (!action) {
			return false;
		}

		const isEnabled =
			action &&
			action.isVisible !== false &&
			!this.isPreviewMode &&
			(!this.requiresConfig || action.isEnabledNotConfigured === true);
		if (isEnabled) {
			return true;
		}
		return false;
	}

	get hasStatusMessage(): boolean {
		if (this.widget.status) {
			return true;
		}
		return false;
	}

	get statusCount(): string {
		const status = this.widget.status;
		const count = status && status.count;
		if (count && count < 100) {
			return "" + count;
		}
		return null;
	}

	get statusMessage(): string {
		return this.widget.status && this.widget.status.message;
	}

	get hasHeader(): boolean {
		return (
			this.widgetId !== Constants.memoWidgetID &&
			(!this.isDynamic || this.hasTitle || this.hasPrimaryAction)
		);
	}

	get hasVisibleActions(): boolean {
		const instance = this.widget.instance;
		const actions = (instance && instance.actions) || [];
		const hasVisible = this.widget.hasVisibleActions();

		return (
			hasVisible &&
			(!this.requiresConfig ||
				actions.some(
					(action) =>
						action.isVisible !== false &&
						action.isEnabledNotConfigured === true &&
						!action.isSeparator,
				))
		);
	}

	get actionsTabIndex(): string {
		return this.isInactive ? "-1" : null;
	}

	get badgeClass(): string {
		const badgeType = this.widget.badge?.type;
		let className: string;
		if (badgeType === BadgeType.Alert) {
			className = "alert";
		} else if (badgeType === BadgeType.Error) {
			className = "error";
		} else if (badgeType === BadgeType.Good) {
			className = "good";
		} else {
			className = "info";
		}
		return className;
	}

	get badgeLabel(): string {
		const badgeCount = this.widget.badge?.count;
		return badgeCount < 1000
			? badgeCount.toString()
			: `${Math.floor(badgeCount / 1000)}k+`;
	}

	private static counter = 0;
	private static refreshCooldown = 5000;
	@Input() widget: IWidget = {} as IWidget;
	@Input() page: IPageInstance; // TODO Should use IWidgetParentContext instead
	@Output() visibilityToggled = new EventEmitter<boolean>();

	@ViewChild("target", { read: ViewContainerRef, static: true })
	target: ViewContainerRef;

	@ViewChild("widgetViewParent", { read: ViewContainerRef, static: true })
	widgetViewParent: ViewContainerRef;

	@ViewChild("widgetView", { read: ViewContainerRef, static: true })
	widgetView: ViewContainerRef;

	widgetId: string;
	elementId: string;
	lang: ILanguageLime;
	context = {} as IContext;
	safeMode: boolean;
	showPublishItem = false;
	showPublishCopyItem = false;
	showEditPublishItem = false;
	showClearPublishItem = false;
	showDuplicateItem = false;
	showAdvancedItem = false;
	showRestoreItem = false;
	showCopyItem = false;
	menuId: string;
	primaryAction: IWidgetAction;
	isPreviewMode: boolean;
	isPublished: boolean;
	isInactive: boolean;
	isBannerEnabled: boolean;
	isBanner: boolean;
	showRefreshAction: boolean;
	showRefreshItem: boolean;
	showSettingsItem: boolean;
	requiresConfig: boolean;
	isDynamic: boolean;
	isUserPreview = false;
	dynamicContainer: IDynamicContainer;
	title: string;
	hasTitle = true;
	isBroken: boolean;
	brokenMessage: string;
	isAccessDenied: boolean;
	iconColor?: string;
	emptyConfig?: IEmptyConfig;
	isContextApp = false;
	isCollapsed = false;
	isCollapsedDefault = false;
	isMaintenance = false;
	maintenance: IMaintenanceItem;
	automationIdIdentifier: string;
	standardWidgetId: string;

	/**
	 * Addtional data for a published widget in edit mode.
	 */
	private publishedItem: IPublishedWidgetItem;
	private publishInfo: IWidgetPublishInfo;
	private isPublishCopy: boolean;
	private widgetInstance: IWidgetInstance;
	private iframe: JQuery;
	private url: string;
	private isExternal: boolean;
	private unsubscribers: (() => void)[] = [];
	private isCustomizedUnlocked: boolean;
	private lastRefresh = 0;
	private componentRef: ComponentRef<any>;
	private isSettingsOpen: boolean;
	private maintenanceSubscription: Subscription;
	private displayValue: string;

	@HostBinding("class.lm-display-none") private hidden: boolean;

	constructor(
		private injector: Injector,
		messageService: SohoMessageService,
		languageService: LanguageService,
		private lazyTypeService: LazyTypeService,
		private sohoModalDialogService: SohoModalDialogService,
		private widgetService: WidgetService,
		private contextService: ContextService,
		private containerService: ContainerService,
		private editModeService: EditModeService,
		private progressService: ProgressService,
		private toastService: SohoToastService,
		private companyonService: CompanyonService,
		private mediaService: MediaService,
		private zone: NgZone,
		private systemMessagesService: SystemMessagesService,
		private maintenanceService: MaintenanceService,
		private viewTrackerContext: YgViewTrackerContext,
	) {
		super("WidgetContainerComponent", messageService, languageService);
		WidgetContainerComponent.counter++;
		this.menuId = `lm-w-m-${WidgetContainerComponent.counter}`;

		this.context = contextService.getContext();
		this.safeMode = contextService.isSafeModeAll;
		this.isContextApp = contextService.isContextApp;
		this.lang = languageService.getLanguage();
	}

	ngOnInit(): void {
		const widget = this.widget;
		widget.view = this.target;
		widget.element = $(this.target.element.nativeElement);
		this.setWidget(widget); // Call this to initialize other properties
		this.initDynamic();
		this.loadWidget(widget);
	}

	ngOnDestroy(): void {
		this.logDebug("ngOnDestroy");

		this.page = null;

		if (this.widget) {
			this.widget.componentRef = null;
			this.setWidget(null);
		}

		const ref = this.componentRef;
		if (ref) {
			ref.destroy();
			this.componentRef = null;
		}

		if (this.widgetView) {
			this.widgetView.clear();
			this.widgetView = null;
		}

		this.widgetViewParent = null;
		this.target = null;
		if (this.maintenanceSubscription) {
			this.maintenanceSubscription.unsubscribe();
		}
	}

	closeMessage(): void {
		const message = this.widget.message;
		if (message.onClose) {
			message.onClose();
		}
		this.widget.message = null;
	}

	getActions(): IWidgetAction[] {
		const widget = this.widget;
		return widget ? this.filterEnabled(widget.instance.actions) : [];
	}

	loadExternal(widget: IWidget, iframe: JQuery) {
		this.setWidget(widget);
		this.iframe = iframe;
		this.isExternal = true;
		this.updateUrl();
	}

	setUrl(url: string): void {
		this.url = url;
	}

	getLayoutClasses(): string {
		const widget = this.widget;
		if (!widget || (this.isBanner && !this.isBannerEnabled)) {
			return "";
		}
		let classString: string;
		if (this.isBanner) {
			classString =
				"lm-banner lm-transparent " +
				WidgetUtil.getLayoutClasses(widget.data.layout);
			if (this.isDynamic) {
				classString += " dynamic";
			}
		} else {
			classString = WidgetUtil.getLayoutClasses(widget.data.layout);
		}

		return "widget " + classString;
	}

	executePrimary(): void {
		const primary = this.primaryAction;
		if (primary.execute) {
			primary.execute();
			return;
		}

		this.logWarning("executePrimary: Execute function property not set");
	}

	configButtonTriggered() {
		this.showSettings();
	}

	showSettings() {
		if (this.isSettingsOpen) {
			return;
		}
		this.isSettingsOpen = true;

		this.widgetService
			.showSettings(this.widget, null, this.isCustomizedUnlocked)
			.subscribe(
				(r: IDialogResult) => {
					if (r && r.value) {
						if (this.widget.definition.requiresConfig) {
							this.setConfigState();
						}
						if (this.isExternal) {
							this.updateUrl();
						}
					}
					this.isSettingsOpen = false;
				},
				(r: IOperationResponse) => {
					this.isSettingsOpen = false;
					this.widgetService.handleError(r);
				},
			);
	}

	refresh() {
		if (this.isRefreshCooldown()) {
			return;
		}

		const widget = this.widget;
		if (widget.isExternal()) {
			this.refreshUrl();
		} else {
			this.refreshInline();
		}

		this.lastRefresh = new Date().getTime();
	}

	startEditMode(isCopy: boolean) {
		this.isPublishCopy = isCopy;
		const widget = this.widget;
		if (widget.definition.isPublished) {
			// Load the custom definition data for a published widget before starting edit mode
			this.progressService.setBusy(true);
			const handle: IWidgetHandle = {
				id: widget.id,
				pid: widget.definition.standardWidgetId,
				byRef: widget.byRef,
			};
			this.widgetService.getPublished(handle).subscribe(
				(item: IPublishedWidgetItem) => {
					const definition = item.definition;
					if (definition.custom) {
						definition.settings = WidgetUtil.applyRestrictions(
							definition.settings,
							definition.custom.metadata,
						);
					}
					this.publishedItem = item;
					this.progressService.setBusy(false);
					this.startEditModeInternal();
				},
				(r: IOperationResponse) => {
					this.widgetService.handleError(r);
					this.progressService.setBusy(false);
				},
			);
		} else {
			this.startEditModeInternal();
		}
	}

	reset() {
		// If the widget is in edit mode and has user settings there should be a dialog to select if reset to default should be default to standard or default to published
		const editMode = this.editModeService.getCurrent();
		const isEditMode = !!editMode && editMode.isActive;
		const isWidgetEditMode = isEditMode && editMode.mode === EditModes.widget;
		const hasUserSettings = this.hasUserSettings();
		const isPublished = this.widget.isPublished();

		if (isPublished && isWidgetEditMode && hasUserSettings) {
			const dialog = this.sohoModalDialogService
				.modal(WidgetRestoreComponent, this.target)
				.id("lm-wc-resetoptions-dialog")
				.title(this.lang.restoreOptions)
				.afterClose((r: IDialogResult) => {
					if (r && r.value && r.button === DialogButtonType.Ok) {
						if (r.value === Constants.widgetRestoreUserSettings) {
							// Restore only widget settings
							this.widget.restore(true);
							this.afterRestore();
						} else {
							this.widget.restore(false);
							this.afterRestore();
						}
					}
				});

			dialog
				.apply((component) => {
					component.dialog = dialog;
				})
				.open();
		} else {
			const lang = this.lang;
			const onlyUserSettings = isPublished ? hasUserSettings : false;
			this.showConfirm(lang.confirmReset, lang.confirmResetMessage).subscribe(
				() => {
					this.widget.restore(onlyUserSettings);
					this.afterRestore();
				},
			);
		}
	}

	/*
	 * Copies the widget on the page using the standard widget,
	 * applying all settings form standard widget combined with the current settings
	 */
	duplicate() {
		const lang = this.lang;
		if (
			this.page.noOfWidgets() >=
			this.contextService.getContext().settings.getMaxWidgetsOnPageCount()
		) {
			this.showMessage(lang.unableToAddWidget, lang.maxWidgetsOnPageMessage);
			return;
		}

		this.progressService.setBusy(true);
		const addWidgetInfo = this.widgetService.getAddWidgetInfo(this.widget);
		// Add to same page context
		const context = this.widget.parentContext;
		// Copy all the settings and apply it to the newly added widget
		this.widgetService.addWidgetCopyToPage(context, addWidgetInfo).subscribe(
			() => {
				this.progressService.setBusy(false);
			},
			(error: IOperationResponse) => {
				this.widgetService.handleError(error);
			},
		);
	}

	copy() {
		const widget = this.widget;
		const info = this.widgetService.getAddWidgetInfo(widget);
		const targets = widget.definition.targets;
		const clipboardWidget = {
			addInfo: info,
			isBanner: widget.isBanner(),
			isMultiTarget:
				targets &&
				ArrayUtil.contains(targets, "banner") &&
				ArrayUtil.contains(targets, "default"),
		};
		this.widgetService.setClipboardWidget(clipboardWidget);
		const lang = this.lang;
		const widgetTitle = widget.title || widget.definition.standardTitle;
		const message = lang.format(lang.widgetCopiedMessage, widgetTitle);
		this.toastService.show(
			CoreUtil.getToastOptions(lang.widgetCopied, message),
		);
	}

	showPublishConfiguration() {
		this.progressService.setBusy(true);
		const self = this;
		this.widgetService
			.showPublishConfiguration(
				this.target,
				this.widget,
				this.publishedItem,
				this.publishInfo,
			)
			.subscribe(
				(result) => {
					self.onClosePublishConfiguration(result);
				},
				(error: IOperationResponse) => {
					this.widgetService.handleError(error);
				},
			);
	}

	clearPublishConfiguration() {
		const lang = this.lang;
		this.showConfirm(
			lang.ConfirmClearConfig,
			lang.clearConfigMessage,
		).subscribe(() => {
			const data = this.widget.data;
			data.custom = null;
			data.title = this.title;
			if (this.editModeService.isActive()) {
				this.widget.updateTitle();
				this.updateMenu();
			} else {
				this.containerService.getContainer().saveAndRefreshCurrent();
			}
		});
	}

	/**
	 * Show the about dialog for a widget.
	 */
	showAbout() {
		this.lazyTypeService.loadLazyModule().then(({ WidgetAboutComponent }) => {
			const dialog = this.sohoModalDialogService
				.modal(WidgetAboutComponent, this.target)
				.id("lm-wc-about")
				.title(this.lang.about);
			dialog
				.apply((component: any) => {
					component.dialog = dialog;
					component.widget = this.widget;
				})
				.open();
		});
	}

	show() {
		this.hidden = false;
		this.notifyInstanceVisibility("activated");
	}

	hide() {
		this.hidden = true;
		this.notifyInstanceVisibility("deactivated");
	}

	toggleVisibility() {
		this.isCollapsed = !this.isCollapsed;
		if (!this.isCollapsed) {
			this.clearStatus();
		}
		this.visibilityToggled.emit(this.isCollapsed);
	}

	private clearStatus() {
		delete this.widget.status;
	}

	private initDynamic(): void {
		const widget = this.widget;
		const parentContext = widget.parentContext;
		if (!parentContext.isDynamic) {
			return;
		}

		this.isDynamic = true;

		const settings = widget.data.settings;
		if (!settings) {
			return;
		}

		const container = settings.lm_container as IDynamicContainer;
		if (!container) {
			return;
		}

		this.dynamicContainer = container;

		const id = widget.data.id;
		if (id && !id.startsWith(Constants.dynamicWidgetPrefix)) {
			// Remove for all widgets except our own dynamic ones
			delete settings.lm_container;
		}

		this.parseIconColor();
		if (!container.t && container.ct !== DynamicContainerType.Widget) {
			this.hasTitle = false;
		}
		if (
			container.ct === DynamicContainerType.Widget &&
			parentContext.isUserPreview()
		) {
			this.isUserPreview = true;
		}
	}

	private setWidget(widget: IWidget): void {
		if (widget) {
			this.elementId = widget.elementId;
			this.widgetId = widget.id;
			this.title = widget.title;
			this.isPublished = widget.isPublished();
			this.automationIdIdentifier =
				"-" + StringUtil.formatTextForId(widget.title, "widget");
			this.standardWidgetId = widget.definition?.standardWidgetId || widget.id;
			if (widget.isBroken()) {
				this.isBroken = true;
				this.brokenMessage = widget.data.brokenMessage;
				this.isAccessDenied = widget.isBrokenByAccessDenied();
			}
		} else {
			this.title = null;
		}

		this.widget = widget || ({} as IWidget);
	}

	private createContext(widget: IWidget, element: JQuery): WidgetContextBase {
		let values = widget.data.settings;
		if (!values) {
			widget.data.settings = values = {} as IStringToAnyMap;
		}

		const settings = new WidgetSettings(this.widgetService, widget, values);
		const context = this.contextService.getContext();

		return new WidgetContext(
			this.injector,
			this.widgetService,
			widget,
			settings,
			element,
			context,
			this.languageService,
			this.containerService,
			this.companyonService,
			this.mediaService,
			this.zone,
		);
	}

	private attach(widget: IWidget, element: JQuery): void {
		const unregister = widget.restored().on(() => {
			// Exernal widgets (iframe) will only be reloaded if url has changed
			this.setUrl("");

			unregister();
			element.children().not("lm-widget-empty-config").remove();
			this.addWidget(widget, element);
		});
	}

	private addExternal(widget: IWidget, element: JQuery) {
		const definition = this.widgetService.getCachedDefinition(widget.id);
		// TODO Check why instanceId is null or empty
		const name = widget.data.instanceId || CommonUtil.random();
		const iframe = HtmlUtil.iframe(null, name);
		iframe.attr("title", widget.title);
		const autoId = definition.standardWidgetId || definition.widgetId;
		iframe.attr(
			"name",
			"lm-widget-iframe-" + StringUtil.formatTextForId(autoId, "widget"),
		);
		element.addClass("lm-position-r");
		element.append(iframe);
		widget.iframe = iframe;
		widget.context = this.createContext(
			widget,
			element,
		) as any as IWidgetContext;
		this.loadExternal(widget, iframe);
		this.attach(widget, element);
		this.checkForDeprecation(definition, widget);
		widget.raiseInitialized();
	}

	private createProviders(
		context: IWidgetContext,
		instance: IWidgetInstance,
	): StaticProvider[] {
		return [
			{ provide: widgetContextInjectionToken, useValue: context },
			{ provide: widgetInstanceInjectionToken, useValue: instance },
			{ provide: IWidgetContext, useValue: context },
			{ provide: IWidgetInstance, useValue: instance },
		];
	}

	/**
	 * Adds content for a new Angular widget.
	 */
	private addContent(
		definition: IWidgetDefinition,
		context: IWidgetContext,
		widget: IWidget,
	): void {
		const widgetFactory = widget.widgetModule.widgetFactory;

		const isDebug = this.isDebug();
		let logSuffix = "";

		if (isDebug) {
			logSuffix = WidgetUtil.toLog(widget);
			this.logDebug("addContent: Calling widget factory for " + logSuffix);
		}

		const instance = widgetFactory(context) as IWidgetInstance;
		widget.instance = instance as any as IWidgetInstance;
		this.widgetInstance = widget.instance;

		if (definition.framework !== "angular") {
			// jQuery widget
			widget.raiseInitialized();
			return;
		}

		// Angular widget
		const config = this.widgetInstance
			.angularConfig as any as IAngularWidgetConfig;
		if (!config) {
			this.logError(
				"addContent: The angularConfig property is missing for " + logSuffix,
			);
			return;
		}

		setTimeout(() => {
			this.addComponent(definition, context, widget, instance, config);
		}, 20);
	}

	private addComponent(
		definition: IWidgetDefinition,
		context: IWidgetContext,
		widget: IWidget,
		instance: IWidgetInstance,
		config: IAngularWidgetConfig,
	): void {
		const isDebug = this.isDebug();
		let logSuffix = "";
		if (isDebug) {
			logSuffix = WidgetUtil.toLog(widget);
			this.logDebug(
				"addComponent: Loading components/modules for " + logSuffix,
			);
		}

		const view = this.widgetView;
		view.clear(); // TODO Verify if this is necessary
		let ngModuleRef = definition.getModuleRef?.();
		if (!ngModuleRef) {
			this.logDebug(
				`addComponent: Creating NgModuleRef based on config.moduleType`,
			);
			ngModuleRef = createNgModuleRef(config.moduleType, this.injector);
			definition.getModuleRef = () => ngModuleRef;
		}

		const providers = this.createProviders(context, instance);
		const injector = Injector.create({
			providers,
			parent: ngModuleRef.injector,
		});
		const componentRef = view.createComponent(config.componentType, {
			injector,
			ngModuleRef,
		});
		const component = componentRef.instance as IWidgetComponent;

		if (!component.widgetContext) {
			component.widgetContext = context;
		}
		if (!component.widgetInstance) {
			component.widgetInstance = instance;
		}
		widget.componentRef = componentRef;
		this.componentRef = componentRef;
		widget.raiseInitialized();
	}

	private parseIconColor() {
		const colorType = this.dynamicContainer.clt
			? this.dynamicContainer.clt
			: DynamicColorType.Custom;
		const colorNumber = this.dynamicContainer.icl
			? this.dynamicContainer.icl
			: 0;
		this.iconColor =
			colorType === DynamicColorType.InheritPage
				? UIUtil.numberToHexCode(colorNumber)
				: UIUtil.numberToHexCodeExtended(colorNumber);
	}

	private addInline(widget: IWidget) {
		const module = widget.widgetModule;
		if (!module) {
			throw new Error("Widget module missing");
		}

		const factory = module.widgetFactory;
		if (!factory) {
			throw new Error("No widgetFactory function found in widget module");
		}

		const definition = this.widgetService.getCachedDefinition(widget.id);
		if (!definition) {
			throw new Error("Widget definition missing");
		}

		// TODO Fix element issues. The element used for the widget context is no longer the same as the one where the content is setnode bui
		const element = $(this.widgetViewParent.element.nativeElement);

		const context = this.createContext(widget, element);
		widget.context = context as any as IWidgetContext;

		this.addContent(definition, context as any as IWidgetContext, widget);
		this.checkForDeprecation(definition, widget);

		// TODO Handle this for both Angular and AngularJS (JÅ uncommented to fix reset to default)
		this.attach(widget, element);
	}

	private checkForDeprecation(definition: IWidgetDefinition, widget: IWidget) {
		if (definition && definition.isDeprecated) {
			// Show message
			const message = widget.isPublished()
				? this.lang.get("deprecatedParentWidget")
				: this.lang.get("deprecatedWidget");
			widget.message = { message: message, type: WidgetMessageType.Alert };
		}
	}
	private createTenantSafeModeMessage(): IWidgetMessage {
		const message: IWidgetMessage = {
			type: WidgetMessageType.Alert,
			message: this.lang.safemodeWidgetMessage,
		};
		return message;
	}

	private addWidget(widget: IWidget, element: JQuery) {
		try {
			// TODO Resize is a fix for LIME-2470 & LIME-2460. Hopefully not needed after full Angular conversion is done.
			$(widget.element).resize();
			if (this.isSafeModeTenant(widget)) {
				this.logInfo(
					"Tenant widget safe mode, skipping widget " +
						widget.title +
						", id " +
						widget.id,
				);
				// Specifically this container is in safe mode since safe mode for tenant widgets is on
				this.safeMode = true;
				// Set message
				widget.message = this.createTenantSafeModeMessage();
				const systemMessage: ISystemMessage = {
					errorCode: ResponseErrorCodes.safeMode,
					message: this.lang.safemodeMessageTenant,
					messageType: SystemMessageType.information,
				};
				// Show system message in the system message bar
				this.systemMessagesService.addMessage(systemMessage);
			}

			if (widget.isBroken() || this.isUserPreview || this.safeMode) {
				this.init(widget);
				widget.raiseInitialized();
				return;
			}

			widget.initialized$
				.pipe(
					switchMapTo(this.viewTrackerContext.getTracker()),
					tap((tracker) => {
						const standardId = widget.isPublished()
							? widget.definition.standardWidgetId
							: widget.id;
						tracker.trackContent(
							standardId,
							"widget",
							{
								widgetId: widget.id,
							},
							[
								(this.isDynamic && "dynamic") ||
									(widget.isPublished() && "published") ||
									"standard",
							],
						);
					}),
				)
				.subscribe();

			widget.initialized$.pipe(first()).subscribe(() => {
				this.init(widget);

				this.maintenanceSubscription =
					this.maintenanceService.maintenance$.subscribe((items) => {
						this.onMaintenance(items);
					});
			});

			if (widget.isExternal()) {
				this.addExternal(widget, element);
			} else {
				this.addInline(widget);
			}
		} catch (ex) {
			this.logError("Failed to add widget. " + WidgetUtil.toLog(widget), ex);
		}
	}

	private onMaintenance(items: IMaintenanceItem[]): void {
		let item: IMaintenanceItem = null;
		if (items && items.length > 0) {
			item = this.findMaintenance(items);
		}
		if (item) {
			this.startMaintenance(item);
		} else {
			this.stopMaintenance();
		}
	}

	private findMaintenance(items: IMaintenanceItem[]): IMaintenanceItem {
		if (!this.widget) {
			return null;
		}

		const definition = this.widget.definition;
		const logicalIdPrefix = definition.applicationLogicalId;
		if (logicalIdPrefix) {
			for (const item of items) {
				if (item.logicalIdPrefix === logicalIdPrefix) {
					return item;
				}
			}
		}
		return null;
	}

	private startMaintenance(item: IMaintenanceItem): void {
		this.isMaintenance = true;
		this.maintenance = item;
		this.updateMenu();
		this.widget.startMaintenance();
	}

	private stopMaintenance(): void {
		if (this.isMaintenance) {
			this.isMaintenance = false;
			this.maintenance = null;
			this.updateMenu();
			this.widget.stopMaintenance();
		}
	}

	private isSafeModeTenant(widget: IWidget): boolean {
		return WidgetUtil.isTenantSafeMode(
			widget.definition,
			this.contextService.isSafeModeTenant,
		);
	}

	private loadWidget(widget: IWidget): void {
		const element = $(this.widgetViewParent.element.nativeElement);

		// Load the widget and add it to the template
		this.widgetService.loadWidget(widget).subscribe(
			(w) => this.addWidget(w, element),
			(response) => {
				const brokenWidget = response.widget as IWidget;
				if (!brokenWidget.data) {
					// For context app widgets there might be no data
					brokenWidget.data = {};
				}
				brokenWidget.data.isBroken = true;
				brokenWidget.data.brokenMessage = WidgetUtil.getBrokenMessage(
					this.lang,
					BrokenReason.WidgetMissing,
				);
				this.logWarning(
					"loadWidget: unable to load widget definition, adding broken widget",
				);
				this.addWidget(brokenWidget, element);
			},
		);
	}

	private filterEnabled(items: IWidgetAction[]): IWidgetAction[] {
		return items ? ArrayUtil.filterByPredicate(items, (i) => i.isEnabled) : [];
	}

	private destroy(): void {
		for (const f of this.unsubscribers) {
			f();
		}
	}

	private applyUrl(newUrl: string) {
		if (!newUrl) {
			return;
		}

		if (this.widget.definition.standardParameters) {
			newUrl = this.applyStandard(newUrl);
		}

		if (newUrl !== this.url) {
			this.url = newUrl;
			this.iframe.attr("src", newUrl);
		}
	}

	private applyStandard(url: string): string {
		// Add logical ID first if applicable
		let key = Constants.logicalId;
		const logicalId = this.widget.context.getLogicalId();
		if (logicalId && url.indexOf(key) < 0) {
			url = HttpUtil.appendParam(url, key, logicalId);
		}

		// Add standard parameter with infor-prefix
		const items = this.context.getStandardParameters();
		for (const item of items) {
			key = item.key;
			if (url.indexOf(key) < 0) {
				const value = item.value;
				if (value) {
					url = HttpUtil.appendParam(url, key, value);
				}
			}
		}

		return url;
	}

	private clearUrl() {
		this.iframe.attr("src", "");
		this.url = null;
	}

	private refreshUrl() {
		const url = this.url;
		this.clearUrl();
		this.applyUrl(url);
	}

	private updateUrl() {
		const widget = this.widget;
		const iframe = this.iframe;
		if (widget && iframe) {
			let newUrl = widget.externalUrl;
			if (newUrl && newUrl.indexOf("{") >= 0) {
				newUrl = this.widget.context.resolveAndReplace(newUrl);
				this.widget.context
					.resolveAndReplaceAsync(newUrl, null)
					.subscribe((s: string) => {
						this.applyUrl(s);
					});
			} else {
				this.applyUrl(newUrl);
			}
			iframe.attr("title", widget.title);
		}
	}

	private setConfigState(): void {
		// TODO This function is called to early for widgets that set isConfigured in ngAfterViewInit
		// so we need to decided if that should be supported or not
		if (this.safeMode) {
			// Nothing to do in safe mode
			return;
		}
		const widget = this.widget;
		const instance = widget.instance;
		const currentSettings = widget.context.getSettings();

		if (instance && instance.isConfigured) {
			try {
				this.requiresConfig = !instance.isConfigured(currentSettings);
			} catch (e) {
				this.logError(
					"Failed to invoke the isProperyConfigured event handler",
					e,
				);
			}
		} else {
			this.requiresConfig = !WidgetUtil.isConfigured(currentSettings);
		}

		this.toggleConfigAlert();
	}

	private toggleConfigAlert(): void {
		// Show message if the widget is not configured and the user is not allowed to.
		this.requiresConfig && !this.showSettingsItem
			? this.widget.context.showWidgetMessage({
					type: WidgetMessageType.Alert,
					message: this.lang.widgetNotConfigured,
			  })
			: this.widget.context.removeWidgetMessage();
	}

	private init(widget: IWidget) {
		this.setWidget(widget);

		// const instanceId = widget.data.instanceId;
		// this.menuId = "lm-w-m-" + instanceId;

		const self = this;
		const editModeService = self.editModeService;
		if (!widget.isBroken()) {
			this.setPrimaryAction();

			const requiresConfig = widget.definition.requiresConfig;
			this.emptyConfig = widget.definition.emptyConfig;

			const isEditMode = editModeService.isActive();
			const editMode = editModeService.getCurrent();
			const isRepublishMode =
				isEditMode && editMode.submode === EditSubmodes.republish;
			self.isPreviewMode = isEditMode && editMode.mode === EditModes.preview;

			if (!self.isPreviewMode) {
				if (isRepublishMode) {
					widget.enableSettingsTemporary(true);
				}
				self.updateMenu();
				if (requiresConfig) {
					self.setConfigState();
				}
			}

			const updateHandler = () => {
				if (!self.isPreviewMode) {
					if (isRepublishMode) {
						widget.enableSettingsTemporary(true);
					}
					self.updateMenu();
					if (requiresConfig) {
						self.setConfigState();
					}
				}
			};

			const primaryActionHandler = () => self.setPrimaryAction();

			widget.updated().on(updateHandler);
			widget.changed().on(updateHandler);
			widget.primaryActionChanged().on(primaryActionHandler);

			this.unsubscribers.push(
				editModeService.changed().on((e: IEditMode) => {
					// Always update the menu when edit mode changes unless preview mode since entire menu is hidden
					if (!self.isPreviewMode) {
						if (isRepublishMode) {
							widget.enableSettingsTemporary(true);
						}
						self.updateMenu();
						if (requiresConfig) {
							self.toggleConfigAlert();
						}
					}
				}),
			);
		}

		this.unsubscribers.push(
			editModeService.started().on((e: IEditMode) => {
				const param = e.parameter;
				if (param && param !== self.widget.elementId) {
					self.isInactive = true;
				}
			}),
		);

		this.isBanner = this.widget.isBanner();
		if (this.isBanner) {
			this.isBannerEnabled = this.contextService
				.getContext()
				.settings.isFeatureHeroWidget();
		}

		widget.destroyed().on(() => {
			self.destroy();
		});
		self.widget.raiseAdded();
	}

	/**
	 * Updates which items should be visible / enabled in the widget menu.
	 */

	private updateMenu(): void {
		const widget = this.widget;
		if (!widget || widget.isBroken()) {
			return;
		}

		const definition = widget.definition;
		if (!definition) {
			return;
		}
		if (this.isSafeModeTenant(widget) || this.contextService.isSafeModeAll) {
			return;
		}

		const isMaintenance = this.isMaintenance;
		const isStandardMode = this.contextService.isStandard;
		const isContextApp = this.contextService.isContextApp;
		const isSettingsEnabled = widget.isSettingsEnabled() && !isMaintenance;
		const hasEditRights = this.hasEditRights() && !isMaintenance;
		const isDisabled =
			widget.accessLevel === WidgetAccessLevel.Disabled || isMaintenance;

		if ((!isStandardMode && !isContextApp) || isDisabled || !hasEditRights) {
			this.showSettingsItem = false;
		} else {
			const settingsMetadata = widget.context.getSettings().getMetadata();
			let hasSettings =
				(settingsMetadata && settingsMetadata.length > 0) ||
				widget.isTitleEditEnabled ||
				!CommonUtil.isUndefined(widget.instance.widgetSettingsFactory);
			if (!hasSettings && definition.applicationLogicalId != null) {
				const applications = widget.context.getApplications();
				hasSettings = applications && applications.length >= 2;
			}
			this.showSettingsItem =
				isSettingsEnabled && widget.isSettingsMenuEnabled() && hasSettings;
		}

		const widgetPublishEnabled = definition.enablePublish !== false;
		const editMode = this.editModeService.getCurrent();
		const isEditMode = !!editMode && editMode.isActive;
		const isWidgetEditMode = isEditMode && editMode.mode === EditModes.widget;
		const currentPage = this.page;
		const isPagePublished = currentPage && currentPage.isPublished();
		const isPageEditMode = isEditMode && editMode.mode === EditModes.page;

		if (isStandardMode && hasEditRights) {
			const isPublished = widget.isPublished();
			const isStandard = !isPublished;
			const hasPublishSettingsRights =
				this.context.settings.isWidgetPublishEnabled();
			const isPagePublishDisabled =
				isPagePublished && !(currentPage && currentPage.isRepublishEnabled());
			const isBannerAndEditDisabled =
				widget.isBanner() && !this.context.settings.isBannerWidgetEditEnabled();
			const isPublishEnabled =
				widgetPublishEnabled &&
				!isBannerAndEditDisabled &&
				hasPublishSettingsRights &&
				(isStandard || (isPublished && this.hasEditPublishedRights()));
			const isEditPublish =
				widgetPublishEnabled &&
				(isWidgetEditMode ||
					(isStandard && (!isPagePublished || isPageEditMode)));
			this.showPublishItem =
				!isPagePublishDisabled &&
				isPublishEnabled &&
				!isEditMode &&
				!(isStandard && isPagePublished);
			this.showPublishCopyItem =
				isPublishEnabled && !isEditMode && !isPublished;
			this.showEditPublishItem =
				isEditPublish &&
				(isPublishEnabled || this.context.settings.isPagePublishEnabled());
			this.showClearPublishItem =
				this.showEditPublishItem &&
				widget.data.custom &&
				(!isEditMode || isPageEditMode) &&
				(!isPagePublished || isPageEditMode) &&
				!isPublished;

			// Show for standard widgets with settings but also for published widgets where settings is enabled to be changed
			this.showRestoreItem =
				isSettingsEnabled &&
				(isEditPublish || (isPublished && this.hasUserSettings()));
		}

		const isBannerOnly = this.isBannerOnly(widget);
		const canCopy = this.hasCopyRights();
		this.showDuplicateItem =
			isStandardMode &&
			canCopy &&
			!isBannerOnly &&
			(isPageEditMode || (!isEditMode && !isPagePublished));
		this.showCopyItem = canCopy;

		let enableRefresh = definition.enableRefresh === true;
		if (enableRefresh) {
			const settings = widget.context.getSettings();
			if (settings.get("enableRefresh", true) !== true) {
				enableRefresh = false;
			}
		}
		this.showRefreshItem = enableRefresh;
		this.showRefreshAction = enableRefresh && !widget.hasVisiblePrimaryAction();

		if (isMaintenance) {
			this.showAdvancedItem = false;
		} else if (isStandardMode) {
			// Enable the advanced menu item in standard mode if it has at least one visible item
			this.showAdvancedItem =
				this.showPublishItem ||
				this.showPublishCopyItem ||
				this.showEditPublishItem ||
				this.showDuplicateItem ||
				this.showRestoreItem ||
				this.showCopyItem;
		}
	}

	/**
	 * Find and set the primary action to be shown in title bar
	 */
	private setPrimaryAction() {
		this.primaryAction = undefined;
		const actions = this.widget.instance.actions;
		if (actions && actions.length) {
			for (const action of actions) {
				if (
					action.isPrimary &&
					(action.standardIconName || action.customIconName)
				) {
					this.primaryAction = action;
					return;
				}
			}
		}
	}

	private isContentAdmin(): boolean {
		return this.context && this.context.isPageAdministrator;
	}

	private hasBasicRights(): boolean {
		const widget = this.widget;
		if (widget.isDisabled()) {
			return false;
		}

		const parentContext = widget.parentContext;
		if (parentContext.isDynamic) {
			// Widgets on a standard or dynamic page can never be edited
			return false;
		}

		return true;
	}

	private hasCopyRights(): boolean {
		if (this.context.isDev()) {
			return false;
		}

		if (!this.hasBasicRights()) {
			return false;
		}

		const widget = this.widget;
		if (widget.isEditable()) {
			return true;
		}

		if (this.isContentAdmin()) {
			return true;
		}

		if (this.context.isCurrentUser(widget.definition.owner)) {
			return true;
		}

		return false;
	}

	/**
	 * Gets a value that indicates if the current user is allowed to edit the widget.
	 */
	private hasEditRights(): boolean {
		if (this.context.isDev()) {
			return true;
		}

		if (!this.hasBasicRights()) {
			return false;
		}

		const widget = this.widget;
		if (widget.isStandard() && widget.isEditable()) {
			return true;
		}

		if (
			this.getAccess() === WidgetAccessLevel.Configure &&
			widget.isSettingsEnabled()
		) {
			return true;
		}

		return this.hasEditPublishedRights();
	}

	private hasEditPublishedRights(): boolean {
		return (
			this.isContentAdmin() ||
			this.getAccess() === WidgetAccessLevel.Publish ||
			this.context.isCurrentUser(this.getOwner())
		);
	}

	private getOwner(): string {
		return this.widget.definition.owner;
	}

	private getAccess(): WidgetAccessLevel {
		return this.widget.definition.accessLevel;
	}

	private isBannerOnly(widget: IWidget): boolean {
		const definition = widget.definition;
		const target = definition.target;

		return (
			(target &&
				(target === Constants.targetBanner ||
					target === Constants.targetHero)) ||
			(definition.targets &&
				!ArrayUtil.contains(definition.targets, Constants.targetDefault))
		);
	}

	private isRefreshCooldown(): boolean {
		const elapsed = new Date().getTime() - this.lastRefresh;
		return elapsed < WidgetContainerComponent.refreshCooldown;
	}

	private refreshInline() {
		const instance = this.widget.instance;
		if (instance.refreshed) {
			try {
				instance.refreshed({ lastRefresh: this.lastRefresh });
			} catch (ex) {
				this.logError("Failed to refresh", ex);
			}
		}
	}

	private onPublishWidget() {
		const editMode = this.editModeService.getCurrent();
		const isUpdate = editMode.submode === EditSubmodes.republish;
		const item = this.getPublishItem(!isUpdate);

		// Verify mandatory values
		if (!item.definition.description || !item.definition.title) {
			this.showMissingInfoMessage();
			return;
		}

		if (
			editMode.submode === EditSubmodes.publish ||
			editMode.submode === EditSubmodes.publishCopy
		) {
			this.publishWidget(item);
		} else {
			this.republishWidget(item);
		}
	}

	private closeEditmode(isSave: boolean) {
		this.publishedItem = null;
		this.publishInfo = null;
		this.editModeService.stop({ isSave: isSave });
	}

	private startEditModeInternal() {
		const lang = this.lang;
		const widget = this.widget;
		const isPublished = widget.isPublished();
		let title: string;
		let commandText: string;

		if (isPublished) {
			title = lang.republishWidget;
			commandText = lang.republish;
		} else {
			title = this.isPublishCopy ? lang.publishWidgetCopy : lang.publishWidget;
			commandText = lang.publish;
		}

		try {
			widget.enableSettingsTemporary(true);
			const instance = widget.instance;
			if (instance.publishing) {
				instance.publishing();
				this.setPrimaryAction();
			}
		} catch (ex) {
			this.logError("Failed to call publishing event function", ex);
		}

		const self = this;
		const colorNumber = this.page.data.color || Constants.defaultColorNumber;
		const headerColor = UIUtil.numberToHexCode(colorNumber);
		const entityTitle = widget.definition.title || widget.title;

		this.editModeService.start({
			mode: EditModes.widget,
			title: title,
			entityTitle: entityTitle,
			headerColor: headerColor,
			parameter: widget.elementId,
			submode: this.isPublishCopy
				? EditSubmodes.publishCopy
				: isPublished
				? EditSubmodes.republish
				: EditSubmodes.publish,
			actions: [
				{
					text: this.lang.cancel,
					icon: "close-cancel",
					execute: () => {
						self.onCancelPublish();
					},
					id: "wp-cancel",
				},
				{
					text: commandText,
					icon: "send",
					execute: () => {
						self.onPublishWidget();
					},
					id: "wp-publish",
				},
			],
			secondaryActions: [
				{
					text: this.lang.widgetSettings,
					icon: "settings",
					execute: () => {
						self.showSettings();
					},
					id: "wp-config",
				},
				{
					text: this.lang.editPublishConfiguration,
					icon: "edit",
					execute: () => {
						self.showPublishConfiguration();
					},
					id: "wp-e-publish",
				},
			],
		});

		// Always show the dialog when edit mode starts
		if (!isPublished) {
			this.showPublishConfiguration();
		}
	}

	private onCancelPublish() {
		const lang = this.lang;
		this.showConfirm(lang.confirmCancel, lang.confirmCancelMessage).subscribe(
			() => {
				this.editModeService.stop({ isSave: false });
			},
		);
	}

	private getPublishItem(isNew: boolean): IPublishedWidgetItem {
		const sourceDefinition = this.widget.definition;
		const widgetData = this.widget.data;
		const info = this.publishInfo;
		const publishedItem = this.publishedItem;
		const settingsValues = widgetData.settings || {};
		let definition: IWidgetDefinition;
		let item: IPublishedWidgetItem;
		let sourceMetadata: IWidgetSettingMetadata[];

		if (info) {
			item = info.publishedItem;
			if (!info.isLocalizationChanged) {
				item.localization = null;
			}
		} else if (publishedItem) {
			item = publishedItem;
		} else if (widgetData.custom) {
			item = widgetData.custom;
		}

		if (item) {
			definition = item.definition;
			sourceMetadata = definition.settings;
			if (!sourceMetadata && definition.custom) {
				sourceMetadata = definition.custom.metadata;
			}
		} else {
			definition = {};
			WidgetUtil.copyPublishSettings(sourceDefinition, definition);
			sourceMetadata = definition.settings;
			item = { definition: definition };
			if (this.publishedItem) {
				item.localization = this.publishedItem.localization;
				item.access = this.publishedItem.access;
			}
		}

		let title = widgetData.title;
		if (title == null) {
			// If not changed this time then use last published, definition title or the standardTitle
			title =
				sourceDefinition.custom && sourceDefinition.custom.title != null
					? sourceDefinition.custom.title
					: definition.title || sourceDefinition.standardTitle;
		}

		const metadata = WidgetUtil.getPublishSettings(sourceMetadata);
		const custom = {
			settings: settingsValues,
			metadata: metadata,
			title: title,
			isCatalogTitle: this.widget.isCatalogTitle(),
			isTitleLocked: widgetData.isTitleLocked,
		} as ICustomWidget;

		if (widgetData.logicalId) {
			// Only set this when necessary
			custom.logicalId = widgetData.logicalId;
		}
		if (widgetData.titleApi) {
			custom.titleApi = widgetData.titleApi;
		}

		definition.custom = custom;

		// Reset properties that is not used for published widgets
		widgetData.custom = null;
		definition.settings = null;

		// Verify mandatory properties for publish
		if (!definition.standardWidgetId) {
			definition.standardWidgetId =
				sourceDefinition.standardWidgetId || sourceDefinition.widgetId;
		}

		if (!isNew) {
			definition.widgetId = widgetData.id;
		}

		return item;
	}

	private publishWidget(item: IPublishedWidgetItem) {
		const isCopy = this.isPublishCopy;
		const widget = this.widget;
		this.progressService.setBusy(true);
		this.widgetService.publish(item).subscribe(
			(response: IWidgetHandleResponse) => {
				const title =
					this.getLocalized(item.localization, "title") ||
					item.definition.title ||
					widget.title;
				const container = this.containerService.getContainer();
				this.closeEditmode(true);
				this.progressService.setBusy(false);
				if (isCopy) {
					// When a copy of the widget is published we don't need to save but the page must still be refreshed to discard local changes to the widget.
					container.refresh();
				} else {
					WidgetUtil.toPublished(this.widget, response.content);
					container.saveAndRefreshCurrent();
				}
				this.showPublishedToast(title);
			},
			(r: IStringResponse) => {
				this.widgetService.handleError(r);
				this.progressService.setBusy(false);
			},
		);
	}

	private republishWidget(item: IPublishedWidgetItem) {
		const widget = this.widget;
		this.progressService.setBusy(true);
		this.widgetService.updatePublished(item).subscribe(
			(response: IStringResponse) => {
				const title =
					this.getLocalized(item.localization, "title") ||
					item.definition.title ||
					widget.title;
				this.closeEditmode(true);
				this.progressService.setBusy(false);
				this.showPublishedToast(title);
				this.containerService.getContainer().refresh();
			},
			(r: IStringResponse) => {
				this.widgetService.handleError(r);
				this.progressService.setBusy(false);
			},
		);
	}

	private showPublishedToast(widgetTitle: string): void {
		this.widgetService.showPublishedToast(widgetTitle);
	}

	private showMissingInfoMessage() {
		this.showMessage(
			this.lang.missingInformation,
			this.lang.noTitleOrDescription,
		).subscribe(() => {
			this.showPublishConfiguration();
		});
	}

	private hasUserSettings(): boolean {
		const data = this.widget.getUserData();
		if (data) {
			if (CoreUtil.isEmpty(data)) {
				return false;
			}
			return true;
		}
		return false;
	}

	private afterRestore() {
		if (this.widget.instance.actions) {
			this.setPrimaryAction();
		}
		if (this.widget.definition.requiresConfig) {
			this.setConfigState();
		}
	}

	private onClosePublishConfiguration(r: IDialogResult): void {
		if (!(r && r.value)) {
			return;
		}

		const info: IWidgetPublishInfo = r.value;
		this.publishInfo = info;
		const item = info.publishedItem;
		const definition = item.definition;
		const widget = this.widget;
		const sourceDefinition = widget.definition;
		const customWidget = sourceDefinition.custom;

		let localization: IStringToEntityLocalizationMap = null;
		if (info.isLocalizationChanged) {
			localization = info.publishedItem.localization;
		}

		const widgetData = widget.data;
		let customItem = widgetData.custom;

		const isPublished = sourceDefinition.isPublished;
		if (!isPublished) {
			// Save only a subset of the settings metadata.
			definition.settings = WidgetUtil.getPublishSettings(definition.settings);

			// For a non-published widget the custom configuration is stored in the custom property in the widget data
			if (!customItem) {
				customItem = {} as IPublishedWidgetItem;
				widgetData.custom = customItem;
			}
			customItem.definition = definition;
			customItem.localization = localization;
		}

		let title = definition.title;
		if (sourceDefinition.enableTitleEditDef !== false) {
			const isCatalogTitle = definition.isCatalogTitle;
			let titleOverride = this.getLocalized(localization, "title");
			if (titleOverride) {
				title = titleOverride;
			}

			if (isCatalogTitle) {
				if (customItem) {
					customItem.definition.isCatalogTitle = true;
				} else if (customWidget) {
					customWidget.isCatalogTitle = true;
				}

				if (!titleOverride && isPublished) {
					titleOverride = title;
				}
				if (titleOverride) {
					widget.definition.title = titleOverride;
					title = titleOverride;
				}

				// A null title will reset any existing title (by design for now).
				widget.setTitleInternal(null);
			} else {
				if (customItem) {
					customItem.definition.isCatalogTitle = false;
				} else if (customWidget) {
					customWidget.isCatalogTitle = false;
				}
				widget.updateTitle();
			}
		}

		this.finalizePublishConfiguration(title);
	}

	private finalizePublishConfiguration(title: string): void {
		const editModeService = this.editModeService;
		if (editModeService.isWidget()) {
			editModeService.updateEditModeContext({ entityTitle: title });
		} else {
			// Only save here if we are not in edit mode since it should be possible to cancel edit mode without applying changes.
			if (!editModeService.isActive()) {
				this.containerService.getContainer().saveAndRefreshCurrent();
			}
		}
	}

	private getLocalized(
		localizations: IStringToEntityLocalizationMap,
		key: string,
	): string {
		return WidgetUtil.getLocalized(this.context, localizations, key);
	}

	private notifyInstanceVisibility(eventName: "activated" | "deactivated") {
		const instance = this.widgetInstance;

		if (instance && instance[eventName]) {
			try {
				instance[eventName]({ type: WidgetActivationType.visibility });
			} catch (error) {
				this.logError(`Failed to invoke widget ${eventName} event`, error);
			}
		}
	}
}
