import { AfterViewInit, Component, Input } from "@angular/core";
import { IWidgetContext, IWidgetInstance } from "lime";
import { DynamicImageAlignment, IDynamicContainer } from "lime/core";
import { IDynamicImage } from "../../base/core";

@Component({
	selector: "lm-dyn-image",
	template: ` <div [ngStyle]="styles"></div> `,
	styles: [
		`
			:host > div {
				height: 100%;
				width: 100%;
				min-height: 100%;
				min-width: 100%;
				top: 0;
				left: 0;
				margin: 0;
				padding: 0;
				border: 0;
				background-repeat: no-repeat;
				background-position: center;
			}
		`,
	],
})
export class DynamicImageComponent implements AfterViewInit {
	@Input() widgetContext: IWidgetContext;
	@Input() widgetInstance: IWidgetInstance;
	styles: Object;

	ngAfterViewInit(): void {
		const container = this.widgetContext
			.getSettings()
			.get<IDynamicContainer>("lm_container");
		if (container && container.im && container.im.u) {
			this.setStyles(container.im);
		}
	}

	private setStyles(image: IDynamicImage): void {
		let alignment = "auto";
		const alignmentSetting = image.al || DynamicImageAlignment.Fill;
		switch (alignmentSetting) {
			case DynamicImageAlignment.Cover: {
				alignment = "cover";
				break;
			}
			case DynamicImageAlignment.Fill: {
				alignment = "100% 100%";
				break;
			}
			case DynamicImageAlignment.Fit: {
				alignment = "contain";
				break;
			}
		}

		let url = image.u;
		if (url.indexOf("{") > -1) {
			url = this.widgetContext.resolveAndReplace(url);
		}
		this.styles = {
			"background-image": `url('${url}')`,
			"background-size": `${alignment}`,
		};
	}
}
