import { Component, OnInit } from "@angular/core";
import { DevService } from "../../base/dev";

@Component({
	selector: "lm-icons",
	template: `
		<ng-container *ngIf="useNewTheme; else classicTheme">
			<soho-icons-new></soho-icons-new>
			<soho-icons-empty icons="colorful"></soho-icons-empty>
		</ng-container>
		<ng-template #classicTheme>
			<soho-icons></soho-icons>
			<soho-icons-empty icons="classic"></soho-icons-empty>
		</ng-template>
		<lm-svg></lm-svg>
	`,
})
export class IconsComponent implements OnInit {
	useNewTheme = false;

	constructor(private devService: DevService) {}

	ngOnInit(): void {
		if (this.devService.isDev && Soho.theme.currentTheme.id.includes("new")) {
			this.useNewTheme = true;
		}
	}
}
