/**
 * Dependencies:
 * runtime
 * core
 * lime
 */

import {
	createNgModuleRef,
	Injectable,
	Injector,
	NgModuleRef,
	ViewContainerRef,
} from "@angular/core";
import { SohoMessageService } from "@infor/sohoxi-angular";
import { StringUtil } from "lime";
import {
	EditModes,
	ICommandBarAction,
	IEditMode,
	IEditModeContext,
	IEditModeStartOptions,
	IEditModeStopOptions,
	IInstanceEvent,
	ILanguageService,
} from "./core";
import { CoreBase, CoreUtil, InstanceEvent } from "./runtime";

@Injectable()
export class ProgressService extends CoreBase {
	private busyChangedEvent = new InstanceEvent<boolean>();
	private lmBusy = false;

	constructor() {
		super("ProgressService");
	}

	setBusy(isBusy: boolean): void {
		if (this.lmBusy !== isBusy) {
			this.lmBusy = isBusy;
			this.busyChangedEvent.raise(isBusy);
		}
	}

	isBusy(): boolean {
		return this.lmBusy;
	}

	/**
	 * Gets an event that is raised when edit mode either starts or stops.
	 */
	busyChanged(): IInstanceEvent<boolean> {
		return this.busyChangedEvent;
	}

	/**
	 * Set up a callback function to trigger next time isBusy is set to false
	 * The callback will only trigger once.
	 */
	onNextNotBusy(callback: () => void) {
		const unsubscriber = this.busyChanged().on((isBusy) => {
			if (!isBusy) {
				setTimeout(() => {
					callback();
					unsubscriber();
				}, 0);
			}
		});
	}
}

type LazyNgModuleRef = NgModuleRef<
	import("../../lazy/lazy.module-aot").LimeLazyModule
>;
type LazyModule = typeof import("../../lazy/lazy.module-aot") & {
	ngModuleRef: LazyNgModuleRef;
};
type AdminNgModuleRef = NgModuleRef<
	import("../../admin/admin.module-aot").LimeAdminModule
>;
type AdminModule = typeof import("../../admin/admin.module-aot") & {
	ngModuleRef: AdminNgModuleRef;
};
type ValueOf<T> = T[keyof T];

@Injectable({
	providedIn: "root", // TODO: Might not do well with injector
})
export class LazyTypeService extends CoreBase {
	private adminNgModuleRef?: AdminNgModuleRef;
	private lazyNgModuleRef?: LazyNgModuleRef;

	// Flags that indicates if module loading has failed
	// Is is currently not possible to retry import which is why we need this for now
	// https://github.com/tc39/ecma262/pull/1645
	private adminError = false;
	private lazyError = false;

	constructor(
		private readonly injector: Injector,
		private progressService: ProgressService,
		messageService: SohoMessageService,
		languageService: LanguageService,
	) {
		super("LazyTypeService", messageService, languageService);
	}

	loadLazyModule(): Promise<LazyModule> {
		if (this.lazyError) {
			this.showUpdateMessage();
			return Promise.reject();
		}

		return import(
			/* webpackChunkName: "lime-lazy" */ "../../lazy/lazy.module-aot"
		)
			.then((lazyModule) => {
				if (!this.lazyNgModuleRef) {
					this.lazyNgModuleRef = createNgModuleRef(
						lazyModule.LimeLazyModule,
						this.injector,
					);
				}
				return {
					...lazyModule,
					ngModuleRef: this.lazyNgModuleRef,
				};
			})
			.catch((error) => {
				this.logError("Error when loading lazy module:", error);
				this.lazyError = true;
				this.showUpdateMessage();
				return Promise.reject(error);
			});
	}

	loadAdminModule(): Promise<AdminModule> {
		if (this.adminError) {
			this.showUpdateMessage();
			return Promise.reject();
		}

		return import(
			/* webpackChunkName: "lime-admin" */ "../../admin/admin.module-aot"
		)
			.then((adminModule) => {
				if (!this.adminNgModuleRef) {
					this.adminNgModuleRef = createNgModuleRef(
						adminModule.LimeAdminModule,
						this.injector,
					);
				}
				return {
					...adminModule,
					ngModuleRef: this.adminNgModuleRef,
				};
			})
			.catch((error) => {
				this.logError("Error when loading Admin module:", error);
				this.adminError = true;
				this.showUpdateMessage();
				return Promise.reject(error);
			});
	}

	injectLazyService<TypeName extends keyof LazyModule>(
		type: TypeName,
	): Promise<ValueOf<LazyModule[TypeName]>> {
		return this.loadLazyModule().then((lazyModule) => {
			const token = lazyModule[type];
			return lazyModule.ngModuleRef.injector.get(token);
		});
	}

	private showUpdateMessage(): void {
		this.progressService.setBusy(false);

		const title = this.languageService.get("homepagesUpdate");
		const description = this.languageService.get("homepagesUpdateMessage");
		this.showConfirm(title, description).subscribe((result) => {
			if (result) {
				CoreUtil.reloadDocument();
			}
		});
	}
}

@Injectable({
	providedIn: "root",
})
export class LanguageService implements ILanguageService {
	readonly language: ILanguageLime = null;

	/**
	 * Temporary property for root view container.
	 * @deprecated
	 */
	rootView: ViewContainerRef;

	constructor() {
		let language: ILanguageLime;
		if (typeof infor !== "undefined") {
			language = infor.lime.ResourcesKeys as ILanguageLime;
		} else {
			language = {} as ILanguageLime;
		}
		language.format = StringUtil.format;
		language.get = (name: string): string => {
			const text = language[name] as string;
			return text ? text : name;
		};
		this.language = language;
	}

	getLanguage(): ILanguageLime {
		return this.language;
	}

	get(name: string): string {
		return this.language ? this.language.get(name) : name;
	}
}

@Injectable()
export class EditModeService extends CoreBase {
	current: IEditMode;

	private startedEvent = new InstanceEvent<IEditMode>();
	private stoppedEvent = new InstanceEvent<IEditMode>();
	private changedEvent = new InstanceEvent<IEditMode>();
	private contextChangedEvent = new InstanceEvent<IEditModeContext>();
	private modes: IEditMode[] = [];

	constructor() {
		super("EditModeService");
	}

	start(options: IEditModeStartOptions): void {
		const mode = options as IEditMode;
		this.logDebug("start " + mode.mode);
		mode.isActive = true;
		this.modes.push(mode);
		this.updateMode();
		this.startedEvent.raise(mode);
		this.changedEvent.raise(mode);
	}

	isActive(): boolean {
		const current = this.getCurrent();
		return current && current.isActive;
	}

	stop(options: IEditModeStopOptions): void {
		let mode = this.modes.pop();
		if (!mode) {
			return;
		}

		this.logDebug("stop " + mode.mode);
		mode.isActive = false;
		mode.isSave = options.isSave;
		mode.result = options.result;

		this.destroyActions(mode.actions);
		this.destroyActions(mode.secondaryActions);

		this.updateMode();

		// Raise events for the mode that stopped
		this.stoppedEvent.raise(mode);
		this.changedEvent.raise(mode);

		// Raise event for any mode remaining in the stack
		mode = this.current;
		if (mode) {
			this.logDebug("resume " + mode.mode);
			this.changedEvent.raise(mode);
		}
	}

	updateEditModeContext(context: IEditModeContext) {
		const current = this.getCurrent();
		current.entityTitle = context.entityTitle;
		if (context.headerColor) {
			current.headerColor = context.headerColor;
		}
		this.contextChangedEvent.raise({
			...context,
			headerColor: current.headerColor,
		});
	}

	isPage(): boolean {
		return this.isMode(EditModes.page);
	}

	isLayout(): boolean {
		return this.isMode(EditModes.layout);
	}

	isWidget(): boolean {
		return this.isMode(EditModes.widget);
	}

	isPreview(): boolean {
		return this.isMode(EditModes.preview);
	}

	/**
	 * Gets a value that indicates if the specified mode is the current mode.
	 * @param mode The mode to check
	 * @returns True if the mode is the current mode
	 */
	isMode(mode: string): boolean {
		const current = this.getCurrent();
		return current && current.mode === mode;
	}

	/**
	 * Gets a value that indicates if the specified mode exists in the mode stack.
	 * The mode does not have to be the active one if more than one edit mode has been started.
	 * @param mode The mode to check
	 * @returns True if the mode was found
	 */
	containsMode(mode: string): boolean {
		// Check if the mode exists anywhere in the mode stack
		for (const item of this.modes) {
			if (item.mode === mode) {
				return true;
			}
		}
		return false;
	}

	getCurrent(): IEditMode {
		return this.modes.length > 0 ? this.modes[this.modes.length - 1] : null;
	}

	/**
	 * Gets an event that is raised when edit mode starts.
	 */
	started(): IInstanceEvent<IEditMode> {
		return this.startedEvent;
	}

	/**
	 * Gets an event that is raised when edit mode stops.
	 */
	stopped(): IInstanceEvent<IEditMode> {
		return this.stoppedEvent;
	}

	/**
	 * Gets an event that is raised when edit mode either starts or stops.
	 */
	changed(): IInstanceEvent<IEditMode> {
		return this.changedEvent;
	}

	contextChanged(): IInstanceEvent<IEditModeContext> {
		return this.contextChangedEvent;
	}

	private updateMode() {
		const mode = this.getCurrent();
		this.current = mode;
	}

	private destroyActions(actions: ICommandBarAction[]): void {
		if (actions) {
			for (const action of actions) {
				action.execute = null;
			}
		}
	}
}
