import { Pipe, PipeTransform } from "@angular/core";
import { StringUtil } from "lime";

/**
 * Surrounds a URL with a CSS url() function.
 *
 * Example in: https://my.image
 * Example out: url(https://my.image)
 */
@Pipe({
	name: "url",
	pure: true,
})
export class UrlPipe implements PipeTransform {
	transform(url: string) {
		if (!StringUtil.isNullOrWhitespace(url)) {
			return `url(${url})`;
		}
	}
}
