/**
 * Dependencies:
 * runtime
 * core
 * ../../lime
 */
import { NgZone, ViewContainerRef } from "@angular/core";
import {
	IAccelerationData,
	IDevice,
	IGetAudioOptions,
	IGetAudioResult,
	IGetImageOptions,
	IGetImageResult,
	IGetLocationOptions,
	IGetLocationResult,
	IGetNetworkOptions,
	IGetNetworkResult,
	IGetSensorsOptions,
	IGetSensorsResult,
	IGetVideoOptions,
	IGetVideoResult,
	IGyroscopeData,
	IMapCoordinates,
	IMapLocationOptions,
	IMapNavigationOptions,
	IMarker,
	IMediaSource,
	IOpenDocumentOptions,
	IOpenDocumentResult,
	IOpenLinkOptions,
	IOpenLinkResult,
	IReadBarcodeOptions,
	IReadBarcodeResult,
	IReadQRCodeOptions,
	IReadQRCodeResult,
	IShowMapOptions,
	IShowMapResult,
	IWidgetContext,
	NetworkConnectionState,
	NetworkConnectionType,
} from "lime";
import {
	combineLatest,
	fromEvent,
	iif,
	merge,
	Observable,
	of,
	throwError,
} from "rxjs";
import { filter, first, map, mapTo, switchMap, take } from "rxjs/operators";
import { ICompanyonService } from "./core";
import { MediaService } from "./media.service";
import { CoreBase } from "./runtime";

/**
 * This custom operator can be used to connect a stream to a given NgZone,
 * causing all changes to be monitored by Angular.
 *
 * TODO: Move to a generic utility module?
 */
export const zoned =
	(zone: NgZone) =>
	<T>(source: Observable<T>) => {
		return new Observable<T>((observer) => {
			return source.subscribe({
				next(value) {
					zone.run(() => observer.next(value));
				},
				error(err) {
					zone.run(() => observer.error(err));
				},
				complete() {
					zone.run(() => observer.complete());
				},
			});
		});
	};

const mapMediaSource = (source: IMediaSource): DeviceMediaSource => {
	switch (source) {
		case "camera":
			return DeviceMediaSource.camera;
		case "library":
			return DeviceMediaSource.library;
		case "all":
			return DeviceMediaSource.all;
		default:
			throw TypeError(`Invalid IMediaSource '${source}'`);
	}
};

/**
 * MobileDevice is used to access native capabilities through the Infor GO messaging
 * protocol.
 */
export class MobileDevice extends CoreBase implements IDevice {
	constructor(
		private widgetId: string,
		private companyonService: ICompanyonService,
		private zone: NgZone,
	) {
		super("MobileDevice");
	}

	getLocation(
		options: IGetLocationOptions = {},
	): Observable<IGetLocationResult> {
		if (this.isDebug()) {
			this.logDebug(
				`getLocation called with options ${JSON.stringify(options)}`,
			);
		}
		const parseLocationMessage = (
			message: ISharedLocationMessage,
		): IGetLocationResult => {
			return {
				latitude: Number(message.data.lat),
				longitude: Number(message.data.long),
			};
		};
		if (options.watch) {
			const watchLocation$ = new Observable<IGetLocationResult>((observer) => {
				const source = this.widgetId;
				const stopLocationUpdates = () =>
					this.sendMessage<IGetLocationMessage>(
						MobileMessage.REQUEST_LOCATION,
						{
							options: LocationRequestOption.stopUpdates,
							source,
						},
					);
				const startLocationUpdates = () =>
					this.sendMessage<IGetLocationMessage>(
						MobileMessage.REQUEST_LOCATION,
						{
							options: LocationRequestOption.continuous,
							source,
						},
					);
				const locationUpdates$ = this.awaitMessages$<ISharedLocationMessage>(
					MobileMessage.RESPONSE_LOCATION,
					source,
				).pipe(map(parseLocationMessage));
				locationUpdates$.subscribe(observer);
				startLocationUpdates();
				return stopLocationUpdates;
			});
			return watchLocation$.pipe(zoned(this.zone));
		} else {
			return this.requestMessage$<IGetLocationMessage, ISharedLocationMessage>(
				MobileMessage.REQUEST_LOCATION,
				MobileMessage.RESPONSE_LOCATION,
				{
					options: LocationRequestOption.once,
					source: this.widgetId,
				},
			).pipe(map(parseLocationMessage), zoned(this.zone));
		}
	}

	getImage(options?: IGetImageOptions): Observable<IGetImageResult> {
		if (this.isDebug()) {
			this.logDebug(`getImage called with options ${JSON.stringify(options)}`);
		}
		const mediaSource: IMediaSource = (options && options.source) || "all";
		return this.requestMessage$<IGetMediaMessage, ISharedMediaMessage>(
			MobileMessage.REQUEST_MEDIA,
			MobileMessage.RESPONSE_MEDIA,
			{
				mediaType: DeviceMediaType.image,
				options: mapMediaSource(mediaSource),
				source: this.widgetId,
			},
		).pipe(
			map<ISharedMediaMessage, IGetImageResult>((message) => ({
				data: message.base64Str,
			})),
			zoned(this.zone),
		);
	}

	getVideo(options?: IGetVideoOptions): Observable<IGetVideoResult> {
		if (this.isDebug()) {
			this.logDebug(`getVideo called with options ${JSON.stringify(options)}`);
		}
		const mediaSource: IMediaSource = (options && options.source) || "all";
		return this.requestMessage$<IGetMediaMessage, ISharedMediaMessage>(
			MobileMessage.REQUEST_MEDIA,
			MobileMessage.RESPONSE_MEDIA,
			{
				mediaType: DeviceMediaType.video,
				options: mapMediaSource(mediaSource),
				source: this.widgetId,
			},
		).pipe(
			map<ISharedMediaMessage, IGetVideoResult>((message) => ({
				data: message.base64Str,
			})),
			zoned(this.zone),
		);
	}

	getAudio(options?: IGetAudioOptions): Observable<IGetAudioResult> {
		if (this.isDebug()) {
			this.logDebug(`getAudio called with options ${JSON.stringify(options)}`);
		}
		return this.requestMessage$<IGetAudioMessage, ISharedAudioMessage>(
			MobileMessage.REQUEST_AUDIO_RECORDING,
			MobileMessage.RESPONSE_AUDIO_RECORDING,
			{
				source: this.widgetId,
			},
		).pipe(
			map<ISharedAudioMessage, IGetAudioResult>((message) => ({
				data: message.base64Str,
			})),
			zoned(this.zone),
		);
	}

	getSensors(options: IGetSensorsOptions = {}): Observable<IGetSensorsResult> {
		if (this.isDebug()) {
			this.logDebug(
				`getSensors called with options ${JSON.stringify(options)}`,
			);
		}
		const getSensors$ = new Observable<IGetSensorsResult>((observer) => {
			const source = this.widgetId;
			const stopSensorUpdates = () =>
				this.sendMessage<IGetMotionMessage>(MobileMessage.REQUEST_MOTION, {
					options: RequestMotionOption.stopUpdates,
					source,
				});
			const startSensorUpdates = () =>
				this.sendMessage<IGetMotionMessage>(MobileMessage.REQUEST_MOTION, {
					options: RequestMotionOption.startUpdates,
					source,
				});
			const sensorUpdates$ = this.awaitMessages$<ISharedMotionMessage>(
				MobileMessage.RESPONSE_MOTION,
				source,
			).pipe(
				map<ISharedMotionMessage, IGetSensorsResult>((message) => ({
					acceleration: message.data.acceleration,
					gyroscope: message.data.gyro,
				})),
			);

			if (options.watch) {
				sensorUpdates$.subscribe(observer);
			} else {
				sensorUpdates$.pipe(first()).subscribe(observer);
			}
			startSensorUpdates();
			return stopSensorUpdates;
		});
		return getSensors$.pipe(zoned(this.zone));
	}

	getNetwork(options: IGetNetworkOptions = {}): Observable<IGetNetworkResult> {
		if (this.isDebug()) {
			this.logDebug(
				`getNetwork called with options ${JSON.stringify(options)}`,
			);
		}
		const getConnectionState = (
			message: ISharedNetworkStatusMessage,
		): NetworkConnectionState => {
			switch (message.data.status) {
				case NetworkResponseConnectionStatus.online:
					return "online";
				case NetworkResponseConnectionStatus.offline:
					return "offline";
				default:
					this.logWarning(
						`Invalid network connection status '${message.data.status}'`,
					);
					return "offline";
			}
		};
		const getConnectionType = (
			message: ISharedNetworkStatusMessage,
		): NetworkConnectionType => {
			switch (message.data.connectionType) {
				case NetworkResponseConnectionType.mobile:
					return "mobile";
				case NetworkResponseConnectionType.wifi:
					return "wifi";
				case NetworkResponseConnectionType.none:
					return "unknown";
				default:
					this.logWarning(
						`Invalid network connection type '${message.data.connectionType}'`,
					);
					return "unknown";
			}
		};
		const parseNetworkResponse = (
			response: ISharedNetworkStatusMessage,
		): IGetNetworkResult => {
			return {
				connectionState: getConnectionState(response),
				connectionType: getConnectionType(response),
			};
		};
		const source = this.widgetId;
		if (options.watch) {
			const networkUpdates$ = this.awaitMessages$<ISharedNetworkStatusMessage>(
				MobileMessage.RESPONSE_NETWORK,
				source,
			).pipe(map(parseNetworkResponse), zoned(this.zone));
			const startNetworkUpdates = () =>
				this.sendMessage<IGetNetworkStatusMessage>(
					MobileMessage.REQUEST_NETWORK,
					{
						options: NetworkRequestOption.continuous,
						source,
					},
				);
			const stopNetworkUpdates = () =>
				this.sendMessage<IGetNetworkStatusMessage>(
					MobileMessage.REQUEST_NETWORK,
					{
						options: NetworkRequestOption.stopUpdates,
						source,
					},
				);
			return new Observable<IGetNetworkResult>((observer) => {
				networkUpdates$.subscribe(observer);
				startNetworkUpdates();
				return stopNetworkUpdates;
			});
		} else {
			return this.requestMessage$<
				IGetNetworkStatusMessage,
				ISharedNetworkStatusMessage
			>(MobileMessage.REQUEST_NETWORK, MobileMessage.RESPONSE_NETWORK, {
				options: NetworkRequestOption.once,
				source,
			}).pipe(
				map<ISharedNetworkStatusMessage, IGetNetworkResult>(
					parseNetworkResponse,
				),
				zoned(this.zone),
			);
		}
	}

	readQRCode(options?: IReadQRCodeOptions): Observable<IReadQRCodeResult> {
		this.logDebug("delegating readQRCode to readBarcode");
		return this.readBarcode(options);
	}

	readBarcode(options?: IReadBarcodeOptions): Observable<IReadBarcodeResult> {
		if (this.isDebug()) {
			this.logDebug(
				`readBarcode called with options ${JSON.stringify(options)}`,
			);
		}
		return this.requestMessage$<IGetQRCodeMessage, ISharedQRCodeMessage>(
			MobileMessage.REQUEST_QR,
			MobileMessage.RESPONSE_QR,
			{ source: this.widgetId },
		).pipe(
			map<ISharedQRCodeMessage, IReadBarcodeResult>((message) => ({
				text: message.data,
			})),
			zoned(this.zone),
		);
	}

	showMap(options?: IShowMapOptions): Observable<IShowMapResult> {
		if (this.isDebug()) {
			this.logDebug(`showMap called with options ${JSON.stringify(options)}`);
		}
		const mapCoordinates = (coords: IMapCoordinates): IMapLocation => {
			return {
				lat: `${coords.latitude}`,
				long: `${coords.longitude}`,
				name: "",
			};
		};
		const mapMarker = (marker: IMarker): IMapLocation => {
			return {
				...mapCoordinates(marker.coordinates),
				name: marker.label,
			};
		};
		const makeMapMsg = (): IShowMapMessage => {
			switch (options.mapType) {
				case "navigation":
					return {
						locs: [
							mapCoordinates(options.start),
							mapCoordinates(options.destination),
						],
						mapType: MapRequestType.showDirections,
						source: this.widgetId,
					};
				case "location":
					return {
						locs: [mapCoordinates(options.coordinates)],
						mapType: MapRequestType.showLocation,
						source: this.widgetId,
					};
				case "marker":
					return {
						locs: options.markers.map(mapMarker),
						mapType: MapRequestType.showMultipleAnnotations,
						source: this.widgetId,
					};
				default:
					this.logError(`Unknown mapType in showMap options.`);
					return null;
			}
		};
		return this.sendMessage$<IShowMapMessage>(
			MobileMessage.REQUEST_SHOW_MAP,
			makeMapMsg(),
		).pipe(mapTo<void, IShowMapResult>({}), zoned(this.zone));
	}

	openExternalLink(options: IOpenLinkOptions): Observable<IOpenLinkResult> {
		if (this.isDebug()) {
			this.logDebug(
				`openExternalLink called with options ${JSON.stringify(options)}`,
			);
		}
		return this.sendMessage$<IExternalLinkMessage>(
			MobileMessage.REQUEST_OPEN_LINK,
			{
				link: options.url,
				source: this.widgetId,
			},
		).pipe(mapTo<void, IOpenLinkResult>({}), zoned(this.zone));
	}

	openDocument(options: IOpenDocumentOptions): Observable<IOpenDocumentResult> {
		if (this.isDebug()) {
			this.logDebug(
				`openDocument called with options name:${options.name}, type:${options.type}, data length:${options.data.length}`,
			);
		}
		return this.sendMessage$<IOpenDocumentMessage>(
			MobileMessage.REQUEST_OPEN_DOCUMENT,
			{
				fileData: options.data,
				fileName: options.name,
				fileType: options.type,
				source: this.widgetId,
			},
		).pipe(mapTo<void, IOpenDocumentResult>({}), zoned(this.zone));
	}

	private requestMessage$<
		RequestType extends IMobileRequestMessage,
		ResponseType extends IMobileResponseMessage,
	>(
		reqName: MobileMessage,
		resName: MobileMessage,
		req: RequestType,
	): Observable<ResponseType> {
		if (this.isDebug()) {
			this.logDebug(
				`requestMessage$ called with reqName:'${reqName}', resName:'${resName}', req:'${JSON.stringify(
					req,
				)}'`,
			);
		}
		const send$ = this.sendMessage$<RequestType>(reqName, req);
		const receive$ = this.awaitMessages$<ResponseType>(resName, req.source);
		return combineLatest(receive$, send$).pipe(
			first(),
			map(([response]) => response),
		);
	}

	private awaitMessages$<T extends IMobileResponseMessage>(
		name: MobileMessage,
		source?: string,
	): Observable<T> {
		if (this.isDebug()) {
			this.logDebug(
				`awaitMessages$ called with name:'${name}', source:'${source}'`,
			);
		}
		return this.companyonService
			.receive$<T>(name)
			.pipe(filter((data) => data.source === source || !source));
	}

	private sendMessage$<T extends IMobileRequestMessage>(
		name: MobileMessage,
		data: T,
	): Observable<void> {
		if (this.isDebug()) {
			this.logDebug(
				`sendMessage$ called with name:'${name}', data:'${JSON.stringify(
					data,
				)}'`,
			);
		}
		return this.companyonService.send$<T>({ name, data });
	}

	private sendMessage<T>(name: MobileMessage, data: T) {
		if (this.isDebug()) {
			this.logDebug(
				`sendMessage called with name:'${name}', data:'${JSON.stringify(
					data,
				)}'`,
			);
		}
		this.companyonService.send<T>({ name, data });
	}
}

export enum MobileMessage {
	REQUEST_OPEN_LINK = "mobile_openLinkInExternalBrowser",
	REQUEST_OPEN_DOCUMENT = "mobile_openDocument",
	REQUEST_SHOW_MAP = "mobile_showMap",
	REQUEST_LOCATION = "mobile_getGeoLocation",
	RESPONSE_LOCATION = "mobile_shareGeoLocation",
	REQUEST_MEDIA = "mobile_getMediaFromMobile",
	RESPONSE_MEDIA = "mobile_sharePickedMedia",
	REQUEST_AUDIO_RECORDING = "mobile_getAudioRecording",
	RESPONSE_AUDIO_RECORDING = "mobile_shareAudioRecording",
	REQUEST_QR = "mobile_showQRCodeScanner",
	RESPONSE_QR = "mobile_shareQRCodeData",
	REQUEST_NETWORK = "mobile_getNetworkInfo",
	RESPONSE_NETWORK = "mobile_shareNetworkInfo",
	REQUEST_MOTION = "mobile_getDeviceMotionInfo",
	RESPONSE_MOTION = "mobile_shareDeviceMotionInfo",
}

export interface IMobileRequestMessage {
	source: string;
}

export interface IMobileResponseMessage {
	readonly source: string;
}

enum LocationRequestOption {
	once = "1",
	continuous = "2",
	stopUpdates = "3",
}

interface IGetLocationMessage extends IMobileRequestMessage {
	options: LocationRequestOption;
}

interface ISharedLocationMessage extends IMobileResponseMessage {
	readonly data: {
		readonly lat: string;
		readonly long: string;
	};
}

export interface IExternalLinkMessage extends IMobileRequestMessage {
	link: string;
}

export interface IOpenDocumentMessage extends IMobileRequestMessage {
	fileName: string;
	fileData: string;
	fileType: string;
}

enum DeviceMediaSource {
	all = "1",
	camera = "2",
	library = "3",
	cameraAndLibrary = "4",
}

enum DeviceMediaType {
	any = "1",
	image = "2",
	video = "3",
}

interface IGetMediaMessage extends IMobileRequestMessage {
	options: DeviceMediaSource;
	mediaType: DeviceMediaType;
}

interface ISharedMediaMessage extends IMobileResponseMessage {
	readonly base64Str: string;
	readonly data: {
		readonly options: DeviceMediaSource;
		readonly mediaType: DeviceMediaType;
	};
}

interface IGetQRCodeMessage extends IMobileRequestMessage {}

interface ISharedQRCodeMessage extends IMobileResponseMessage {
	readonly data: string;
}

interface IGetAudioMessage extends IMobileRequestMessage {}

interface ISharedAudioMessage extends IMobileResponseMessage {
	readonly data: {
		readonly fileType: string;
	};
	readonly base64Str: string;
}

enum NetworkRequestOption {
	once = "1",
	continuous = "2",
	stopUpdates = "3",
}

enum NetworkResponseConnectionType {
	none = "0",
	wifi = "1",
	mobile = "2",
}

enum NetworkResponseConnectionStatus {
	offline = "0",
	online = "1",
}

interface INetworkResponseData {
	readonly status: NetworkResponseConnectionStatus;
	readonly connectionType: NetworkResponseConnectionType;
}

interface IGetNetworkStatusMessage extends IMobileRequestMessage {
	options: NetworkRequestOption;
}

interface ISharedNetworkStatusMessage extends IMobileResponseMessage {
	readonly data: INetworkResponseData;
}

enum MapRequestType {
	showLocation = "1",
	showMultipleAnnotations = "2",
	showDirections = "3",
}

interface IMapLocation {
	lat: string;
	long: string;
	name: string;
	others?: string; // Not sure if/how this is used...
}

interface IShowMapMessage extends IMobileRequestMessage {
	mapType: MapRequestType;
	locs: IMapLocation[];
}

enum RequestMotionOption {
	stopUpdates = "0",
	startUpdates = "1",
}

interface IGetMotionMessage extends IMobileRequestMessage {
	options: RequestMotionOption;
}

interface ISharedMotionMessage extends IMobileResponseMessage {
	readonly data: {
		readonly acceleration: {
			readonly x: number;
			readonly y: number;
			readonly z: number;
		};
		readonly gyro: {
			readonly x: number;
			readonly y: number;
			readonly z: number;
		};
	};
}

export class BrowserDevice extends CoreBase implements IDevice {
	constructor(
		private widgetContext: IWidgetContext,
		private viewRef: ViewContainerRef,
		private mediaService: MediaService,
	) {
		super("BrowserDevice");
	}

	getLocation(options?: IGetLocationOptions): Observable<IGetLocationResult> {
		const getPosition$ = new Observable<GeolocationPosition>((observer) => {
			navigator.geolocation.getCurrentPosition(
				(position) => {
					observer.next(position);
					observer.complete();
				},
				(error) => {
					observer.error(error);
				},
			);
		});
		const watchPosition$ = new Observable<GeolocationPosition>((observer) => {
			const watchId = navigator.geolocation.watchPosition(
				(position) => observer.next(position),
				(error) => observer.error(error),
			);
			return () => navigator.geolocation.clearWatch(watchId);
		});
		const watchOptionSet = () => options && options.watch;
		return iif(watchOptionSet, watchPosition$, getPosition$).pipe(
			map<GeolocationPosition, IGetLocationResult>((position) => {
				return {
					latitude: position.coords.latitude,
					longitude: position.coords.longitude,
				};
			}),
		);
	}

	getImage(options?: IGetImageOptions): Observable<IGetImageResult> {
		return iif(
			() => options && options.source === "camera",
			this.mediaService.takePicture(this.viewRef),
			iif(
				() => options && options.source === "library",
				this.mediaService.importPicture(),
				this.mediaService.getPicture(this.viewRef),
			),
		).pipe(
			switchMap((pictureBlob) => this.mediaService.base64Encode(pictureBlob)),
			map<string, IGetImageResult>((data) => ({ data })),
		);
	}

	getVideo(options?: IGetVideoOptions): Observable<IGetVideoResult> {
		return iif(
			() => options && options.source === "camera",
			this.mediaService.recordVideo(this.viewRef),
			iif(
				() => options && options.source === "library",
				this.mediaService.importVideo(),
				this.mediaService.getVideo(this.viewRef),
			),
		).pipe(
			switchMap((videoBlob) => this.mediaService.base64Encode(videoBlob)),
			map<string, IGetVideoResult>((data) => ({ data })),
		);
	}

	getAudio(options?: IGetAudioOptions): Observable<IGetAudioResult> {
		return this.mediaService.recordAudio(this.viewRef).pipe(
			switchMap((audioBlob) => this.mediaService.base64Encode(audioBlob)),
			map<string, IGetAudioResult>((data) => ({ data })),
		);
	}

	getSensors(options?: IGetSensorsOptions): Observable<IGetSensorsResult> {
		const motion$ = fromEvent<DeviceMotionEvent>(window, "devicemotion").pipe(
			map<DeviceMotionEvent, IAccelerationData>((event) => {
				return {
					x: event.acceleration.x,
					y: event.acceleration.y,
					z: event.acceleration.z,
				};
			}),
		);
		const orientation$ = fromEvent<DeviceOrientationEvent>(
			window,
			"deviceorientation",
		).pipe(
			map<DeviceOrientationEvent, IGyroscopeData>((event) => {
				return { x: event.beta, y: event.gamma, z: event.alpha };
			}),
		);
		const result$ = combineLatest(motion$, orientation$).pipe(
			map<[IAccelerationData, IGyroscopeData], IGetSensorsResult>(
				([motion, orientation]) => {
					return {
						acceleration: motion,
						gyroscope: orientation,
					};
				},
			),
		);
		return iif(() => options && options.watch, result$, result$.pipe(take(1)));
	}

	getNetwork(options?: IGetNetworkOptions): Observable<IGetNetworkResult> {
		const connectionState$: Observable<NetworkConnectionState> = merge(
			fromEvent(window, "online").pipe(mapTo(true)),
			fromEvent(window, "offline").pipe(mapTo(false)),
			of(navigator.onLine),
		).pipe(map((online) => (online ? "online" : "offline")));
		const connectionType$ = of<NetworkConnectionType>("unknown");

		const result$: Observable<IGetNetworkResult> = combineLatest(
			connectionState$,
			connectionType$,
		).pipe(
			map(([connectionState, connectionType]) => {
				return { connectionState, connectionType };
			}),
		);

		return iif(() => options && options.watch, result$, result$.pipe(take(1)));
	}

	readQRCode(options?: IReadQRCodeOptions): Observable<IReadQRCodeResult> {
		this.logDebug("delegating readQRCode to readBarcode");
		return this.readBarcode(options);
	}

	readBarcode(options?: IReadBarcodeOptions): Observable<IReadBarcodeResult> {
		return throwError(
			new Error("readBarcode/readQRCode is not supported on this device"),
		);
	}

	showMap(options?: IShowMapOptions): Observable<IShowMapResult> {
		const showMapLocation = (opts: IMapLocationOptions) => {
			const url = `https://www.google.com/maps/@?api=1&map_action=map&center=${formatCoords(
				opts.coordinates,
			)}`;
			return this.openExternalLink({ url });
		};

		const showMapNavigation = (opts: IMapNavigationOptions) => {
			const url = `https://www.google.com/maps/dir/?api=1&origin=${formatCoords(
				opts.start,
			)}&destination=${formatCoords(opts.destination)}`;
			return this.openExternalLink({ url });
		};

		const showMapOnly = () => {
			const url = "https://www.google.com/maps/@?api=1&map_action=map";
			return this.openExternalLink({ url });
		};

		if (options && options.mapType === "location") {
			return showMapLocation(options);
		} else if (options && options.mapType === "navigation") {
			return showMapNavigation(options);
		} else {
			// TODO: Warn/error on unsupported "marker" location request.
			return showMapOnly();
		}

		function formatCoords(coordinates?: IMapCoordinates): string {
			if (coordinates) {
				return `${coordinates.latitude},${coordinates.longitude}`;
			} else {
				return "";
			}
		}
	}

	/**
	 * TODO: Open External links only?
	 * Needs to deal with protocols other than http, e.g tel, mailto. WidgetContext can't do that..
	 */
	openExternalLink(options: IOpenLinkOptions): Observable<IOpenLinkResult> {
		return new Observable<IOpenLinkResult>((observer) => {
			this.widgetContext.launch({
				url: options.url,
			});
			observer.next();
			observer.complete();
		});
	}

	openDocument(options: IOpenDocumentOptions): Observable<IOpenDocumentResult> {
		return new Observable<IOpenDocumentResult>((observer) => {
			try {
				const link = document.createElement("a");
				link.href = `data:application/octet-stream;base64,${options.data}`;
				link.download = options.name;
				link.click();
				observer.next();
				observer.complete();
			} catch (err) {
				observer.error(err);
			}
		});
	}
}
