import { Injectable, OnDestroy } from "@angular/core";
import { interval, Observable, Subject } from "rxjs";
import {
	distinctUntilChanged,
	filter,
	map,
	share,
	skip,
	takeUntil,
} from "rxjs/operators";
import { CoreBase } from "../base/runtime";

/**
 * This service can be used to detect when IDS modals are opened and closed.
 */
@Injectable({
	providedIn: "root",
})
export class ModalMonitorService extends CoreBase implements OnDestroy {
	static readonly MONITOR_INTERVAL_MS = 1000;

	readonly modalOpened$: Observable<unknown>;
	readonly modalClosed$: Observable<unknown>;
	readonly modalToggled$: Observable<boolean>;
	private readonly destroyed$ = new Subject<void>();
	constructor() {
		super("ModalMonitorService");

		this.modalToggled$ = interval(ModalMonitorService.MONITOR_INTERVAL_MS).pipe(
			map(() => $(document.body).hasClass("modal-engaged")), // Class set by IDS modal controller
			distinctUntilChanged(), // Only interested in changes
			skip(1), // Ignore current state on subscription
			takeUntil(this.destroyed$), // Prevent leaky subscriptions
			share(), // Multicast results to prevent multiple intervals for multiple subscribers
		);

		this.modalOpened$ = this.modalToggled$.pipe(filter((isOpened) => isOpened));

		this.modalClosed$ = this.modalToggled$.pipe(
			filter((isOpened) => !isOpened),
		);
	}

	ngOnDestroy() {
		this.destroyed$.next();
		this.destroyed$.complete();
	}

	/**
	 * Closes all open modals.
	 *
	 * *NOTE: This should only be used in response to some global state change, where previously opened modals are no longer relevant*
	 */
	closeAll(): void {
		if (typeof (Soho as any)?.modalManager?.closeAll === "function") {
			this.logDebug("Closing dialogs using Soho.modalManager.closeAll()");
			(Soho as any).modalManager.closeAll();
		} else {
			this.logWarning(
				"Soho.modalManager.closeAll() is no longer available. Attempting manual close.",
			);
			document.querySelectorAll(".modal").forEach((modalElement) => {
				try {
					const modal: SohoModalStatic = $(modalElement).data("modal");
					if (modal) {
						modal.close(true);
					}
				} catch (err) {
					this.logError("Failed to close modal", err);
				}
			});
		}
	}
}
