export class WidgetSettings implements IWidgetSettings {
	constructor(
		private readonly widgetService: WidgetService,
		private widget: IWidget,
		private values: any,
	) {}

	getValues(): any {
		return this.values;
	}

	setValues(values: any): void {
		this.values = values;
		// need to set reference between Widget.data.settings and WidgetSettings.values back correctly
		this.widget.data.settings = this.values;
	}

	get<T>(name: string, defaultValue?: T): T {
		const value = this.values[name];
		return !CommonUtil.isUndefined(value) ? value : defaultValue;
	}

	set(name: string, value: any): void {
		this.values[name] = value;
	}

	getString(name: string, defaultValue?: string): string {
		const value = this.values[name];
		return value ? value.toString() : defaultValue;
	}

	showSettings(options?: IShowSettingsOptions): void {
		const data = options ? options.data : null;
		this.widgetService.showSettings(this.widget, data);
	}

	getMetadata(): IWidgetSettingMetadata[] {
		return this.widget.definition.settings;
	}

	setMetadata(metadata: IWidgetSettingMetadata[]): any {
		const definition = this.widget.definition;
		if (metadata) {
			const customMetadata = definition.customMetadata;
			if (customMetadata) {
				metadata = WidgetUtil.applyRestrictions(metadata, customMetadata);
			}
		}
		definition.settings = metadata;
	}

	isSettingsEnabled(): boolean {
		return this.widget.isSettingsEnabled();
	}

	isSettingEnabled(name: string): boolean {
		if (!this.isSettingsEnabled()) {
			return false;
		}

		const setting = this.getCustomSetting(name) || this.getSetting(name);
		if (setting) {
			const isTemporary = this.widget.isEnableSettingsTemporary();
			return isTemporary || setting.isEnabled !== false;
		}

		return true;
	}

	isSettingVisible(name: string): boolean {
		const setting = this.getCustomSetting(name) || this.getSetting(name);
		if (setting) {
			const isTemporary = this.widget.isEnableSettingsTemporary();
			return isTemporary || setting.isVisible !== false;
		}

		return true;
	}

	enableSettingsMenu(enabled: boolean): void {
		this.widget.setSettingsMenuEnabled(enabled);
	}

	hasMandatory(): boolean {
		const metadata = this.getMetadata();
		return metadata
			? ArrayUtil.indexByPredicate(metadata, (s) => s.isMandatory) >= 0
			: false;
	}

	isMandatory(name: string): boolean {
		const setting = this.getSetting(name);
		return setting && setting.isMandatory;
	}

	private getSetting(name: string): IWidgetSettingMetadata {
		return ArrayUtil.itemByProperty(this.getMetadata(), "name", name);
	}

	private getCustomSetting(name: string): IWidgetSettingMetadata {
		const metadata = this.widget.definition.customMetadata;
		if (metadata) {
			return ArrayUtil.itemByProperty(metadata, "name", name);
		}
		return null;
	}
}

export class WidgetContextValueResolver extends ContextValueResolver {
	constructor(
		config: IConfiguration,
		context: IContext,
		private readonly widget: IWidget,
		private application: IApplication,
		companyonService: ICompanyonService,
	) {
		super(config, context, companyonService, widget.id);
	}

	setApplication(application: IApplication) {
		this.application = application;
	}

	protected getWidgetData(): any {
		return this.widget.data;
	}

	protected getWidgetLanguage(): any {
		return this.widget.context.getLanguage();
	}

	protected getLogicalId(): string {
		const application = this.application;
		return application ? application.logicalId : null;
	}

	protected resolveFramework(name: string) {
		const widget = this.widget;
		name = name.toLowerCase();
		if ("pageid" === name) {
			return widget.parentContext.id;
		}
		if ("widgetid" === name) {
			return widget.id;
		}
		if ("standardwidgetid" === name) {
			return widget.definition.standardWidgetId || widget.id;
		}
		if ("widgetinstanceid" === name) {
			return widget.data.instanceId;
		}
		if ("containerurl" === name) {
			return widget.context.getContainerUrl();
		}
		return super.resolveFramework(name);
	}
}

export class WidgetContextBase extends CoreBase {
	widget: IWidget;

	protected config: IConfiguration = null;
	protected contextValueResolver: WidgetContextValueResolver;

	private language: ILanguage;
	private application: IApplication;
	private applications: IApplication[];

	private mode: Mode;
	private subMode: SubMode;

	constructor(
		logPrefix: string,
		protected widgetService: WidgetService,
		widget: IWidget,
		protected settings: IWidgetSettings,
		protected element: JQuery,
		protected context: IContext,
		languageService: LanguageService,
		protected containerService: ContainerService,
		protected readonly companyonService: ICompanyonService,
	) {
		super(logPrefix);
		this.widget = widget;
		this.config = context.getConfiguration();

		const language = (widget.definition.lang || {}) as ILanguage;

		// Extend the language object with the get function.
		language.get = (id: string) => {
			const text = language[id];
			return text || null;
		};

		// Extend the language object with supported shared lime language constants
		const limeLanguage = languageService.getLanguage();
		const constants = Constants.sharedLimeLanguageConstants;
		for (const constant of constants) {
			if (!language.hasOwnProperty(constant)) {
				language[constant] = limeLanguage[constant];
			}
		}

		// Extend the language object with the format function.
		if (!language.hasOwnProperty("format")) {
			language.format = StringUtil.format;
		}

		this.language = language;

		this.initializeApplication();

		this.contextValueResolver = new WidgetContextValueResolver(
			this.config,
			context,
			widget,
			this.application,
			this.companyonService,
		);
		this.mode = widget.parentContext ? widget.parentContext.mode : Mode.Default;
		this.subMode = widget.parentContext
			? widget.parentContext.subMode
			: SubMode.Default;
	}

	isPortal(): boolean {
		return false;
	}

	isHomepages(): boolean {
		return true;
	}

	getTenantId(): string {
		return this.context.getTenantId();
	}

	getUserId(): string {
		return this.context.getUserId();
	}

	findWidgetsOnPage(options?: IFindWidgetOptions): IWidgetInstanceInfo[] {
		let items: IWidgetInstanceInfo[] = [];

		try {
			const page = this.getPage();
			if (page) {
				items = page.findWidgets(this.getWidgetInstanceId(), options || {});
			}
		} catch (ex) {
			this.logError(
				"findWidgetsOnPage: Failed to find widgets for widget with id: " +
					this.widget.id,
				ex,
			);
		}

		return items;
	}

	isWidgetOnPage(options: IFindWidgetOptions): boolean {
		const widgets = this.findWidgetsOnPage(options);
		return widgets.length > 0;
	}

	getBannerBackgroundColor(): string {
		const page = this.getPage();
		return page ? UIUtil.numberToHexCode(page.data.color, true) : null;
	}
	getPrefferedLogicalIdInstance(): string {
		const def = this.widget.definition;
		return WidgetUtil.getPrefferedLogicalIdInstance(def);
	}

	getId(): string {
		return this.widget.id;
	}

	getSettings(): IWidgetSettings {
		return this.settings;
	}

	getLanguage(): ILanguage {
		return this.language;
	}

	getElement(): JQuery {
		return this.element;
	}

	getUrl(path?: string): string {
		return WidgetUtil.getUrl(this.widget.definition, path);
	}

	isPublished(): boolean {
		const widget = this.widget;
		return widget.definition.isPublished || widget.parentContext.isPublished;
	}

	isDev(): boolean {
		return this.widgetService.isDev();
	}

	isBanner(): boolean {
		return this.widget.isBanner();
	}

	save(): void {
		if (this.widget.isSettingsEnabled()) {
			this.widget.raiseChanged();
		} else {
			const msg = `Settings were not saved since settings are disabled for widget with id ${this.widget.id}`;
			if (this.isDev()) {
				throw msg;
			} else {
				this.logError(msg);
			}
		}
	}

	isActive(): boolean {
		const widget = this.widget;
		return !!(
			widget.isVisible &&
			widget.state === WidgetState.running &&
			!widget.isEdit &&
			!widget.isSettings
		);
	}

	isVisible(): boolean {
		return !!this.widget.isVisible;
	}

	getState(): string {
		return this.widget.state;
	}

	getTitle(): string {
		const widget = this.widget;
		return widget.title || widget.data.title;
	}

	getStandardTitle(): string {
		return this.widget.definition.standardTitle;
	}

	setTitle(title: string): void {
		try {
			const widget = this.widget;
			widget.titleApi = title;
			widget.data.titleApi = title;

			if (
				widget.isCatalogTitle() ||
				(!widget.data.isTitleLocked && !widget.isSettings)
			) {
				if (this.isDebug()) {
					this.logDebug(
						"Ignoring setTitle call from implementation because widget is configured to use catalog title or the title is unlocked",
					);
				}
				return;
			}

			widget.setTitleInternal(title);
		} catch (ex) {
			this.logError("Failed to setTitle " + ex);
		}
	}

	setStandardTitle(): void {
		const widget = this.widget;
		widget.titleApi = null;
		widget.data.titleApi = null;
		this.setTitleLocked(true);
	}

	getResolvedTitle(isTitleLocked: boolean): string {
		return this.widget.calculateTitle(isTitleLocked);
	}

	enableTitleEdit(isEnabled: boolean) {
		this.widget.isTitleEditEnabled = isEnabled;
	}

	isTitleEditEnabled(): boolean {
		return this.widget.isTitleEditEnabled;
	}

	isTitleLocked(): boolean {
		const widget = this.widget;

		// ReSharper disable once RedundantComparisonWithBoolean
		return widget.data.isTitleLocked === true || widget.isCatalogTitle();
	}

	isTitleUnlockable(): boolean {
		return !this.widget.isCatalogTitle();
	}

	setTitleLocked(isLocked: boolean): void {
		if (this.isTitleUnlockable()) {
			const widget = this.widget;
			widget.data.isTitleLocked = isLocked;
			if (isLocked) {
				this.widget.updateTitle();
			}
		}
	}

	getPageId(): string {
		try {
			return this.widget.parentContext.id;
		} catch (ex) {
			return null;
		}
	}

	getStandardWidgetId(): string {
		return this.widget.definition.standardWidgetId || this.widget.id;
	}

	getWidgetInstanceId(): string {
		return this.widget.data.instanceId;
	}

	getApplication(): IApplication {
		return this.application;
	}

	getApplications(): IApplication[] {
		return this.applications || [];
	}

	getLogicalId(): string {
		const application = this.application;
		return application ? application.logicalId : null;
	}

	setLogicalId(logicalId: string): void {
		const data = this.widget.data;
		if (logicalId) {
			if (!this.isValidLogicalId(logicalId)) {
				throw new Error("Invalid logical ID");
			}
			data.logicalId = logicalId;
		} else {
			delete data.logicalId;
		}
		this.initializeApplication();
	}

	isCloud(): boolean {
		return this.context.isCloud();
	}

	isSingleTenantCloud(): boolean {
		return this.context.isSingleTenantCloud();
	}

	getContainerUrl(): string {
		this.logError(
			"Widget with id: " +
				this.getStandardWidgetId() +
				" is using deprecated getContainerUrl in IWidgetContext. This method should not be used. There is no replacement.",
		);
		return this.context.getContainerUrl();
	}

	getContextParameter(parameter: string): string {
		const params = this.containerService.getContextParameters();
		if (params) {
			return params[parameter] || null;
		} else {
			return null;
		}
	}

	resolve(key: string): string {
		return this.contextValueResolver.resolveValue(key, this.getLogicalId());
	}

	resolveAndReplace(template: string): string {
		return this.contextValueResolver.resolveAndReplaceInternal(
			template,
			this.getLogicalId(),
		);
	}

	showWidgetMessage(message: IWidgetMessage) {
		this.widget.message = message;
	}

	removeWidgetMessage() {
		delete this.widget.message;
	}

	setWidgetStatus(status: IWidgetStatus): void {
		this.widget.status = status;
	}

	clearWidgetStatus(): void {
		delete this.widget.status;
	}

	/**
	 * Returns the Infor time zone in a raw format or null if no time zone was found.
	 * Example: (UTC-05:00)Eastern Time(US & Canada)
	 */
	getInforTimeZoneRaw(): string {
		return this.context.getInforTimeZoneRaw();
	}

	/**
	 * Returns the Infor time zone or null if no time zone was found.
	 * Example: UTC-05:00
	 */
	getInforTimeZone(): string {
		return this.context.getInforTimeZone();
	}

	getInforStdTimeZone(): string {
		return this.context.getInforStdTimeZone();
	}

	getInforCurrentLanguage(): string {
		return this.context.getInforCurrentLanguage();
	}

	getInforCurrentLocale(): string {
		return this.context.getInforCurrentLocale();
	}

	getInforThemeName(): string {
		return this.context.getInforThemeName();
	}

	updatePrimaryAction(): void {
		this.widget.raisePrimaryActionChanged();
	}

	getMode(): Mode {
		return this.mode;
	}

	getSubMode(): SubMode {
		return this.subMode;
	}

	getPortal(): unknown {
		this.logPortalOnly("getPortal");
		return {
			workspace: {
				showAdd: () => {},
			},
			getUserApplicationSetting: () => EMPTY,
		};
	}

	getNavigation(): unknown {
		this.logPortalOnly("getNavigation");
		return {
			navigated$: EMPTY,
			navigate: () => {},
			back: () => {},
		};
	}

	setSubTitle(): void {
		this.logPortalOnly("setSubTitle");
	}

	private getPage(): IPageInstance {
		let widgetPage: IPageInstance = null;

		const pageId = this.getPageId();
		const pages = this.containerService.getContainer().pages;

		for (const page of pages) {
			if (pageId === page.data.id) {
				widgetPage = page;
			}
		}

		return widgetPage;
	}

	private isValidLogicalId(logicalId: string) {
		const logicalIdPrefix = this.getLogicalIdPrefix();
		return (
			logicalIdPrefix && logicalId && logicalId.indexOf(logicalIdPrefix) === 0
		);
	}

	private initializeApplication(): void {
		const logicalIdPrefix = this.getLogicalIdPrefix();
		if (!logicalIdPrefix) {
			return;
		}

		// Check if the default logical ID has been overridden by the widget (and is still valid).
		const data = this.widget.data;
		let logicalId = data.logicalId;
		if (logicalId) {
			if (!this.isValidLogicalId(logicalId)) {
				logicalId = null;
				delete data.logicalId;
			}
		}

		// If preffered logicalId instance is set in manifest by using suffix
		const prefferedDefault = this.getPrefferedLogicalIdInstance();
		this.setApplication(logicalId || prefferedDefault || logicalIdPrefix);
	}

	private setApplication(logicalId: string) {
		if (logicalId) {
			this.applications = this.config.getApplicationsCached(logicalId);
			const application = this.config.getApplicationCached(logicalId);
			this.application = application;
			if (this.contextValueResolver) {
				this.contextValueResolver.setApplication(application);
			}
		} else {
			this.applications = null;
			this.application = null;
		}
	}

	private getLogicalIdPrefix(): string {
		return this.widget.definition.applicationLogicalId;
	}

	private logPortalOnly(methodName: string): void {
		this.logWarning(
			`Widget with id ${this.getStandardWidgetId()} is using IWidgetContext ${methodName}. This method is not supported in Homepages.`,
		);
	}
}

/**
 * Widget context implementation for Angular and jQuery widgets.
 */
export class WidgetContext extends WidgetContextBase implements IWidgetContext {
	private device?: IDevice;
	private destroyed$ = new Observable((observer) => {
		const unregister = this.widget.destroyed().on(() => {
			observer.next();
			observer.complete();
		});
		return unregister;
	});

	constructor(
		private injector: Injector,
		widgetService: WidgetService,
		widget: IWidget,
		settings: IWidgetSettings,
		element: JQuery,
		context: IContext,
		languageService: LanguageService,
		containerService: ContainerService,
		companyonService: ICompanyonService,
		private mediaService: MediaService,
		private zone: NgZone,
	) {
		super(
			"WidgetContext",
			widgetService,
			widget,
			settings,
			element,
			context,
			languageService,
			containerService,
			companyonService,
		);
	}

	getIonApiCustomerContext(): string {
		return this.config.ionApiCustomerContext;
	}

	getIonApiContextAsync(options?: IIonApiOptions): Observable<IIonApiContext> {
		return this.config.getIonApiContextAsync(options);
	}

	executeIonApiAsync<T>(
		options: IIonApiRequestOptions,
	): Observable<IIonApiResponse<T>> {
		return this.config.executeIonApiAsync(options, this.getStandardWidgetId());
	}

	getIonApiInfoAsync(options: IIonApiInfoOptions): Observable<IIonApiInfo> {
		return this.config.getIonApiInfoAsync(options, this.getStandardWidgetId());
	}

	getApplicationAsync(logicalId: string): Observable<IApplication> {
		return this.config.getApplication(logicalId);
	}

	getApplicationsAsync(logicalId: string): Observable<IApplication[]> {
		return this.config.getApplications(logicalId);
	}

	getDevice(): Observable<IDevice> {
		if (!this.device) {
			this.device = this.createDevice();
		}
		return of(this.device);
	}

	getVersionInfo(): IVersionInfo {
		return this.context.getVersionInfo();
	}

	getViewUrlAsync(options: IViewUrlOptions): Observable<string> {
		return this.contextValueResolver.getViewUrlAsync(options);
	}

	getService<T>(serviceType: new (...args: any[]) => T): T {
		return this.injector.get(serviceType);
	}

	interval(options: IIntervalOptions): Observable<unknown> {
		const MIN_PERIOD = 1000;
		return iif(
			() => options.period >= MIN_PERIOD,
			interval(options.period).pipe(
				takeUntil(this.destroyed$),
				filter(() => this.isActive()),
				mapTo(undefined),
			),
			throwError(
				new RangeError(
					`The interval period ${options.period} is lower than the minimum ${MIN_PERIOD}.`,
				),
			),
		);
	}

	launch(launchOptions: ILaunchOptions) {
		this.contextValueResolver.launch(launchOptions);
	}

	resolveAndReplaceAsync(
		template: string,
		logicalId: string,
	): Observable<string> {
		const subject = new AsyncSubject<string>();
		this.contextValueResolver.resolveAndReplaceInternalAsync(
			template,
			logicalId || this.getLogicalId(),
			subject,
			true,
			false,
		);
		return subject.asObservable();
	}

	setState(state: string, options?: BusyStateOptions): void {
		const widget = this.widget;

		if (widget.state !== state) {
			widget.state = state;
			if (state === "running" && widget?.stateOption?.position === "bottom") {
				widget.stateOption.position = "center";
			}
		}

		if (options?.position) {
			if (!widget.stateOption) {
				widget.stateOption = {};
			}

			widget.stateOption.position = options.position;
		}
	}

	listBookmarks(): Observable<IBookmarkResponse> {
		let url = "/user/bookmark/list";
		if (this.isDev()) {
			const config = ClientConfiguration;
			url = config.getLocalUrl() + "/limerest" + url;
			this.logInfo("Using dev mode calling url " + url);
		}
		// This function should not be documented and only used from the Custom menu and Bookmark widgets
		return (
			this.context as unknown as { dataService: DataService }
		).dataService.post(url, { content: null });
	}

	send(name: string, data: unknown): void {
		this.companyonService.send({ name, data });
	}

	receive(options: string | IMessageOptions): Observable<unknown> {
		let messageType;
		if (typeof options === "string") {
			messageType = options;
		} else {
			messageType = options.messageType;
			if (options.source === "push") {
				throw new Error("Push notifications are not supported in Homepages");
			}
		}

		if (!messageType) {
			throw new Error("messageType is mandatory");
		}

		const parentContext = this.widget.parentContext;
		if (parentContext && parentContext.receive) {
			return parentContext.receive(messageType);
		}

		return this.companyonService
			.receive$<unknown>(messageType)
			.pipe(takeUntil(this.destroyed$), zoned(this.zone));
	}

	getEnvironmentInformation(): Observable<EnvironmentInfoMap> {
		return this.companyonService.getEnvironmentInformation();
	}

	getParentUrl(): Observable<string> {
		return this.companyonService.getParentUrl();
	}

	getSize(): Observable<IWidgetSize> {
		const toWidgetSize = (homepageColumns: number): IWidgetSize => {
			const widgetLayout = this.widget.data.layout;
			const widgetSize: IWidgetSize = {
				cols: widgetLayout.columnSpan,
				rows: widgetLayout.rowSpan,
			};
			if (widgetSize.cols > homepageColumns) {
				widgetSize.cols = homepageColumns;
			}
			return widgetSize;
		};

		const homepageElement = this.containerService.selectedPage
			.getElement()
			.find("div.homepage");
		return fromEvent<number[]>(homepageElement, "resize.homepage").pipe(
			debounceTime(100),
			filter((event) => event.length > 0),
			map((event) => event[1]),
			distinctUntilChanged(),
			map((columns) => toWidgetSize(columns)),
			distinctUntilChanged((a, b) => {
				return a.cols === b.cols && a.rows === b.rows;
			}),
			takeUntil(this.destroyed$),
			zoned(this.zone),
		);
	}

	setEmptyState(options: IEmptyStateOptions): void {
		this.widget.emptyState = CoreUtil.copy(options);
	}

	clearEmptyState(): void {
		delete this.widget.emptyState;
	}

	showBadge(options: IBadgeOptions): void {
		const maxValue = 10000;
		const minValue = 0;

		try {
			Validator.int(options.count, minValue, maxValue);
			this.widget.badge = { type: BadgeType.Info, ...options };
		} catch (ex) {
			this.removeBadge();
			this.logError(ex);
		}
	}

	removeBadge(): void {
		delete this.widget.badge;
	}

	trackEvent(options: ITrackEventOptions): void {
		const viewTracker = this.widget.subViewTracker ?? this.widget.viewTracker;
		if (viewTracker) {
			let type: string;
			switch (options.type) {
				case TrackEventType.Click:
					type = "click";
					break;
				default:
					this.logWarning(
						`trackEvent: Got unsupported event type '${options.type}'`,
					);
					return;
			}
			viewTracker.trackEvent(options.name, type);
		}
	}

	async trackView(options: ITrackViewOptions): Promise<void> {
		const parentView = this.widget.viewTracker;
		if (parentView) {
			await this.widget.subViewTracker?.trackEnd();
			this.widget.subViewTracker = parentView.createChild({
				name: options.name,
				type: "view",
			});
			await this.widget.subViewTracker?.trackStart();
		}
	}

	getSpotlight(): ISpotlight {
		return {
			data$: EMPTY,
		};
	}

	private createDevice(): IDevice {
		if (this.getMode() === Mode.Mobile && !this.isDev()) {
			return new MobileDevice(
				this.getWidgetInstanceId(),
				this.companyonService,
				this.zone,
			);
		} else {
			return new BrowserDevice(this, this.widget.view, this.mediaService);
		}
	}
}

export class WidgetSettingsContextBase {
	angularConfig = null as IAngularWidgetConfig;
	private isSaveEnabledInternal = true;

	constructor(
		protected widget: IWidget,
		protected element: JQuery,
		protected dialog: IDialog,
	) {}

	getElement(): JQuery {
		return this.element;
	}

	enableSave(isEnabled: boolean): void {
		this.isSaveEnabledInternal = isEnabled;
	}

	isSaveEnabled(): boolean {
		return this.isSaveEnabledInternal;
	}

	close(isSave: boolean): void {
		this.dialog.close({
			button: isSave ? DialogButtonType.Ok : DialogButtonType.Cancel,
		});
	}
}

export class WidgetSettingsContext
	extends WidgetSettingsContextBase
	implements IWidgetSettingsContext
{
	constructor(widget: IWidget, element: JQuery, dialog: IDialog) {
		super(widget, element, dialog);
	}

	getWidgetContext(): IWidgetContext {
		return this.widget.context as any as IWidgetContext;
	}
}
