import { Pipe, PipeTransform } from "@angular/core";
import { Observable } from "rxjs";
import { IMarkdownSyntaxSupportOptions, MarkdownParser } from "./markdown";

@Pipe({
	name: "markdown",
	pure: true,
})
export class MarkdownPipe implements PipeTransform {
	transform(
		markdown = "",
		support: IMarkdownSyntaxSupportOptions,
	): Observable<string> {
		const markdownParser = new MarkdownParser(support);
		return markdownParser.parse(markdown);
	}
}
