import {
	ChangeDetectionStrategy,
	Component,
	EventEmitter,
	HostListener,
	Input,
	Output,
} from "@angular/core";
import {
	IMarkdownSyntaxSupportOptions,
	MarkdownSyntaxSupport,
} from "./markdown";

@Component({
	changeDetection: ChangeDetectionStrategy.OnPush,
	selector: "lm-markdown-renderer",
	templateUrl: "./markdown-renderer.component.html",
	styleUrls: ["./markdown-renderer.component.scss"],
})
export class MarkdownRendererComponent {
	@Input() content: string;
	@Input() support: IMarkdownSyntaxSupportOptions = MarkdownSyntaxSupport.All;
	@Output() linkClick = new EventEmitter<string>();

	@HostListener("click", ["$event"])
	handleAnchorClick(event: MouseEvent) {
		const anchor = event.target;
		if (isAnchor(anchor)) {
			this.linkClick.emit(anchor.href);
			event.preventDefault();
			event.stopImmediatePropagation();
		}

		function isAnchor(value: any): value is HTMLAnchorElement {
			return value.nodeName === "A" && value.href;
		}
	}
}
