import { Component, HostBinding } from "@angular/core";
import { FormControl, FormGroup } from "@angular/forms";
import { Observable, defer, map, switchMap } from "rxjs";

import { ClientMode } from "../../base/core";
import { DevService } from "../../base/dev";
import { CoreBase } from "../../base/runtime";
import { ContextService } from "../../service";

@Component({
	selector: "lm-dev-menu",
	templateUrl: "./dev-menu.component.html",
	styleUrls: ["./dev-menu.component.scss"],
})
export class DevMenuComponent extends CoreBase {
	@HostBinding("class.expanded") expanded = true;

	readonly languages = LANGUAGES;
	personalizationForm = new FormGroup({
		mode: new FormControl<PersonalizationMode>(
			this.getCurrentPersonalizationMode(),
		),
		theme: new FormControl<PersonalizationTheme>(
			this.getCurrentPersonalizationTheme(),
		),
	});

	localizationForm = new FormGroup({
		locale: new FormControl<SupportedLocale>(this.getCurrentLocale()),
	});

	messagingForm = new FormGroup({
		messageType: new FormControl("inforBusinessContext"),
		messageContent: new FormControl('{"screenid": "hello"}'),
	});

	widgetsForm = new FormGroup({
		widgets: new FormControl<string[]>(
			this.devService.getWidgetItems().map((item) => item.devPath),
		),
	});

	miscForm = new FormGroup({
		mode: new FormControl<ClientMode>(this.contextService.mode),
	});

	widgets$: Observable<DevWidgetInfo[]> = defer(() =>
		fetch("/_devWidgets"),
	).pipe(
		switchMap((response) => response.json() as Promise<DevWidgetsResponse>),
		map((widgets) =>
			widgets.map((widget) => {
				if (typeof widget === "string") {
					// In the new SDK, /_devWidgets just returns a list of widget IDs.
					return {
						id: widget,
						path: `/widgets/${widget}`,
						title: widget,
					};
				} else {
					return widget;
				}
			}),
		),
	);

	constructor(
		private devService: DevService,
		private contextService: ContextService,
	) {
		super("DevMenuComponent");
		this.addJsonValidator();
	}

	sendMessage() {
		const name = this.messagingForm.controls.messageType.value;
		let content = this.messagingForm.controls.messageContent.value;
		try {
			content = JSON.parse(content);
		} catch (error) {
			this.logError("Failed to parse companyon content:", error);
		}
		infor.companyon.client.sendMessage(name, content);
	}

	apply() {
		const devThemeName = this.personalizationForm.controls.theme.value;
		const devThemeVersion = this.personalizationForm.controls.mode.value;
		const devLanguage = this.localizationForm.controls.locale.value;
		const devWidget = this.widgetsForm.controls.widgets.value.join(";");

		const lmMode = this.miscForm.controls.mode.value;

		const url = new URL(location.href);
		url.searchParams.set("devThemeName", devThemeName);
		url.searchParams.set("devThemeVersion", devThemeVersion);
		url.searchParams.set("devLanguage", devLanguage);
		url.searchParams.set("devWidget", devWidget);
		url.searchParams.set("lm-mode", lmMode.toString());

		location.href = url.toString();
	}

	private getCurrentPersonalizationMode(): PersonalizationMode {
		const mode = Soho.theme.currentTheme.id.match(
			/theme-(?<mode>\w+)-(?<color>\w+)/,
		).groups.mode;
		return mode as PersonalizationMode;
	}

	private getCurrentPersonalizationTheme(): PersonalizationTheme {
		const color = Soho.theme.currentTheme.id.match(
			/theme-(?<mode>\w+)-(?<color>\w+)/,
		).groups.color;
		return color as PersonalizationTheme;
	}

	private getCurrentLocale(): SupportedLocale {
		return Soho.Locale.currentLocale.name as SupportedLocale;
	}

	private addJsonValidator() {
		this.logDebug("Adding custom json validation rule (data-validate='json')");
		try {
			type Rules = Record<
				string,
				{
					message: string;
					type: "error";
					id: string;
					check: (content: string) => boolean;
				}
			>;
			(Soho.Validation.rules as Rules).json = {
				id: "json",
				message: "Invalid JSON",
				type: "error",
				check: (content) => {
					try {
						JSON.parse(content);
						return true;
					} catch (error) {
						return false;
					}
				},
			};
		} catch (error) {
			this.logError(
				"Failed to add custom JSON validation, data-validate='json' will not work.",
				error,
			);
		}
	}
}

type PersonalizationMode = "classic" | "new";
type PersonalizationTheme = "light" | "dark" | "contrast";

