import { Injectable } from "@angular/core";
import { ArrayUtil, Log } from "lime";
import { Observable, ReplaySubject } from "rxjs";
import { tap } from "rxjs/operators";
import {
	Constants,
	IPageContainer,
	IStringMap,
	IWidgetHandle,
} from "../base/core";
import { CoreBase } from "../base/runtime";
import { IContainerOptions } from "../container/core";
import { ContainerLoaderService } from "../container/loader";
import { MingleMessageBroker } from "../mingle";
import { ContextService } from "../service";
import { BrowserStorageService } from "../services/browser-storage.service";
import { WidgetService } from "../widget/service";
import {
	ContextAppType,
	ContextMessageReceiveType,
	ContextMessageSendType,
	IContextSiteData,
	IContextualMessages,
	IContextualMessagesData,
	IContextWidget,
	ILoadContextZoneData,
	IToggleContextZoneData,
	IWindowNameData,
} from "./core";

@Injectable({
	providedIn: "root",
})
export class ContextAppService extends CoreBase {
	private readonly loadSubject = new ReplaySubject<ILoadContextZoneData>(1);
	load$: Observable<ILoadContextZoneData> = this.loadSubject.asObservable();

	private readonly showSubject = new ReplaySubject<IContextSiteData>(1);
	show$: Observable<IContextSiteData> = this.showSubject.asObservable();

	private readonly hideSubject = new ReplaySubject<IContextSiteData>(1);
	hide$: Observable<IContextSiteData> = this.hideSubject.asObservable();

	private readonly toggleSubject = new ReplaySubject<IToggleContextZoneData>(1);
	toggle$: Observable<IToggleContextZoneData> =
		this.toggleSubject.asObservable();

	private readonly resetSubject = new ReplaySubject<ILoadContextZoneData>(1);
	reset$: Observable<ILoadContextZoneData> = this.resetSubject.asObservable();

	private readonly messageSubject = new ReplaySubject<IContextualMessages>(1);
	message$: Observable<IContextualMessages> =
		this.messageSubject.asObservable();

	private readonly clearMessageSubject = new ReplaySubject<any>(1);
	clearMessages$: Observable<any> = this.clearMessageSubject.asObservable();

	private readonly windowNameData: IWindowNameData;
	private readonly messageNames: IStringMap = {};
	private hasSettings: boolean;
	private isContextZoneEnabled: boolean = undefined;
	private collapsedWidgets: Set<string>;

	constructor(
		mingleMessageBroker: MingleMessageBroker,
		private readonly contextService: ContextService,
		private readonly containerLoaderService: ContainerLoaderService,
		private readonly widgetService: WidgetService,
		private readonly browserStorageService: BrowserStorageService,
	) {
		super("ContextAppService");

		this.windowNameData = { name: window.name };
		// TODO Temporary
		Log.setDebug();

		if (contextService.isContextApp) {
			// mingleMessageBroker.initialize();
			this.registerMessages();
			this.sendComlete();
		}
	}

	enableContextZone(): void {
		this.isContextZoneEnabled = true;
		this.sendMessage("enableContextZone", this.windowNameData);
	}

	disableContextZone(): void {
		this.isContextZoneEnabled = false;
		this.sendMessage("disableContextZone", this.windowNameData);
	}

	registerAppMessage(name: string): void {
		// TODO Remove this method and callers
	}

	loadWidgets(widgets: IContextWidget[]): Observable<any> {
		const widgetHandles: IWidgetHandle[] = this.getPendingWidgets(widgets);
		// Since we use local storage we now need the container always the get the UserID.
		if (!widgetHandles) {
			this.logDebug("loadWidgets: No widgets to load");
		} else {
			this.logInfo(
				"loadWidgets: Loading widget definitions for " +
					widgetHandles.length +
					" widget(s).",
			);
		}

		if (this.hasSettings && widgetHandles) {
			return this.loadDefinitions(widgetHandles);
		}

		return this.loadContainer(widgetHandles);
	}

	isWidgetCollapsed(widgetParentId: string): boolean {
		return this.collapsedWidgets && this.collapsedWidgets.has(widgetParentId);
	}

	updateCollapsedWidgetsStorage(parentContextId: string, isCollapsed: boolean) {
		const collapsedWidgets = this.collapsedWidgets;
		if (isCollapsed) {
			collapsedWidgets.add(parentContextId);
		} else {
			collapsedWidgets.delete(parentContextId);
		}
		this.browserStorageService.setLocalStorageItem(
			Constants.collapsedContextApps,
			collapsedWidgets,
		);
	}

	private loadContainer(widgetHandles: IWidgetHandle[]): Observable<any> {
		const options = {
			mode: this.contextService.mode,
			settings: !this.hasSettings,
			pages: false,
			widgetHandles: widgetHandles,
		} as IContainerOptions;

		return this.containerLoaderService
			.loadContainer(options)
			.pipe(tap((c) => this.onContainerLoaded(c)));
	}

	private loadDefinitions(widgetHandles: IWidgetHandle[]): Observable<any> {
		return this.widgetService.loadDefinitions(widgetHandles);
	}

	private onContainerLoaded(pageContainer: IPageContainer) {
		this.hasSettings = true;
		const storedInfo = this.browserStorageService.getLocalStorageItem<string[]>(
			Constants.collapsedContextApps,
		);
		this.collapsedWidgets = new Set(storedInfo);
	}

	private registerMessages(): void {
		this.registerMessage("loadContextZone", (data) =>
			this.onLoadContextZone(data),
		);
		this.registerMessage("showContextZone", (data) =>
			this.onShowContextZone(data),
		);
		this.registerMessage("hideContextZone", (data) =>
			this.onHideContextZone(data),
		);
		this.registerMessage("toggleContextZone", (data) =>
			this.onToggleContextZone(data),
		);
		this.registerMessage("resetContextZone", (data) =>
			this.onResetContextZone(data),
		);
		this.registerMessage("contextualMessages", (data) =>
			this.onContextualMessages(data),
		);
	}

	private registerMessage(
		type: ContextMessageReceiveType,
		handler: (data: any) => void,
	): void {
		this.logInfo("registerMessage: " + type);
		this.register(type, (data: any) => {
			this.logDebug(
				() => "Received message: " + type + " -> " + JSON.stringify(data),
			);
			handler(data);
		});
	}

	private sendComlete(): void {
		// Use explicit initialization for Homepages but wiht custom message in context app mode
		this.sendMessage("hpContextAppInitComplete", this.windowNameData);
	}

	private sendMessage(name: ContextMessageSendType, data: any): void {
		this.logDebug("sendMessage: " + name);
		const client = infor.companyon.client;
		client.sendMessage(name, data);
	}

	private onLoadContextZone(data: ILoadContextZoneData): void {
		this.loadSubject.next(data);
	}

	private onShowContextZone(data: IContextSiteData): void {
		this.clearMessageSubject.next({});
		this.showSubject.next(data);
	}

	private onHideContextZone(data: IContextSiteData): void {
		this.hideSubject.next(data);
	}

	private onToggleContextZone(data: IToggleContextZoneData): void {
		this.toggleSubject.next(data);
	}

	private onResetContextZone(data: ILoadContextZoneData): void {
		this.resetSubject.next(data);
	}

	private onContextualMessages(data: IContextualMessagesData): void {
		this.logDebug(
			() =>
				"onContextualMessages: Received message: contextualMessages -> " +
				JSON.stringify(data),
		);

		// Temporary check if Portal sent a single item instead of an array.
		const messages = data.data;
		if (
			!messages ||
			typeof messages.length !== "number" ||
			messages.length < 1
		) {
			this.logWarning(
				"onContextualMessages: Skipping message without innner messages -> " +
					JSON.stringify(data),
			);
			return;
		}

		this.messageSubject.next({ type: "contextualMessages", data: data });
	}

	private getPendingWidgets(widgets: IContextWidget[]): IWidgetHandle[] {
		const widgetHandles: IWidgetHandle[] = [];
		for (const widget of widgets) {
			if (
				widget.type === ContextAppType.Utility ||
				widget.type === ContextAppType.Context
			) {
				const handle = widget.handle;
				if (!this.widgetService.getCachedDefinition(handle.id)) {
					if (!ArrayUtil.containsByProperty(widgetHandles, "id", handle.id)) {
						widgetHandles.push(handle);
					}
				}
			}
		}
		return widgetHandles.length > 0 ? widgetHandles : null;
	}

	private register(
		type: ContextMessageReceiveType | string,
		handler: any,
	): void {
		const client = infor.companyon.client;
		client.registerMessageHandler(type, handler);
	}
}
