import { Component, Input } from "@angular/core";
import { IBadgePopoverInfo } from "../../base/core";

@Component({
	selector: "lm-badges-popover",
	styleUrls: ["./badges-popover.scss"],
	template: `
		<div class="lm-badge-container">
			<div
				*ngFor="let badge of badges"
				soho-tooltip
				[popover]="true"
				[title]="badge.title"
				extraClass="lm-badges-popover"
				[content]="badge.description">
				<svg
					*ngIf="badge.isCustom"
					class="icon"
					aria-hidden="true"
					focusable="false"
					[attr.name]="badge.title | lmAutoId : 'lm-badge'">
					<use [attr.xlink:href]="badge.badgeIcon" />
				</svg>
				<svg
					*ngIf="!badge.isCustom"
					soho-icon
					[icon]="badge.badgeIcon"
					[attr.name]="badge.title | lmAutoId : 'lm-badge'"></svg>
			</div>
		</div>
	`,
})
export class BadgesPopoverComponent {
	@Input() badges: IBadgePopoverInfo[];
}
