import { Component, Input } from "@angular/core";

@Component({
	selector: "lm-memo-area",
	template: `<lm-memos
		[backgroundColor]="backgroundColor"
		[memoDuration]="memoDuration"
		[animate]="animate"
		parentAreaName="topbar"></lm-memos>`,
	styles: [
		`
			:host {
				display: block;
			}
		`,
	],
})
export class MemoAreaComponent {
	@Input() backgroundColor: string;
	@Input() memoDuration: number;
	@Input() animate: boolean;
}
