import { Observable } from "rxjs";
import { IWidget, IWidgetParentContext } from "../base/core";

export interface IContextWidgetHandle {
	id: string;
	pid?: string;
}

export enum ContextAppType {
	Context = 1,
	Utility = 2,
}

export interface IScreen {
	value: string;
	operator: ScreenOperator;
}

export enum ScreenOperator {
	Equals = 51,
	StartsWith = 52,
	EndsWith = 53,
	Contains = 54,
}

export interface IContextWidgetSetting {
	name: string;
	value: string | any;
}

export interface IContextWidget {
	uniqueId?: string;
	type: ContextAppType;
	screens: IScreen[];
	messages?: string[];
	handle?: IContextWidgetHandle;
	settings?: IContextWidgetSetting[];
	name?: string;
	description?: string;
	url?: string;
	isExternal?: boolean;
}

export interface IMingleMessage<T> {
	type: string;
	data: T;
}

export interface IWindowNameData {
	name: string;
}

export type ToggleState = "collapse" | "expand";

export interface IContextSiteData {
	siteId: string;
	logicalId: string;
	state?: ToggleState;
}

export interface IToggleContextZoneData {
	state: ToggleState;
}

export type InforBusinessContext = "inforBusinessContext";
export type HPContextAppInitCompleteType = "hpContextAppInitComplete";
export type EnableContextZoneType = "enableContextZone";
export type DisableContextZoneType = "disableContextZone";
export type ResetContextZoneType = "resetContextZone";
export type LoadContextZoneType = "loadContextZone";
export type ShowContextZoneType = "showContextZone";
export type HideContextZoneType = "hideContextZone";
export type ToggleContextZoneType = "toggleContextZone";
export type ContextualMessagesType = "contextualMessages";

export class ContextConstants {
	static readonly ContextViewerWidgetId = "infor.mingle.contextviewer";
	static readonly ContextViewerName = "Context Viewer";
	static readonly ContextViewerUrl = "/contextapps/contextreceiver";
}

export interface ILoadContextZoneData extends IContextSiteData {
	widgets: IContextWidget[];
}

export interface ILoadContextZoneMessage
	extends IMingleMessage<ILoadContextZoneData> {
	type: LoadContextZoneType;
	data: ILoadContextZoneData;
}

export interface IShowContextZoneMessage
	extends IMingleMessage<IContextSiteData> {
	type: ShowContextZoneType;
	data: IContextSiteData;
}

export interface IHideContextZoneMessage
	extends IMingleMessage<IContextSiteData> {
	type: HideContextZoneType;
	data: IContextSiteData;
}

export interface IContextualMessagesData
	extends IMingleMessage<IMingleMessage<any>[]> {
	iframeListeners: string[];
	logicalId: string;
	contextId: string;
}

export interface IContextualMessages
	extends IMingleMessage<IContextualMessagesData> {
	type: ContextualMessagesType;
}

/**
 * Context app messages that can be received from Ming.le.
 */
export type ContextMessageReceiveType =
	| LoadContextZoneType
	| ShowContextZoneType
	| HideContextZoneType
	| ToggleContextZoneType
	| ResetContextZoneType
	| ContextualMessagesType;

/**
 * Context app messages that can be sent to Ming.le.
 */
export type ContextMessageSendType =
	| HPContextAppInitCompleteType
	| EnableContextZoneType
	| DisableContextZoneType;

// export interface IContextSiteItem {
