// 	view: ViewContainerRef;
// 	isActive: boolean;
// }

export interface IContextSiteState {
	visibility$: Observable<boolean>;
	isVisible: boolean;
	isCurrent: boolean;
	site: IContextSiteData;
	widgets: IContextWidget[];
}

export interface IContextHostComponent {
	createWidget(): void;
}

export interface IContextWidgetItem {
	widget: IContextWidget;
	isHidden?: boolean;
	isInstanceHidden?: boolean;
	widgetInstance?: IWidget;
	contextHostComponent?: IContextHostComponent;
	widgetParentContext?: IWidgetParentContext;
}
