import { Component, Input } from "@angular/core";
import { IEmptyStateOptions } from "lime";

@Component({
	selector: "lm-widget-empty-state",
	template: `
		<div
			soho-emptymessage
			color="azure"
			[icon]="icon"
			[title]="options.title"
			[info]="options.description"
			[button]="button"
			[attributes]="{ name: 'name', value: 'lm-emptystate' }"></div>
	`,
})
export class WidgetEmptyStateComponent {
	@Input() options: IEmptyStateOptions;

	get icon(): string {
		return "icon-" + this.options.icon;
	}

	get button(): SohoEmptyMessageButtonOptions {
		const button = this.options.button;
		if (button) {
			return {
				text: button.text,
				click: button.click,
				isPrimary: true,
			};
		}
	}
}
