import {
	Component,
	EventEmitter,
	Input,
	OnDestroy,
	OnInit,
	Output,
} from "@angular/core";
import { Observable, Observer } from "rxjs";
import { CoreBase } from "../../base/runtime";
import { LanguageService } from "../../base/service";

@Component({
	selector: "lm-media-capture",
	styleUrls: ["./media-capture.component.scss"],
	templateUrl: "./media-capture.component.html",
})
export class MediaCaptureComponent
	extends CoreBase
	implements OnInit, OnDestroy
{
	@Input() mode: MediaCaptureMode = "picture";

	@Output() data = new EventEmitter<Blob>();

	stream?: MediaStream;
	waitingForMedia = true;
	lang = this.languageService.language;

	private recorder: MediaRecorder;

	constructor(languageService: LanguageService) {
		super("MediaCaptureComponent", null, languageService);
	}

	private get isVideoMode(): boolean {
		return this.mode === "video";
	}

	private get isPictureMode(): boolean {
		return this.mode === "picture";
	}

	private get isAudioMode(): boolean {
		return this.mode === "audio";
	}

	get showStopRecordingButton(): boolean {
		return (
			!this.isPictureMode &&
			this.recorder &&
			this.recorder.state === "recording"
		);
	}

	get showStartRecordingButton(): boolean {
		return !this.isPictureMode && !this.showStopRecordingButton;
	}

	get showCameraButton(): boolean {
		return this.isPictureMode;
	}

	async ngOnInit() {
		try {
			this.assertGetUserMediaSupported();
			this.stream = await navigator.mediaDevices.getUserMedia({
				audio: this.isVideoMode || this.isAudioMode,
				video: this.isVideoMode || this.isPictureMode,
			});
		} catch (error) {
			this.data.error(error);
		}
	}

	ngOnDestroy() {
		if (this.stream) {
			this.stream.getTracks().forEach((track) => track.stop());
		}
	}

	snapPicture(video: HTMLVideoElement) {
		const canvas = document.createElement("canvas");
		const context = canvas.getContext("2d");
		canvas.width = video.videoWidth;
		canvas.height = video.videoHeight;
		context.drawImage(video, 0, 0, video.videoWidth, video.videoHeight);

		toBlob(canvas, (blob) => {
			this.data.next(blob);
		});
	}

	startRecording() {
		try {
			this.assertMediaRecorderSupported();
			this.recorder = new MediaRecorder(this.stream);
			this.record(this.recorder).subscribe(this.data);
		} catch (error) {
			this.data.error(error);
		}
	}

	stopRecording() {
		this.recorder.stop();
	}

	mediaReady() {
		this.waitingForMedia = false;
	}

	private record(recorder: MediaRecorder): Observable<Blob> {
		return Observable.create((observer: Observer<Blob>) => {
			const chunks: Blob[] = [];

			const onData = (evt: MediaRecorderDataAvailableEvent) =>
				chunks.push(evt.data);
			recorder.addEventListener("dataavailable", onData);

			const onStop = () => {
				const blob = new Blob(chunks);
				observer.next(blob);
				observer.complete();
			};
			recorder.addEventListener("stop", onStop);

			const onError = (evt: MediaRecorderErrorEvent) =>
				observer.error(new Error(evt.name));
			recorder.addEventListener("error", onError);

			recorder.start();

			return () => {
				recorder.removeEventListener("dataavailable", onData);
				recorder.removeEventListener("stop", onStop);
				recorder.removeEventListener("error", onError);
			};
		});
	}

	private assertGetUserMediaSupported() {
		const gum =
			navigator &&
			navigator.mediaDevices &&
			navigator.mediaDevices.getUserMedia;
		if (!gum) {
			const error = new Error("GetUserMedia is not available");
			throw error;
		}
	}

	private assertMediaRecorderSupported() {
		if (!(window as any).MediaRecorder) {
			const error = new Error("MediaRecorder is not available");
			throw error;
		}
	}
}

/**
 * HtmlCanvasElement.toBlob with polyfill for Edge support
 * https://developer.mozilla.org/en-US/docs/Web/API/HTMLCanvasElement/toBlob#Polyfill
 */
function toBlob(canvas: HTMLCanvasElement, callback: BlobCallback) {
	if (canvas.toBlob) {
		return canvas.toBlob(callback);
	}
	const dataUrl = canvas.toDataURL().split(",")[1];
	const binString = atob(dataUrl);
	const arr = new Uint8Array(binString.length);
	for (let i = 0; i < binString.length; i++) {
		arr[i] = binString.charCodeAt(i);
	}
	callback(new Blob([arr], { type: "image/png" }));
}

export type MediaCaptureMode = "picture" | "video" | "audio";

// TypeScript does not include MediaRecorder yet. Remove this section once it has been added to lib.d.ts
// https://stackoverflow.com/a/51454066
// BEGIN MediaRecorder declaration

interface MediaRecorderErrorEvent extends Event {
	name: string;
}

interface MediaRecorderDataAvailableEvent extends Event {
	data: Blob;
}

interface MediaRecorderEventMap {
	dataavailable: MediaRecorderDataAvailableEvent;
	error: MediaRecorderErrorEvent;
	pause: Event;
	resume: Event;
	start: Event;
	stop: Event;
	warning: MediaRecorderErrorEvent;
}

declare class MediaRecorder extends EventTarget {
	readonly mimeType: string;
	readonly state: "inactive" | "recording" | "paused";
	readonly stream: MediaStream;
	ignoreMutedMedia: boolean;
	videoBitsPerSecond: number;
	audioBitsPerSecond: number;

	ondataavailable: (event: MediaRecorderDataAvailableEvent) => void;
	onerror: (event: MediaRecorderErrorEvent) => void;
	onpause: () => void;
	onresume: () => void;
	onstart: () => void;
	onstop: () => void;

	constructor(stream: MediaStream);

	start(): void;

	stop(): void;

	resume(): void;

	pause(): void;

	isTypeSupported(type: string): boolean;

	requestData(): void;

	addEventListener<K extends keyof MediaRecorderEventMap>(
		type: K,
		listener: (this: MediaStream, ev: MediaRecorderEventMap[K]) => any,
		options?: boolean | AddEventListenerOptions,
	): void;

	addEventListener(
		type: string,
		listener: EventListenerOrEventListenerObject,
		options?: boolean | AddEventListenerOptions,
	): void;

	removeEventListener<K extends keyof MediaRecorderEventMap>(
		type: K,
		listener: (this: MediaStream, ev: MediaRecorderEventMap[K]) => any,
		options?: boolean | EventListenerOptions,
	): void;

	removeEventListener(
		type: string,
		listener: EventListenerOrEventListenerObject,
		options?: boolean | EventListenerOptions,
	): void;
}

// END MediaRecorder declaration
