import { Injectable } from "@angular/core";
import { ContextService } from "../service";

@Injectable({
	providedIn: "root",
})
export class BrowserStorageService {
	private storagePrefix = "default";

	constructor(contextService: ContextService) {
		contextService.context$.subscribe((context) => {
			this.storagePrefix = context.getUserId();
		});
	}

	setLocalStorageItem(key: string, value: any): void {
		localStorage.setItem(this.getUserKey(key), JSON.stringify(value));
	}

	getLocalStorageItem<T>(key: string): T {
		return JSON.parse(localStorage.getItem(this.getUserKey(key))) as T;
	}

	deleteLocalStorageItem(key: string): void {
		localStorage.removeItem(this.getUserKey(key));
	}

	private getUserKey(key: string): string {
		return `${this.storagePrefix}-${key}`;
	}
}
