import {
	ChangeDetectionStrategy,
	Component,
	EventEmitter,
	Input,
	Output,
	Pipe,
	PipeTransform,
} from "@angular/core";
import { IWidgetSize } from "lime";

@Component({
	selector: "[lm-widget-size-display]",
	templateUrl: "widget-size-display.html",
	styleUrls: ["widget-size-display.scss"],
	changeDetection: ChangeDetectionStrategy.OnPush,
})
export class WidgetSizeDisplayComponent {
	@Input() includeSizeSelector = false;
	@Input() selectionLabel: string;
	@Input() indicatorLabel: string;
	@Input() size: IWidgetSize;

	private _maxSize: IWidgetSize = null;

	@Input() get maxSize(): IWidgetSize {
		return this._maxSize;
	}

	set maxSize(maxSize: IWidgetSize) {
		if (this._maxSize !== maxSize) {
			this._maxSize = maxSize;
			this.updateSizeIndicator();
		}
	}

	@Output() sizeChanged = new EventEmitter<IWidgetSize>();

	sizeIndicator = { rows: [], columns: [] };
	availableSizes: IWidgetSize[] = [
		{ cols: 1, rows: 1 },
		{ cols: 2, rows: 1 },
		{ cols: 3, rows: 1 },
		{ cols: 4, rows: 1 },
		{ cols: 1, rows: 2 },
		{ cols: 2, rows: 2 },
		{ cols: 3, rows: 2 },
		{ cols: 4, rows: 2 },
	];

	ngOnInit() {
		this.size = this.availableSizes.find(
			(item) => item.cols === this.size.cols && item.rows === this.size.rows,
		);
		this.updateSizeIndicator();
	}

	notifySizeChange(size: IWidgetSize) {
		this.sizeChanged.emit(size);
	}

	onSizeChange() {
		this.updateSizeIndicator();
		this.notifySizeChange(this.size);
	}

	updateSizeIndicator() {
		const size = this.size;
		this.sizeIndicator.columns = [];
		this.sizeIndicator.rows = [];

		for (let i = 0; i < size.cols; i++) {
			this.sizeIndicator.columns.push(i);
		}
		for (let y = 0; y < size.rows; y++) {
			this.sizeIndicator.rows.push(y);
		}
	}
}

@Pipe({ name: "enforceMaxSize" })
export class WidgetSizeDisplayPipe implements PipeTransform {
	transform(sizes: IWidgetSize[], maxSize: IWidgetSize): IWidgetSize[] {
		if (!maxSize) {
			return sizes;
		} else {
			return sizes.filter(
				(size) => size.cols <= maxSize.cols && size.rows <= maxSize.rows,
			);
		}
	}
}
