/**
 * Dependencies:
 * runtime
 * core
 * ../../lime
 */
import { HttpClient } from "@angular/common/http";
import { ElementRef, Injectable } from "@angular/core";
import { ArrayUtil, CommonUtil, StringUtil } from "lime";
import { Observable, of } from "rxjs";
import { catchError, map } from "rxjs/operators";
import {
	AccessType,
	IConfigurationData,
	IDevAttributes,
	IOperationResponse,
	IPage,
	IPageContainerData,
	IPageData,
	IWidgetDefinition,
	IWidgetInfo,
	WidgetCategory,
} from "./core";
import { CoreBase } from "./runtime";

/**
 * Represents configuration data for a widget in the development environment.
 */
export class DevConfigurationData {
	/**
	 * Gets or sets the widget ID.
	 */
	widgetId: string;

	devPath: string;

	sharedPath: string;

	/**
	 * Gets or sets the path to an optional JSON file with widget settings.
	 * When this settings file is used the settings in local storage will be ignored.
	 */
	settingsPath: string;

	/**
	 * Gets or sets widget settings loaded from a JSON settings file.
	 * If this property is set it should override settings from local storage.
	 */
	settings: any;

	/**
	 * Gets or sets the name of the settings property.
	 *
	 */
	propSettings = "settings";

	/**
	 * Gets or sets the widget definition.
	 */
	widgetDefinition: IWidgetDefinition;

	sharedDefinition: IWidgetDefinition;

	/**
	 * Gets or sets the name of the widget definition property.
	 */
	propWidgetDefinition = "widgetDefinition";

	propSharedDefinition = "sharedDefinition";

	customDefinitionPath: string;

	customDefinition: IWidgetDefinition;

	propCustomDefinition = "customDefinition";
}

export class DevConfigurationInfo {
	items: DevConfigurationData[];

	/**
	 * Gets or sets the path to an optional JSON file with configuration data.
	 */
	configurationPath: string;

	/**
	 * Gets or sets configuration data from the configuration JSON file.
	 * Since the configuration file is optional this property might not be set.
	 */
	configuration: IConfigurationData;

	/**
	 * Gets or sets the language key to use for translations.
	 */
	languageKey: string;

	/**
	 * Gets or sets the name of the configuration property.
	 */
	propConfiguration = "configuration";

	static fromElement(element: ElementRef): DevConfigurationInfo {
		const attributes = element.nativeElement.attributes;
		const clean = (value: string, find: string) => {
			return StringUtil.replaceAll(value, find, "");
		};
		const getName = (name: string) => {
			name = clean(name, "\\[");
			name = clean(name, "\\]");
			name = clean(name, "-");
			return name.toLowerCase();
		};
		const getValue = (value: string) => {
			value = clean(value, "'");
			value = clean(value, '"');
			return value;
		};

		const devAttributes = {} as IDevAttributes;
		for (const attribute of attributes) {
			const name = getName(attribute.name);
			const value = getValue(attribute.value);
			if (name === "devconfiguration") {
				devAttributes.devConfiguration = value;
			} else if (name === "devcustom") {
				devAttributes.devCustom = value;
			} else if (name === "ismobiledev") {
				devAttributes.isMobileDev = value === "true";
			} else if (name === "devsettings") {
				devAttributes.devSettings = value;
			} else if (name === "devwidget") {
				devAttributes.devWidget = value;
			} else if (name === "devwidgetshared") {
				devAttributes.devWidgetShared = value;
			} else if (name === "devlanguage") {
				devAttributes.devLanguage = value;
			}
		}
		return DevConfigurationInfo.fromAttributes(devAttributes);
	}

	static fromAttributes(attributes: IDevAttributes): DevConfigurationInfo {
		const split = (value: string): string[] => {
			return value ? value.split(";") : null;
		};

		const ids = split(attributes.devWidget);
		if (!ids || ids.length === 0) {
			return null;
		}

		const sharedPaths = split(attributes.devWidgetShared);

		const info = new DevConfigurationInfo();
		info.configurationPath = attributes.devConfiguration;
		info.languageKey = attributes.devLanguage;
		info.items = [];

		const settings = split(attributes.devSettings);
		const customs = split(attributes.devCustom);

		const getIndex = (items: string[], index: number): string => {
			return items && items.length >= index ? items[index].trim() : null;
		};

		for (let i = 0; i < ids.length; i++) {
			const devData = new DevConfigurationData();
			devData.widgetId = ids[i];
			devData.sharedPath = getIndex(sharedPaths, i);
			devData.settingsPath = getIndex(settings, i);
			devData.customDefinitionPath = getIndex(customs, i);
			info.items.push(devData);
		}

		return info;
	}

	getItem(widgetId: string): DevConfigurationData {
		return ArrayUtil.itemByPredicate(this.items, (item) => {
			return item.widgetDefinition.widgetId === widgetId;
		});
	}
}

export interface IDevConfiguration {
	devInfo: DevConfigurationInfo;
	id?: string;
	container?: IPageContainerData;
	initPage(page: IPageData): void;
	load(id: string): IPageContainerData;
	save(page: IPageData);
	clear();
}

class DevConfiguration extends CoreBase implements IDevConfiguration {
	id: string;
	container: IPageContainerData;

	private isPersistent = true;
	private storagePrefix = "lmDevContainer-";

	constructor(readonly devInfo: DevConfigurationInfo) {
		super("DevConfiguration");
	}

	initPage(page: IPageData): void {
		if (!page.id) {
			page.id = CommonUtil.random();
		}
		page.changedBy = page.createdBy = "developer";
		page.changeDate = "2019-01-01T12:00:00.000Z";
		page.viewAccess = AccessType.Owner;
	}

	load(id: string): IPageContainerData {
		this.id = id;
		let container = null as IPageContainerData;
		if (this.isPersistent) {
			try {
				const data = localStorage.getItem(this.getKey());
				if (data) {
					container = JSON.parse(decodeURI(data)) as IPageContainerData;
					if (container && container.pages && container.pages.length === 0) {
						// Don't start with an empty test container even if it was last saved as empty. Load a page with the widget.
						container.pages = null;
					}
					this.logDebug("Loaded container in dev mode for widget " + id);
				}
			} catch (e) {
				container = null as IPageContainerData;
			}
		} else {
			// Clear the stored container
			this.clear();
		}

		if (!container || !container.pages || !container.pages[0].data) {
			container = {
				userId: "TEST",
				version: "dev",
				pages: [
					{
						data: {
							id: CommonUtil.random().toLowerCase(),
							title: "Test Page",
							color: 0,
						},
					},
				],
			};
		}

		this.container = container;
		return container;
	}

	clear() {
		this.container = null as IPageContainerData;
		this.save(null as IPageData);
		this.logDebug("Cleared local dev container");
	}

	save(pageData: IPageData) {
		try {
			const key = this.getKey();
			if (this.container) {
				if (pageData) {
					this.updatePageData(pageData);
				}
				const containerString = JSON.stringify(this.container);
				const content = encodeURI(containerString);
				localStorage.setItem(key, content);
				this.logDebug("Saved local dev container");
			} else {
				localStorage.removeItem(key);
			}
		} catch (e) {
			this.logError("Failed to save local dev container", e);
		}
	}

	private getKey() {
		return this.storagePrefix + this.id;
	}

	private updatePageData(pageData: IPageData) {
		const pages = this.container.pages;
		const pageLength = pages.length;
		for (let i = 0; i < pageLength; i++) {
			const existingPage: IPage = pages[i];
			if (pageData.id === existingPage.data.id) {
				existingPage.data = pageData;
			}
		}
		this.logDebug("Updated page data in dev container");
	}
}

@Injectable({
	providedIn: "root",
})
export class DevService extends CoreBase {
	isDev: boolean;
	configuration: IDevConfiguration;

	constructor(private http: HttpClient) {
		super("DevService");
	}

	init(element: ElementRef): boolean {
		try {
			const devInfo = DevConfigurationInfo.fromElement(element);
			if (devInfo) {
				this.logInfo("Development mode detected");
				this.configuration = new DevConfiguration(devInfo);
				this.isDev = true;
				this.initLocale();
			}
		} catch (ex) {
			this.logError("Failed to initialize", ex);
		}
		return this.isDev;
	}

	getId(): string {
		return this.configuration.id;
	}

	getInfo(): DevConfigurationInfo {
		return this.configuration.devInfo;
	}

	getConfiguration(): IDevConfiguration {
		return this.configuration;
	}

	getLanguages(): Observable<IOperationResponse> {
		return this.http.get("scripts/lime/resources/languagekeys.json").pipe(
			catchError(() => of({ "en-US": "English", "sv-SE": "Swedish" })),
			map((response) => {
				return {
					content: response,
				};
			}),
		) as any as Observable<IOperationResponse>;
	}

	getLanguageKey(): string {
		return this.getInfo().languageKey || infor?.lime?.language || "en-US";
	}

	getWidgetItem(widgetId: string): DevConfigurationData {
		return this.configuration.devInfo.getItem(widgetId);
	}

	getWidgetItems(): DevConfigurationData[] {
		return this.configuration.devInfo.items;
	}

	getWidgetInfos(): IWidgetInfo[] {
		return this.getWidgetItems().map((item) => {
			const definition = item.widgetDefinition;
			return {
				title: definition.localization
					? definition.localization.widgetTitle
					: definition.title,
				widgetId: definition.widgetId,
				standardWidgetId: definition.standardWidgetId,
				category: WidgetCategory.getCategory(definition.category),
			};
		});
	}

	savePage(pageData: IPageData): void {
		this.logDebug("Saved page in dev mode");
		this.configuration.save(pageData);
	}

	private initLocale() {
		const devLocale = this.getLanguageKey();
		this.logDebug(`Setting development locale to ${devLocale}`);
		Soho.Locale.culturesPath = "scripts/xi/cultures/";
		Soho.Locale.set(devLocale)
			.then(() => this.logInfo(`Development locale was set to ${devLocale}`))
			.catch((err) => this.logError("Failed to set development locale", err));
	}
}
