import { Injectable, ViewContainerRef } from "@angular/core";
import { SohoContextualActionPanelService } from "@infor/sohoxi-angular";
import { fromEvent, Observable, Observer, Subject } from "rxjs";
import { map, switchMap, take, takeUntil } from "rxjs/operators";
import {
	MediaCaptureComponent,
	MediaCaptureMode,
} from "../components/device/media-capture.component";
import {
	MediaSourceSelectComponent,
	MediaSourceSelection,
} from "../components/device/media-source-select.component";
import { CoreBase } from "./runtime";
import { LanguageService } from "./service";

@Injectable({
	providedIn: "root",
})
export class MediaService extends CoreBase {
	private lang = this.languageService.language;
	constructor(
		private capService: SohoContextualActionPanelService,
		languageService: LanguageService,
	) {
		super("MediaService", null, languageService);
	}

	takePicture(viewRef: ViewContainerRef): Observable<Blob> {
		return this.openMediaCapture("picture", this.lang.camera, viewRef);
	}

	recordVideo(viewRef: ViewContainerRef): Observable<Blob> {
		return this.openMediaCapture("video", this.lang.videoRecorder, viewRef);
	}

	recordAudio(viewRef: ViewContainerRef): Observable<Blob> {
		return this.openMediaCapture("audio", this.lang.audioRecorder, viewRef);
	}

	importPicture(): Observable<Blob> {
		return this.openMediaImport([".jpg", ".jpeg", ".png", ".gif"]);
	}

	importVideo(): Observable<Blob> {
		return this.openMediaImport([".mp4", ".webm", ".mov"]);
	}

	getPicture(viewRef: ViewContainerRef): Observable<Blob> {
		return this.openSourceSelection(viewRef).pipe(
			switchMap((selection) =>
				selection === "device"
					? this.takePicture(viewRef)
					: this.importPicture(),
			),
		);
	}

	getVideo(viewRef: ViewContainerRef): Observable<Blob> {
		return this.openSourceSelection(viewRef).pipe(
			switchMap((selection) =>
				selection === "device" ? this.recordVideo(viewRef) : this.importVideo(),
			),
		);
	}

	base64Encode(blob: Blob): Observable<string> {
		return Observable.create((observer: Observer<string>) => {
			const reader = new FileReader();
			reader.addEventListener("loadend", () => {
				observer.next(btoa(reader.result.toString()));
				observer.complete();
			});
			reader.addEventListener("error", () => {
				observer.error(reader.error);
			});
			reader.readAsBinaryString(blob);
		});
	}

	private openSourceSelection(
		viewRef: ViewContainerRef,
	): Observable<MediaSourceSelection> {
		return Observable.create((observer: Observer<MediaSourceSelection>) => {
			const capClosed = new Subject<void>();
			const cap = this.capService.contextualactionpanel(
				MediaSourceSelectComponent,
				viewRef,
			);
			cap.title(this.lang.selectSource);
			cap.apply((component) => {
				component.selection
					.pipe(takeUntil(capClosed), take(1))
					.subscribe(observer);
			});
			cap.closed(() => capClosed.next());
			cap.buttons([
				{
					click: () => cap.close(),
					cssClass: "btn",
					icon: "#icon-close",
					text: this.lang.close,
				},
			]);
			cap.open();

			return () => cap.close();
		});
	}

	private openMediaCapture(
		mode: MediaCaptureMode,
		title: string,
		viewRef: ViewContainerRef,
	): Observable<Blob> {
		return Observable.create((observer: Observer<Blob>) => {
			const capClosed = new Subject<void>();
			const cap = this.capService.contextualactionpanel(
				MediaCaptureComponent,
				viewRef,
			);
			cap.title(title);
			cap.apply((cameraComponent) => {
				cameraComponent.mode = mode;
				cameraComponent.data
					.pipe(takeUntil(capClosed), take(1))
					.subscribe(observer);
			});
			cap.closed(() => capClosed.next());
			cap.buttons([
				{
					click: () => cap.close(),
					cssClass: "btn",
					icon: "#icon-close",
					text: this.lang.close,
				},
			]);
			cap.open();

			return () => cap.close();
		});
	}

	private openMediaImport(extensions: string[]): Observable<Blob> {
		return Observable.create((observer: Observer<Blob>) => {
			const fileInput = document.createElement("input");
			fileInput.type = "file";
			fileInput.accept = extensions.join(",");
			fromEvent(fileInput, "change")
				.pipe(map(() => fileInput.files[0]))
				.subscribe(observer);
			fileInput.click();
		});
	}
}
