import {
	Component,
	EventEmitter,
	HostBinding,
	Input,
	Output,
} from "@angular/core";
import { IWidgetMessage, WidgetMessageType } from "lime";
import { CoreBase, LanguageService } from "lime/core";

@Component({
	selector: "widget-message",
	templateUrl: "./widget-message.component.html",
	styleUrls: ["./widget-message.component.scss"],
})
export class WidgetMessageComponent extends CoreBase {
	@Input() message: IWidgetMessage;
	@Input() automationIdIdentifier: string;
	@Output() dismiss = new EventEmitter<void>();
	closeLabel: string;

	constructor(languageService: LanguageService) {
		super("WidgetMessageComponent");
		this.closeLabel = languageService.getLanguage().close;
	}

	@HostBinding("class") get notificationClasses() {
		return `notification ${this.notificationType}`;
	}

	get notificationType(): SohoNotificationType {
		switch (this.message.type) {
			case WidgetMessageType.Info:
				return "info";
			case WidgetMessageType.Alert:
				return "alert";
			case WidgetMessageType.Error:
				return "error";
			case WidgetMessageType.Success:
				return "success";
		}
	}

	onLinkClick(): void {
		try {
			this.message.onLinkClick();
		} catch (ex) {
			this.logError("Failed to call IWidgetMessage.onLinkClick", ex);
		}
	}
}
