export interface IValidationInfo<T> {
	/**
	 * The max number of a characters in the value.
	 */
	max: number;

	/**
	 * Indicates if the value is optional.
	 * The default value is false.
	 */
	optional?: boolean;

	/**
	 * Indicates if the value should be trimmed.
	 * The default value is true.
	 */
	trim?: boolean;

	/**
	 * The name of the property.
	 */
	name?: string;

	// TODO Consider adding getter/setter functions as type safe alternative to name
}

export abstract class ValidatorBase<T> {
	protected isValid = true;

	constructor(protected validations?: IValidationInfo<T>[]) {}

	validate(item: T): boolean {
		this.onValidate(item);
		return this.isValid;
	}

	onValidate(item: T): void {
		const validations = this.validations;
		if (validations) {
			for (const validation of validations) {
				this.validateProperty(item, validation);
			}
		}
	}

	protected validateProperty(item: T, info: IValidationInfo<T>): void {
		let value: string;
		const name = info.name;
		if (name) {
			value = item[name];
		}

		if (info.trim !== false) {
			value = this.trim(value);
			if (name) {
				item[name] = value;
			}
		}

		const max = info.max;
		if (info.optional) {
			this.optional(value, max);
		} else {
			this.mandatory(value, max);
		}
	}

	protected trim(value: string): string {
		return value ? value.trim() : value;
	}

	protected max(value: string, maxLength: number): boolean {
		return this.valid(value ? value.length <= maxLength : true);
	}

	protected min(value: string, minLength: number): boolean {
		return this.valid(value ? value.length >= minLength : false);
	}

	protected mandatory(value: string, maxLength: number): boolean {
		return this.valid(this.min(value, 1) && this.max(value, maxLength));
	}

	protected optional(value: string, maxLength: number): boolean {
		if (!value) {
			return true;
		}
		return this.valid(this.max(value, maxLength));
	}

	protected trimMandatory(value: string, maxLength: number): string {
		value = this.trim(value);
		this.mandatory(value, maxLength);
		return value;
	}

	protected trimOptional(value: string, maxLength: number): string {
		value = this.trim(value);
		this.optional(value, maxLength);
		return value;
	}

	private valid(value: boolean): boolean {
		if (!value) {
			this.isValid = false;
		}
		return value;
	}
}

/**
 * Validates and limits values without throwing.
 */
export class Limiter {
	public static int(value: number, min: number, max: number): number {
		if (value != null) {
			if (value < min) {
				return min;
			}
			if (value > max) {
				return max;
			}
			return value;
		}
		return min;
	}
}

/**
 * Validates values and throws on errors.
 */
export class Validator {
	public static int(value: number, minValue: number, maxValue: number): void {
		if (!Number.isInteger(value)) {
			throw new TypeError(`${value} is not an integer`);
		}
		if (value < minValue || value > maxValue) {
			throw new TypeError(
				`${value} is not in the range [${minValue},${maxValue}]`,
			);
		}
	}
}
