import { Component, Input } from "@angular/core";

/**
 * Unavailable Entity Component
 *
 * Shows an icon and a message telling the user that a widget or page is either restricted or broken.
 */
@Component({
	selector: "lm-unavailable-entity",
	styleUrls: ["./unavailable-entity.scss"],
	template: `
		<div class="unavailable-entity" [class.banner-entity]="isBanner">
			<ng-container *ngIf="isUserPreview; else brokenEntity">
				<svg soho-icon icon="info"></svg>
			</ng-container>
			<ng-template #brokenEntity>
				<svg *ngIf="isPermissionError" soho-icon icon="cancel"></svg>
				<svg
					*ngIf="!isPermissionError"
					class="icon"
					aria-hidden="true"
					focusable="false">
					<use xlink:href="#lime-icon-broken-widget" />
				</svg>
			</ng-template>
			<p style="padding: 0 25px 0 25px;">{{ message }}</p>
		</div>
	`,
})
export class UnavailableEntityComponent {
	@Input() message: string;
	@Input() isBanner: boolean;
	@Input() isPermissionError: boolean;
	@Input() isUserPreview: boolean;

	ngOnInit(): void {
		if (this.isUserPreview) {
			this.message =
				"This content cannot be displayed when previewing as another user.";
		}
	}
}
