import { CommonUtil, Log, StringUtil } from "lime";
import {
	ClientMode,
	Constants,
	IOperationRequest,
	IPageContainerData,
	IStringMap,
	IWidgetHandle,
	IWidgetLayout,
	OperationResponse,
} from "../base/core";
import { HttpUtil } from "../base/runtime";
import { IHomepageSettings } from "../page/core";

export interface IContainerOptions {
	/**
	 * Indicates the client mode.
	 * The parameter is optional for standard mode but mandatory at least for the legacy context app mode.
	 */
	mode?: ClientMode;

	/**
	 * Indicates if pages should be loaded by the server.
	 * The default value is true.
	 */
	pages?: boolean;

	/**
	 * Indicates if settings should be loaded by the server.
	 * The default value is true.
	 */
	settings?: boolean;

	/**
	 * Optional array of widget handles for widget definitions that should be loaded by the server.
	 */
	widgetHandles?: IWidgetHandle[];

	/**
	 * Widget ID property for the legacy context app mode for a single widget.
	 */
	widgetId?: string;
}

export interface IPageContainerResponse extends OperationResponse {
	content: IPageContainerData;
}

export interface IPageContainerRequest extends IOperationRequest {
	/**
	 * Optional options that controls what the server loads in the container.
	 * This property is optional in standard mode but required in all or most other modes.
	 */
	options?: IContainerOptions;

	/**
	 * @deprecated Use options property once the server has been updated.
	 *
	 * Gets or sets an optional widget ID used to load a single widget in the page container.
	 * This parameter should not be used in the normal page container mode.
	 */
	widgetId?: string;
}

export interface IWidgetEditData {
	elementId?: string;
	widgetLayout?: IWidgetLayout;
	allowContainerChange?: boolean;
	homepageSettings?: IHomepageSettings;
}

export class CompanyonRequest {
	/**
	 * Used by InforGO to pass an ID as part of the companyon request.
	 */
	Id: number = null;
	private readonly params: IStringMap;

	constructor(logicalId: string, data: any) {
		if (!data) {
			return;
		}

		if (Log.isDebug()) {
			Log.debug("[CompanyonRequest] " + JSON.stringify(data));
		}

		if (StringUtil.isString(data)) {
			this.logInfo("The companyon request is a string: " + data);

			try {
				const obj = JSON.parse(data);
				this.logInfo(
					"The companyon request was transformed to an object: " + data,
				);
				data = obj;
			} catch (ex) {
				this.logInfo("Failed to parse string to JSON object: " + ex);
			}
		}
		this.resolveId(data);
		this.params = this.parse(logicalId, data);
	}

	isValid(): boolean {
		return !!this.params;
	}

	getParameters(): IStringMap {
		return this.params;
	}

	get(key: string): string {
		return this.params ? this.params[key] : null;
	}

	private resolveId(data: any) {
		const id = data.id;
		if (!CommonUtil.isUndefined(id)) {
			this.Id = id;
			this.logDebug("ID is set to " + id);
		}
	}

	private logInfo(message: string) {
		Log.info("[CompanyonRequest] " + message);
	}

	private logDebug(message: string) {
		if (Log.isDebug()) {
			Log.debug("[CompanyonRequest] " + message);
		}
	}

	private parse(logicalId: string, data: any): any {
		const url = data.applicationDrillback || data.link;
		if (url) {
			const parameters = HttpUtil.parseQuery(url);
			if (logicalId === parameters[Constants.logicalId]) {
				return parameters;
			}
		}
		return null;
	}
}
