import { Component, EventEmitter, Output } from "@angular/core";
import { CoreBase } from "../../base/runtime";
import { LanguageService } from "../../base/service";

@Component({
	templateUrl: "./media-source-select.component.html",
})
export class MediaSourceSelectComponent extends CoreBase {
	@Output() selection = new EventEmitter<MediaSourceSelection>();

	lang = this.languageService.language;

	constructor(languageService: LanguageService) {
		super("MediaSourceSelectComponent", null, languageService);
	}

	deviceClicked() {
		this.selection.emit("device");
	}

	fileClicked() {
		this.selection.emit("file");
	}
}

export type MediaSourceSelection = "device" | "file";
