import { Injectable, ViewContainerRef } from "@angular/core";
import {
	SohoAboutService,
	SohoModalDialogService,
} from "@infor/sohoxi-angular";
import { HtmlUtil } from "lime";
import { ContainerService } from "../base/container";
import { IPageContainer, IServerSettings, Product } from "../base/core";
import { LanguageService, LazyTypeService } from "../base/service";
import { ContextService } from "../service";

@Injectable({
	providedIn: "root",
})
export class AboutService {
	private lang: ILanguageLime;
	private settings?: IServerSettings;
	private pageContainer?: IPageContainer;
	private isDialogOpen: boolean;

	constructor(
		languageService: LanguageService,
		private sohoAboutService: SohoAboutService,
		private sohoModalDialogService: SohoModalDialogService,
		private lazyTypeService: LazyTypeService,
		private contextService: ContextService,
		private containerService: ContainerService,
	) {
		this.lang = languageService.getLanguage();
		this.contextService.context$.subscribe((context) => {
			this.settings = context.settings;
		});
		this.containerService.container$.subscribe((container) => {
			this.pageContainer = container;
		});
	}

	showAboutDialog(view: ViewContainerRef) {
		const name = Product.productName;
		const settings = this.settings;
		const adminTemplate = settings ? this.getAdminTemplate(settings) : "";
		const container = this.pageContainer;
		const version =
			container && container.data ? container.data.displayVersion : "";
		const content =
			'<div class="lm-padding-md-l"><button class="hyperlink e2e-showUserSettings" type="button" id="lmAboutPageLink">' +
			this.lang.viewUserPermissions +
			"</button></div>" +
			adminTemplate;
		this.sohoAboutService
			.about()
			.appName(name)
			.productName(name)
			.version(version)
			.content(content)
			.attributes({ name: "id", value: "lm-about" })
			.open();

		// JQuery "hack" for hyperlink click
		$("#lmAboutPageLink").click(() => {
			this.showUserSettings(view);
		});
	}

	private getAdminTemplate(settings: IServerSettings): string {
		let template = "";
		let admin = HtmlUtil.escapeStringForHtml(settings.getAdminContactInfo());
		if (admin && admin.length > 0) {
			admin = admin.replace(/\n/g, "<br>");
		}
		const adminEmail = HtmlUtil.escapeStringForHtml(settings.getAdminEmail());
		const emailTemplate = adminEmail
			? ' <a class="hyperlink" id="lm-abt-email" href="mailto:' +
			  adminEmail +
			  '" target="_top">' +
			  adminEmail +
			  "</a>"
			: "";
		if (admin) {
			template = '<p id="lm-abt-contact">' + admin + emailTemplate + "</p>";
		} else if (adminEmail) {
			template = "<p>" + emailTemplate + "</p>";
		}
		return template;
	}

	/**
	 * Shows the user settings that applies to the current user in a read-only dialog.
	 */
	private showUserSettings(view: ViewContainerRef): void {
		if (this.isDialogOpen) {
			return;
		}
		this.isDialogOpen = true;

		this.lazyTypeService
			.loadLazyModule()
			.then(({ PageUserSettingsComponent }) => {
				const dialog = this.sohoModalDialogService
					.modal(PageUserSettingsComponent, view)
					.id("lm-abt-usr-set-mdl")
					.title(this.lang.userPermissions)
					.afterClose(() => {
						this.isDialogOpen = false;
					});
				dialog
					.apply((component: any) => {
						component.dialog = dialog;
					})
					.open();
			});
	}
}
