import {
	Component,
	ElementRef,
	EventEmitter,
	Input,
	Output,
} from "@angular/core";
import {
	HtmlParser,
	IMarkdownSyntaxSupportOptions,
	MarkdownSyntaxSupport,
} from "./markdown";

@Component({
	selector: "lm-markdown-editor",
	templateUrl: "./markdown-editor.component.html",
	styleUrls: ["./markdown-editor.component.scss"],
})
export class MarkdownEditorComponent {
	@Input() toolbar: boolean;
	@Input() preview: boolean;
	@Input() help: boolean;
	@Input() model: string;
	@Input() maxLength = 1000;
	@Input() support: IMarkdownSyntaxSupportOptions = MarkdownSyntaxSupport.All;
	@Input() showCharacterCount = false;
	@Output() modelChange = new EventEmitter<string>();

	editing = true;

	constructor(private element: ElementRef<HTMLElement>) {}

	ngAfterViewInit() {
		this.focusTextarea();
	}

	onToolbarSelection(action: string) {
		switch (action) {
			case "addHeading":
				this.addHeading();
				break;
			case "addSubheading":
				this.addSubheading();
				break;
			case "addBold":
				this.addBold();
				break;
			case "addItalic":
				this.addItalic();
				break;
			case "addUnderline":
				this.addUnderline();
				break;
			case "addStrikethrough":
				this.addStrikethrough();
				break;
			case "addQuote":
				this.addQuote();
				break;
			case "addNumberList":
				this.addNumberList();
				break;
			case "addBulletList":
				this.addBulletList();
				break;
			case "addLink":
				this.addLink();
				break;
			case "addImage":
				this.addImage();
				break;
			case "addTable":
				this.addTable();
				break;
			case "importHtml":
				this.importHtml();
				break;
			case "startPreview":
				this.startPreview();
				break;
			case "stopPreview":
				this.stopPreview();
				break;
		}
	}

	startPreview() {
		this.editing = false;
	}

	stopPreview() {
		this.editing = true;
	}

	addHeading() {
		this.insertLine("# {text}");
	}

	addSubheading() {
		this.insertLine("## {text}");
	}

	addBold() {
		this.insertText("**{text}**");
	}

	addItalic() {
		this.insertText("*{text}*");
	}

	addUnderline() {
		this.insertText("<u>{text}</u>");
	}

	addStrikethrough() {
		this.insertText("~{text}~");
	}

	addQuote() {
		this.insertLine("> {text}");
	}

	addLink() {
		this.insertText("[{text}](https://example.com)");
	}

	addImage() {
		this.insertText("![{text}](https://picsum.photos/150)");
	}

	addBulletList() {
		this.insertLine("- {text}");
	}

	addNumberList() {
		this.insertLine("1. {text}");
	}

	addTable() {
		this.insertLine(
			"| Header1  | Header2  | Header3  |\n| -------- | -------- | -------- |\n| column 1 | column 2 | column 3 |\n",
		);
	}

	importHtml() {
		const htmlParser = new HtmlParser();
		const selection = this.getSelection();
		htmlParser.parse(selection.selected).subscribe((result) => {
			this.modelChange.emit(selection.before + result + selection.after);
		});
	}

	private insertLine(text: string) {
		this.insertText(text, true);
	}

	private insertText(text: string, newLine?: boolean) {
		const selection = this.getSelection();
		const optionalNewline =
			!selection.before.endsWith("\n") &&
			selection.before.length !== 0 &&
			newLine
				? "\n"
				: "";
		const insertedText = text.replace("{text}", selection.selected);
		const updatedText =
			selection.before + optionalNewline + insertedText + selection.after;
		if (updatedText.length <= this.maxLength) {
			this.modelChange.emit(updatedText);
			this.focusTextarea();
		}
	}

	private getSelection(): { before: string; selected: string; after: string } {
		const textarea = this.textarea();
		const start = textarea.selectionStart;
		const end = textarea.selectionEnd;

		const before = this.model.slice(0, start);
		const selected = this.model.slice(start, end);
		const after = this.model.slice(end);

		return { before, selected, after };
	}

	private focusTextarea() {
		this.textarea().select();
	}

	private textarea() {
		return this.element.nativeElement.querySelector("textarea");
	}
}
