import {
	Component,
	HostBinding,
	Input,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import { IWidgetSettingMetadata } from "lime";
import { CoreBase, IContextWidgetItem } from "lime/core";
import { Subscription } from "rxjs";
import {
	IPublishedWidgetItem,
	IStringToAnyMap,
	IWidget,
	IWidgetData,
	IWidgetDefinition,
} from "../../base/core";
import { CoreUtil } from "../../base/runtime";
import { IContextWidgetSetting } from "../../context-app/core";
import { WidgetParentContext } from "../../context-app/runtime";
import { ContextAppService } from "../../context-app/service";
import { WidgetFactory } from "../../widget/runtime";
import { WidgetService } from "../../widget/service";
import { WidgetContainerComponent } from "../widget-container/widget-container";

/**
 * Context app host component.
 *
 * The component can host a single widget instance.
 */
@Component({
	selector: "lm-context-host",
	templateUrl: "./context-host.html",
	styles: [
		`
			:host {
				display: block;
				padding: 5px 5px 0px 5px;
			}
		`,
	],
})
export class ContextHostComponent extends CoreBase implements OnInit {
	@ViewChild("view", { read: ViewContainerRef, static: true })
	view: ViewContainerRef;
	@Input() widgetItem: IContextWidgetItem;
	@Input() @HostBinding("class.lm-padding-sm-b") isLast = false;
	@HostBinding("class.lm-display-none") get isHidden(): boolean {
		return this.widgetItem && this.widgetItem.isHidden;
	}

	private widget: IWidget;
	private parentContext: WidgetParentContext;
	private visibilitySubscription: Subscription;

	constructor(
		private readonly contextAppService: ContextAppService,
		private readonly widgetService: WidgetService,
		private readonly widgetFactory: WidgetFactory,
	) {
		super("ContextHostComponent");
	}

	ngOnInit(): void {
		this.logDebug("ngOnInit");

		this.parentContext = this.createParentContext();
		this.widgetItem.widgetParentContext = this.parentContext;
		this.widgetItem.contextHostComponent = this;

		if (this.isCreateOnInit()) {
			this.createWidget();
		}
	}

	ngOnDestroy() {
		this.visibilitySubscription.unsubscribe();
	}

	get widgetId() {
		return this.widgetItem.widget.handle.id;
	}

	createWidget(): void {
		// TODO Set last byRef parameter to correct value
		this.widget = this.widgetFactory.createWidget(
			this.parentContext,
			this.createWidgetData(),
			false,
			false,
		);
		this.widgetItem.widgetInstance = this.widget;

		this.addWidget();
	}

	private isCreateOnInit(): boolean {
		// TODO This check currently only handles legacy context apps. To handle external widgets the definition must be checked.
		if (this.widgetItem.widget.isExternal) {
			return true;
		}
		return !this.widgetItem.isHidden;
	}

	private createWidgetData(): IWidgetData {
		const widget = this.widgetItem.widget;
		const settings = this.convertSettings(widget.settings);

		// TODO The name property should probably be removed from settings
		// TODO Verify if there are cases when the name from the message should not override widget title
		const title = widget.name;

		if (widget.url) {
			settings.url = widget.url;
		}

		const data = {
			id: this.widgetId,
			title: title,
			layout: { column: 0, columnSpan: 1, row: 0, rowSpan: 1 },
			settings: settings,
		} as IWidgetData;

		// const custom = this.generateCustom();
		// if (custom) {
		// 	data.custom = custom;
		// }

		return data;
	}

	private generateCustom(): IPublishedWidgetItem {
		const definition = this.widgetService.getCachedDefinition(this.widgetId);
		if (!definition || definition.isPublished) {
			return null;
		}

		const config = definition.contextConfig;
		if (config && config.enableSettings) {
			const userSettings = this.getUserSettings(definition);
			if (userSettings && userSettings.length > 0) {
				return {
					definition: {
						settings: userSettings,
						enableSettings: true,
						enableTitleEdit: false,
					} as IWidgetDefinition,
				} as IPublishedWidgetItem;
			}
		}

		// ,
		// custom: {
		// 	definition: {
		// 		settings: [{
		// 			name: "showIcons",
		// 			isEnabled: true,
		// 			isVisible: true
		// 		}, {
		// 			name: "links",
		// 			isEnabled: false,
		// 			isVisible: false
		// 		}, {
		// 			name: "pinned",
		// 			isEnabled: false,
		// 			isVisible: false
		// 		}, {
		// 			name: "convertLinks",
		// 			isEnabled: false,
		// 			isVisible: false
		// 		}
		// 		],
		// 		enableSettings: true,
		// 		enableTitleEdit: false,
		// 		title: "Context Menu",
		// 		description: "Context Menu test",
		// 		tags: "",
		// 		isCatalogTitle: false,
		// 		defaultSize: "1,1",
		// 		targets: ["mobile", "default"]
		// 	},
		// 	localization: {}
		// }
		return null;
	}

	private getUserSettings(
		definition: IWidgetDefinition,
	): IWidgetSettingMetadata[] {
		const userSettings: IWidgetSettingMetadata[] = [];
		const settings = definition.settings;
		let hasUserSetting = false;
		if (settings) {
			for (const setting of settings) {
				const userSetting = CoreUtil.copy(setting);
				if (setting.isUser) {
					userSetting.isVisible = true;
					userSetting.isEnabled = true;
					hasUserSetting = true;
				} else {
					userSetting.isVisible = false;
					userSetting.isEnabled = false;
				}

				userSettings.push(userSetting);
			}
		}
		return hasUserSetting ? userSettings : null;
	}

	private convertSettings(settings: IContextWidgetSetting[]): IStringToAnyMap {
		if (settings) {
			return settings.reduce((map, setting) => {
				map[setting.name] = setting.value;
				return map;
			}, {});
		}
		return {};
	}

	private createParentContext(): WidgetParentContext {
		return new WidgetParentContext(this.widgetItem.widget.uniqueId);
	}

	private addWidget(): void {
		const ref = this.view.createComponent(WidgetContainerComponent);
		this.widget.containerRef = ref;
		this.initWidgetComponent(ref.instance);

		// TODO Verify if this is needed in some scenarios, currently handled by zone.run at a hihger level
		// https://github.com/angular/angular/issues/17087
		// ref.changeDetectorRef.detectChanges();
	}

	private initWidgetComponent(component: WidgetContainerComponent) {
		// TODO
		// instance.page = this.page;
		component.widget = this.widget;
		const parentContextId = this.widget.parentContext.id;
		const initiallyCollapsed =
			this.contextAppService.isWidgetCollapsed(parentContextId);
		component.isCollapsed = initiallyCollapsed;
		component.isCollapsedDefault = initiallyCollapsed;
		this.visibilitySubscription = component.visibilityToggled.subscribe(
			(isCollapsed: boolean) => {
				this.contextAppService.updateCollapsedWidgetsStorage(
					parentContextId,
					isCollapsed,
				);
			},
		);
	}
}
