/**
 * Represents the response object returned from the server.
 */
export class OperationResponse implements IOperationResponse {
	id: string = null;
	content: any = null;
	errorList: ErrorInfo[] = null;
	messageList: MessageInfo[] = null;

	/**
	 * Optional error code when the http promise was rejected.
	 * Used for invalid session if the code is "0".
	 */
	errorHttpCode: string;

	constructor(content?: any) {
		this.content = content;
	}

	hasError(): boolean {
		return this.errorList && this.errorList.length > 0;
	}

	hasMessage(): boolean {
		return this.messageList && this.messageList.length > 0;
	}

	hasGenericError(): boolean {
		return (
			this.hasError() &&
			this.errorList.length === 1 &&
			this.errorList[0].message === "The action could not be performed."
		);
	}

	getErrorMessages(): string {
		const errors = this.errorList;
		if (!errors) {
			return "";
		}
		let output = "";

		for (const error of errors) {
			output += error.message + " ";
		}
		return output.trim();
	}

	toErrorLog(): string {
		const errors = this.errorList;
		if (!errors) {
			return "";
		}
		let output = "";

		const listLength = errors.length;
		for (let i = 0; i < listLength; i++) {
			const errorInfo = errors[i];
			output +=
				errorInfo.message +
				" (Error code: " +
				errorInfo.code +
				")" +
				(i === listLength - 1 ? "" : ", ");
		}
		return output;
	}
}

