export interface IPage {
	/**
	 * Gets or sets the localized page title in the current user language.
	 * This property may be null if no localization exists.
	 */
	title?: string;

	/**
	 * Gets or sets the localized page description in the current user language.
	 * This property may be null if no localization exists.
	 */
	description?: string;

	/**
	 * Gets the core page data.
	 */
	data: IPageData;

	dynamicPage?: IDynamicPage;

	/**
	 * Popularity is set on public pages only. Was previously stored on the WidgetData but is now on the top level because
	 * Standard pages can't have the popularity on the PageData.
	 */
	popularity?: number;

	/**
	 * Gets a value that indicates if this page is mandatory for the current user.
	 */
	isMandatory?: boolean;

	/**
	 * Gets a value that indicates if the current user is allowed to edit the page.
	 */
	isEditable?: boolean;

	/**
	 * Gets a value that indicates if the current user is allowed to view the page.
	 *
	 * A page that the user is not allowed to view will still be returned by the server but
	 * without any widget content and with this property set to false.
	 *
	 */
	isViewable?: boolean;

	isPrimary?: boolean;

	/**
	 * Gets a value that indicates if this page is enabled in mobile mode.
	 */
	isMobile?: boolean;

	/**
	 * Gets or sets the accessState. Used in admin views to see if there are permissions. See AccessState.
	 */
	accessState?: number;

	/**
	 * Gets or sets the access list.
	 */
	access?: IEntityAccess[];

	widgetDefinitions?: IWidgetDefinitionItem[];

	applications?: IStringToIApplicationArrayMap;

	/**
	 * The page localization data used when publishing or updating a published page.
	 */
	localization?: IStringToEntityLocalizationMap;

	/**
	 * Gets or sets additional user settings for a published page.
	 */
	settings?: IStringToAnyMap;

	/**
	 * Date of last change.
	 */
	changeDate?: string;

	/**
	 * Gets or sets the page sort order.
	 */
	sortOrder?: number;

	/**
	 * Does the page have translations?
	 */
	isLocalized?: boolean;

	/**
	 * Error info
	 */
	err?: IPageError;
}

