export class WidgetCategory {
	// ReSharper disable InconsistentNaming
	static BusinessProcess = 5;
	static Application = 1;
	static Social = 2;
	static Utilities = 3;
	static BusinessIntelligence = 4;
	static StatisticsUsage = 6;

	// Client only categories
	static All = -1;
	static NewUpdated = -2;
	static MyRecent = -3;

	// ReSharper restore InconsistentNaming

	static getCategory(category: string): number {
		switch (category) {
			case "application":
				return WidgetCategory.Application;
			case "businessprocess":
				return WidgetCategory.BusinessProcess;
			case "social":
				return WidgetCategory.Social;
			case "utilities":
				return WidgetCategory.Utilities;
			case "businessintelligence":
				return WidgetCategory.BusinessIntelligence;
			case "statisticsusage":
				return WidgetCategory.StatisticsUsage;
			default:
				return WidgetCategory.Application;
		}
	}
}

