/**
 * A type that separates users from groups. Never use 0 as this was the Ming.le group that has now been removed.
 */
export enum PrincipalType {
	MingleGroup = 0,
	User = 1,
	Role = 2,
	DistributionGroup = 3,
}

/**
 * Represents an access level granted to a specific principal which may be a group, role or a single user.
 */
export interface IEntityAccess {
	/**
	 * Gets or sets the entity ID.
	 */
	id: string;

	/**
	 * Gets or sets the operation.
	 * This property should be used by the client when modifying permissions.
	 */
	operation?: EntityOperation;

	/**
	 * Gets or sets the entity access level.
	 */
	accessLevel: number;

	/**
	 * Gets or sets the group, role or user that the access level applies to.
	 */
	principal: string;

	/**
	 * Gets or sets the name of the group, role or user that the access level applies to.
	 */
	principalName?: string;

	/**
	 * States whether the entity is a user or group.
	 */
	principalType?: PrincipalType;

	/**
	 * Gets or sets the info of the group, role or user that the access level applies to.
	 * This is currently only used for emails for users.
	 */
	info?: string;

	/**
	 * Gets or sets a value that indicates if the entity should be shown in a catalog or not.
	 * This property currently only applies to widgets.
	 */
	isCatalog?: boolean;

	/**
	 * Gets or sets a value that indicates if the entity is a published or not.
	 * This is only a client property.
	 */
	isPublished?: boolean;

	changedBy?: string;
	changedByName?: string;
	changeDate?: string;
	isUser?: boolean;
}

