	static colorToBackgroundStyle(colorNumber: number, isHero = false): any {
		let color: string;
		if (!colorNumber) {
			color = isHero ? Constants.defaultHeroColor : Constants.defaultColor;
		} else {
			color = UIUtil.numberToHexCode(colorNumber, isHero);
		}
		return { "background-color": color };
	}

