	/**
	 * Returns a hex color code converted from provided number.
	 * @param colorNumber
	 * @param isHero
	 */
	static numberToHexCode(colorNumber: number, isHero = false): string {
		const colorArrayItem = ArrayUtil.itemByProperty(
			this.pageColorArray,
			"number",
			colorNumber,
		);
		if (!colorArrayItem) {
			return isHero ? Constants.defaultHeroColor : Constants.defaultColor;
		} else {
			return isHero ? colorArrayItem.heroColorCode : colorArrayItem.colorCode;
		}
	}

	/**
	 * Returns an announcement background hex color code converted from provided number.
	 * @param colorNumber
	 */
	static numberToMemoHexCode(colorNumber: number): string {
		const colorItem = this.pageColorArray.find(
			(item) => item.number === colorNumber,
		);
		return colorItem ? colorItem.memoColorCode : Constants.defaultMemoColor;
	}

	/**
	 * Returns a color number converted from the provided hex code.
	 * @param hexCode
	 * @param isHero
	 */
	static hexCodeToNumber(hexCode: string, isHero = false): number {
		if (!hexCode) {
			return 0;
		}
		if (!isHero) {
			return ArrayUtil.itemByProperty(this.pageColorArray, "colorCode", hexCode)
				.number;
		} else {
			return ArrayUtil.itemByProperty(
				this.pageColorArray,
				"heroColorCode",
				hexCode,
			).number;
		}
	}

	/**
	 * Returns a rgba color string for page header converted from provided number. Opacity can be provided (0-1).
	 * @param colorNumber
	 * @param opacity
	 */
	static numberToRgba(colorNumber: number, opacity = 1): string {
		const hexString = UIUtil.numberToHexCode(colorNumber).replace("#", "");

		const r = parseInt(hexString.substring(0, 2), 16);
		const g = parseInt(hexString.substring(2, 4), 16);
		const b = parseInt(hexString.substring(4, 6), 16);

		return `rgba(${r}, ${g}, ${b}, ${opacity})`;
	}

