	static numberToHexCodeExtended(nr: number): string {
		return "#" + this.getColorpickerOptionsExtended().colors[nr].value;
	}

	/**
	 * Returns a hex code from an extended color set.
	 * Use with getColorpickerOptionsExtended().
	 * @param hexCode, like #0f0f0f
	 */
	static hexCodeToNumberExtended(hexCode: string): number {
		hexCode = hexCode.slice(1);
		const colors = this.getColorpickerOptionsExtended().colors;
		return ArrayUtil.indexByProperty(colors, "value", hexCode);
	}

	static refreshSvgIcons(element: JQuery): void {
		if (!element) {
			return;
		}
		const userAgent = navigator.userAgent;
		// Refresh SVG elements if IE11
		if (
			!!userAgent.match(/Trident.*rv\:11\./) &&
			userAgent.toLowerCase().indexOf("windows nt 10") !== -1
		) {
			const svgElements = element.find("svg"); // Or use directly?
			for (let i = 0; i < svgElements.length; i++) {
				const parent = $(svgElements[i]).parent();
				parent.html(parent.html()); // Optional useElement.href.baseval = useElement.href.baseval
			}
		}
	}

	/**
	 * Check if the locale options of LocaleCompare is supported by the current runtime environment.
	 */
	static localeCompareSupportsLocales() {
		const options: ILocaleSortOptions = {
			localeMatcher: "lookup",
			usage: "search",
			sensitivity: "base",
			ignorePunctuation: true,
			numeric: true,
			caseFirst: "upper",
		};

		try {
			return "a".localeCompare("A", "en-US", options) === 0;
		} catch (e) {
			Log.debug(
				"The full implementation of LocaleCompare is not supported by this browser.",
			);
		}
		return false;
	}
