export class ContainerVersion {
	private static version: string = null;
	static setVersion(containerVersion: string): void {
		ContainerVersion.version = containerVersion;
	}

	static isUpdated(responseVersion: string): boolean {
		if (!ContainerVersion.version) {
			return false;
		}
		if (!responseVersion) {
			return false;
		}
		if (responseVersion == null || responseVersion.trim() === "") {
			return false;
		}
		return ContainerVersion.version !== responseVersion;
	}
}

