export class Theme {
	private static _className: string;
	private static isInitialized: boolean;

	static get className(): string {
		return Theme._className;
	}

	static init(): void {
		if (Theme.isInitialized) {
			return;
		}
		Theme.isInitialized = true;

		const className = Theme.resolveTheme();
		$("html").addClass(className);
		Theme._className = className;
	}

	private static resolveTheme(): string {
		let theme = Constants.themeClassLight;
		try {
			$("link").each((i, value) => {
				const url = $(value).attr("href");
				if (url && url.includes(".css") && url.includes("theme-")) {
					if (url.indexOf("dark") >= 0) {
						theme = Constants.themeClassDark;
					} else if (url.indexOf("contrast") >= 0) {
						theme = Constants.themeClassContast;
					}
				}
			});
		} catch (ex) {
			Log.error("Failed to resolve theme", ex);
		}
		return theme;
	}
}

export class Toggle {
	static readonly Default = 0;
	static readonly Enabled = 1;
	static readonly Disabled = 2;

	static isEnabled(value: number): boolean {
		return Toggle.Enabled === value;
	}

	static isDisabled(value: number): boolean {
		return Toggle.Disabled === value;
	}
}
