import { Component } from "@angular/core";
import {
	ContainerService,
	ContextService,
	CoreBase,
	LanguageService,
	PageService,
} from "lime/core";

@Component({
	selector: "lm-welcome-container",
	templateUrl: "./welcome-container.html",
})
export class WelcomeComponent extends CoreBase {
	lang: ILanguageLime;
	showPrivate = false;
	showCatalog = false;
	showBoth = false;

	constructor(
		languageService: LanguageService,
		contextService: ContextService,
		private readonly containerService: ContainerService,
		private readonly pageService: PageService,
	) {
		super("WelcomeComponent");
		this.lang = languageService.getLanguage();

		const settings = contextService.getContext().settings;
		const isPrivate = settings.isPrivatePagesEnabled();
		const isCatalog = settings.isPageCatalogEnabled();
		if (isPrivate && isCatalog) {
			this.showBoth = true;
		} else {
			this.showPrivate = isPrivate && !isCatalog;
			this.showCatalog = !isPrivate && isCatalog;
		}
	}

	addPage(): void {
		this.containerService.showAddPage();
	}

	showPageCatalog(): void {
		this.pageService.showPageCatalog();
	}
}
