import { Injectable } from "@angular/core";
import { StringUtil } from "lime";
import { IWidget } from "lime/core";
import { BehaviorSubject, merge, Observable, of, ReplaySubject } from "rxjs";
import {
	catchError,
	debounceTime,
	filter,
	map,
	scan,
	shareReplay,
	switchMap,
	tap,
} from "rxjs/operators";
import { CompanyonService } from "../base/companyon";
import { ContainerService } from "../base/container";
import {
	BrokenReason,
	Constants,
	ErrorInfo,
	FailedShorcutErrorCode,
	IContext,
	IFailedShortcutMessage,
	IMingleContext,
	IMissingPage,
	IOperationResponse,
	IPageContainer,
	IPageInstance,
	IPagingInfo,
	IShortcutContextData,
	IWidgetCatalogRequest,
	IWidgetHandle,
	IWidgetInfo,
	IWidgetListResponse,
	UIUtil,
} from "../base/core";
import { DevService } from "../base/dev";
import { CoreBase, CoreUtil } from "../base/runtime";
import { LanguageService } from "../base/service";
import { WidgetContainerComponent } from "../components/widget-container/widget-container";
import { IContainerOptions } from "../container/core";
import { ContainerLoaderService } from "../container/loader";
import { PageService } from "../page/service";
import { ContextService, DataService } from "../service";
import { WidgetUtil } from "../widget/runtime";
import { WidgetService } from "../widget/service";
import { ModalMonitorService } from "./modal-monitor.service";

export interface IMobileService {
	widgetList$: Observable<IWidgetInfo[]>;
	pageList$: Observable<IPageInstance[]>;
	widgetPage$: Observable<IPageInstance>;
	mode$: Observable<MobileMode>;
	features$: Observable<IMobileFeatures>;
	listWidgets(): Observable<IWidgetInfo[]>;
	openWidget(widgetInfo: IWidgetInfo): Observable<IPageInstance>;
	sendFavoriteContext(widgetHandle: IWidgetHandle, title: string);
	selectPage(pageId?: string): void;
}

export enum MobileMode {
	None,
	Pages,
	Widget,
}

export interface IMobileFeatures {
	pages: boolean;
	widgets: boolean;
}

export enum MobileEmptyType {
	Default,
	Broken,
	Permission,
}

export interface IMobileEmpty {
	isVisible: boolean;
	message?: string;
	type?: MobileEmptyType;
}

interface IPageInstanceMap {
	[key: string]: IPageInstance;
}

@Injectable({
	providedIn: "root",
})
export class MobileService extends CoreBase implements IMobileService {
	features$: Observable<IMobileFeatures> = this.contextService.context$.pipe(
		map<IContext, IMobileFeatures>((context) => ({
			pages: context.settings.isMobilePagesEnabled() || this.devService.isDev,
			widgets:
				context.settings.isMobileWidgetsEnabled() || this.devService.isDev,
		})),
	);
	empty$: Observable<IMobileEmpty>;
	widgetPage$: Observable<IPageInstance>;
	widgetList$: Observable<IWidgetInfo[]>;
	mode$: Observable<MobileMode>;
	menuVisibility$: Observable<boolean>;
	startupOverlayVisibility$: Observable<boolean>;
	title$: Observable<string>;
	pageColor$: Observable<string>;
	pageList$: Observable<IPageInstance[]>;
	widgetContainer$: Observable<WidgetContainerComponent>;

	private emptySubject = new ReplaySubject<IMobileEmpty>(1);
	private widgetPageSubject = new ReplaySubject<IPageInstance>(1);
	private widgetsLoadedSubject = new BehaviorSubject<IWidgetInfo[]>([]);
	private modeSubject = new ReplaySubject<MobileMode>(1);
	private menuVisibilitySubject = new ReplaySubject<boolean>(1);
	private startupOverlayVisibilitySubject = new ReplaySubject<boolean>(1);
	private titleSubject = new BehaviorSubject<string>(Constants.applicationName);
	private pagesLoadedSubject = new ReplaySubject<IPageInstance[]>(1);
	private widgetContainerSubject =
		new BehaviorSubject<WidgetContainerComponent>(null);

	private mode: MobileMode = MobileMode.None;
	private pageMap: IPageInstanceMap = {};
	private widgetPaging: IPagingInfo = null;
	private readonly lang: ILanguageLime;

	constructor(
		languageService: LanguageService,
		private contextService: ContextService,
		private dataService: DataService,
		private containerLoaderService: ContainerLoaderService,
		private widgetService: WidgetService,
		private containerService: ContainerService,
		private readonly pageService: PageService,
		private readonly devService: DevService,
		private readonly modalMonitor: ModalMonitorService,
		private companyonService: CompanyonService,
	) {
		super("MobileService");

		this.lang = languageService.getLanguage();
		this.assignStreams();

		// Check for previous events
		const mingleContext = this.containerService.consumePreviousMobileEvent();
		if (mingleContext) {
			this.logInfo("Found drillback to mobile widget");
			this.handleFavoriteContextCallback(mingleContext);
		}

		// Register handler for receiving favorite callbacks
		this.containerService
			.mobileWidgetSelected()
			.on((context: IMingleContext) => {
				this.handleFavoriteContextCallback(context);
				this.handleStartupOverlay();
			});

		this.containerService.selected$.subscribe(() => {
			this.hideEmpty();
			this.hideAppMenu();
			// Select page mode as soon as a page is selected, can be a favoriteContext
			this.setMode(MobileMode.Pages);
			this.handleStartupOverlay();
		});

		this.containerService.missingPage$.subscribe(
			(missingPage: IMissingPage) => {
				this.onMissingPage(missingPage);
				this.handleStartupOverlay();
			},
		);

		this.hideEmpty();
		this.monitorModals();
		this.initHomeCallback();
		this.loadPageContainer();
	}

	onMissingPage(missingPage: IMissingPage): void {
		const pagesEnabled = this.contextService
			.getContext()
			.settings.isMobilePagesEnabled();
		const message = pagesEnabled
			? this.lang.brokenPage
			: this.lang.pagesNotAvailable;

		this.showEmpty(message, MobileEmptyType.Broken);
		if (missingPage != null && missingPage.refId) {
			const failureMessage = this.createBrokenFailedShortcutMessage(
				true,
				missingPage.refId,
			);
			this.sendFailedContextMessage(failureMessage);
		}
	}

	createBrokenFailedShortcutMessage(
		isPage: boolean,
		refId: number,
	): IFailedShortcutMessage {
		const failureMessage: IFailedShortcutMessage = {
			id: refId,
			errorCode: FailedShorcutErrorCode.Broken,
			message: isPage ? this.lang.brokenPage : this.lang.brokenWidget,
		};
		return failureMessage;
	}

	sendFailedContextMessage(message: IFailedShortcutMessage): void {
		this.logInfo("Sending failed context message " + JSON.stringify(message));
		infor.companyon.client.sendMessage("failedShortcutContext", message);
	}

	listWidgets(): Observable<IWidgetInfo[]> {
		return this.getWidgets().pipe(
			map((widgets) =>
				widgets.map((widget) => ({
					...widget,
					displayIcon: this.widgetService.createImagePath(widget),
				})),
			),
			tap((widgets) => this.widgetsLoadedSubject.next(widgets)),
		);
	}

	openWidget(widgetInfo: IWidgetInfo): Observable<IPageInstance> {
		const id = widgetInfo.widgetId;
		const widgetHandle: IWidgetHandle = {
			id: id,
			pid: widgetInfo.standardWidgetId,
			byRef: CoreUtil.isGuid(id),
		};
		return this.openWidgetHandle(widgetHandle);
	}

	selectPage(pageId?: string): void {
		if (pageId) {
			this.containerService.select(pageId);
		}
		this.setMode(MobileMode.Pages);
	}

	sendFavoriteContext(widgetHandle: IWidgetHandle, title: string) {
		// Send a message to inform Ming.le that a widget was successfully loaded

		const mingleContext: IMingleContext = {
			id: widgetHandle.id,
			type: Constants.shortcutTypeWidget,
			parameters: { pid: widgetHandle.pid },
		};
		const data: IShortcutContextData = {
			absoluteURL: "false",
			name: title,
			shortcutContext: mingleContext,
		};
		this.containerService.sendShortcutContext(data);
	}

	setWidgetContainer(widgetContainer: WidgetContainerComponent) {
		this.widgetContainerSubject.next(widgetContainer);
	}

	private monitorModals() {
		this.modalMonitor.modalToggled$.subscribe((isOpen) => {
			this.logDebug("sending message to toggle the bottom bar");
			this.companyonService.send({
				name: "mobile_setTheBottomBarState",
				data: {
					state: isOpen ? "0" : "1",
				},
			});
		});
		const contextSwitch$ = merge(
			this.containerService.selected$,
			this.widgetPage$,
		);
		contextSwitch$
			.pipe(
				debounceTime(1), // Avoid duplicate execution when context switches are unhumanly fast.
			)
			.subscribe(() => {
				this.logDebug("Page/Widget was switched, closing any open modals");
				this.modalMonitor.closeAll();
			});
	}

	private assignStreams(): void {
		this.empty$ = this.emptySubject.asObservable();
		this.widgetPage$ = this.widgetPageSubject.asObservable();
		this.mode$ = this.modeSubject.asObservable();
		this.menuVisibility$ = this.menuVisibilitySubject.asObservable();
		this.startupOverlayVisibility$ =
			this.startupOverlayVisibilitySubject.asObservable();
		this.pageList$ = this.pagesLoadedSubject.asObservable();
		this.widgetList$ = this.widgetsLoadedSubject.pipe(
			scan((oldWidgets, newWidgets) => [...oldWidgets, ...newWidgets], []),
		);

		this.title$ = merge(
			this.containerService.selected$.pipe(map((page) => page.title)),
			this.widgetPage$.pipe(
				filter((page) => !!page),
				map((page) => page.widgets[0]),
				switchMap((widget) => WidgetUtil.getTitleAsync(widget)),
			),
			this.titleSubject.asObservable(),
		).pipe(shareReplay(1));

		this.pageColor$ = merge(
			this.containerService.selected$,
			this.widgetPage$,
		).pipe(
			filter((page) => !!page),
			map((page) => UIUtil.numberToHexCode(page.data.color)),
		);

		this.widgetContainer$ = this.widgetContainerSubject.asObservable();
	}

	private openWidgetHandle(
		widgetHandle: IWidgetHandle,
		refId?: number,
	): Observable<IPageInstance> {
		this.logInfo(
			"openWidgetHandle: " +
				widgetHandle.id +
				" " +
				widgetHandle.pid +
				", refId " +
				refId,
		);

		this.setMode(MobileMode.Widget);
		this.hideAppMenu();

		const page = this.pageMap[widgetHandle.id];
		if (page) {
			this.initializeWidgetPage(page);
			return of(page);
		}

		return this.pageService.createSingleWidgetPage(widgetHandle).pipe(
			tap((page) => {
				this.pageMap[widgetHandle.id] = page;
				if (this.isBrokenSingleWidgetPage(page)) {
					if (refId) {
						const message = this.createFailedWidgetShortcutMessage(page, refId);
						if (message) {
							this.sendFailedContextMessage(message);
						}
					} else {
						this.logInfo(
							"openWidgetHandle: There is no id, so there will be no failContextMessage sent.",
						);
					}
				}
				this.initializeWidgetPage(page);
			}),
			catchError((err) => {
				this.logWarning("Failed to open widget handle " + JSON.stringify(err));
				this.handleInforGoFailedMessage(err, refId);
				const errInfo: ErrorInfo = err;
				const isPermission = this.isPermissionError(errInfo);
				if (isPermission) {
					this.showEmpty(this.lang.noWidgetAccess, MobileEmptyType.Permission);
				} else {
					this.showEmpty(this.lang.brokenWidget, MobileEmptyType.Broken);
				}
				return of(null);
			}),
		);
	}

	private isPermissionError(errorInfo: ErrorInfo) {
		if (errorInfo.code) {
			return (
				errorInfo.code === BrokenReason.NoAccess ||
				errorInfo.code === BrokenReason.NoParentAccess
			);
		} else {
			return false;
		}
	}

	private handleInforGoFailedMessage(error: any, refId: number) {
		if (!refId) {
			this.logInfo(
				"handleInforGoFailedMessage: There is no id, so there will be no failContextMessage sent.",
			);
			return;
		}
		if (error && error.code) {
			const errorInfo: ErrorInfo = error;
			if (refId && errorInfo.code) {
				const message = this.createFiledWidgetShortcutMessageReason(
					errorInfo.code,
					refId,
				);
				if (message) {
					this.sendFailedContextMessage(message);
				}
			}
		}
	}

	private createFailedWidgetShortcutMessage(
		page: IPageInstance,
		refId: number,
	): IFailedShortcutMessage {
		// Get reason and create context message if the widget is deleted, you don't have access etc
		const widget = this.getFirstWidget(page);
		if (widget == null) {
			return null;
		}
		const brokenReason = widget.getBrokenReason();
		return this.createFiledWidgetShortcutMessageReason(brokenReason, refId);
	}

	private createFiledWidgetShortcutMessageReason(
		brokenReason: number,
		refId: number,
	) {
		const text = WidgetUtil.getBrokenMessage(this.lang, brokenReason);
		const errorCode =
			WidgetUtil.getBrokenErrorCodeForContextMessage(brokenReason);
		return { errorCode: errorCode, id: refId, message: text };
	}

	private getFirstWidget(pageInstance: IPageInstance): IWidget {
		try {
			if (pageInstance && pageInstance.widgets) {
				const widget = pageInstance.widgets[0];
				return widget;
			}
		} catch (err) {
			this.logWarning("Failed to get first widget " + err);
			return null;
		}
	}

	private isBrokenSingleWidgetPage(pageInstance: IPageInstance): boolean {
		const widget = this.getFirstWidget(pageInstance);
		// If there is no widget there is also an indication that something is broken
		if (widget == null) {
			this.logWarning("isBrokenSingleWidgetPage: widget is null");
		}
		return widget != null ? widget.isBroken() : true;
	}

	private initializeWidgetPage(page: IPageInstance): void {
		this.nextPage(page);
	}

	private setMode(mode: MobileMode): void {
		if (this.mode !== mode) {
			this.mode = mode;
			this.modeSubject.next(mode);
		}
	}

	private handleFavoriteContextCallback(mingleContext: IMingleContext) {
		this.hideAppMenu();
		// Get the widget handle
		const widgetHandle = this.getWidgetHandle(mingleContext);

		if (widgetHandle == null) {
			this.logError("handleFavoriteContextCallback: unable to parse bookmark");
			this.showEmpty(this.lang.brokenWidget, MobileEmptyType.Broken);
			return;
		}
		this.logInfo(
			"handleFavoriteContextCallback: Received call to open widget with id: " +
				widgetHandle.id +
				" pid: " +
				widgetHandle.pid,
		);
		this.openWidgetHandle(widgetHandle, mingleContext.refId).subscribe();
	}

	private getWidgetHandle(mingleContext: IMingleContext): IWidgetHandle {
		const id = mingleContext.id;
		if (StringUtil.isNullOrWhitespace(id)) {
			return null;
		}

		const widgetHandle: IWidgetHandle = { id: id };
		const pid = mingleContext.parameters ? mingleContext.parameters.pid : null;
		widgetHandle.pid = pid;
		if (pid != null || CoreUtil.isGuid(id)) {
			widgetHandle.byRef = true;
		}
		return widgetHandle;
	}

	private handleStartupOverlay() {
		if (this.containerService.getFavoriteMessagePending()) {
			this.hideStartupOverlay();
			this.containerService.setFavoriteMessagePending(false);
		}
	}

	private loadPageContainer(): void {
		this.setMode(MobileMode.Pages);

		const options: IContainerOptions = {
			mode: this.contextService.mode,
			settings: true,
			pages: true,
		};

		this.containerLoaderService.loadContainer(options).subscribe(
			(container: IPageContainer) => {
				this.containerService.updateContainer(container);
				container.selectStartPage();
				this.pagesLoadedSubject.next(container.pages);
				if (container.pages.length === 0) {
					this.showEmpty();
				}
			},
			(r: IOperationResponse) => {
				this.dataService.handleError(r);
			},
		);
	}

	private getWidgets(): Observable<IWidgetInfo[]> {
		if (this.devService.isDev) {
			return of(this.devService.getWidgetInfos());
		}

		return this.fetchWidgets();
	}

	private fetchWidgets(): Observable<IWidgetInfo[]> {
		const request: IWidgetCatalogRequest = {
			includeMobile: true,
			includePublished: true,
			includeStandard: true,
			pageSize: 15,
			paging: this.widgetPaging,
		};
		// TODO: context@ is async. Use accordingly
		const mobileWidgetsEnabled = this.contextService
			.getContext()
			.settings.isMobileWidgetsEnabled();
		const fetchFromService$ = this.dataService
			.post<IWidgetListResponse>("/widget/list", request)
			.pipe(
				tap((response) => (this.widgetPaging = response.paging)),
				map((response) => response.content),
			);

		if (mobileWidgetsEnabled && this.hasMoreWidgetPages()) {
			return fetchFromService$;
		} else {
			return of([]);
		}
	}

	private hasMoreWidgetPages() {
		return !(
			this.widgetPaging &&
			this.widgetPaging.publishedEnd &&
			this.widgetPaging.standardEnd
		);
	}

	private initHomeCallback(): void {
		infor.companyon.client.registerMessageHandler("loadHomeView", () => {
			this.showHomeView();
		});
	}

	private showHomeView() {
		if (this.mode === MobileMode.Widget) {
			this.nextPage(null);
		}
		this.setDefaultTitle();
		this.setMode(MobileMode.Pages);
		this.containerService.getContainer().selectStartPage();
	}

	private setDefaultTitle(): void {
		this.titleSubject.next(Constants.applicationName);
	}

	private nextPage(page: IPageInstance): void {
		if (page) {
			this.hideEmpty();
		} else {
			this.showEmpty();
		}

		this.widgetPageSubject.next(page);
	}

	private hideEmpty(): void {
		this.emptySubject.next({ isVisible: false });
	}

	private hideAppMenu(): void {
		this.menuVisibilitySubject.next(false);
	}

	private hideStartupOverlay(): void {
		this.startupOverlayVisibilitySubject.next(false);
	}

	private showEmpty(message?: string, type?: MobileEmptyType): void {
		this.setDefaultTitle();
		this.hideAppMenu();
		this.emptySubject.next({
			isVisible: true,
			message: message || this.getEmptyMessage(),
			type: type,
		});
	}

	private getEmptyMessage(): string {
		if (this.contextService.getContext().settings.isMobileWidgetsEnabled()) {
			return this.lang.selectWidget;
		}
		return this.lang.noContent;
	}
}
