import {
	Component,
	ComponentRef,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	CoreBase,
	IPageInstance,
	IWidget,
	IWidgetHandle,
	IWidgetInfo,
	MobileService,
} from "lime/core";
import { Observable } from "rxjs";
import { filter, tap } from "rxjs/operators";
import { WidgetContainerComponent } from "../widget-container/widget-container";

interface IMobileWidgetInfo {
	page: IPageInstance;
	widget: IWidget;
	widgetId: string;
	ref: ComponentRef<WidgetContainerComponent>;
}

interface IMobileInfoMap {
	[key: string]: IMobileWidgetInfo;
}

@Component({
	selector: "lm-mobile-widget",
	styleUrls: ["./mobile-widget.scss"],
	templateUrl: "./mobile-widget.html",
})
export class MobileWidgetComponent extends CoreBase {
	@ViewChild("widgetView", { read: ViewContainerRef, static: false })
	widgetView: ViewContainerRef;

	widgets$: Observable<IWidgetInfo[]> = this.mobileService.widgetList$;

	widgetPage$: Observable<IPageInstance> = this.mobileService.widgetPage$.pipe(
		filter((page) => !!page),
		tap((page) => {
			this.onWidgetPage(page);
		}),
	);

	private widgetMap: IMobileInfoMap = {};
	private currentWidgetInfo: IMobileWidgetInfo;

	constructor(private readonly mobileService: MobileService) {
		super("MobileContainerComponent");
	}

	createWidgetHandle(widget: IWidget): IWidgetHandle {
		try {
			const definition = widget.definition;
			const widgetHandle: IWidgetHandle = {
				id: definition.widgetId,
				pid: definition.standardWidgetId,
				byRef: definition.isByRef,
			};
			return widgetHandle;
		} catch (err) {
			this.logError(
				"createWidgetHandle: Failed to create widgetHandle from the resolved IWidget" +
					err,
			);
			return null;
		}
	}

	private onWidgetPage(page: IPageInstance): void {
		const widget = this.getWidget(page);
		const widgetId = widget.id;

		this.logDebug("Widget updated: " + widgetId);

		const info = this.widgetMap[widgetId];
		if (info) {
			this.selectExisting(info);
		} else {
			this.selectNew(page);
		}

		this.setWidgetContainer();
	}

	private selectNew(page: IPageInstance): void {
		this.deselectCurrent();

		const widget = this.getWidget(page);
		const widgetId = widget.id;

		const ref = this.widgetView.createComponent(WidgetContainerComponent);
		const instance = ref.instance;
		instance.page = page;
		instance.widget = widget;
		widget.containerRef = ref;

		const info: IMobileWidgetInfo = {
			widgetId: widgetId,
			page: page,
			widget: widget,
			ref: ref,
		};
		this.widgetMap[widgetId] = info;
		this.currentWidgetInfo = info;

		// Note that the definition for the widget might not even be loaded here
		// Notify Mingle if the widget was loaded correctly. Make sure error scenarios are handled
		const subscription = widget.initialized$.subscribe((widget) => {
			if (!widget.isBroken()) {
				this.sendFavoriteContext(widget);
				subscription.unsubscribe();
			}
		});
	}

	private selectExisting(info: IMobileWidgetInfo): void {
		this.deselectCurrent();

		this.toggleVisibility(info, true);
		this.currentWidgetInfo = info;

		this.sendFavoriteContext(info.widget);
	}

	private deselectCurrent(): void {
		const info = this.currentWidgetInfo;
		if (info) {
			this.toggleVisibility(info, false);
		}
	}

	private toggleVisibility(info: IMobileWidgetInfo, isVisible: boolean): void {
		const instance = info.ref.instance;

		if (isVisible) {
			instance.show();
		} else {
			instance.hide();
		}
	}

	private sendFavoriteContext(widget: IWidget): void {
		const widgetHandle = this.createWidgetHandle(widget);
		if (widgetHandle) {
			this.mobileService.sendFavoriteContext(widgetHandle, widget.title);
		}
	}

	private getWidget(page: IPageInstance): IWidget {
		return page.widgets[0];
	}

	private setWidgetContainer() {
		const widgetContainer = this.currentWidgetInfo.ref.instance;
		this.mobileService.setWidgetContainer(widgetContainer);
	}
}
