import { enableProdMode, NgModuleRef } from "@angular/core";
import { platformBrowserDynamic } from "@angular/platform-browser-dynamic";
import { AppModule, IInitOptions, initAppModule } from "./app";
import { ClientConfiguration } from "./base/runtime";

import * as angularAnimations from "@angular/animations";
import * as angularCommon from "@angular/common";
import * as angularCommonHttp from "@angular/common/http";
import * as angularCore from "@angular/core";
import * as angularForms from "@angular/forms";
import * as angularPlatformBrowser from "@angular/platform-browser";
import * as idsEnterpriseNg from "ids-enterprise-ng";
import * as lime from "lime";
import * as limeCore from "lime/core";
import * as rxjs from "rxjs";
import * as rxjsOperators from "rxjs/operators";
import * as tslib from "tslib";
import { environment } from "../../../environments/environment";

// Application bootstrap with Angular JIT

export const bootstrapModule = () => {
	platformBrowserDynamic()
		.bootstrapModule(AppModule)
		.then((moduleRef: NgModuleRef<any>) => {
			ClientConfiguration.appModuleRef = moduleRef;
		});
};

export const bootstrap = async (options?: IInitOptions) => {
	if (environment.production) {
		enableProdMode();
	} else {
		options = options ?? {};
		const params = new URL(location.href).searchParams;
		if (params.has("devLanguage")) {
			options.language = params.get("devLanguage");
		}
		if (params.has("devThemeName")) {
			options.devThemeName = params.get("devThemeName");
		}
		if (params.has("devThemeVersion")) {
			options.devThemeVersion = params.get("devThemeVersion");
		}
		if (params.has("devWidget")) {
			options.devWidget = params.get("devWidget");
		}
	}
	prepareSystemJS();
	overrideIDSModals();
	await initAppModule(options);
	bootstrapModule();
};

function prepareSystemJS() {
	SystemJS.set("tslib", SystemJS.newModule(tslib));
	SystemJS.set("rxjs", SystemJS.newModule(rxjs));
	SystemJS.set("rxjs/operators", SystemJS.newModule(rxjsOperators));
	SystemJS.set("@angular/core", SystemJS.newModule(angularCore));
	SystemJS.set("@angular/common", SystemJS.newModule(angularCommon));
	SystemJS.set("@angular/common/http", SystemJS.newModule(angularCommonHttp));
	SystemJS.set("@angular/forms", SystemJS.newModule(angularForms));
	SystemJS.set("@angular/animations", SystemJS.newModule(angularAnimations));
	SystemJS.set(
		"@angular/platform-browser",
		SystemJS.newModule(angularPlatformBrowser),
	);
	SystemJS.set("ids-enterprise-ng", SystemJS.newModule(idsEnterpriseNg));
	SystemJS.set("@infor/sohoxi-angular", SystemJS.newModule(idsEnterpriseNg));
	SystemJS.set("lime", SystemJS.newModule(lime));
	SystemJS.set("@infor-lime/core", SystemJS.newModule(lime));
	SystemJS.set("lime/core", SystemJS.newModule(limeCore));
	SystemJS.config({
		map: {
			// TODO: Might need to add more of these in case widgets with old imports are crashing.
			"rxjs/AsyncSubject": "rxjs",
			"rxjs/Observable": "rxjs",
			"rxjs/Subject": "rxjs",
		},
		packages: {
			"standard-widgets": {
				// TODO: Not sure why this is needed. js should already be the default
				defaultExtension: "js",
			},
			"sample-widgets": {
				// TODO: Not sure why this is needed. js should already be the default
				defaultExtension: "js",
			},
			widgets: {
				// TODO: Not sure why this is needed. js should already be the default
				defaultExtension: "js",
			},
		},
	});
}

/**
 * Overrides $.modal() which is used by IDS dialog, cap, about & other services.
 * This makes all dialogs full-size by default on smaller screens.
 */
function overrideIDSModals() {
	try {
		const oldModal = $.fn.modal;
		if (!oldModal) {
			throw new Error(
				"IDS modal function ($.fn.modal) hasn't been defined yet.",
			);
		}
		$.fn.modal = function (options = {}) {
			options.breakpoint = options.breakpoint ?? "wide-tablet"; // Overrides: "phone-to-tablet"
			options.fullsize = options.fullsize ?? "responsive"; // Overrides: false
			return oldModal.call(this, options);
		};
	} catch (error) {
		console.error("Failed to override modal default settings:", error);
	}
}

bootstrap();
