import { Component, EventEmitter, Output } from "@angular/core";
import { CoreBase } from "../../base/runtime";
import { LanguageService } from "../../base/service";
import { SystemMessagesService } from "../../services/system-messages.service";

@Component({
	selector: "lm-system-message",
	templateUrl: "./system-message.component.html",
	styleUrls: ["./system-message.component.scss"],
	host: {
		class: "lm-hdr-bg",
	},
})
export class SystemMessageComponent extends CoreBase {
	@Output() dismissed = new EventEmitter<void>();

	currentMessage: string;
	messageMoreBefore: string;
	messageMoreAfter: string;
	labelMore: string;

	constructor(
		private readonly systemMessagesService: SystemMessagesService,
		public languageService: LanguageService,
	) {
		super("SystemMessageComponent");
	}

	ngOnInit() {
		this.setMessages();
	}

	onDismiss() {
		this.dismissed.emit();
	}

	showMessages() {
		this.systemMessagesService.showSystemMessages();
	}

	private setMessages() {
		const lang = this.languageService.getLanguage();
		this.currentMessage = this.systemMessagesService.getHeading();
		const clickForMore = lang.clickForMoreInformation;
		this.messageMoreBefore = clickForMore.substring(
			0,
			clickForMore.indexOf("{"),
		);
		this.messageMoreAfter = clickForMore.substring(
			clickForMore.indexOf("}") + 1,
		);

		this.labelMore = lang.readMoreLink;
	}
}
